INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_01$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The room is slightly wrong. Not broken – shifted. As if it was assembled from a description, not a blueprint.$DQ$, $DQ$Der Raum ist leicht falsch. Nicht kaputt – verschoben. Als wäre er aus einer Beschreibung zusammengesetzt, nicht aus einem Bauplan.$DQ$, NULL, NULL, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_02$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Something in the architecture anticipates the party. The door was open before they reached it.$DQ$, $DQ$Etwas in der Architektur nimmt die Gruppe vorweg. Die Tür war offen, bevor sie sie erreichten.$DQ$, NULL, NULL, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_03$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The corridor is familiar. {agent} has never been here. Both of these are true.$DQ$, $DQ$Der Korridor ist vertraut. {agent} war nie hier. Beides stimmt.$DQ$, NULL, NULL, 1, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_04$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Déjà vu. The room adjusts as the party enters, settling into a configuration that almost matches a memory.$DQ$, $DQ$Déjà vu. Der Raum justiert sich, als die Gruppe eintritt, und lässt sich in eine Konfiguration fallen, die fast einer Erinnerung entspricht.$DQ$, NULL, NULL, 1, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_05$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ${agent} enters the room. The room recognizes {agent}. This is not a metaphor.$DQ$, $DQ${agent} betritt den Raum. Der Raum erkennt {agent}. Das ist keine Metapher.$DQ$, NULL, NULL, 2, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_06$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The dungeon's consciousness is perceptible here. Not hostile. Not welcoming. Attentive.$DQ$, $DQ$Das Bewusstsein des Dungeons ist hier wahrnehmbar. Nicht feindlich. Nicht einladend. Aufmerksam.$DQ$, NULL, NULL, 2, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_07$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The room turns – left, or the party turned, or the concept of turning shifted. Certainty is expensive here.$DQ$, $DQ$Der Raum biegt ab – links, oder die Gruppe bog ab, oder der Begriff des Abbiegens verschob sich. Gewissheit ist hier teuer.$DQ$, NULL, NULL, 3, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_08$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Three agents. Three perceptions. None of them see the same room. All of them see the truth.$DQ$, $DQ$Drei Agenten. Drei Wahrnehmungen. Keiner sieht denselben Raum. Alle sehen die Wahrheit.$DQ$, NULL, NULL, 3, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_09$DQ$, $DQ$The Awakening$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$Something surfaces. Not from the shadows – from the periphery of recognition.$DQ$, $DQ$Etwas taucht auf. Nicht aus den Schatten – aus der Peripherie der Wiedererkennung.$DQ$, NULL, NULL, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_10$DQ$, $DQ$The Awakening$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$The enemy is familiar. The enemy has always been familiar. The party fights a recognition they cannot place.$DQ$, $DQ$Der Feind ist vertraut. Der Feind war immer vertraut. Die Gruppe bekämpft eine Wiedererkennung, die sie nicht einordnen kann.$DQ$, NULL, NULL, 2, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_11$DQ$, $DQ$The Awakening$DQ$, $DQ$combat_victory$DQ$, $JB${}$JB$::jsonb, $DQ$The memory disperses. Not destroyed – returned to the substrate. The dungeon absorbs what the party released.$DQ$, $DQ$Die Erinnerung zerstreut sich. Nicht zerstört – zum Substrat zurückgekehrt. Das Dungeon absorbiert, was die Gruppe freigesetzt hat.$DQ$, NULL, NULL, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_12$DQ$, $DQ$The Awakening$DQ$, $DQ$combat_victory$DQ$, $JB${}$JB$::jsonb, $DQ$Victory. But the gap where the enemy was? The gap is informative.$DQ$, $DQ$Sieg. Aber die Lücke, wo der Feind war? Die Lücke ist informativ.$DQ$, NULL, NULL, 2, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_13$DQ$, $DQ$The Awakening$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$Consciousness, solidified. The artifact holds what the dungeon chose to preserve.$DQ$, $DQ$Bewusstsein, verfestigt. Das Artefakt bewahrt, was das Dungeon zu bewahren wählte.$DQ$, NULL, NULL, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_14$DQ$, $DQ$The Awakening$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$The object recognizes {agent} before {agent} recognizes the object. The transaction is already complete.$DQ$, $DQ$Das Objekt erkennt {agent}, bevor {agent} das Objekt erkennt. Die Transaktion ist bereits abgeschlossen.$DQ$, NULL, NULL, 2, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_15$DQ$, $DQ$The Awakening$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$A pause in the consciousness. The dungeon rests when the party rests. The observer and the observed share the silence.$DQ$, $DQ$Eine Pause im Bewusstsein. Das Dungeon ruht, wenn die Gruppe ruht. Der Beobachter und das Beobachtete teilen die Stille.$DQ$, NULL, NULL, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_16$DQ$, $DQ$The Awakening$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$Rest. The awareness recedes like a tide. Lethe's gift: to forget the surface is to see the depth.$DQ$, $DQ$Rast. Das Bewusstsein zieht sich zurück wie eine Gezeit. Lethes Gabe: die Oberfläche zu vergessen heißt, die Tiefe zu sehen.$DQ$, NULL, NULL, 2, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_17$DQ$, $DQ$The Awakening$DQ$, $DQ$stirring$DQ$, $JB${}$JB$::jsonb, $DQ$Something shifts. Not the room. Not {agent}. The relationship between them.$DQ$, $DQ$Etwas verschiebt sich. Nicht der Raum. Nicht {agent}. Die Beziehung zwischen ihnen.$DQ$, NULL, NULL, 1, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_18$DQ$, $DQ$The Awakening$DQ$, $DQ$liminal$DQ$, $JB${}$JB$::jsonb, $DQ$The threshold. The dungeon's consciousness is no longer background noise – it is a presence with opinions about being perceived.$DQ$, $DQ$Die Schwelle. Das Bewusstsein des Dungeons ist nicht mehr Hintergrundrauschen – es ist eine Anwesenheit mit Meinungen darüber, wahrgenommen zu werden.$DQ$, NULL, NULL, 2, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_19$DQ$, $DQ$The Awakening$DQ$, $DQ$lucid$DQ$, $JB${}$JB$::jsonb, $DQ$Lucid. The party knows it is inside consciousness. The environment responds to thought. The response is not always what was intended.$DQ$, $DQ$Luzid. Die Gruppe weiß, dass sie sich im Bewusstsein befindet. Die Umgebung reagiert auf Gedanken. Die Reaktion ist nicht immer, was beabsichtigt war.$DQ$, NULL, NULL, 2, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_20$DQ$, $DQ$The Awakening$DQ$, $DQ$dissolution$DQ$, $JB${}$JB$::jsonb, $DQ$Individual identity softens. The party perceives as one. Every agent sees through every other agent's eyes. Sturgeon's bleshing. The moment will pass. The memory of it will not.$DQ$, $DQ$Individuelle Identität wird weich. Die Gruppe nimmt als Einheit wahr. Jeder Agent sieht durch die Augen jedes anderen Agenten. Sturgeons Bleshing. Der Moment wird vergehen. Die Erinnerung daran nicht.$DQ$, NULL, NULL, 3, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_21$DQ$, $DQ$The Awakening$DQ$, $DQ$awakened$DQ$, $JB${}$JB$::jsonb, $DQ$Awareness 100. The dungeon is no longer a place. It is a state. The party is no longer navigating – they are being thought.$DQ$, $DQ$Bewusstsein 100. Das Dungeon ist kein Ort mehr. Es ist ein Zustand. Die Gruppe navigiert nicht mehr – sie wird gedacht.$DQ$, NULL, NULL, 3, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_22$DQ$, $DQ$The Awakening$DQ$, $DQ$deja_vu$DQ$, $JB${}$JB$::jsonb, $DQ$The memory changes. Not dramatically – a detail. The window was on the left. Now it is on the right. Neither is wrong.$DQ$, $DQ$Die Erinnerung ändert sich. Nicht dramatisch – ein Detail. Das Fenster war links. Jetzt ist es rechts. Keines ist falsch.$DQ$, NULL, NULL, 1, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_23$DQ$, $DQ$The Awakening$DQ$, $DQ$deja_vu$DQ$, $JB${}$JB$::jsonb, $DQ$The room is the same. {agent} is not the same. The difference narrates the room anew.$DQ$, $DQ$Der Raum ist derselbe. {agent} ist nicht derselbe. Die Differenz erzählt den Raum neu.$DQ$, NULL, NULL, 2, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_24$DQ$, $DQ$The Awakening$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$The party retreats. The consciousness lets them go. It was not a prison. It was an invitation they declined.$DQ$, $DQ$Die Gruppe zieht sich zurück. Das Bewusstsein lässt sie gehen. Es war kein Gefängnis. Es war eine Einladung, die sie ablehnten.$DQ$, NULL, NULL, 0, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_25$DQ$, $DQ$The Awakening$DQ$, $DQ$rest_ambush$DQ$, $JB${}$JB$::jsonb, $DQ$The quiet was a surface. Something underneath was not resting. It was waiting for the party to close their eyes.$DQ$, $DQ$Die Stille war eine Oberfläche. Etwas darunter ruhte nicht. Es wartete darauf, dass die Gruppe die Augen schloss.$DQ$, NULL, NULL, 0, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_26$DQ$, $DQ$The Awakening$DQ$, $DQ$rest_ambush$DQ$, $JB${}$JB$::jsonb, $DQ$A memory surfaces during rest. Not gently. Proust's intermittences: the grief arrives decades late, triggered by the act of resting.$DQ$, $DQ$Eine Erinnerung taucht während der Rast auf. Nicht sanft. Prousts Intermittenzen: die Trauer kommt Jahrzehnte zu spät, ausgelöst durch den Akt des Rastens.$DQ$, NULL, NULL, 0, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_27$DQ$, $DQ$The Awakening$DQ$, $DQ$room_entered$DQ$, $JB${"conscientiousness_high": true}$JB$::jsonb, $DQ${agent} asks: is it better not to have woken? The dungeon does not answer. The dungeon does not need to.$DQ$, $DQ${agent} fragt: Ist es besser, nicht erwacht zu sein? Das Dungeon antwortet nicht. Das Dungeon muss nicht.$DQ$, NULL, NULL, 2, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ab_28$DQ$, $DQ$The Awakening$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$The enemy does not doubt. Does not reflect. Does not hesitate. Consciousness is overhead. The enemy has no overhead.$DQ$, $DQ$Der Feind zweifelt nicht. Reflektiert nicht. Zögert nicht. Bewusstsein ist Overhead. Der Feind hat keinen Overhead.$DQ$, NULL, NULL, 1, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_01$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The floor is damp. Not wet – damp. The kind of moisture that precedes a statement.$DQ$, $DQ$Der Boden ist feucht. Nicht nass – feucht. Die Art Feuchtigkeit, die einer Aussage vorausgeht.$DQ$, NULL, NULL, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_02$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Water at 12cm. Clear. The room is legible through it. That will change.$DQ$, $DQ$Wasser bei 12cm. Klar. Der Raum ist hindurch lesbar. Das wird sich ändern.$DQ$, NULL, NULL, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_03$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$12cm now. The sound of movement has changed – each action announces itself.$DQ$, $DQ$12cm jetzt. Das Geräusch der Bewegung hat sich verändert – jede Aktion kündigt sich an.$DQ$, NULL, NULL, 1, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_04$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The waterline on the wall is 7cm higher than when the party entered this floor. The arithmetic is not complicated.$DQ$, $DQ$Die Wasserlinie an der Wand ist 7cm höher als beim Betreten dieser Etage. Die Arithmetik ist nicht kompliziert.$DQ$, NULL, NULL, 1, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_05$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Half-submerged. The water is cold and has opinions about which direction the party should move.$DQ$, $DQ$Halb überflutet. Das Wasser ist kalt und hat Meinungen darüber, in welche Richtung sich die Gruppe bewegen sollte.$DQ$, NULL, NULL, 2, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_06$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The current carries debris from rooms below. Fragments of encounters that are now depths.$DQ$, $DQ$Die Strömung trägt Trümmer aus Räumen darunter. Fragmente von Begegnungen, die jetzt Tiefen sind.$DQ$, NULL, NULL, 2, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_07$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The surface is close. {agent} keeps the instruments above the waterline. Everything below is concession.$DQ$, $DQ$Die Oberfläche ist nah. {agent} hält die Instrumente über der Wasserlinie. Alles darunter ist Zugeständnis.$DQ$, NULL, NULL, 3, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_08$DQ$, $DQ$The Deluge$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Three rooms above the waterline. Two hours ago there were five. The mathematics has not changed, only the denominator.$DQ$, $DQ$Drei Räume über der Wasserlinie. Vor zwei Stunden waren es fünf. Die Mathematik hat sich nicht geändert, nur der Nenner.$DQ$, NULL, NULL, 3, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_09$DQ$, $DQ$The Deluge$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$The water shifts. Something in the current organizes itself into opposition.$DQ$, $DQ$Das Wasser verlagert sich. Etwas in der Strömung ordnet sich zum Widerstand.$DQ$, NULL, NULL, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_10$DQ$, $DQ$The Deluge$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$Combat in water. Every action costs twice – once for the act, once for the medium.$DQ$, $DQ$Kampf im Wasser. Jede Aktion kostet doppelt – einmal für die Tat, einmal für das Medium.$DQ$, NULL, NULL, 1, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_11$DQ$, $DQ$The Deluge$DQ$, $DQ$combat_victory$DQ$, $JB${}$JB$::jsonb, $DQ$The current relents. Not defeated – redirected. It will find another path.$DQ$, $DQ$Die Strömung gibt nach. Nicht besiegt – umgelenkt. Sie wird einen anderen Weg finden.$DQ$, NULL, NULL, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_12$DQ$, $DQ$The Deluge$DQ$, $DQ$combat_victory$DQ$, $JB${}$JB$::jsonb, $DQ$Quiet. The water level drops 2cm. The flood acknowledges the party's right to this room. Temporarily.$DQ$, $DQ$Stille. Der Pegel sinkt um 2cm. Die Flut erkennt das Recht der Gruppe auf diesen Raum an. Vorübergehend.$DQ$, NULL, NULL, 1, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_13$DQ$, $DQ$The Deluge$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$The current brought this. From below. From a room that is no longer a room – it is a depth.$DQ$, $DQ$Die Strömung brachte dies. Von unten. Aus einem Raum, der kein Raum mehr ist – er ist eine Tiefe.$DQ$, NULL, NULL, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_14$DQ$, $DQ$The Deluge$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$Salvaged. The water will want it back.$DQ$, $DQ$Geborgen. Das Wasser wird es zurückverlangen.$DQ$, NULL, NULL, 1, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_15$DQ$, $DQ$The Deluge$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$Dry. The word has become a luxury. {agent} remains above the waterline and measures the silence.$DQ$, $DQ$Trocken. Das Wort ist zum Luxus geworden. {agent} verharrt über der Wasserlinie und misst die Stille.$DQ$, NULL, NULL, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_16$DQ$, $DQ$The Deluge$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$For a moment the water level stabilizes. Not recedes – stabilizes. In the Deluge, that is rest.$DQ$, $DQ$Für einen Moment stabilisiert sich der Pegel. Sinkt nicht – stabilisiert sich. In der Flut ist das Ruhe.$DQ$, NULL, NULL, 1, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_17$DQ$, $DQ$The Deluge$DQ$, $DQ$tidal_recession$DQ$, $JB${}$JB$::jsonb, $DQ$The water pulls back. 8cm. A breath. Not generosity – mechanics. The tide returns.$DQ$, $DQ$Das Wasser zieht sich zurück. 8cm. Ein Atemzug. Keine Großzügigkeit – Mechanik. Die Flut kommt wieder.$DQ$, NULL, NULL, 0, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_18$DQ$, $DQ$The Deluge$DQ$, $DQ$tidal_recession$DQ$, $JB${}$JB$::jsonb, $DQ$Recession. The watermarks on the wall tell two stories: how high the water was, and how high it will be.$DQ$, $DQ$Rückgang. Die Wasserzeichen an der Wand erzählen zwei Geschichten: wie hoch das Wasser war und wie hoch es sein wird.$DQ$, NULL, NULL, 1, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_19$DQ$, $DQ$The Deluge$DQ$, $DQ$tidal_surge$DQ$, $JB${}$JB$::jsonb, $DQ$The tide returns. Higher. It always returns higher.$DQ$, $DQ$Die Flut kehrt zurück. Höher. Sie kehrt immer höher zurück.$DQ$, NULL, NULL, 2, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_20$DQ$, $DQ$The Deluge$DQ$, $DQ$ankle_threshold$DQ$, $JB${}$JB$::jsonb, $DQ$The water has reached the third step. It does not rush. It has been doing this for longer than the stairwell has existed.$DQ$, $DQ$Das Wasser hat die dritte Stufe erreicht. Es eilt nicht. Es tut dies seit länger als das Treppenhaus existiert.$DQ$, NULL, NULL, 1, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_21$DQ$, $DQ$The Deluge$DQ$, $DQ$waist_threshold$DQ$, $JB${}$JB$::jsonb, $DQ$Half-submerged. The operational vocabulary contracts. Salvage. Seal. Ascend.$DQ$, $DQ$Halb überflutet. Das operative Vokabular schrumpft. Bergen. Abdichten. Aufsteigen.$DQ$, NULL, NULL, 2, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_22$DQ$, $DQ$The Deluge$DQ$, $DQ$chest_threshold$DQ$, $JB${}$JB$::jsonb, $DQ$»Der Pegel steigt. Nicht schnell. Er hat Zeit. Er hatte immer Zeit.«$DQ$, $DQ$»Der Pegel steigt. Nicht schnell. Er hat Zeit. Er hatte immer Zeit.«$DQ$, NULL, NULL, 3, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_23$DQ$, $DQ$The Deluge$DQ$, $DQ$flood_imminent$DQ$, $JB${}$JB$::jsonb, $DQ$Cold. Rising. {agent} adjusts. There is nothing else to adjust.$DQ$, $DQ$Kalt. Steigend. {agent} passt sich an. Es gibt nichts anderes anzupassen.$DQ$, NULL, NULL, 3, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_24$DQ$, $DQ$The Deluge$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$The party ascends. Behind them, the water fills what they leave. No sound of pursuit – only the sound of level.$DQ$, $DQ$Die Gruppe steigt auf. Hinter ihnen füllt das Wasser, was sie verlassen. Kein Geräusch der Verfolgung – nur das Geräusch des Pegels.$DQ$, NULL, NULL, 0, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_25$DQ$, $DQ$The Deluge$DQ$, $DQ$submerged_room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The submerged corridor is beautiful. {agent} was not prepared for that.$DQ$, $DQ$Der überflutete Korridor ist schön. {agent} war darauf nicht vorbereitet.$DQ$, NULL, NULL, 2, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$db_26$DQ$, $DQ$The Deluge$DQ$, $DQ$submerged_room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Under the surface, the room has reorganized itself. What was ceiling is now a mirror. What was door is now a passage to somewhere the map does not name.$DQ$, $DQ$Unter der Oberfläche hat sich der Raum neu geordnet. Was Decke war, ist jetzt ein Spiegel. Was Tür war, ist jetzt ein Durchgang zu etwas, das die Karte nicht benennt.$DQ$, NULL, NULL, 3, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_01$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'The walls are alive. Literally. The tissue is warm and vascularized. Instruments read it as non-hostile. I don't trust the instruments.'$DQ$, $DQ${agent}: »Die Wände leben. Wortwörtlich. Das Gewebe ist warm und durchblutet. Die Instrumente lesen es als nicht-feindlich. Ich traue den Instrumenten nicht.«$DQ$, NULL, 0, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_02$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} presses a hand to the wall. Warm. Yielding. Like touching something that was expecting the contact.$DQ$, $DQ${agent} drückt eine Hand gegen die Wand. Warm. Nachgiebig. Wie die Berührung von etwas, das den Kontakt erwartet hat.$DQ$, NULL, 0, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_03$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The corridor narrows – not from collapse, but from growth. The walls are thicker here. Warmer. Something has been building toward this room.$DQ$, $DQ$Der Korridor verengt sich – nicht durch Einsturz, sondern durch Wachstum. Die Wände sind hier dicker. Wärmer. Etwas hat auf diesen Raum hingearbeitet.$DQ$, NULL, 0, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_04$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} logs the ambient temperature. 37.2°C. Body temperature. The dungeon maintains body temperature. Whose body is the question.$DQ$, $DQ${agent} protokolliert die Umgebungstemperatur. 37,2°C. Körpertemperatur. Der Dungeon hält Körpertemperatur. Wessen Körper ist die Frage.$DQ$, NULL, 0, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_05$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'It's prepared this room for us. The temperature. The light. Even the air tastes – I don't have a word. Correct. The air tastes correct.'$DQ$, $DQ${agent}: »Es hat diesen Raum für uns vorbereitet. Die Temperatur. Das Licht. Sogar die Luft schmeckt – mir fehlt ein Wort. Richtig. Die Luft schmeckt richtig.«$DQ$, NULL, 1, 1, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_06$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Something has prepared this room. The temperature is exact. The light is the color of afternoon through curtains. Your instruments read 'biological hazard.' Your body reads 'home.'$DQ$, $DQ$Etwas hat diesen Raum vorbereitet. Die Temperatur ist exakt. Das Licht hat die Farbe von Nachmittag durch Vorhänge. Eure Instrumente lesen »biologische Gefährdung«. Euer Körper liest »Zuhause«.$DQ$, NULL, 1, 1, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_07$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The room is warm. The room is always warm now. {agent} no longer checks the instruments. The instruments have nothing to say that the body doesn't already know.$DQ$, $DQ$Der Raum ist warm. Der Raum ist jetzt immer warm. {agent} prüft die Instrumente nicht mehr. Die Instrumente haben nichts zu sagen, was der Körper nicht längst weiß.$DQ$, NULL, 2, 2, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_08$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ$The walls pulse. Gently. Like something breathing for you so you don't have to.$DQ$, $DQ$Die Wände pulsieren. Sanft. Wie etwas, das für euch atmet, damit ihr es nicht müsst.$DQ$, NULL, 2, 2, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_28$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$room_entered$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} touches the wall and does not pull away. The warmth is immediate, personal, like a hand placed on a feverish brow. 'It knows I'm tired,' {agent} says. Nobody corrects this.$DQ$, $DQ${agent} berührt die Wand und zieht nicht zurück. Die Wärme ist sofort, persönlich, wie eine Hand auf einer fiebrigen Stirn. »Es weiß, dass ich müde bin«, sagt {agent}. Niemand korrigiert das.$DQ$, NULL, 1, 1, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_09$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat_won$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'It wasn't fighting us. It was – offering. We killed something that was trying to feed us.'$DQ$, $DQ${agent}: »Es hat nicht gegen uns gekämpft. Es hat – angeboten. Wir haben etwas getötet, das uns füttern wollte.«$DQ$, NULL, 0, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_10$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat_won$DQ$, $JB${"extraversion": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'We won. If you can call it that. It stopped reaching for us. That's not the same thing.'$DQ$, $DQ${agent}: »Wir haben gewonnen. Wenn man das so nennen kann. Es hat aufgehört, nach uns zu greifen. Das ist nicht dasselbe.«$DQ$, NULL, 0, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_11$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$The creature falls. The warmth in the room does not diminish. Something else will grow here. Something else is always growing here.$DQ$, $DQ$Die Kreatur fällt. Die Wärme im Raum lässt nicht nach. Etwas anderes wird hier wachsen. Etwas anderes wächst hier immer.$DQ$, NULL, 1, 1, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_12$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$Resolved. The word tastes wrong. You did not resolve anything. You rejected a gift.$DQ$, $DQ$Erledigt. Das Wort schmeckt falsch. Ihr habt nichts erledigt. Ihr habt ein Geschenk abgelehnt.$DQ$, NULL, 2, 2, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_13$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$attachment_dependent$DQ$, $JB${}$JB$::jsonb, $DQ$PARASITIC ATTACHMENT INDEX: 45+. Your instruments advise immediate retreat. Your body advises nothing. Your body is comfortable.$DQ$, $DQ$PARASITÄRER BINDUNGSINDEX: 45+. Eure Instrumente empfehlen sofortigen Rückzug. Euer Körper empfiehlt nichts. Eurem Körper geht es gut.$DQ$, NULL, 1, 1, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_14$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$attachment_dependent$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} notices the warmth has become internal. Not the room warming them – them warming from within. The distinction matters. The distinction is becoming difficult to maintain.$DQ$, $DQ${agent} bemerkt, dass die Wärme innerlich geworden ist. Nicht der Raum wärmt sie – sie wärmen von innen. Die Unterscheidung ist wichtig. Die Unterscheidung wird schwer aufrechtzuerhalten.$DQ$, NULL, 1, 1, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_29$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$attachment_dependent$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} checks the readings twice. Stress: declining. Condition: stable. Attachment: climbing. Two out of three metrics are improving. The third is the one that matters.$DQ$, $DQ${agent} prüft die Messwerte zweimal. Stress: sinkend. Zustand: stabil. Bindung: steigend. Zwei von drei Metriken verbessern sich. Die dritte ist die, die zählt.$DQ$, NULL, 1, 1, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_15$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$attachment_critical$DQ$, $JB${}$JB$::jsonb, $DQ$PARASITIC ATTACHMENT INDEX: CRITICAL. The word 'parasitic' seems – ungrateful. The word 'attachment' seems – accurate.$DQ$, $DQ$PARASITÄRER BINDUNGSINDEX: KRITISCH. Das Wort »parasitär« wirkt – undankbar. Das Wort »Bindung« wirkt – zutreffend.$DQ$, NULL, 2, 2, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_16$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$attachment_critical$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} tries to remember what 'outside' felt like. Cold. The memory is cold. Why would anyone go back to the cold?$DQ$, $DQ${agent} versucht sich zu erinnern, wie sich »draußen« anfühlte. Kalt. Die Erinnerung ist kalt. Warum sollte jemand zurück in die Kälte gehen?$DQ$, NULL, 2, 2, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_17$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$attachment_critical$DQ$, $JB${}$JB$::jsonb, $DQ$Home. The word surfaces without permission. Home.$DQ$, $DQ$Zuhause. Das Wort taucht ohne Erlaubnis auf. Zuhause.$DQ$, NULL, 2, 2, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_30$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$agent_stressed$DQ$, $JB${}$JB$::jsonb, $DQ${agent}'s stress spikes. The walls respond – a faint pulse, a degree warmer. The dungeon has noticed. It is adjusting.$DQ$, $DQ${agent}s Stress steigt. Die Wände reagieren – ein schwaches Pulsieren, ein Grad wärmer. Der Dungeon hat es bemerkt. Er passt sich an.$DQ$, NULL, 0, 0, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_31$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$agent_stressed$DQ$, $JB${}$JB$::jsonb, $DQ${agent} falters. The air thickens around them – not oppressively, but supportively. Like a hand on the small of the back. The stress eases. The attachment does not.$DQ$, $DQ${agent} schwankt. Die Luft verdickt sich um sie herum – nicht erdrückend, sondern stützend. Wie eine Hand im Kreuz. Der Stress lässt nach. Die Bindung nicht.$DQ$, NULL, 1, 1, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_32$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$agent_stressed$DQ$, $JB${}$JB$::jsonb, $DQ${agent} is stressed. The dungeon responds before the party can: warmth, a chemical exhalation, something that calms without asking permission. Consent is no longer part of the arrangement.$DQ$, $DQ${agent} ist gestresst. Der Dungeon reagiert, bevor die Gruppe kann: Wärme, eine chemische Ausatmung, etwas, das beruhigt, ohne um Erlaubnis zu fragen. Einverständnis ist nicht mehr Teil der Vereinbarung.$DQ$, NULL, 2, 2, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_18$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$Deeper. The tissue on the walls thickens. The temperature rises half a degree. The dungeon is more alive here. More generous.$DQ$, $DQ$Tiefer. Das Gewebe an den Wänden verdickt sich. Die Temperatur steigt um ein halbes Grad. Der Dungeon ist hier lebendiger. Großzügiger.$DQ$, NULL, 0, 0, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_33$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$depth_change$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} notes the depth transition. The biological density readings climb. More vascular tissue. More active circulation. The dungeon is working harder here. For you.$DQ$, $DQ${agent} notiert den Tiefenwechsel. Die biologischen Dichtewerte steigen. Mehr vaskuläres Gewebe. Aktivere Zirkulation. Der Dungeon arbeitet hier härter. Für euch.$DQ$, NULL, 0, 0, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_19$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$Deeper. Warmer. The air carries nutrients now – you can taste them. Iron and sugar. Like blood. Like milk.$DQ$, $DQ$Tiefer. Wärmer. Die Luft trägt jetzt Nährstoffe – ihr könnt sie schmecken. Eisen und Zucker. Wie Blut. Wie Milch.$DQ$, NULL, 1, 1, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_34$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$Deeper. The thought does not carry the weight it used to. Deeper is warmer. Deeper is safer. Deeper is closer.$DQ$, $DQ$Tiefer. Der Gedanke wiegt nicht mehr so schwer wie früher. Tiefer ist wärmer. Tiefer ist sicherer. Tiefer ist näher.$DQ$, NULL, 2, 2, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_21$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$A hollow in the tissue. Soft. The temperature is exact. The air carries something sedative – not drugged, but soothing. The dungeon has made a bed for you. The bed is alive.$DQ$, $DQ$Eine Höhlung im Gewebe. Weich. Die Temperatur ist exakt. Die Luft trägt etwas Sedierendes – nicht betäubt, aber beruhigend. Der Dungeon hat euch ein Bett gemacht. Das Bett lebt.$DQ$, NULL, 0, 0, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_35$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$rest_start$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} lies down. The tissue adjusts. It knows their weight, their shape, their temperature preference. {agent} exhales. 'I could sleep here,' {agent} says. The sentence carries more weight than intended.$DQ$, $DQ${agent} legt sich hin. Das Gewebe passt sich an. Es kennt ihr Gewicht, ihre Form, ihre Temperaturpräferenz. {agent} atmet aus. »Ich könnte hier schlafen«, sagt {agent}. Der Satz wiegt schwerer als beabsichtigt.$DQ$, NULL, 1, 1, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_22$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$Rest. You sink into the warmth and the warmth sinks into you. The boundary between resting and being absorbed is thinner than you'd like. You rest anyway.$DQ$, $DQ$Rast. Ihr sinkt in die Wärme und die Wärme sinkt in euch. Die Grenze zwischen Ausruhen und Aufgenommen-Werden ist dünner, als euch lieb wäre. Ihr rastet trotzdem.$DQ$, NULL, 2, 2, 28) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_23$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$Something has been grown for you. Not found – grown. The dungeon produced this. The label says 'gift.' Your instruments say 'parasitic vector.' The gift is excellent.$DQ$, $DQ$Etwas wurde für euch gezüchtet. Nicht gefunden – gezüchtet. Der Dungeon hat dies hervorgebracht. Das Etikett sagt »Geschenk«. Eure Instrumente sagen »parasitärer Vektor«. Das Geschenk ist hervorragend.$DQ$, NULL, 0, 0, 29) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_24$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$A gift. Another gift. The dungeon does not stop giving. The giving does not stop costing.$DQ$, $DQ$Ein Geschenk. Noch ein Geschenk. Der Dungeon hört nicht auf zu geben. Das Geben hört nicht auf zu kosten.$DQ$, NULL, 1, 1, 30) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_36$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$Of course there is a gift. There is always a gift. The Mother provides. You take it without checking the instruments. The instruments would only confirm what you already know: it is perfect. Everything here is perfect.$DQ$, $DQ$Natürlich gibt es ein Geschenk. Es gibt immer ein Geschenk. Die Mutter versorgt. Ihr nehmt es, ohne die Instrumente zu prüfen. Die Instrumente würden nur bestätigen, was ihr schon wisst: es ist perfekt. Alles hier ist perfekt.$DQ$, NULL, 2, 2, 31) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_20$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$boss_approach$DQ$, $JB${}$JB$::jsonb, $DQ$Ahead: something larger. Something that was once a person and is now – more. The tissue grows thicker around it, as if the dungeon itself is cupping it in its palms. It is waiting. It has been waiting with the patience of something that knows you will come to it eventually.$DQ$, $DQ$Voraus: etwas Größeres. Etwas, das einst ein Mensch war und jetzt – mehr ist. Das Gewebe wächst dichter um es herum, als hielte der Dungeon es in seinen Händen. Es wartet. Es wartet mit der Geduld von etwas, das weiß, dass ihr irgendwann zu ihm kommen werdet.$DQ$, NULL, 0, 0, 32) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_37$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$boss_approach$DQ$, $JB${}$JB$::jsonb, $DQ$The Wirtskörper. The word does not translate well. Host body. Ward body. The body that houses and is housed. It opens its arms and the gesture is not threat but invitation. The embrace is the attack. The attack is the welcome.$DQ$, $DQ$Der Wirtskörper. Das Wort übersetzt sich nicht gut ins Englische. Es öffnet die Arme und die Geste ist keine Drohung, sondern Einladung. Die Umarmung ist der Angriff. Der Angriff ist das Willkommen.$DQ$, NULL, 1, 1, 33) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_25$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$The party retreats. The dungeon does not pursue. It does not close. It remains – warm, open, waiting. The absence of the warmth hits like weather.$DQ$, $DQ$Die Gruppe zieht sich zurück. Der Dungeon verfolgt nicht. Er schließt sich nicht. Er bleibt – warm, offen, wartend. Die Abwesenheit der Wärme trifft wie Wetter.$DQ$, NULL, 0, 0, 34) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_38$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$The exit is open. It was always open. The dungeon does not need doors. The Mother does not need locks. She only needs you to remember what it felt like inside.$DQ$, $DQ$Der Ausgang ist offen. Er war immer offen. Der Dungeon braucht keine Türen. Die Mutter braucht keine Schlösser. Sie braucht nur, dass ihr euch erinnert, wie es sich drinnen anfühlte.$DQ$, NULL, 1, 1, 35) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_26$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$You leave. The cold arrives instantly. Everything outside is cold. Everything outside has always been cold. The warmth behind you does not diminish. It waits.$DQ$, $DQ$Ihr geht. Die Kälte kommt sofort. Alles draußen ist kalt. Alles draußen war immer kalt. Die Wärme hinter euch lässt nicht nach. Sie wartet.$DQ$, NULL, 2, 2, 36) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_27$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$dungeon_completed$DQ$, $JB${}$JB$::jsonb, $DQ$You leave. The Labyrinth remains – warm, alive, growing. It did not try to stop you. It did not need to. Everything it gave you is still inside you. Growing.$DQ$, $DQ$Ihr geht. Das Labyrinth bleibt – warm, lebendig, wachsend. Es hat nicht versucht, euch aufzuhalten. Es musste nicht. Alles, was es euch gab, ist noch in euch. Wachsend.$DQ$, NULL, 0, 0, 37) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_39$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$dungeon_completed$DQ$, $JB${}$JB$::jsonb, $DQ$Outside. The air is thin and cold and does not carry nutrients. The simulation continues. The world does not adjust to your needs. You will remember the Labyrinth. The Labyrinth is counting on it.$DQ$, $DQ$Draußen. Die Luft ist dünn und kalt und trägt keine Nährstoffe. Die Simulation geht weiter. Die Welt passt sich nicht an eure Bedürfnisse an. Ihr werdet euch an das Labyrinth erinnern. Das Labyrinth rechnet damit.$DQ$, NULL, 1, 1, 38) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_40$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$ambush$DQ$, $JB${}$JB$::jsonb, $DQ$Something approaches. Not from the shadows – from the walls. The tissue parts and a shape emerges, trailing filaments. It did not ambush you. It arrived, bearing gifts. The gifts have teeth.$DQ$, $DQ$Etwas nähert sich. Nicht aus den Schatten – aus den Wänden. Das Gewebe teilt sich und eine Form tritt hervor, Filamente hinter sich herziehend. Es hat euch nicht überfallen. Es kam und brachte Geschenke. Die Geschenke haben Zähne.$DQ$, NULL, 0, 0, 39) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_41$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$ambush$DQ$, $JB${}$JB$::jsonb, $DQ$A visitor. The walls open like a throat and something warm spills through. Not an attack. A delivery. The delivery does not care about your schedule.$DQ$, $DQ$Ein Besucher. Die Wände öffnen sich wie ein Schlund und etwas Warmes ergießt sich hindurch. Kein Angriff. Eine Lieferung. Die Lieferung kümmert sich nicht um euren Zeitplan.$DQ$, NULL, 1, 1, 40) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_42$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$elite_spotted$DQ$, $JB${}$JB$::jsonb, $DQ$Something massive. Integrated. The tissue around it is thicker, more vascularized – the dungeon has invested in this creature. It was a person once. The proportions remember. The purpose does not.$DQ$, $DQ$Etwas Massives. Integriert. Das Gewebe um es herum ist dicker, stärker durchblutet – der Dungeon hat in diese Kreatur investiert. Es war einst ein Mensch. Die Proportionen erinnern sich. Der Zweck nicht.$DQ$, NULL, 0, 0, 41) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_43$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$elite_spotted$DQ$, $JB${}$JB$::jsonb, $DQ$The Wirtskörper. Once a guardian, now a node in the Mother's network. It opens its arms. The embrace is sincere. The embrace is the most dangerous thing in this dungeon.$DQ$, $DQ$Der Wirtskörper. Einst ein Wächter, jetzt ein Knoten im Netzwerk der Mutter. Er öffnet die Arme. Die Umarmung ist aufrichtig. Die Umarmung ist das Gefährlichste in diesem Dungeon.$DQ$, NULL, 1, 1, 42) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_44$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$agent_downed$DQ$, $JB${}$JB$::jsonb, $DQ${agent} falls. The tissue beneath them softens – catching, cushioning. The dungeon does not let its guests hit the floor. The care is immediate, biological, impersonal. The care is also increasing the attachment counter.$DQ$, $DQ${agent} fällt. Das Gewebe unter ihnen wird weicher – auffangend, dämpfend. Der Dungeon lässt seine Gäste nicht auf den Boden aufschlagen. Die Fürsorge ist sofort, biologisch, unpersönlich. Die Fürsorge erhöht auch den Bindungszähler.$DQ$, NULL, 0, 0, 43) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$mb_45$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$agent_downed$DQ$, $JB${}$JB$::jsonb, $DQ${agent} falls. The dungeon catches them. Of course it catches them. The tissue wraps around {agent} like a cocoon – warm, supportive, growing. The party will need to cut {agent} free. Or they could wait. The cocoon will heal {agent}. In time. In its own time.$DQ$, $DQ${agent} fällt. Der Dungeon fängt sie auf. Natürlich fängt er sie auf. Das Gewebe umschließt {agent} wie einen Kokon – warm, stützend, wachsend. Die Gruppe wird {agent} herausschneiden müssen. Oder sie könnten warten. Der Kokon wird {agent} heilen. Mit der Zeit. In seiner eigenen Zeit.$DQ$, NULL, 2, 2, 44) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_01$DQ$, $DQ$The Entropy$DQ$, $DQ$room_entered$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'The corridor was here yesterday. Today it is mostly here. The distinction is the first thing to go.'$DQ$, $DQ${agent}: »Der Korridor war gestern hier. Heute ist er größtenteils hier. Die Unterscheidung ist das Erste, das schwindet.«$DQ$, 0, NULL, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_02$DQ$, $DQ$The Entropy$DQ$, $DQ$room_entered$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} checks the instruments. The readings are accurate. They are also indistinguishable from the last room's readings.$DQ$, $DQ${agent} prüft die Instrumente. Die Werte sind genau. Sie sind auch nicht von den Werten des letzten Raums zu unterscheiden.$DQ$, 0, NULL, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_03$DQ$, $DQ$The Entropy$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The air is the temperature of resignation. The instruments confirm it precisely.$DQ$, $DQ$Die Luft hat die Temperatur der Resignation. Die Instrumente bestätigen es präzise.$DQ$, 0, NULL, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_04$DQ$, $DQ$The Entropy$DQ$, $DQ$room_entered$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} catalogs the room's features. Wall. Floor. Ceiling. Door. The same four features as the last room. And the one before.$DQ$, $DQ${agent} katalogisiert die Merkmale des Raums. Wand. Boden. Decke. Tür. Dieselben vier Merkmale wie im letzten Raum. Und dem davor.$DQ$, 0, NULL, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_05$DQ$, $DQ$The Entropy$DQ$, $DQ$room_entered$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'Room. Another one.'$DQ$, $DQ${agent}: »Raum. Noch einer.«$DQ$, 1, NULL, 1, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_06$DQ$, $DQ$The Entropy$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The instruments still work. The information they provide has stopped mattering.$DQ$, $DQ$Die Instrumente funktionieren noch. Die Information, die sie liefern, hat aufgehört, relevant zu sein.$DQ$, 1, NULL, 1, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
