INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_10$DQ$, $DQ$The Entropy$DQ$, $DQ$combat_won$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'It stopped. Not because we won. Because it ran out of reasons to continue.'$DQ$, $DQ${agent}: »Es hat aufgehört. Nicht weil wir gewonnen haben. Weil ihm die Gründe ausgingen weiterzumachen.«$DQ$, 0, NULL, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_11$DQ$, $DQ$The Entropy$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$Victory. Though the word means less here than it did a floor ago.$DQ$, $DQ$Sieg. Obwohl das Wort hier weniger bedeutet als noch ein Stockwerk zuvor.$DQ$, 0, NULL, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_12$DQ$, $DQ$The Entropy$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$The enemy dissipates. The party remains. For now, that distinction holds.$DQ$, $DQ$Der Feind vergeht. Die Gruppe bleibt. Vorerst hält diese Unterscheidung.$DQ$, 1, NULL, 1, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_13$DQ$, $DQ$The Entropy$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$Resolved. The word feels generous.$DQ$, $DQ$Erledigt. Das Wort fühlt sich großzügig an.$DQ$, 2, NULL, 2, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_14$DQ$, $DQ$The Entropy$DQ$, $DQ$decay_degraded$DQ$, $JB${}$JB$::jsonb, $DQ$The decay counter passes 40. Somewhere, a distinction that existed no longer does.$DQ$, $DQ$Der Verfallszähler überschreitet 40. Irgendwo existiert eine Unterscheidung nicht mehr, die es gab.$DQ$, 1, NULL, 1, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
