INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_20$DQ$, $DQ$The Entropy$DQ$, $DQ$dissolution$DQ$, $JB${}$JB$::jsonb, $DQ$The decay counter reads 100. The instruments agree with the walls agree with the floor agree with the silence. Agreement is total. Agreement is final.$DQ$, $DQ$Der Verfallszähler zeigt 100. Die Instrumente stimmen den Wänden zu, die dem Boden zustimmen, der der Stille zustimmt. Übereinstimmung ist vollständig. Übereinstimmung ist endgültig.$DQ$, 3, NULL, 3, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
