INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_22$DQ$, $DQ$The Entropy$DQ$, $DQ$agent_stressed$DQ$, $JB${}$JB$::jsonb, $DQ${agent} falters. Not from fear – from the effort of maintaining a self that the environment considers redundant.$DQ$, $DQ${agent} stockt. Nicht vor Angst – vor der Anstrengung, ein Selbst aufrechtzuerhalten, das die Umgebung für überflüssig hält.$DQ$, 0, NULL, 0, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_23$DQ$, $DQ$The Entropy$DQ$, $DQ$agent_stressed$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent}'s composure fragments. They have begun counting differences. The count is shortening.$DQ$, $DQ${agent}s Fassung splittert. Sie haben begonnen, Unterschiede zu zählen. Die Zählung wird kürzer.$DQ$, 0, NULL, 0, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
