INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_25$DQ$, $DQ$The Entropy$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$Deeper. The word implies a direction. Direction implies difference. The difference is becoming theoretical.$DQ$, $DQ$Tiefer. Das Wort impliziert eine Richtung. Richtung impliziert Unterschied. Der Unterschied wird theoretisch.$DQ$, 0, NULL, 0, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_26$DQ$, $DQ$The Entropy$DQ$, $DQ$depth_change$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} notes the depth change in the log. The log is beginning to repeat itself. The log does not notice.$DQ$, $DQ${agent} notiert die Tiefenänderung im Protokoll. Das Protokoll beginnt sich zu wiederholen. Das Protokoll bemerkt es nicht.$DQ$, 0, NULL, 0, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
