INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_30$DQ$, $DQ$The Entropy$DQ$, $DQ$rest_start$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'Rest here. The walls still have texture. That is more than we deserve.'$DQ$, $DQ${agent}: »Rastet hier. Die Wände haben noch Textur. Das ist mehr, als wir verdienen.«$DQ$, 0, NULL, 0, 29) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_31$DQ$, $DQ$The Entropy$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$Rest. The concept erodes even as you practice it.$DQ$, $DQ$Rast. Das Konzept erodiert, selbst während ihr es praktiziert.$DQ$, 2, NULL, 2, 30) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_32$DQ$, $DQ$The Entropy$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$Something here has resisted the dissolution. Not for long, but long enough.$DQ$, $DQ$Etwas hier hat der Auflösung widerstanden. Nicht lange, aber lang genug.$DQ$, 0, NULL, 0, 31) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_33$DQ$, $DQ$The Entropy$DQ$, $DQ$loot_found$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} examines the find with the reverence of an archaeologist. In the Verfall-Garten, anything that remains itself is a museum piece.$DQ$, $DQ${agent} untersucht den Fund mit der Ehrfurcht eines Archäologen. Im Verfall-Garten ist alles, was noch es selbst ist, ein Museumsstück.$DQ$, 0, NULL, 0, 32) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_34$DQ$, $DQ$The Entropy$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$A remnant. Take it before it isn't.$DQ$, $DQ$Ein Überrest. Nehmt ihn, bevor er keiner mehr ist.$DQ$, 1, NULL, 1, 33) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_35$DQ$, $DQ$The Entropy$DQ$, $DQ$boss_approach$DQ$, $JB${}$JB$::jsonb, $DQ$Something ahead retains more definition than its surroundings. This passes for remarkable.$DQ$, $DQ$Etwas voraus behält mehr Definition als seine Umgebung. Das gilt hier als bemerkenswert.$DQ$, 0, NULL, 0, 34) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_36$DQ$, $DQ$The Entropy$DQ$, $DQ$boss_approach$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent}: 'It's still trying to be something. That makes it the most dangerous thing here.'$DQ$, $DQ${agent}: »Es versucht noch, etwas zu sein. Das macht es zum Gefährlichsten hier.«$DQ$, 0, NULL, 0, 35) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_37$DQ$, $DQ$The Entropy$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$The party retreats. The dungeon does not pursue. It does not need to. It is patient. It is also everywhere.$DQ$, $DQ$Die Gruppe zieht sich zurück. Der Dungeon verfolgt nicht. Er muss nicht. Er ist geduldig. Er ist auch überall.$DQ$, 0, NULL, 0, 36) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_38$DQ$, $DQ$The Entropy$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$Back. If 'back' still means anything.$DQ$, $DQ$Zurück. Falls 'zurück' noch etwas bedeutet.$DQ$, 2, NULL, 2, 37) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_39$DQ$, $DQ$The Entropy$DQ$, $DQ$dungeon_completed$DQ$, $JB${}$JB$::jsonb, $DQ$You leave. The garden remains. It is very patient. It has nothing but time. And less and less of everything else.$DQ$, $DQ$Ihr geht. Der Garten bleibt. Er ist sehr geduldig. Er hat nichts als Zeit. Und immer weniger von allem anderen.$DQ$, 0, NULL, 0, 38) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_40$DQ$, $DQ$The Entropy$DQ$, $DQ$party_wipe$DQ$, $JB${}$JB$::jsonb, $DQ$The party dissolves. Not violently. Gently. The way a word dissolves when you say it too many times. The garden accepts them without ceremony.$DQ$, $DQ$Die Gruppe löst sich auf. Nicht gewaltsam. Sanft. So wie ein Wort sich auflöst, wenn man es zu oft sagt. Der Garten nimmt sie auf, ohne Zeremonie.$DQ$, 0, NULL, 0, 39) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_41$DQ$, $DQ$The Entropy$DQ$, $DQ$party_wipe$DQ$, $JB${}$JB$::jsonb, $DQ$Dissolution complete. The instruments record this accurately. The instruments will be next.$DQ$, $DQ$Auflösung vollständig. Die Instrumente verzeichnen dies genau. Die Instrumente sind als Nächstes dran.$DQ$, 0, NULL, 0, 40) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_42$DQ$, $DQ$The Entropy$DQ$, $DQ$rest_safe$DQ$, $JB${}$JB$::jsonb, $DQ$No ambush. The decay pauses. Not stops – pauses. The difference is everything. The difference is also decaying.$DQ$, $DQ$Kein Hinterhalt. Der Verfall pausiert. Hält nicht an – pausiert. Der Unterschied ist alles. Der Unterschied verfällt ebenfalls.$DQ$, 0, NULL, 0, 41) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_43$DQ$, $DQ$The Entropy$DQ$, $DQ$rest_safe$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'We're still different from each other. That counts for something. I think.'$DQ$, $DQ${agent}: »Wir sind noch verschieden voneinander. Das zählt für etwas. Glaube ich.«$DQ$, 0, NULL, 0, 42) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_44$DQ$, $DQ$The Entropy$DQ$, $DQ$rest_ambush$DQ$, $JB${}$JB$::jsonb, $DQ$Something drifts through the walls. Even sanctuaries are temporary. Especially sanctuaries.$DQ$, $DQ$Etwas treibt durch die Wände. Auch Refugien sind vorübergehend. Besonders Refugien.$DQ$, 0, NULL, 0, 43) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$eb_45$DQ$, $DQ$The Entropy$DQ$, $DQ$rest_ambush$DQ$, $JB${}$JB$::jsonb, $DQ$The decay found you resting. It did not hesitate. Hesitation requires purpose.$DQ$, $DQ$Der Verfall fand euch rastend. Er zögerte nicht. Zögern erfordert Absicht.$DQ$, 0, NULL, 0, 44) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_01$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The corridor is orderly. Signs indicate direction. The signs have been recently updated.$DQ$, $DQ$Der Korridor ist ordentlich. Schilder weisen die Richtung. Die Schilder wurden kürzlich aktualisiert.$DQ$, NULL, NULL, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_02$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Alliance offered. Alliance accepted. The cost will be announced later.$DQ$, $DQ$Bündnis angeboten. Bündnis angenommen. Die Kosten werden später bekanntgegeben.$DQ$, NULL, NULL, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_03$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Everyone sees what you appear to be. Few experience what you really are. The Spiegelpalast sees both.$DQ$, $DQ$Jeder sieht, was ihr zu sein scheint. Wenige erfahren, was ihr wirklich seid. Der Spiegelpalast sieht beides.$DQ$, NULL, NULL, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_04$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$A faction representative nods at {agent}. The nod is precisely calibrated: acknowledgment without commitment.$DQ$, $DQ$Ein Fraktionsvertreter nickt {agent} zu. Das Nicken ist präzise kalibriert: Anerkennung ohne Verpflichtung.$DQ$, NULL, NULL, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_05$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$The enforcers are down. The report will say they were never here. The revised report will say {agent} was never here either.$DQ$, $DQ$Die Vollstrecker sind am Boden. Der Bericht wird sagen, sie waren nie hier. Der überarbeitete Bericht wird sagen, {agent} war auch nie hier.$DQ$, NULL, NULL, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_06$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$The faction leader smiles. The smile has been authorized.$DQ$, $DQ$Der Fraktionsführer lächelt. Das Lächeln wurde genehmigt.$DQ$, NULL, NULL, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_07$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Three factions. Three truths. None of them are lying. This is the problem.$DQ$, $DQ$Drei Fraktionen. Drei Wahrheiten. Keine davon lügt. Das ist das Problem.$DQ$, NULL, NULL, 1, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_08$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ${agent} is offered a seat at the table. The seat is comfortable. The table is set for fewer people than it was yesterday.$DQ$, $DQ${agent} wird ein Platz am Tisch angeboten. Der Sitz ist bequem. Der Tisch ist für weniger Personen gedeckt als gestern.$DQ$, NULL, NULL, 1, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_09$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Walls have ears. These walls have faction insignia. The insignia changed since the party entered.$DQ$, $DQ$Wände haben Ohren. Diese Wände haben Fraktionsabzeichen. Die Abzeichen haben sich geändert, seit die Gruppe eintrat.$DQ$, NULL, NULL, 1, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_10$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$»Erst kommt das Bündnis«, sagt der Fraktionsführer. »Dann kommt die Wahrheit. Falls noch jemand fragt.«$DQ$, $DQ$»Erst kommt das Bündnis«, sagt der Fraktionsführer. »Dann kommt die Wahrheit. Falls noch jemand fragt.«$DQ$, NULL, NULL, 1, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_11$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$The enforcers make speeches while fighting. They die with quotable last words. The Overthrow is theatrical even in violence.$DQ$, $DQ$Die Vollstrecker halten Reden, während sie kämpfen. Sie sterben mit zitierwürdigen letzten Worten. Der Umsturz ist selbst in der Gewalt theatralisch.$DQ$, NULL, NULL, 1, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_12$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$The enforcers are down. Which faction sent them? The answer depends on which faction asks.$DQ$, $DQ$Die Vollstrecker sind am Boden. Welche Fraktion hat sie geschickt? Die Antwort hängt davon ab, welche Fraktion fragt.$DQ$, NULL, NULL, 1, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_13$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${"conscientiousness_high": true}$JB$::jsonb, $DQ${agent} reads the new decree. It contradicts the previous decree. Both remain in effect. Doublethink.$DQ$, $DQ${agent} liest das neue Dekret. Es widerspricht dem vorherigen Dekret. Beide bleiben in Kraft. Doppeldenk.$DQ$, NULL, NULL, 1, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_14$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The old leader is gone. The new leader enters. Same room. Same desk. Same view from the window.$DQ$, $DQ$Der alte Anführer ist weg. Der neue Anführer tritt ein. Derselbe Raum. Derselbe Schreibtisch. Dieselbe Aussicht.$DQ$, NULL, NULL, 2, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_15$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Every revolutionary ends as an oppressor or a heretic. The Spiegelpalast offers both options. Choose quickly.$DQ$, $DQ$Jeder Revolutionär endet als Unterdrücker oder als Ketzer. Der Spiegelpalast bietet beide Optionen. Wählt schnell.$DQ$, NULL, NULL, 2, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_16$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ${agent} joins the revolution. The revolution has a sign-up sheet. The sign-up sheet has a second page that is not immediately visible.$DQ$, $DQ${agent} schließt sich der Revolution an. Die Revolution hat eine Anmeldeliste. Die Anmeldeliste hat eine zweite Seite, die nicht sofort sichtbar ist.$DQ$, NULL, NULL, 2, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_17$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$The party can never be mistaken. {agent} can make a mistake. Not the party. Not the faction. Fight accordingly.$DQ$, $DQ$Die Partei kann sich nie irren. {agent} kann sich irren. Nicht die Partei. Nicht die Fraktion. Kämpft entsprechend.$DQ$, NULL, NULL, 2, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_18$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$Victory. The revolution devours its children — but not today. Today, the children devour.$DQ$, $DQ$Sieg. Die Revolution frisst ihre Kinder — aber nicht heute. Heute fressen die Kinder.$DQ$, NULL, NULL, 2, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_19$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${"agreeableness_high": true}$JB$::jsonb, $DQ${agent} tries to mediate between factions. Both sides thank {agent}. Both sides add {agent}'s name to a list that is not labeled 'mediators.'$DQ$, $DQ${agent} versucht, zwischen den Fraktionen zu vermitteln. Beide Seiten danken {agent}. Beide Seiten setzen {agent}s Namen auf eine Liste, die nicht 'Vermittler' heißt.$DQ$, NULL, NULL, 2, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_20$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Macht. Macht des Machens. Spiegel. Spiegel des Spiegels. Wer regiert?$DQ$, $DQ$Macht. Macht des Machens. Spiegel. Spiegel des Spiegels. Wer regiert?$DQ$, NULL, NULL, 3, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_21$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The Pretender speaks. {agent} has heard these words before — in their own voice, on Floor 1.$DQ$, $DQ$Der Prätendent spricht. {agent} hat diese Worte schon gehört — in der eigenen Stimme, auf Etage 1.$DQ$, NULL, NULL, 3, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_22$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$All factions are equal. But some factions are more equal than others. The sign was always there. The party is only now able to read it.$DQ$, $DQ$Alle Fraktionen sind gleich. Aber manche Fraktionen sind gleicher als andere. Das Schild war immer da. Die Gruppe kann es erst jetzt lesen.$DQ$, NULL, NULL, 3, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_23$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$»Wir haben Ihre Akte gelesen. Eine bemerkenswerte Karriere. Leider müssen wir sie umschreiben.«$DQ$, $DQ$»Wir haben Ihre Akte gelesen. Eine bemerkenswerte Karriere. Leider müssen wir sie umschreiben.«$DQ$, NULL, NULL, 3, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_24$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$The boot. The face. Forever. But whose boot? The answer changes with the faction.$DQ$, $DQ$Der Stiefel. Das Gesicht. Für immer. Aber wessen Stiefel? Die Antwort wechselt mit der Fraktion.$DQ$, NULL, NULL, 3, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_25$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$»Ihr wolltet Freiheit. Ich wollte Freiheit. Seht, was wir daraus gemacht haben.«$DQ$, $DQ$»Ihr wolltet Freiheit. Ich wollte Freiheit. Seht, was wir daraus gemacht haben.«$DQ$, NULL, NULL, 3, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_26$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Loyalty costs nothing. Disloyalty costs everything. Both are true. Welcome to the Overthrow.$DQ$, $DQ$Treue kostet nichts. Untreue kostet alles. Beides ist wahr. Willkommen im Umsturz.$DQ$, NULL, NULL, 3, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_27$DQ$, $DQ$The Overthrow$DQ$, $DQ$room_entered$DQ$, $JB${"openness_high": true}$JB$::jsonb, $DQ$»Der Spiegelpalast zeigt jedem, was er sehen will. Nicht was er ist. Was er will. Das ist schlimmer.«$DQ$, $DQ$»Der Spiegelpalast zeigt jedem, was er sehen will. Nicht was er ist. Was er will. Das ist schlimmer.«$DQ$, NULL, NULL, 3, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$ob_28$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat_start$DQ$, $JB${}$JB$::jsonb, $DQ$Power is not a means; it is an end. One does not establish a dictatorship to safeguard a revolution. The Pretender knows this. {agent} is learning.$DQ$, $DQ$Macht ist kein Mittel; sie ist ein Zweck. Man errichtet keine Diktatur, um eine Revolution zu sichern. Der Prätendent weiß das. {agent} lernt.$DQ$, NULL, NULL, 2, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_01$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${"openness": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} scans the workbench. Tools arranged by a system that is not alphabetical, not chronological, not any system {agent} recognizes. But organized. Precisely organized.$DQ$, $DQ${agent} scannt die Werkbank. Werkzeuge, angeordnet nach einem System, das nicht alphabetisch ist, nicht chronologisch, kein System, das {agent} erkennt. Aber geordnet. Präzise geordnet.$DQ$, NULL, NULL, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_02$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ$The instruments register heat. Not from a source – from the room itself. The walls are warm. The floor is warm. The air conducts.$DQ$, $DQ$Die Instrumente registrieren Hitze. Nicht von einer Quelle – vom Raum selbst. Die Wände sind warm. Der Boden ist warm. Die Luft leitet.$DQ$, NULL, NULL, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_03$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$A workbench. Clean. Expectant. The kind of clean that suggests recent use, not abandonment.$DQ$, $DQ$Eine Werkbank. Sauber. Erwartungsvoll. Die Art von Sauberkeit, die auf kürzliche Benutzung hindeutet, nicht auf Verlassenheit.$DQ$, NULL, NULL, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_04$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${"openness": [0.6, 1.0]}$JB$::jsonb, $DQ${agent}: 'The reagents are sorting themselves. Did anyone else see that? The reagents are sorting themselves.'$DQ$, $DQ${agent}: »Die Reagenzien sortieren sich selbst. Hat das sonst jemand gesehen? Die Reagenzien sortieren sich selbst.«$DQ$, NULL, NULL, 1, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_05$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${"neuroticism": [0.0, 0.4]}$JB$::jsonb, $DQ$The workshop hums. Not electrically – deliberately. A sustained note of anticipation, as if the room knows what the party has not yet decided to build.$DQ$, $DQ$Die Werkstatt summt. Nicht elektrisch – absichtlich. Ein gehaltener Ton der Erwartung, als wüsste der Raum, was der Trupp noch nicht zu bauen beschlossen hat.$DQ$, NULL, NULL, 1, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_06$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$On the wall: a formula. Half the variables are in a notation {agent} doesn't recognize. The other half are disturbingly familiar.$DQ$, $DQ$An der Wand: eine Formel. Die Hälfte der Variablen ist in einer Notation, die {agent} nicht erkennt. Die andere Hälfte ist beunruhigend vertraut.$DQ$, NULL, NULL, 1, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_07$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ$The components in {agent}'s pack shift. Not settling – rearranging. They have preferences about proximity. The metal does not want to be near the powder.$DQ$, $DQ$Die Komponenten in {agent}s Rucksack bewegen sich. Kein Setzen – Umordnen. Sie haben Präferenzen bezüglich Nähe. Das Metall will nicht neben dem Pulver sein.$DQ$, NULL, NULL, 2, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_08$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$»Die Werkstatt ordnet sich um.« The workshop rearranges itself. Tools migrate to different shelves. The anvil has moved three inches to the left. Nobody touched it.$DQ$, $DQ$»Die Werkstatt ordnet sich um.« Werkzeuge wandern in andere Regale. Der Amboss hat sich drei Zentimeter nach links bewegt. Niemand hat ihn berührt.$DQ$, NULL, NULL, 2, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_09$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${"neuroticism": [0.5, 1.0]}$JB$::jsonb, $DQ${agent}'s hands are shaking. Not from fear. From something worse: the absolute certainty that the next combination will work. The fire knows. {agent} knows the fire knows.$DQ$, $DQ${agent}s Hände zittern. Nicht vor Angst. Vor etwas Schlimmerem: der absoluten Gewissheit, dass die nächste Kombination funktionieren wird. Das Feuer weiß es. {agent} weiß, dass das Feuer es weiß.$DQ$, NULL, NULL, 3, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_10$DQ$, $DQ$The Prometheus$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The workshop is no longer subtle. Surfaces glow. Materials levitate briefly before settling. The air tastes of ozone and ambition. Something in this room is about to happen whether the party participates or not.$DQ$, $DQ$Die Werkstatt ist nicht mehr subtil. Oberflächen glühen. Materialien schweben kurz, bevor sie sich setzen. Die Luft schmeckt nach Ozon und Ambition. Etwas in diesem Raum wird gleich passieren, ob der Trupp teilnimmt oder nicht.$DQ$, NULL, NULL, 3, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_11$DQ$, $DQ$The Prometheus$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$Deeper. The workshop's complexity increases. The tools here are not for amateur hands.$DQ$, $DQ$Tiefer. Die Komplexität der Werkstatt nimmt zu. Die Werkzeuge hier sind nicht für Laienhände.$DQ$, NULL, NULL, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_12$DQ$, $DQ$The Prometheus$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$The forge-heat intensifies with depth. The workshop is revealing its inner chambers – the rooms where the serious work happens.$DQ$, $DQ$Die Schmiedehitze intensiviert sich mit der Tiefe. Die Werkstatt enthüllt ihre inneren Kammern – die Räume, in denen die ernsthafte Arbeit stattfindet.$DQ$, NULL, NULL, 1, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_13$DQ$, $DQ$The Prometheus$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$This deep, the workshop stops pretending to be a place. It is a process. The party is inside the process now.$DQ$, $DQ$So tief hört die Werkstatt auf, ein Ort zu sein. Sie ist ein Prozess. Der Trupp ist jetzt im Prozess.$DQ$, NULL, NULL, 2, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_14$DQ$, $DQ$The Prometheus$DQ$, $DQ$elite_spotted$DQ$, $JB${}$JB$::jsonb, $DQ$Ahead: something that was built with intent. Not the workshop's ambient creations – a deliberate construct. It works at something. It does not wish to be interrupted.$DQ$, $DQ$Voraus: etwas, das mit Absicht gebaut wurde. Nicht die Zufallsschöpfungen der Werkstatt – ein absichtliches Konstrukt. Es arbeitet an etwas. Es wünscht nicht, unterbrochen zu werden.$DQ$, NULL, NULL, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_15$DQ$, $DQ$The Prometheus$DQ$, $DQ$elite_spotted$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} stops. 'That one is different. That one was MADE.'$DQ$, $DQ${agent} hält inne. »Das da ist anders. Das wurde GEMACHT.«$DQ$, NULL, NULL, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_16$DQ$, $DQ$The Prometheus$DQ$, $DQ$boss_approach$DQ$, $JB${}$JB$::jsonb, $DQ$The workshop contracts. All corridors converge. Ahead: the central chamber. The heat is absolute. Something inside is functioning with the confidence of a finished thing. It is not finished.$DQ$, $DQ$Die Werkstatt zieht sich zusammen. Alle Korridore konvergieren. Voraus: die zentrale Kammer. Die Hitze ist absolut. Etwas darin funktioniert mit der Zuversicht eines fertigen Dings. Es ist nicht fertig.$DQ$, NULL, NULL, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_17$DQ$, $DQ$The Prometheus$DQ$, $DQ$boss_approach$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'It knows we have been crafting. It has been watching. It wants to see what we built.'$DQ$, $DQ${agent}: »Es weiß, dass wir gecraften haben. Es hat zugesehen. Es will sehen, was wir gebaut haben.«$DQ$, NULL, NULL, 0, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_18$DQ$, $DQ$The Prometheus$DQ$, $DQ$agent_afflicted$DQ$, $JB${}$JB$::jsonb, $DQ${agent} burns. Not physically – creatively. The fire that drove them to build has consumed the boundary between maker and material. {agent} is both craftsman and component now.$DQ$, $DQ${agent} brennt. Nicht physisch – kreativ. Das Feuer, das sie zum Bauen trieb, hat die Grenze zwischen Macher und Material verzehrt. {agent} ist jetzt beides: Handwerker und Komponente.$DQ$, NULL, NULL, 0, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_19$DQ$, $DQ$The Prometheus$DQ$, $DQ$agent_afflicted$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent}'s instruments read their own vital signs now. The instruments have suggestions.$DQ$, $DQ${agent}s Instrumente lesen jetzt ihre eigenen Vitalwerte. Die Instrumente haben Vorschläge.$DQ$, NULL, NULL, 0, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_20$DQ$, $DQ$The Prometheus$DQ$, $DQ$agent_virtue$DQ$, $JB${}$JB$::jsonb, $DQ${agent} steadies. The fire is still there – but channeled now. Controlled. Primo Levi understood: the hand that works matter develops a different kind of intelligence.$DQ$, $DQ${agent} stabilisiert sich. Das Feuer ist noch da – aber kanalisiert jetzt. Kontrolliert. Primo Levi verstand: Die Hand, die Materie bearbeitet, entwickelt eine andere Art von Intelligenz.$DQ$, NULL, NULL, 0, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_21$DQ$, $DQ$The Prometheus$DQ$, $DQ$agent_virtue$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} picks up a tool. It fits. Not because it was designed for {agent}'s hand. Because {agent}'s hand has become what the tool requires.$DQ$, $DQ${agent} nimmt ein Werkzeug auf. Es passt. Nicht weil es für {agent}s Hand entworfen wurde. Weil {agent}s Hand zu dem geworden ist, was das Werkzeug verlangt.$DQ$, NULL, NULL, 0, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_22$DQ$, $DQ$The Prometheus$DQ$, $DQ$insight_inspired$DQ$, $JB${}$JB$::jsonb, $DQ$Something shifts. {agent} sees connections that were invisible a moment ago. The components are not separate things – they are parts of something that wants to exist.$DQ$, $DQ$Etwas verschiebt sich. {agent} sieht Verbindungen, die vor einem Moment noch unsichtbar waren. Die Komponenten sind keine separaten Dinge – sie sind Teile von etwas, das existieren will.$DQ$, NULL, NULL, 0, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_23$DQ$, $DQ$The Prometheus$DQ$, $DQ$insight_feverish$DQ$, $JB${}$JB$::jsonb, $DQ$The fire is in everything now. {agent}'s instruments are warm to the touch. The workshop has stopped hiding its mechanisms. It is showing them – all of them, at once. It is too much. It is exactly enough.$DQ$, $DQ$Das Feuer ist jetzt in allem. {agent}s Instrumente sind warm bei Berührung. Die Werkstatt hat aufgehört, ihre Mechanismen zu verbergen. Sie zeigt sie – alle, auf einmal. Es ist zu viel. Es ist genau genug.$DQ$, NULL, NULL, 0, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_24$DQ$, $DQ$The Prometheus$DQ$, $DQ$insight_breakthrough$DQ$, $JB${}$JB$::jsonb, $DQ$For a moment – only a moment – the workshop is transparent. Every mechanism visible. Every connection mapped. Every possible combination illuminated. The fire burns at its brightest. The fire also burns.$DQ$, $DQ$Für einen Moment – nur einen Moment – ist die Werkstatt transparent. Jeder Mechanismus sichtbar. Jede Verbindung kartiert. Jede mögliche Kombination beleuchtet. Das Feuer brennt am hellsten. Das Feuer brennt auch.$DQ$, NULL, NULL, 0, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_25$DQ$, $DQ$The Prometheus$DQ$, $DQ$insight_cold$DQ$, $JB${}$JB$::jsonb, $DQ$The forge is cold. The workshop presents its materials, but they are inert. They wait for a spark that has not yet arrived.$DQ$, $DQ$Die Schmiede ist kalt. Die Werkstatt präsentiert ihre Materialien, aber sie sind inert. Sie warten auf einen Funken, der noch nicht eingetroffen ist.$DQ$, NULL, NULL, 0, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_26$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$The construct disassembles. Its components scatter. Some of them are still warm. Some of them are interesting.$DQ$, $DQ$Das Konstrukt zerlegt sich. Seine Komponenten zerstreuen sich. Manche sind noch warm. Manche sind interessant.$DQ$, NULL, NULL, 0, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_27$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat_won$DQ$, $JB${"openness": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} examines the remains. Not as a soldier examines a defeated enemy. As an engineer examines a competitor's product.$DQ$, $DQ${agent} untersucht die Überreste. Nicht wie ein Soldat einen besiegten Feind untersucht. Wie ein Ingenieur das Produkt eines Konkurrenten untersucht.$DQ$, NULL, NULL, 0, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_28$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$The workshop absorbs the debris. Already recycling. Already planning the next iteration.$DQ$, $DQ$Die Werkstatt absorbiert die Trümmer. Recycelt bereits. Plant bereits die nächste Iteration.$DQ$, NULL, NULL, 0, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_29$DQ$, $DQ$The Prometheus$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$The fire dims. Not out – it is still there, in the walls, in the floor, in the components. But it allows rest. A forge needs its cooling cycles.$DQ$, $DQ$Das Feuer wird schwächer. Nicht aus – es ist noch da, in den Wänden, im Boden, in den Komponenten. Aber es erlaubt Ruhe. Eine Schmiede braucht ihre Abkühlzyklen.$DQ$, NULL, NULL, 0, 28) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_30$DQ$, $DQ$The Prometheus$DQ$, $DQ$rest_start$DQ$, $JB${"neuroticism": [0.5, 1.0]}$JB$::jsonb, $DQ${agent} sets down the components. They cool. For a moment, they are just materials again. Just matter. The workshop permits this.$DQ$, $DQ${agent} legt die Komponenten ab. Sie kühlen ab. Für einen Moment sind sie wieder nur Materialien. Nur Materie. Die Werkstatt erlaubt das.$DQ$, NULL, NULL, 0, 29) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_31$DQ$, $DQ$The Prometheus$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$New material. The workshop offers it like a gift. Like all gifts here: also a question.$DQ$, $DQ$Neues Material. Die Werkstatt bietet es an wie ein Geschenk. Wie alle Geschenke hier: auch eine Frage.$DQ$, NULL, NULL, 0, 30) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_32$DQ$, $DQ$The Prometheus$DQ$, $DQ$loot_found$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} holds the component. It is warm. It pulses once – not a heartbeat, but a frequency. It is introducing itself.$DQ$, $DQ${agent} hält die Komponente. Sie ist warm. Sie pulsiert einmal – kein Herzschlag, sondern eine Frequenz. Sie stellt sich vor.$DQ$, NULL, NULL, 0, 31) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_33$DQ$, $DQ$The Prometheus$DQ$, $DQ$agent_stressed$DQ$, $JB${}$JB$::jsonb, $DQ$The fire in {agent}'s instruments flares. Prometheus did not just bring fire to humanity. He brought the burns too.$DQ$, $DQ$Das Feuer in {agent}s Instrumenten flammt auf. Prometheus brachte nicht nur Feuer zur Menschheit. Er brachte auch die Verbrennungen.$DQ$, NULL, NULL, 0, 32) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$pb_34$DQ$, $DQ$The Prometheus$DQ$, $DQ$agent_stressed$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} flinches. The workshop does not pause. Innovation does not wait for permission. Nor for comfort.$DQ$, $DQ${agent} zuckt zusammen. Die Werkstatt pausiert nicht. Innovation wartet nicht auf Erlaubnis. Auch nicht auf Komfort.$DQ$, NULL, NULL, 0, 33) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_01$DQ$, $DQ$The Shadow$DQ$, $DQ$room_entered$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} flinches at a sound only they can hear.$DQ$, $DQ${agent} zuckt bei einem Geräusch zusammen, das nur sie hören.$DQ$, NULL, NULL, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
