INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_04$DQ$, $DQ$The Shadow$DQ$, $DQ$room_entered$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} checks their equipment methodically. Everything in order. Again.$DQ$, $DQ${agent} überprüft methodisch die Ausrüstung. Alles in Ordnung. Wieder.$DQ$, NULL, NULL, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_05$DQ$, $DQ$The Shadow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The terminal flickers. For a moment, the amber glow is the only light in the world.$DQ$, $DQ$Das Terminal flackert. Für einen Moment ist das Bernsteinleuchten das einzige Licht auf der Welt.$DQ$, NULL, NULL, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
