INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_07$DQ$, $DQ$The Shadow$DQ$, $DQ$combat_won$DQ$, $JB${"extraversion": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'That's what happens. That's what happens when you come at us.'$DQ$, $DQ${agent}: »Das passiert. Das passiert, wenn man sich mit uns anlegt.«$DQ$, NULL, NULL, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_08$DQ$, $DQ$The Shadow$DQ$, $DQ$combat_won$DQ$, $JB${"neuroticism": [0.0, 0.3]}$JB$::jsonb, $DQ${agent} wipes their blade clean. Professional. Done.$DQ$, $DQ${agent} wischt die Klinge sauber. Professionell. Erledigt.$DQ$, NULL, NULL, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_09$DQ$, $DQ$The Shadow$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$Silence returns. It's never comforting here.$DQ$, $DQ$Die Stille kehrt zurück. Hier ist sie nie tröstlich.$DQ$, NULL, NULL, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_10$DQ$, $DQ$The Shadow$DQ$, $DQ$visibility_zero$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'I can feel the walls. They're closer than they should be.'$DQ$, $DQ${agent}: »Ich kann die Wände spüren. Sie sind näher als sie sein sollten.«$DQ$, NULL, NULL, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_11$DQ$, $DQ$The Shadow$DQ$, $DQ$visibility_zero$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent}'s composure fractures. They have begun counting the intervals between sounds that are not there.$DQ$, $DQ${agent}s Fassung bricht. Sie zählen die Abstände zwischen Geräuschen, die nicht da sind.$DQ$, NULL, NULL, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_12$DQ$, $DQ$The Shadow$DQ$, $DQ$visibility_zero$DQ$, $JB${}$JB$::jsonb, $DQ$The instruments read nothing. Not zero – nothing. As if measurement itself has been consumed.$DQ$, $DQ$Die Instrumente zeigen nichts an. Nicht Null – nichts. Als wäre das Messen selbst verschlungen worden.$DQ$, NULL, NULL, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_13$DQ$, $DQ$The Shadow$DQ$, $DQ$agent_stressed$DQ$, $JB${"extraversion": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} mutters: 'I'm fine. I said I'm FINE.'$DQ$, $DQ${agent} murmelt: »Mir geht's gut. Ich SAGTE, mir geht's gut.«$DQ$, NULL, NULL, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
