INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_20$DQ$, $DQ$The Shadow$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$The shadow residue is cold to the touch. It hums faintly, like a tuning fork struck in the dark.$DQ$, $DQ$Der Schattenrückstand ist kalt bei Berührung. Er summt leise, wie eine Stimmgabel, die im Dunkeln angeschlagen wurde.$DQ$, NULL, NULL, 0, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_21$DQ$, $DQ$The Shadow$DQ$, $DQ$rest_start$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} can't rest. They sit in the corner, watching the entrance.$DQ$, $DQ${agent} kann nicht rasten. Sie sitzen in der Ecke und beobachten den Eingang.$DQ$, NULL, NULL, 0, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_22$DQ$, $DQ$The Shadow$DQ$, $DQ$rest_start$DQ$, $JB${"extraversion": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} tries to lighten the mood: 'Anyone else feel like this is the worst holiday they've ever been on?'$DQ$, $DQ${agent} versucht die Stimmung aufzulockern: »Geht es noch jemandem so, dass das der schlimmste Urlaub ist, auf dem sie je waren?«$DQ$, NULL, NULL, 0, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_23$DQ$, $DQ$The Shadow$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$The hollow is silent. For a few minutes, nothing pursues them.$DQ$, $DQ$Die Höhle schweigt. Für ein paar Minuten verfolgt sie nichts.$DQ$, NULL, NULL, 0, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_24$DQ$, $DQ$The Shadow$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$Deeper. The temperature drops. The silence becomes structural.$DQ$, $DQ$Tiefer. Die Temperatur sinkt. Die Stille wird baulich.$DQ$, NULL, NULL, 0, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_25$DQ$, $DQ$The Shadow$DQ$, $DQ$depth_change$DQ$, $JB${"openness": [0.0, 0.3]}$JB$::jsonb, $DQ${agent}: 'We should turn back.' No one responds.$DQ$, $DQ${agent}: »Wir sollten umkehren.« Niemand antwortet.$DQ$, NULL, NULL, 0, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_30$DQ$, $DQ$The Shadow$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$The passage narrows. Not physically – conceptually. There are fewer ways out.$DQ$, $DQ$Der Durchgang verengt sich. Nicht physisch – konzeptuell. Es gibt weniger Wege hinaus.$DQ$, NULL, NULL, 0, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_31$DQ$, $DQ$The Shadow$DQ$, $DQ$depth_change$DQ$, $JB${"neuroticism": [0.5, 1.0]}$JB$::jsonb, $DQ${agent} counts the steps since the last rest. Stops counting.$DQ$, $DQ${agent} zählt die Schritte seit der letzten Rast. Hört auf zu zählen.$DQ$, NULL, NULL, 0, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_32$DQ$, $DQ$The Shadow$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$The darkness here has weight. It presses down like accumulated intention.$DQ$, $DQ$Die Dunkelheit hier hat Gewicht. Sie drückt herab wie angesammelte Absicht.$DQ$, NULL, NULL, 0, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_26$DQ$, $DQ$The Shadow$DQ$, $DQ$elite_spotted$DQ$, $JB${}$JB$::jsonb, $DQ$The darkness coalesces. Something massive. Something old. Something that knows your names.$DQ$, $DQ$Die Dunkelheit verdichtet sich. Etwas Massives. Etwas Altes. Etwas, das eure Namen kennt.$DQ$, NULL, NULL, 0, 28) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_27$DQ$, $DQ$The Shadow$DQ$, $DQ$elite_spotted$DQ$, $JB${"neuroticism": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'No. No, no, no.' But they don't run.$DQ$, $DQ${agent}: »Nein. Nein, nein, nein.« Aber sie rennen nicht.$DQ$, NULL, NULL, 0, 29) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_28$DQ$, $DQ$The Shadow$DQ$, $DQ$boss_approach$DQ$, $JB${}$JB$::jsonb, $DQ$The air changes. The whispers stop. In the silence that follows, something enormous draws breath.$DQ$, $DQ$Die Luft ändert sich. Das Flüstern verstummt. In der folgenden Stille holt etwas Enormes Atem.$DQ$, NULL, NULL, 0, 30) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_29$DQ$, $DQ$The Shadow$DQ$, $DQ$boss_approach$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} reaches out and squeezes the nearest hand. 'Together.'$DQ$, $DQ${agent} greift nach der nächsten Hand und drückt sie. »Zusammen.«$DQ$, NULL, NULL, 0, 31) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_30b$DQ$, $DQ$The Shadow$DQ$, $DQ$boss_approach$DQ$, $JB${"extraversion": [0.0, 0.3]}$JB$::jsonb, $DQ${agent} is already moving before the others react. Quiet. Focused. Ready.$DQ$, $DQ${agent} bewegt sich bereits, bevor die anderen reagieren. Ruhig. Fokussiert. Bereit.$DQ$, NULL, NULL, 0, 32) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_31b$DQ$, $DQ$The Shadow$DQ$, $DQ$agent_afflicted$DQ$, $JB${}$JB$::jsonb, $DQ${agent}'s eyes go distant. When they speak again, the voice isn't entirely theirs.$DQ$, $DQ${agent}s Augen werden leer. Als sie wieder sprechen, ist die Stimme nicht ganz die ihre.$DQ$, NULL, NULL, 0, 33) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_32b$DQ$, $DQ$The Shadow$DQ$, $DQ$agent_virtue$DQ$, $JB${}$JB$::jsonb, $DQ$Something snaps in {agent} – but it's the sound of chains breaking, not bone. They stand straighter.$DQ$, $DQ$Etwas bricht in {agent} – aber es ist das Geräusch brechender Ketten, nicht von Knochen. Sie stehen aufrechter.$DQ$, NULL, NULL, 0, 34) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_33$DQ$, $DQ$The Shadow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$The shadows move. Not with you. Not against you. Around you. Testing.$DQ$, $DQ$Die Schatten bewegen sich. Nicht mit euch. Nicht gegen euch. Um euch herum. Testend.$DQ$, NULL, NULL, 0, 35) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_34$DQ$, $DQ$The Shadow$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$Somewhere above, a distant sound like stone grinding on stone. The dungeon shifts.$DQ$, $DQ$Irgendwo oben, ein fernes Geräusch wie Stein, der auf Stein mahlt. Der Dungeon verschiebt sich.$DQ$, NULL, NULL, 0, 36) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_35$DQ$, $DQ$The Shadow$DQ$, $DQ$room_entered$DQ$, $JB${"conscientiousness": [0.0, 0.3]}$JB$::jsonb, $DQ${agent} kicks a loose stone. It falls into darkness. You don't hear it land.$DQ$, $DQ${agent} tritt gegen einen losen Stein. Er fällt in die Dunkelheit. Ihr hört ihn nicht aufschlagen.$DQ$, NULL, NULL, 0, 37) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_36$DQ$, $DQ$The Shadow$DQ$, $DQ$room_entered$DQ$, $JB${"extraversion": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'You know what this place needs? Windows.'$DQ$, $DQ${agent}: »Wisst ihr, was dieser Ort braucht? Fenster.«$DQ$, NULL, NULL, 0, 38) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_37$DQ$, $DQ$The Shadow$DQ$, $DQ$combat_won$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} pauses to examine the dissolving shadow. 'Fascinating structure. Like frozen smoke.'$DQ$, $DQ${agent} hält inne, um den sich auflösenden Schatten zu untersuchen. »Faszinierende Struktur. Wie gefrorener Rauch.«$DQ$, NULL, NULL, 0, 39) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_38$DQ$, $DQ$The Shadow$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$The darkness lets you leave. That's the most unsettling part.$DQ$, $DQ$Die Dunkelheit lässt euch gehen. Das ist der beunruhigendste Teil.$DQ$, NULL, NULL, 0, 40) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_39$DQ$, $DQ$The Shadow$DQ$, $DQ$retreat$DQ$, $JB${"agreeableness": [0.0, 0.3]}$JB$::jsonb, $DQ${agent}: 'Smart call. Dead heroes don't file reports.'$DQ$, $DQ${agent}: »Kluge Entscheidung. Tote Helden schreiben keine Berichte.«$DQ$, NULL, NULL, 0, 41) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_40$DQ$, $DQ$The Shadow$DQ$, $DQ$dungeon_completed$DQ$, $JB${}$JB$::jsonb, $DQ$Light. Actual light. The party shields their eyes. Behind them, the entrance seals shut.$DQ$, $DQ$Licht. Tatsächliches Licht. Die Gruppe schirmt die Augen ab. Hinter ihnen versiegelt sich der Eingang.$DQ$, NULL, NULL, 0, 42) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$sb_41$DQ$, $DQ$The Shadow$DQ$, $DQ$dungeon_completed$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} doesn't celebrate. They keep checking the shadows. They'll keep checking for a long time.$DQ$, $DQ${agent} feiert nicht. Sie prüfen weiter die Schatten. Sie werden das noch lange tun.$DQ$, NULL, NULL, 0, 43) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
