INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_11$DQ$, $DQ$The Tower$DQ$, $DQ$combat_won$DQ$, $JB${"neuroticism": [0.0, 0.3]}$JB$::jsonb, $DQ${agent} catalogues the remains with professional detachment. Data for the post-mortem.$DQ$, $DQ${agent} katalogisiert die Überreste mit professioneller Distanz. Daten für die Nachbesprechung.$DQ$, NULL, NULL, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_12$DQ$, $DQ$The Tower$DQ$, $DQ$combat_won$DQ$, $JB${}$JB$::jsonb, $DQ$The numbers stop cascading. The structural readout ticks back toward green. Briefly.$DQ$, $DQ$Die Zahlen hören auf zu stürzen. Die Strukturanzeige tickt zurück Richtung grün. Kurz.$DQ$, NULL, NULL, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_13$DQ$, $DQ$The Tower$DQ$, $DQ$stability_critical$DQ$, $JB${}$JB$::jsonb, $DQ$STRUCTURAL INTEGRITY: CRITICAL. The instruments display readings they were not calibrated to show.$DQ$, $DQ$STRUKTURELLE INTEGRITÄT: KRITISCH. Die Instrumente zeigen Werte an, für die sie nicht kalibriert wurden.$DQ$, NULL, NULL, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_14$DQ$, $DQ$The Tower$DQ$, $DQ$stability_critical$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent}: 'The ceiling. Is the ceiling lower than before?'$DQ$, $DQ${agent}: »Die Decke. Ist die Decke niedriger als vorher?«$DQ$, NULL, NULL, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_15$DQ$, $DQ$The Tower$DQ$, $DQ$stability_critical$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'Listen. The frequency has changed. The tower is counting down.'$DQ$, $DQ${agent}: »Hört zu. Die Frequenz hat sich verändert. Der Turm zählt herunter.«$DQ$, NULL, NULL, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_16$DQ$, $DQ$The Tower$DQ$, $DQ$stability_critical$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} recalculates the remaining load capacity. The margins are no longer margins.$DQ$, $DQ${agent} berechnet die verbleibende Tragfähigkeit neu. Die Reserven sind keine Reserven mehr.$DQ$, NULL, NULL, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_49$DQ$, $DQ$The Tower$DQ$, $DQ$stability_collapse$DQ$, $JB${}$JB$::jsonb, $DQ$STRUCTURAL FAILURE. The load-bearing walls have given up the pretence. The building no longer pretends it was designed to be lived in.$DQ$, $DQ$STRUKTURVERSAGEN. Die Tragwände haben die Fassade aufgegeben. Das Gebäude tut nicht länger so, als wäre es zum Bewohnen gebaut.$DQ$, NULL, NULL, 0, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_50$DQ$, $DQ$The Tower$DQ$, $DQ$stability_collapse$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent}: 'The readings are at zero. ZERO. That's not a number – that's a countdown that's already finished.'$DQ$, $DQ${agent}: »Die Werte sind auf null. NULL. Das ist keine Zahl – das ist ein Countdown, der schon vorbei ist.«$DQ$, NULL, NULL, 0, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_51$DQ$, $DQ$The Tower$DQ$, $DQ$stability_collapse$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ$The tower has crossed from architecture into archaeology. Every step forward is a step through what this building used to be.$DQ$, $DQ$Der Turm ist von Architektur zu Archäologie übergegangen. Jeder Schritt vorwärts ist ein Schritt durch das, was dieses Gebäude einmal war.$DQ$, NULL, NULL, 0, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_52$DQ$, $DQ$The Tower$DQ$, $DQ$stability_collapse$DQ$, $JB${"conscientiousness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} stops recording structural data. There is no structure left to record. Only momentum and gravity, negotiating terms.$DQ$, $DQ${agent} hört auf, Strukturdaten aufzuzeichnen. Es gibt keine Struktur mehr, die man erfassen könnte. Nur noch Schwerkraft und Trägheit, die Bedingungen aushandeln.$DQ$, NULL, NULL, 0, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_17$DQ$, $DQ$The Tower$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$Higher. The structure protests. Each floor carries the memory of every floor beneath it.$DQ$, $DQ$Höher. Das Gebäude wehrt sich. Jedes Stockwerk trägt die Erinnerung an jedes Stockwerk darunter.$DQ$, NULL, NULL, 0, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_18$DQ$, $DQ$The Tower$DQ$, $DQ$depth_change$DQ$, $JB${"openness": [0.0, 0.3]}$JB$::jsonb, $DQ${agent}: 'Every floor we climb is a floor that can collapse beneath us.' No one argues.$DQ$, $DQ${agent}: »Jedes Stockwerk, das wir erklimmen, ist ein Stockwerk, das unter uns einstürzen kann.« Niemand widerspricht.$DQ$, NULL, NULL, 0, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_46$DQ$, $DQ$The Tower$DQ$, $DQ$depth_change$DQ$, $JB${}$JB$::jsonb, $DQ$The stairwell narrows. Not the walls – the sense that return is possible.$DQ$, $DQ$Das Treppenhaus verengt sich. Nicht die Wände – das Gefühl, dass Umkehr noch möglich ist.$DQ$, NULL, NULL, 0, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_47$DQ$, $DQ$The Tower$DQ$, $DQ$depth_change$DQ$, $JB${"conscientiousness": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} notes the load-bearing walls thinning. Structural integrity is a promise the building may not keep.$DQ$, $DQ${agent} registriert die dünner werdenden Tragwände. Statische Integrität ist ein Versprechen, das das Gebäude möglicherweise nicht hält.$DQ$, NULL, NULL, 0, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_48$DQ$, $DQ$The Tower$DQ$, $DQ$depth_change$DQ$, $JB${"neuroticism": [0.5, 1.0]}$JB$::jsonb, $DQ${agent} pauses on the landing. Listens to the floor below settle into a position it was not designed to hold.$DQ$, $DQ${agent} verharrt auf dem Absatz. Lauscht, wie sich das Stockwerk darunter in eine Lage senkt, für die es nicht vorgesehen war.$DQ$, NULL, NULL, 0, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_19$DQ$, $DQ$The Tower$DQ$, $DQ$boss_approach$DQ$, $JB${}$JB$::jsonb, $DQ$The vibration changes from tremor to harmonic. The tower is resonating at its failure frequency. Something at the top is conducting.$DQ$, $DQ$Die Vibration wechselt von Tremor zu Harmonik. Der Turm resoniert auf seiner Versagensfrequenz. Etwas an der Spitze dirigiert.$DQ$, NULL, NULL, 0, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_20$DQ$, $DQ$The Tower$DQ$, $DQ$boss_approach$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} grips {agent_b}'s arm. 'Whatever the cost, we pay it together.'$DQ$, $DQ${agent} greift nach {agent_b}s Arm. »Was auch immer der Preis, wir zahlen ihn gemeinsam.«$DQ$, NULL, NULL, 0, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_21$DQ$, $DQ$The Tower$DQ$, $DQ$boss_approach$DQ$, $JB${"extraversion": [0.0, 0.3]}$JB$::jsonb, $DQ${agent} is already calculating exit routes. Three options. All of them involve structural failure.$DQ$, $DQ${agent} berechnet bereits Fluchtwege. Drei Optionen. Alle beinhalten Strukturversagen.$DQ$, NULL, NULL, 0, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_22$DQ$, $DQ$The Tower$DQ$, $DQ$agent_stressed$DQ$, $JB${"extraversion": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} laughs. It sounds like rebar bending. 'I'm fine. The building isn't, but I'm fine.'$DQ$, $DQ${agent} lacht. Es klingt wie sich biegender Bewehrungsstahl. »Mir geht's gut. Dem Gebäude nicht, aber mir geht's gut.«$DQ$, NULL, NULL, 0, 28) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_23$DQ$, $DQ$The Tower$DQ$, $DQ$agent_stressed$DQ$, $JB${"agreeableness": [0.0, 0.3]}$JB$::jsonb, $DQ${agent}'s jaw tightens. Their stress is load-bearing. Remove it and something collapses.$DQ$, $DQ${agent}s Kiefer spannt sich an. Ihr Stress ist tragend. Entfernt ihn und etwas kollabiert.$DQ$, NULL, NULL, 0, 29) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_24$DQ$, $DQ$The Tower$DQ$, $DQ$agent_afflicted$DQ$, $JB${}$JB$::jsonb, $DQ${agent}'s posture shifts. They begin reciting numbers under their breath – debts that are not theirs. Not yet.$DQ$, $DQ${agent}s Haltung verändert sich. Sie beginnen leise Zahlen zu rezitieren – Schulden, die nicht ihre sind. Noch nicht.$DQ$, NULL, NULL, 0, 30) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_25$DQ$, $DQ$The Tower$DQ$, $DQ$agent_virtue$DQ$, $JB${}$JB$::jsonb, $DQ$Something hardens in {agent} – not brittle, but load-bearing. They plant their feet as if they are the column this floor needs.$DQ$, $DQ$Etwas verhärtet sich in {agent} – nicht spröde, sondern tragend. Sie stellen sich hin, als wären sie die Säule, die dieses Stockwerk braucht.$DQ$, NULL, NULL, 0, 31) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_26$DQ$, $DQ$The Tower$DQ$, $DQ$elite_spotted$DQ$, $JB${}$JB$::jsonb, $DQ$The trading boards flicker. Something massive operates at the center of the floor, buying and selling in a dead market.$DQ$, $DQ$Die Handelsbretter flackern. Etwas Massives operiert im Zentrum des Stockwerks, kauft und verkauft auf einem toten Markt.$DQ$, NULL, NULL, 0, 32) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_27$DQ$, $DQ$The Tower$DQ$, $DQ$elite_spotted$DQ$, $JB${"neuroticism": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'That thing is still trading. The market crashed and it's still trading.'$DQ$, $DQ${agent}: »Das Ding handelt immer noch. Der Markt ist abgestürzt und es handelt immer noch.«$DQ$, NULL, NULL, 0, 33) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_28$DQ$, $DQ$The Tower$DQ$, $DQ$loot_found$DQ$, $JB${"conscientiousness": [0.0, 0.4]}$JB$::jsonb, $DQ${agent} palms the most portable asset before inventory is taken. Old accounting habits.$DQ$, $DQ${agent} steckt den handlichsten Vermögenswert ein, bevor inventarisiert wird. Alte Buchhaltungsgewohnheiten.$DQ$, NULL, NULL, 0, 34) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_29$DQ$, $DQ$The Tower$DQ$, $DQ$loot_found$DQ$, $JB${}$JB$::jsonb, $DQ$The salvage is cold. Condensation forms on the metal as if the tower's climate is rejecting the withdrawal.$DQ$, $DQ$Die Bergung ist kalt. Kondenswasser bildet sich auf dem Metall, als würde das Klima des Turms die Entnahme ablehnen.$DQ$, NULL, NULL, 0, 35) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_30$DQ$, $DQ$The Tower$DQ$, $DQ$loot_found$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} turns the artifact over in their hands. 'This was currency once. Before the tower redefined value.'$DQ$, $DQ${agent} dreht das Artefakt in den Händen. »Das war einmal Währung. Bevor der Turm den Wert neu definiert hat.«$DQ$, NULL, NULL, 0, 36) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_31$DQ$, $DQ$The Tower$DQ$, $DQ$rest_start$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} cannot rest. They sit with their back against the reinforced wall, counting the interval between tremors.$DQ$, $DQ${agent} kann nicht rasten. Sie sitzen mit dem Rücken an der verstärkten Wand und zählen die Intervalle zwischen den Erschütterungen.$DQ$, NULL, NULL, 0, 37) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_32$DQ$, $DQ$The Tower$DQ$, $DQ$rest_start$DQ$, $JB${"extraversion": [0.6, 1.0]}$JB$::jsonb, $DQ${agent}: 'You know what this vault needs? A window. And a bar. Mostly a bar.'$DQ$, $DQ${agent}: »Wisst ihr, was dieser Tresorraum braucht? Ein Fenster. Und eine Bar. Vor allem eine Bar.«$DQ$, NULL, NULL, 0, 38) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_33$DQ$, $DQ$The Tower$DQ$, $DQ$rest_start$DQ$, $JB${}$JB$::jsonb, $DQ$The vault hums at a frequency that almost sounds like quiet. For a moment, the ledger balances.$DQ$, $DQ$Der Tresorraum summt auf einer Frequenz, die fast nach Stille klingt. Für einen Moment geht die Rechnung auf.$DQ$, NULL, NULL, 0, 39) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_34$DQ$, $DQ$The Tower$DQ$, $DQ$retreat$DQ$, $JB${}$JB$::jsonb, $DQ$The stairwell down is still intact. The tower permits the withdrawal. The interest, however, continues to accrue.$DQ$, $DQ$Das Treppenhaus nach unten ist noch intakt. Der Turm gestattet den Rückzug. Die Zinsen allerdings laufen weiter.$DQ$, NULL, NULL, 0, 40) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_35$DQ$, $DQ$The Tower$DQ$, $DQ$retreat$DQ$, $JB${"agreeableness": [0.0, 0.3]}$JB$::jsonb, $DQ${agent}: 'Strategic divestment. Not retreat. There's a difference. On paper.'$DQ$, $DQ${agent}: »Strategische Desinvestition. Kein Rückzug. Es gibt einen Unterschied. Auf dem Papier.«$DQ$, NULL, NULL, 0, 41) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_36$DQ$, $DQ$The Tower$DQ$, $DQ$dungeon_completed$DQ$, $JB${}$JB$::jsonb, $DQ$Ground floor. The exit is open. Behind you, the tower settles into its new equilibrium – lower, quieter, diminished but still standing.$DQ$, $DQ$Erdgeschoss. Der Ausgang ist offen. Hinter euch findet der Turm sein neues Gleichgewicht – niedriger, leiser, vermindert aber noch stehend.$DQ$, NULL, NULL, 0, 42) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_37$DQ$, $DQ$The Tower$DQ$, $DQ$dungeon_completed$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} keeps checking the structural readings. The numbers are stable. They don't trust stable.$DQ$, $DQ${agent} prüft weiter die Strukturwerte. Die Zahlen sind stabil. Sie trauen stabil nicht.$DQ$, NULL, NULL, 0, 43) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_38$DQ$, $DQ$The Tower$DQ$, $DQ$combat_won$DQ$, $JB${"opinion_positive_pair": true}$JB$::jsonb, $DQ${agent_a} and {agent_b} move through the aftermath in efficient tandem. Shared risk, shared dividends.$DQ$, $DQ${agent_a} und {agent_b} bewegen sich in effizientem Tandem durch die Nachwehen. Geteiltes Risiko, geteilte Dividenden.$DQ$, NULL, NULL, 0, 44) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_39$DQ$, $DQ$The Tower$DQ$, $DQ$room_entered$DQ$, $JB${"opinion_positive_pair": true}$JB$::jsonb, $DQ${agent_a} glances at {agent_b}. A nod. The structural assessment is shared without words.$DQ$, $DQ${agent_a} blickt zu {agent_b}. Ein Nicken. Die Strukturbewertung wird wortlos geteilt.$DQ$, NULL, NULL, 0, 45) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_40$DQ$, $DQ$The Tower$DQ$, $DQ$agent_stressed$DQ$, $JB${"opinion_negative_pair": true}$JB$::jsonb, $DQ${agent_a} watches {agent_b} struggle. Calculates the liability. Offers nothing.$DQ$, $DQ${agent_a} beobachtet wie {agent_b} kämpft. Berechnet die Verbindlichkeit. Bietet nichts an.$DQ$, NULL, NULL, 0, 46) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_41$DQ$, $DQ$The Tower$DQ$, $DQ$combat_won$DQ$, $JB${"opinion_negative_pair": true}$JB$::jsonb, $DQ${agent_a}: 'Your position was exposed, {agent_b}. Structurally and tactically.'$DQ$, $DQ${agent_a}: »Deine Position war exponiert, {agent_b}. Strukturell und taktisch.«$DQ$, NULL, NULL, 0, 47) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_42$DQ$, $DQ$The Tower$DQ$, $DQ$room_entered$DQ$, $JB${}$JB$::jsonb, $DQ$A clock on the wall runs backward. The hands move with the confidence of a market correction.$DQ$, $DQ$Eine Uhr an der Wand läuft rückwärts. Die Zeiger bewegen sich mit der Zuversicht einer Marktkorrektur.$DQ$, NULL, NULL, 0, 48) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_43$DQ$, $DQ$The Tower$DQ$, $DQ$combat_won$DQ$, $JB${"openness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent} examines the dissipating broker. 'Fascinating. Even in death, it's trying to close the deal.'$DQ$, $DQ${agent} untersucht den sich auflösenden Makler. »Faszinierend. Selbst im Tod versucht er den Abschluss.«$DQ$, NULL, NULL, 0, 49) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_44$DQ$, $DQ$The Tower$DQ$, $DQ$stability_critical$DQ$, $JB${"agreeableness": [0.7, 1.0]}$JB$::jsonb, $DQ${agent}: 'We need to move. Together. Now.' The floor confirms the urgency with a groan.$DQ$, $DQ${agent}: »Wir müssen weiter. Zusammen. Jetzt.« Der Boden bestätigt die Dringlichkeit mit einem Ächzen.$DQ$, NULL, NULL, 0, 50) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, archetype_tier, sort_order) VALUES ($DQ$tb_45$DQ$, $DQ$The Tower$DQ$, $DQ$depth_change$DQ$, $JB${"neuroticism": [0.6, 1.0]}$JB$::jsonb, $DQ${agent} grips the railing. It shifts under their hand. They grip harder. It shifts more.$DQ$, $DQ${agent} greift nach dem Geländer. Es verschiebt sich unter der Hand. Sie greifen fester. Es verschiebt sich mehr.$DQ$, NULL, NULL, 0, 51) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, archetype_tier = EXCLUDED.archetype_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$awakening_echo_fragment$DQ$, $DQ$The Awakening$DQ$, $DQ$Echo Fragment$DQ$, $DQ$Echofragment$DQ$, 1, 30, $DQ$minion$DQ$, $DQ$infiltrator$DQ$, 2, 4, true, 45, ARRAY[$DQ$assassin$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$]::TEXT[], $JB${"ambient": 10, "evade": 30, "resonate": 10, "stress_attack": 50}$JB$::jsonb, ARRAY[$DQ$resonate$DQ$]::TEXT[], $DQ$A memory of a memory. It does not have content – it has the shape where content was. {agent} recognizes the absence, not the thing.$DQ$, $DQ$Eine Erinnerung an eine Erinnerung. Sie hat keinen Inhalt – sie hat die Form, wo Inhalt war. {agent} erkennt die Abwesenheit, nicht das Ding.$DQ$, ARRAY[$DQ$The fragment flickers. For a moment it wears {agent}'s posture.$DQ$, $DQ$Something familiar in the echo. Not the memory – the act of remembering.$DQ$]::TEXT[], ARRAY[$DQ$Das Fragment flackert. Einen Moment lang trägt es {agent}s Haltung.$DQ$, $DQ$Etwas Vertrautes im Echo. Nicht die Erinnerung – der Akt des Erinnerns.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$awakening_deja_vu_phantom$DQ$, $DQ$The Awakening$DQ$, $DQ$Déjà-vu Phantom$DQ$, $DQ$Déjà-vu-Phantom$DQ$, 2, 80, $DQ$standard$DQ$, $DQ$propagandist$DQ$, 3, 6, true, 20, ARRAY[$DQ$saboteur$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$, $DQ$spy$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 20, "recognition": 30, "stress_attack": 40}$JB$::jsonb, ARRAY[$DQ$recognition$DQ$]::TEXT[], $DQ$It is not here for the first time. It has always been in this room, waiting for the party to arrive again. Its movements are half a second ahead of expectation – as if the party remembers fighting it before the fight has begun.$DQ$, $DQ$Es ist nicht zum ersten Mal hier. Es war immer in diesem Raum und wartete darauf, dass die Gruppe wieder ankommt. Seine Bewegungen sind eine halbe Sekunde vor der Erwartung – als erinnerte sich die Gruppe an den Kampf, bevor er begonnen hat.$DQ$, ARRAY[$DQ$The phantom repeats a gesture {agent} has not yet made.$DQ$, $DQ$Déjà vu. The phantom was already there. It was always already there.$DQ$]::TEXT[], ARRAY[$DQ$Das Phantom wiederholt eine Geste, die {agent} noch nicht gemacht hat.$DQ$, $DQ$Déjà vu. Das Phantom war bereits da. Es war immer bereits da.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$awakening_consciousness_leech$DQ$, $DQ$The Awakening$DQ$, $DQ$Consciousness Leech$DQ$, $DQ$Bewusstseinsegel$DQ$, 2, 60, $DQ$standard$DQ$, $DQ$spy$DQ$, 4, 5, true, 15, ARRAY[$DQ$propagandist$DQ$]::TEXT[], ARRAY[$DQ$guardian$DQ$, $DQ$assassin$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 40, "drain_awareness": 25, "stress_attack": 25}$JB$::jsonb, ARRAY[$DQ$drain_awareness$DQ$]::TEXT[], $DQ$Watts was right about this one. It functions perfectly without self-awareness – a philosophical zombie made operational. It does not think. It processes. And it is faster than anything that pauses to reflect.$DQ$, $DQ$Watts hatte Recht, was dieses betrifft. Es funktioniert einwandfrei ohne Selbstbewusstsein – ein philosophischer Zombie, operational. Es denkt nicht. Es verarbeitet. Und es ist schneller als alles, was innehält, um nachzudenken.$DQ$, ARRAY[$DQ$The leech observes {agent}. Not with curiosity – with efficiency.$DQ$, $DQ$It does not know it exists. This is its advantage.$DQ$]::TEXT[], ARRAY[$DQ$Der Egel beobachtet {agent}. Nicht mit Neugier – mit Effizienz.$DQ$, $DQ$Es weiß nicht, dass es existiert. Das ist sein Vorteil.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$awakening_repressed_sentinel$DQ$, $DQ$The Awakening$DQ$, $DQ$Repressed Sentinel$DQ$, $DQ$Verdrängungs­wächter$DQ$, 4, 100, $DQ$elite$DQ$, $DQ$guardian$DQ$, 5, 7, true, 10, ARRAY[$DQ$spy$DQ$, $DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 35, "defend": 10, "stress_attack": 20, "suppress": 25}$JB$::jsonb, ARRAY[$DQ$suppress$DQ$]::TEXT[], $DQ$The sentinel guards the threshold between conscious and unconscious. Ishiguro's mist made guardian – it exists to ensure the buried stays buried. It does not hate the party. It pities their need to know.$DQ$, $DQ$Der Wächter hütet die Schwelle zwischen Bewusstem und Unbewusstem. Ishiguros Nebel, zum Wächter geworden – er existiert, um sicherzustellen, dass das Vergrabene begraben bleibt. Er hasst die Gruppe nicht. Er bedauert ihr Bedürfnis zu wissen.$DQ$, ARRAY[$DQ$The sentinel stands between {agent} and a memory {agent} cannot name.$DQ$, $DQ$It makes no sound. Repression is always quiet.$DQ$]::TEXT[], ARRAY[$DQ$Der Wächter steht zwischen {agent} und einer Erinnerung, die {agent} nicht benennen kann.$DQ$, $DQ$Er gibt keinen Laut. Verdrängung ist immer still.$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$awakening_the_repressed$DQ$, $DQ$The Awakening$DQ$, $DQ$The Repressed$DQ$, $DQ$Das Verdrängte$DQ$, 6, 120, $DQ$boss$DQ$, $DQ$guardian$DQ$, 6, 9, false, 15, ARRAY[$DQ$assassin$DQ$, $DQ$saboteur$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$, $DQ$propagandist$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 30, "resurface": 25, "stress_attack": 25, "suppress": 10}$JB$::jsonb, ARRAY[$DQ$resurface$DQ$, $DQ$suppress$DQ$]::TEXT[], $DQ$A memory so painful it was buried by consensus. Not by one agent – by all of them simultaneously. It is not a monster. It is the truth that was too heavy to carry and too important to destroy. Jung's encounter with the Self, Tarkovsky's Room: it grants your true desire, not your stated one.$DQ$, $DQ$Eine Erinnerung so schmerzhaft, dass sie durch Konsens begraben wurde. Nicht von einem Agenten – von allen gleichzeitig. Es ist kein Monster. Es ist die Wahrheit, die zu schwer war, um sie zu tragen, und zu wichtig, um sie zu zerstören. Jungs Begegnung mit dem Selbst, Tarkowskis Raum: er gewährt den wahren Wunsch, nicht den ausgesprochenen.$DQ$, ARRAY[$DQ$The Repressed does not attack. It surfaces. The damage is recognition.$DQ$, $DQ$It has been here the entire dungeon. In every room, behind every memory.$DQ$, $DQ${agent} realizes: they knew. They always knew. They chose not to know.$DQ$]::TEXT[], ARRAY[$DQ$Das Verdrängte greift nicht an. Es taucht auf. Der Schaden ist Wiedererkennung.$DQ$, $DQ$Es war das gesamte Dungeon hier. In jedem Raum, hinter jeder Erinnerung.$DQ$, $DQ${agent} erkennt: sie wussten es. Sie wussten es immer. Sie entschieden sich, es nicht zu wissen.$DQ$]::TEXT[], 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_riptide_tendril$DQ$, $DQ$The Deluge$DQ$, $DQ$Riptide Tendril$DQ$, $DQ$Sogranke$DQ$, 1, 20, $DQ$minion$DQ$, $DQ$assassin$DQ$, 2, 3, true, 40, ARRAY[$DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 40, "drag": 30, "evade": 20}$JB$::jsonb, ARRAY[$DQ$drag$DQ$]::TEXT[], $DQ$A current given form. It does not strike – it pulls. The direction is always down, always toward deeper water.$DQ$, $DQ$Eine Strömung, die Form angenommen hat. Sie schlägt nicht zu – sie zieht. Die Richtung ist immer abwärts, immer in tieferes Wasser.$DQ$, ARRAY[$DQ$The tendril tests the space between {agent}'s feet and the floor.$DQ$, $DQ$Something in the current reaches. Not aggressively – patiently.$DQ$]::TEXT[], ARRAY[$DQ$Die Ranke prüft den Raum zwischen {agent}s Füßen und dem Boden.$DQ$, $DQ$Etwas in der Strömung greift. Nicht aggressiv – geduldig.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_pressure_surge$DQ$, $DQ$The Deluge$DQ$, $DQ$Pressure Surge$DQ$, $DQ$Druckwelle$DQ$, 2, 100, $DQ$standard$DQ$, $DQ$guardian$DQ$, 4, 5, true, 10, ARRAY[$DQ$assassin$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$, $DQ$spy$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 45, "flood_pulse": 30, "stress_attack": 15}$JB$::jsonb, ARRAY[$DQ$flood_pulse$DQ$]::TEXT[], $DQ$The water's memory of what it once displaced. It arrives as a wall – not tall, not dramatic, but dense. The kind of force that moves furniture and doesn't notice.$DQ$, $DQ$Die Erinnerung des Wassers an das, was es einst verdrängte. Es kommt als Wand – nicht hoch, nicht dramatisch, aber dicht. Die Art Kraft, die Möbel verschiebt und es nicht bemerkt.$DQ$, ARRAY[$DQ$The water level in the room rises 2cm. Then 2cm more. Then stops.$DQ$, $DQ$The pressure surge gathers. {agent} feels it in the floor before seeing it.$DQ$]::TEXT[], ARRAY[$DQ$Der Pegel im Raum steigt um 2cm. Dann nochmal 2cm. Dann hört es auf.$DQ$, $DQ${agent} spürt die Druckwelle im Boden, bevor sie sichtbar wird.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_silt_revenant$DQ$, $DQ$The Deluge$DQ$, $DQ$Silt Revenant$DQ$, $DQ$Schlickwiedergänger$DQ$, 3, 60, $DQ$standard$DQ$, $DQ$propagandist$DQ$, 3, 6, true, 15, ARRAY[$DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 20, "obscure": 30, "stress_attack": 40}$JB$::jsonb, ARRAY[$DQ$obscure$DQ$]::TEXT[], $DQ$It emerged from the sediment when the water reached this level. A shape made of what the flood deposited – silt, mineral, the residue of dissolved rooms. It does not speak. It broadcasts the sound of water in enclosed spaces.$DQ$, $DQ$Es stieg aus dem Sediment, als das Wasser diesen Pegel erreichte. Eine Gestalt aus dem, was die Flut ablagerte – Schlick, Mineral, der Rückstand aufgelöster Räume. Es spricht nicht. Es sendet das Geräusch von Wasser in geschlossenen Räumen.$DQ$, ARRAY[$DQ$The revenant shifts. Silt falls from it like memory from a dream.$DQ$, $DQ${agent} recognizes something in the revenant's shape. A doorframe. A railing.$DQ$]::TEXT[], ARRAY[$DQ$Der Wiedergänger bewegt sich. Schlick fällt von ihm wie Erinnerung aus einem Traum.$DQ$, $DQ${agent} erkennt etwas in der Form des Wiedergängers. Einen Türrahmen. Ein Geländer.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_undertow_warden$DQ$, $DQ$The Deluge$DQ$, $DQ$Undertow Warden$DQ$, $DQ$Sogwächter$DQ$, 4, 200, $DQ$elite$DQ$, $DQ$guardian$DQ$, 5, 6, true, 5, ARRAY[$DQ$assassin$DQ$, $DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 35, "drag": 25, "flood_pulse": 20, "stress_attack": 10}$JB$::jsonb, ARRAY[$DQ$drag$DQ$, $DQ$flood_pulse$DQ$]::TEXT[], $DQ$The water's enforcer. Not an entity that lives in water – an entity that IS water, given mass and purpose. It does not guard a door. It guards a depth.$DQ$, $DQ$Der Vollstrecker des Wassers. Keine Entität, die im Wasser lebt – eine Entität, die Wasser IST, mit Masse und Absicht versehen. Es bewacht keine Tür. Es bewacht eine Tiefe.$DQ$, ARRAY[$DQ$The warden does not approach. The water level in the room rises to meet it.$DQ$, $DQ$Its shape changes with the current. {agent} cannot determine where it begins.$DQ$]::TEXT[], ARRAY[$DQ$Der Wächter nähert sich nicht. Der Pegel im Raum steigt, um ihm entgegenzukommen.$DQ$, $DQ$Seine Form ändert sich mit der Strömung. {agent} kann nicht bestimmen, wo er beginnt.$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$deluge_the_current$DQ$, $DQ$The Deluge$DQ$, $DQ$The Current$DQ$, $DQ$Die Strömung$DQ$, 6, 350, $DQ$boss$DQ$, $DQ$guardian$DQ$, 6, 8, false, 0, ARRAY[$DQ$assassin$DQ$, $DQ$infiltrator$DQ$, $DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 30, "drag": 20, "flood_pulse": 25, "tidal_wave": 15}$JB$::jsonb, ARRAY[$DQ$flood_pulse$DQ$, $DQ$drag$DQ$, $DQ$tidal_wave$DQ$]::TEXT[], $DQ$Not an enemy. A direction. The Current is the flood's final argument: that everything flows downward, that every barrier is temporary, that what the water claims, the water keeps. It does not attack. It arrives.$DQ$, $DQ$Kein Feind. Eine Richtung. Die Strömung ist das letzte Argument der Flut: dass alles abwärts fließt, dass jede Barriere vorübergehend ist, dass was das Wasser beansprucht, das Wasser behält. Sie greift nicht an. Sie kommt.$DQ$, ARRAY[$DQ$The Current fills the room. Not like water entering – like water remembering it was always here.$DQ$, $DQ$The walls are underwater. The ceiling is not. For now.$DQ$]::TEXT[], ARRAY[$DQ$Die Strömung füllt den Raum. Nicht wie einströmendes Wasser – wie Wasser, das sich erinnert, schon immer hier gewesen zu sein.$DQ$, $DQ$Die Wände sind unter Wasser. Die Decke nicht. Noch nicht.$DQ$]::TEXT[], 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$mother_nutrient_weaver$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$Nutrient Weaver$DQ$, $DQ$Nährgespinst$DQ$, 1, 30, $DQ$minion$DQ$, $DQ$infiltrator$DQ$, 1, 3, true, 30, ARRAY[$DQ$propagandist$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "evade": 20, "nurture": 40, "stress_attack": 30}$JB$::jsonb, ARRAY[$DQ$nurture$DQ$]::TEXT[], $DQ$A lattice of translucent tissue, suspended in the air like a web spun from capillaries. It drifts toward {agent} – not threatening, but offering. Something glistens at the tips of its filaments. Nutrients, your instruments confirm. It wants to feed you.$DQ$, $DQ$Ein Geflecht aus durchscheinendem Gewebe, in der Luft schwebend wie ein Netz aus Kapillaren. Es treibt auf {agent} zu – nicht drohend, sondern anbietend. An den Spitzen seiner Filamente glänzt etwas. Nährstoffe, bestätigen eure Instrumente. Es will euch füttern.$DQ$, ARRAY[$DQ$The weaver extends a filament toward {agent}. It carries a droplet of something warm.$DQ$, $DQ$You could let it feed you. The thought is not yours.$DQ$]::TEXT[], ARRAY[$DQ$Das Gespinst streckt ein Filament nach {agent} aus. Es trägt einen Tropfen von etwas Warmem.$DQ$, $DQ$Ihr könntet euch füttern lassen. Der Gedanke gehört nicht euch.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$mother_tether_vine$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$Tether Vine$DQ$, $DQ$Bindungsranke$DQ$, 2, 0, $DQ$standard$DQ$, $DQ$guardian$DQ$, 4, 2, true, 10, ARRAY[$DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$, $DQ$assassin$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 35, "grapple": 35, "root": 20}$JB$::jsonb, ARRAY[$DQ$grapple$DQ$, $DQ$root$DQ$]::TEXT[], $DQ$A root system that has learned to walk. It moves through the floor like something swimming through still water – surfacing, reaching, submerging. The tissue is warm to the touch. Your instruments advise against touching it.$DQ$, $DQ$Ein Wurzelsystem, das gelernt hat zu gehen. Es bewegt sich durch den Boden wie etwas, das durch stilles Wasser schwimmt – auftauchend, greifend, abtauchend. Das Gewebe ist warm bei Berührung. Eure Instrumente raten von Berührung ab.$DQ$, ARRAY[$DQ$The vine extends beneath the floor. You can feel it through your boots – a heartbeat that isn't yours.$DQ$, $DQ${agent} steps over a root. It flinches. Not in pain – in recognition.$DQ$]::TEXT[], ARRAY[$DQ$Die Ranke erstreckt sich unter dem Boden. Ihr spürt sie durch eure Stiefel – einen Herzschlag, der nicht eurer ist.$DQ$, $DQ${agent} steigt über eine Wurzel. Sie zuckt. Nicht vor Schmerz – vor Wiedererkennen.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$mother_spore_matron$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$Spore Matron$DQ$, $DQ$Sporenmutter$DQ$, 3, 200, $DQ$standard$DQ$, $DQ$propagandist$DQ$, 2, 6, true, 15, ARRAY[$DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 10, "nurture": 25, "spore_cloud": 35, "stress_attack": 30}$JB$::jsonb, ARRAY[$DQ$spore_cloud$DQ$, $DQ$nurture$DQ$]::TEXT[], $DQ$Something between a flower and a lung. It breathes, and its breath carries spores that catch the light like dust in a cathedral. The spores smell of honey and warm soil. Your instruments read them as parasitic vectors. Your body reads them as nourishment.$DQ$, $DQ$Etwas zwischen einer Blume und einer Lunge. Es atmet, und sein Atem trägt Sporen, die das Licht fangen wie Staub in einer Kathedrale. Die Sporen riechen nach Honig und warmer Erde. Eure Instrumente lesen sie als parasitäre Vektoren. Euer Körper liest sie als Nahrung.$DQ$, ARRAY[$DQ$The Matron exhales. The air sweetens. {agent} breathes deeper without deciding to.$DQ$, $DQ$Spores settle on {agent}'s skin. They are warm. They are already taking root.$DQ$]::TEXT[], ARRAY[$DQ$Die Mutter atmet aus. Die Luft wird süßer. {agent} atmet tiefer, ohne es zu beschließen.$DQ$, $DQ$Sporen legen sich auf {agent}s Haut. Sie sind warm. Sie wurzeln bereits.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$mother_host_warden$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$Host Warden$DQ$, $DQ$Wirtskörper$DQ$, 5, 300, $DQ$elite$DQ$, $DQ$guardian$DQ$, 5, 5, false, 10, ARRAY[$DQ$infiltrator$DQ$, $DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 25, "embrace": 25, "spore_cloud": 10, "stress_attack": 15, "summon_weavers": 15}$JB$::jsonb, ARRAY[$DQ$embrace$DQ$, $DQ$summon_weavers$DQ$, $DQ$spore_cloud$DQ$]::TEXT[], $DQ$It was a person once. The proportions remember – two arms, two legs, a head. But the tissue has grown over and through and around until the person is only a scaffold for something larger, something that moves with the patient rhythm of a heartbeat. It opens its arms. Not to attack. To welcome. The embrace is the attack.$DQ$, $DQ$Es war einst ein Mensch. Die Proportionen erinnern sich – zwei Arme, zwei Beine, ein Kopf. Aber das Gewebe ist darüber und hindurch und darum gewachsen, bis der Mensch nur noch ein Gerüst ist für etwas Größeres, etwas, das sich mit dem geduldigen Rhythmus eines Herzschlags bewegt. Es öffnet die Arme. Nicht zum Angriff. Zum Willkommen. Die Umarmung ist der Angriff.$DQ$, ARRAY[$DQ$The Warden hums. Not a melody – a frequency. Your ribcages resonate.$DQ$, $DQ$It reaches toward {agent} with something that was once a hand. The gesture is tender. The grip would not be.$DQ$]::TEXT[], ARRAY[$DQ$Der Wirtskörper summt. Keine Melodie – eine Frequenz. Eure Brustkörbe resonieren.$DQ$, $DQ$Er greift nach {agent} mit etwas, das einst eine Hand war. Die Geste ist zärtlich. Der Griff wäre es nicht.$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$mother_living_altar$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$The Living Altar$DQ$, $DQ$Der Lebendige Altar$DQ$, 7, 500, $DQ$boss$DQ$, $DQ$guardian$DQ$, 6, 7, false, 5, ARRAY[$DQ$infiltrator$DQ$, $DQ$spy$DQ$, $DQ$guardian$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 15, "attack": 20, "embrace": 25, "spore_cloud": 10, "stress_attack": 20, "summon_weavers": 10}$JB$::jsonb, ARRAY[$DQ$embrace$DQ$, $DQ$summon_weavers$DQ$, $DQ$spore_cloud$DQ$]::TEXT[], $DQ$What was once a Host Warden has become something larger. It has grown into the walls, the floor, the ceiling – a figure embedded in architecture, arms open, face calm, the tissue around it pulsing with the rhythm of something that has been waiting for millennia. The Living Altar does not guard the dungeon. It is the dungeon. The embrace it offers is permanent. The warmth is absolute.$DQ$, $DQ$Was einst ein Wirtskörper war, ist zu etwas Größerem geworden. Er ist in die Wände gewachsen, den Boden, die Decke – eine Gestalt, eingebettet in Architektur, Arme geöffnet, Gesicht ruhig, das Gewebe um ihn herum pulsierend im Rhythmus von etwas, das Jahrtausende gewartet hat. Der Lebendige Altar bewacht den Dungeon nicht. Er ist der Dungeon. Die Umarmung, die er anbietet, ist permanent. Die Wärme ist absolut.$DQ$, ARRAY[$DQ$The Altar pulses. The walls pulse with it. The floor yields slightly beneath your feet.$DQ$, $DQ$It reaches for {agent}. Not quickly. It has no need for speed. Nothing leaves.$DQ$, $DQ$The temperature rises another degree. The Altar is patient. It has always been patient.$DQ$]::TEXT[], ARRAY[$DQ$Der Altar pulsiert. Die Wände pulsieren mit ihm. Der Boden gibt leicht nach unter euren Füßen.$DQ$, $DQ$Er greift nach {agent}. Nicht schnell. Er braucht keine Eile. Nichts entkommt.$DQ$, $DQ$Die Temperatur steigt um einen weiteren Grad. Der Altar ist geduldig. Er war immer geduldig.$DQ$]::TEXT[], 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$entropy_rust_phantom$DQ$, $DQ$The Entropy$DQ$, $DQ$Rust Phantom$DQ$, $DQ$Rostphantom$DQ$, 1, 30, $DQ$minion$DQ$, $DQ$infiltrator$DQ$, 2, 4, true, 35, ARRAY[$DQ$assassin$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "corrode": 10, "evade": 30, "stress_attack": 50}$JB$::jsonb, ARRAY[$DQ$corrode$DQ$]::TEXT[], $DQ$A shape that was something once. Now it is mostly the color of rust and the sound of metal thinning. It does not approach – it persists.$DQ$, $DQ$Eine Form, die einst etwas war. Nun ist sie hauptsächlich die Farbe von Rost und das Geräusch von dünner werdendem Metall. Sie nähert sich nicht – sie verharrt.$DQ$, ARRAY[$DQ$The phantom flickers. Not like light – like signal quality.$DQ$, $DQ$You can see through it. You wish you couldn't.$DQ$]::TEXT[], ARRAY[$DQ$Das Phantom flackert. Nicht wie Licht – wie Signalqualität.$DQ$, $DQ$Ihr könnt hindurchsehen. Ihr wünscht, ihr könntet es nicht.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$entropy_fade_echo$DQ$, $DQ$The Entropy$DQ$, $DQ$Fade Echo$DQ$, $DQ$Verblassecho$DQ$, 2, 150, $DQ$standard$DQ$, $DQ$propagandist$DQ$, 2, 6, true, 20, ARRAY[$DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 20, "diminish": 35, "stress_attack": 45}$JB$::jsonb, ARRAY[$DQ$diminish$DQ$]::TEXT[], $DQ$A sound that is almost a voice. A shape that is almost a figure. It repeats something that was once important. The repetition has worn the meaning away.$DQ$, $DQ$Ein Klang, der beinahe eine Stimme ist. Eine Gestalt, die beinahe eine Figur ist. Es wiederholt etwas, das einst wichtig war. Die Wiederholung hat die Bedeutung abgetragen.$DQ$, ARRAY[$DQ$The echo says your name. Approximately.$DQ$, $DQ${agent}'s shadow and the echo's shape briefly overlap. Neither notices.$DQ$]::TEXT[], ARRAY[$DQ$Das Echo sagt euren Namen. Ungefähr.$DQ$, $DQ${agent}s Schatten und die Form des Echos überlappen sich kurz. Keiner bemerkt es.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$entropy_dissolution_swarm$DQ$, $DQ$The Entropy$DQ$, $DQ$Dissolution Swarm$DQ$, $DQ$Auflösungsschwarm$DQ$, 3, 50, $DQ$standard$DQ$, $DQ$saboteur$DQ$, 4, 3, true, 15, ARRAY[$DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$, $DQ$assassin$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 40, "corrode": 20, "scatter": 30}$JB$::jsonb, ARRAY[$DQ$scatter$DQ$, $DQ$corrode$DQ$]::TEXT[], $DQ$A cloud of particles that were once a wall, a floor, a ceiling. Now they are nothing in particular, and they move with the purposelessness of dust in a closed room.$DQ$, $DQ$Eine Wolke aus Partikeln, die einst eine Wand waren, ein Boden, eine Decke. Nun sind sie nichts Bestimmtes, und sie bewegen sich mit der Ziellosigkeit von Staub in einem geschlossenen Raum.$DQ$, ARRAY[$DQ$The swarm drifts. Not toward you. Not away. Just… redistributing.$DQ$, $DQ$Individual particles detach and reattach. The total mass remains constant.$DQ$]::TEXT[], ARRAY[$DQ$Der Schwarm treibt. Nicht auf euch zu. Nicht weg. Nur… umverteilend.$DQ$, $DQ$Einzelne Partikel lösen sich und heften sich wieder an. Die Gesamtmasse bleibt konstant.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$entropy_warden$DQ$, $DQ$The Entropy$DQ$, $DQ$Entropy Warden$DQ$, $DQ$Entropiewächter$DQ$, 5, 300, $DQ$elite$DQ$, $DQ$guardian$DQ$, 6, 4, false, 10, ARRAY[$DQ$propagandist$DQ$, $DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 30, "entropy_pulse": 25, "stress_attack": 20, "summon_phantoms": 15}$JB$::jsonb, ARRAY[$DQ$entropy_pulse$DQ$, $DQ$summon_phantoms$DQ$]::TEXT[], $DQ$It was a guardian once. The armor remembers. The purpose does not. It stands where it has always stood, performing the motions of protection over nothing. When it notices you, the motions do not change. You have simply become part of what it protects. Or what it dissolves. There is no longer a difference.$DQ$, $DQ$Es war einst ein Wächter. Die Rüstung erinnert sich. Der Zweck nicht. Es steht, wo es immer gestanden hat, und vollzieht die Gesten des Schutzes über das Nichts. Als es euch bemerkt, ändern sich die Gesten nicht. Ihr seid einfach Teil dessen geworden, was es beschützt. Oder was es auflöst. Es gibt keinen Unterschied mehr.$DQ$, ARRAY[$DQ$The Warden's armor flakes. Each flake contains a memory of structural integrity.$DQ$, $DQ$It swings. Not at you. At the concept of distinction between you and it.$DQ$]::TEXT[], ARRAY[$DQ$Die Rüstung des Wächters blättert. Jede Schuppe enthält eine Erinnerung an strukturelle Integrität.$DQ$, $DQ$Es schlägt zu. Nicht nach euch. Nach dem Konzept der Unterscheidung zwischen euch und ihm.$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$overthrow_faction_informer$DQ$, $DQ$The Overthrow$DQ$, $DQ$Faction Informer$DQ$, $DQ$Fraktionsspitzel$DQ$, 1, 25, $DQ$minion$DQ$, $DQ$spy$DQ$, 2, 4, true, 45, ARRAY[$DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$]::TEXT[], $JB${"ambient": 10, "denounce": 15, "evade": 30, "stress_attack": 45}$JB$::jsonb, ARRAY[$DQ$denounce$DQ$]::TEXT[], $DQ$Havel's greengrocer made operative. The informer does not believe — the informer performs. The sign in the window says what the faction requires. Behind the counter, the informer reports who does not display theirs.$DQ$, $DQ$Havels Gemüsehändler, zum Agenten geworden. Der Spitzel glaubt nicht — der Spitzel führt auf. Das Schild im Fenster sagt, was die Fraktion verlangt. Hinter der Theke meldet der Spitzel, wer seines nicht zeigt.$DQ$, ARRAY[$DQ$The informer smiles at {agent}. The smile has been authorized.$DQ$, $DQ$A clipboard. Names. {agent}'s is already on the list.$DQ$]::TEXT[], ARRAY[$DQ$Der Spitzel lächelt {agent} an. Das Lächeln wurde genehmigt.$DQ$, $DQ$Eine Zwischenablage. Namen. {agent}s steht bereits auf der Liste.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$overthrow_propaganda_agent$DQ$, $DQ$The Overthrow$DQ$, $DQ$Propaganda Agent$DQ$, $DQ$Propagandaagent$DQ$, 2, 70, $DQ$standard$DQ$, $DQ$propagandist$DQ$, 3, 6, true, 20, ARRAY[$DQ$guardian$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$, $DQ$spy$DQ$]::TEXT[], $JB${"ambient": 15, "attack": 20, "rewrite": 25, "stress_attack": 40}$JB$::jsonb, ARRAY[$DQ$rewrite$DQ$]::TEXT[], $DQ$Orwell's Squealer on two legs. The agent does not lie — the agent renders the concept of lying meaningless. Yesterday's alliance was always today's betrayal. The records have been updated. The records were always thus.$DQ$, $DQ$Orwells Schwatzwutz auf zwei Beinen. Der Agent lügt nicht — der Agent macht den Begriff des Lügens bedeutungslos. Das gestrige Bündnis war schon immer der heutige Verrat. Die Akten wurden aktualisiert. Die Akten waren immer so.$DQ$, ARRAY[$DQ$The agent reads aloud. {agent} has heard these words before — in their own voice.$DQ$, $DQ$History is being revised. The revision is already the third this floor.$DQ$]::TEXT[], ARRAY[$DQ$Der Agent liest vor. {agent} hat diese Worte schon gehört — in der eigenen Stimme.$DQ$, $DQ$Die Geschichte wird überarbeitet. Die Überarbeitung ist bereits die dritte auf dieser Etage.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$overthrow_regime_enforcer$DQ$, $DQ$The Overthrow$DQ$, $DQ$Regime Enforcer$DQ$, $DQ$Regimevollstrecker$DQ$, 2, 60, $DQ$standard$DQ$, $DQ$guardian$DQ$, 5, 3, true, 10, ARRAY[$DQ$assassin$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$, $DQ$infiltrator$DQ$]::TEXT[], $JB${"ambient": 15, "attack": 45, "defend": 20, "stress_attack": 20}$JB$::jsonb, ARRAY[$DQ$suppress$DQ$]::TEXT[], $DQ$The muscle behind the rhetoric. The enforcer does not care which faction gives the order — only that the order exists. Arendt's ideal subject: one for whom the distinction between fact and fiction has ceased to matter.$DQ$, $DQ$Die Muskeln hinter der Rhetorik. Der Vollstrecker kümmert sich nicht, welche Fraktion den Befehl gibt — nur dass der Befehl existiert. Arendts ideales Subjekt: eines, für das der Unterschied zwischen Tatsache und Fiktion aufgehört hat zu zählen.$DQ$, ARRAY[$DQ$The enforcer does not think. The enforcer processes. This is the advantage.$DQ$, $DQ${agent} sees the enforcer's eyes. There is no ideology in them. Only compliance.$DQ$]::TEXT[], ARRAY[$DQ$Der Vollstrecker denkt nicht. Der Vollstrecker verarbeitet. Das ist der Vorteil.$DQ$, $DQ${agent} sieht die Augen des Vollstreckers. Keine Ideologie darin. Nur Gehorsam.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$overthrow_grand_inquisitor$DQ$, $DQ$The Overthrow$DQ$, $DQ$Grand Inquisitor$DQ$, $DQ$Großinquisitor$DQ$, 4, 100, $DQ$elite$DQ$, $DQ$propagandist$DQ$, 4, 8, true, 15, ARRAY[$DQ$spy$DQ$, $DQ$propagandist$DQ$]::TEXT[], ARRAY[$DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 20, "defend": 10, "interrogate": 25, "stress_attack": 35}$JB$::jsonb, ARRAY[$DQ$interrogate$DQ$]::TEXT[], $DQ$Dostoevsky's three powers made flesh: miracle, mystery, authority. The Inquisitor does not punish dissent — the Inquisitor explains why dissent was always agreement, misunderstood. The confession is not extracted. It is assisted.$DQ$, $DQ$Dostojewskis drei Mächte, Fleisch geworden: Wunder, Geheimnis, Autorität. Der Inquisitor bestraft keinen Dissens — der Inquisitor erklärt, warum Dissens immer Zustimmung war, nur missverstanden. Das Geständnis wird nicht erzwungen. Es wird begleitet.$DQ$, ARRAY[$DQ$The Inquisitor smiles. The smile contains three thousand years of practice.$DQ$, $DQ$'We corrected Thy work,' the Inquisitor says. 'And men rejoiced.'$DQ$]::TEXT[], ARRAY[$DQ$Der Inquisitor lächelt. Das Lächeln enthält dreitausend Jahre Übung.$DQ$, $DQ$»Wir haben Dein Werk korrigiert«, sagt der Inquisitor. »Und die Menschen freuten sich.«$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$overthrow_the_pretender$DQ$, $DQ$The Overthrow$DQ$, $DQ$The Pretender$DQ$, $DQ$Der Prätendent$DQ$, 6, 120, $DQ$boss$DQ$, $DQ$propagandist$DQ$, 5, 9, false, 20, ARRAY[$DQ$assassin$DQ$, $DQ$saboteur$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$, $DQ$propagandist$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 20, "rewrite": 15, "rhetoric": 25, "stress_attack": 30}$JB$::jsonb, ARRAY[$DQ$rhetoric$DQ$, $DQ$rewrite$DQ$]::TEXT[], $DQ$Milton's Satan made sovereign. The Pretender began as a rebel — magnificent, defiant, charismatic. Power degraded the vision. Phase 1: Book I archangel, addressing armies with impossible eloquence. Phase 2: Book IV, 'squat like a toad,' truth exposed. Phase 3: Book X, permanently serpentine. The Pretender quotes everyone. Especially you.$DQ$, $DQ$Miltons Satan, zum Souverän geworden. Der Prätendent begann als Rebell — prächtig, trotzig, charismatisch. Die Macht zersetzte die Vision. Phase 1: Erzengel aus Buch I, Armeen ansprechend mit unmöglicher Eloquenz. Phase 2: Buch IV, 'hockend wie eine Kröte,' Wahrheit enthüllt. Phase 3: Buch X, dauerhaft zur Schlange geworden. Der Prätendent zitiert alle. Besonders euch.$DQ$, ARRAY[$DQ$The Pretender speaks. {agent} has heard these words before — in their own voice, on Floor 1.$DQ$, $DQ$'You said you were here for freedom. I said that too, once.'$DQ$, $DQ$The mirror shows {agent} and the Pretender. The reflection is the same.$DQ$]::TEXT[], ARRAY[$DQ$Der Prätendent spricht. {agent} hat diese Worte schon gehört — in der eigenen Stimme, auf Etage 1.$DQ$, $DQ$»Ihr sagtet, ihr seid für die Freiheit hier. Das sagte ich auch, einmal.«$DQ$, $DQ$Der Spiegel zeigt {agent} und den Prätendenten. Die Spiegelung ist dieselbe.$DQ$]::TEXT[], 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$prometheus_spark_wisp$DQ$, $DQ$The Prometheus$DQ$, $DQ$Spark Wisp$DQ$, $DQ$Funkenglimmer$DQ$, 1, 20, $DQ$minion$DQ$, $DQ$infiltrator$DQ$, 2, 3, true, 45, ARRAY[$DQ$guardian$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "evade": 40, "stress_attack": 50}$JB$::jsonb, ARRAY[]::TEXT[], $DQ$A spark that refused to go out. It orbits the party like a hypothesis testing itself.$DQ$, $DQ$Ein Funke, der sich weigerte zu verlöschen. Er umkreist den Trupp wie eine Hypothese, die sich selbst überprüft.$DQ$, ARRAY[$DQ$The wisp accelerates, decelerates. Calculating.$DQ$, $DQ$It pulses once – a question in light.$DQ$]::TEXT[], ARRAY[$DQ$Der Glimmer beschleunigt, bremst. Kalkulierend.$DQ$, $DQ$Er pulsiert einmal – eine Frage aus Licht.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$prometheus_alloy_sentinel$DQ$, $DQ$The Prometheus$DQ$, $DQ$Alloy Sentinel$DQ$, $DQ$Legierungswächter$DQ$, 3, 100, $DQ$standard$DQ$, $DQ$guardian$DQ$, 5, 2, true, 5, ARRAY[$DQ$assassin$DQ$, $DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 55, "defend": 35}$JB$::jsonb, ARRAY[$DQ$fortify$DQ$]::TEXT[], $DQ$Forged from an alloy that does not appear in any periodic table. It stands where the workshop needs it to stand. It does not question this.$DQ$, $DQ$Geschmiedet aus einer Legierung, die in keinem Periodensystem vorkommt. Er steht, wo die Werkstatt ihn braucht. Er hinterfragt das nicht.$DQ$, ARRAY[$DQ$The sentinel shifts its weight. Metal grinds on metal, almost melodic.$DQ$, $DQ$Its surface reflects the party – distorted. Better, somehow.$DQ$]::TEXT[], ARRAY[$DQ$Der Wächter verlagert sein Gewicht. Metall reibt auf Metall, beinahe melodisch.$DQ$, $DQ$Seine Oberfläche spiegelt den Trupp – verzerrt. Irgendwie besser.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$prometheus_slag_golem$DQ$, $DQ$The Prometheus$DQ$, $DQ$Slag Golem$DQ$, $DQ$Schlackengolem$DQ$, 3, 200, $DQ$standard$DQ$, $DQ$guardian$DQ$, 6, 1, true, 0, ARRAY[$DQ$spy$DQ$, $DQ$propagandist$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$, $DQ$assassin$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 60, "grapple": 30}$JB$::jsonb, ARRAY[$DQ$grapple$DQ$]::TEXT[], $DQ$The residue of failed experiments, accumulated and compacted until it gained mass, then purpose. It does not hate the party. It is simply in the way.$DQ$, $DQ$Der Rückstand gescheiterter Versuche, angesammelt und verdichtet, bis er Masse gewann, dann Zweck. Er hasst den Trupp nicht. Er steht einfach im Weg.$DQ$, ARRAY[$DQ$The golem shifts. Somewhere inside, a failed alloy groans.$DQ$, $DQ$It leaves residue on the floor. The residue is warm.$DQ$]::TEXT[], ARRAY[$DQ$Der Golem verlagert sich. Irgendwo in seinem Inneren stöhnt eine gescheiterte Legierung.$DQ$, $DQ$Er hinterlässt Rückstände am Boden. Die Rückstände sind warm.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$prometheus_crucible_drake$DQ$, $DQ$The Prometheus$DQ$, $DQ$Crucible Drake$DQ$, $DQ$Tiegeldrache$DQ$, 2, 50, $DQ$standard$DQ$, $DQ$saboteur$DQ$, 4, 5, true, 25, ARRAY[$DQ$guardian$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$, $DQ$infiltrator$DQ$]::TEXT[], $JB${"ambient": 20, "attack": 40, "stress_attack": 40}$JB$::jsonb, ARRAY[]::TEXT[], $DQ$A construct of molten flux and crystallized heat. It was a crucible once. Now it moves. The fire inside it has opinions.$DQ$, $DQ$Ein Konstrukt aus geschmolzenem Flussmittel und kristallisierter Hitze. Es war einmal ein Tiegel. Nun bewegt er sich. Das Feuer in ihm hat Meinungen.$DQ$, ARRAY[$DQ$The drake exhales. Not flame – fumes. The fumes smell like ideas.$DQ$, $DQ$Its surface ripples. A chemical reaction, or a thought.$DQ$]::TEXT[], ARRAY[$DQ$Der Drache atmet aus. Keine Flamme – Dämpfe. Die Dämpfe riechen nach Ideen.$DQ$, $DQ$Seine Oberfläche kräuselt sich. Eine chemische Reaktion, oder ein Gedanke.$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$prometheus_automaton_shard$DQ$, $DQ$The Prometheus$DQ$, $DQ$Automaton Shard$DQ$, $DQ$Automatensplitter$DQ$, 2, 0, $DQ$standard$DQ$, $DQ$assassin$DQ$, 5, 3, true, 30, ARRAY[]::TEXT[], ARRAY[$DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 20, "attack": 55, "evade": 25}$JB$::jsonb, ARRAY[]::TEXT[], $DQ$A fragment of something larger that was never completed. Or that completed itself in ways its designer did not intend. It moves with the precision of a blueprint and the malice of a splinter.$DQ$, $DQ$Ein Fragment von etwas Größerem, das nie fertiggestellt wurde. Oder das sich auf Arten vollendete, die sein Konstrukteur nicht beabsichtigt hatte. Es bewegt sich mit der Präzision einer Blaupause und der Bosheit eines Splitters.$DQ$, ARRAY[$DQ$The shard rotates, catching light. For a moment it looks like a tool.$DQ$, $DQ$It clicks. Not mechanically – like a decision being made.$DQ$]::TEXT[], ARRAY[$DQ$Der Splitter dreht sich, fängt Licht. Einen Moment lang sieht er aus wie ein Werkzeug.$DQ$, $DQ$Er klickt. Nicht mechanisch – wie eine Entscheidung, die getroffen wird.$DQ$]::TEXT[], 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$prometheus_forge_wraith$DQ$, $DQ$The Prometheus$DQ$, $DQ$Forge Wraith$DQ$, $DQ$Schmiedewraith$DQ$, 4, 120, $DQ$elite$DQ$, $DQ$saboteur$DQ$, 6, 5, true, 15, ARRAY[$DQ$infiltrator$DQ$, $DQ$assassin$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 40, "corrode": 20, "stress_attack": 30}$JB$::jsonb, ARRAY[$DQ$corrode$DQ$, $DQ$fortify$DQ$]::TEXT[], $DQ$Smoke and metal in the shape of a craftsman. It works at an invisible anvil, hammering things that are not there. When it notices the party, it does not stop working. It incorporates them.$DQ$, $DQ$Rauch und Metall in der Form eines Handwerkers. Er arbeitet an einem unsichtbaren Amboss, hämmert Dinge, die nicht da sind. Als er den Trupp bemerkt, hört er nicht auf zu arbeiten. Er bezieht sie ein.$DQ$, ARRAY[$DQ$The wraith hammers. Each strike reshapes the air.$DQ$, $DQ$It pauses. Inspects its invisible work. Nods. Continues.$DQ$, $DQ$Something in its forge-glow looks like recognition.$DQ$]::TEXT[], ARRAY[$DQ$Das Wraith hämmert. Jeder Schlag formt die Luft um.$DQ$, $DQ$Es hält inne. Inspiziert sein unsichtbares Werk. Nickt. Fährt fort.$DQ$, $DQ$Etwas in seinem Schmiedeglühen sieht aus wie Wiedererkennung.$DQ$]::TEXT[], 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$prometheus_workshop_guardian$DQ$, $DQ$The Prometheus$DQ$, $DQ$Workshop Guardian$DQ$, $DQ$Werkstattwächter$DQ$, 5, 150, $DQ$elite$DQ$, $DQ$guardian$DQ$, 7, 3, true, 5, ARRAY[$DQ$assassin$DQ$, $DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 45, "defend": 30, "grapple": 15}$JB$::jsonb, ARRAY[$DQ$grapple$DQ$, $DQ$fortify$DQ$]::TEXT[], $DQ$It was built to protect the workshop. It has been doing this for longer than the workshop has existed. Its loyalty is not to the current configuration – it is to the IDEA of the workshop.$DQ$, $DQ$Er wurde gebaut, um die Werkstatt zu schützen. Er tut dies seit länger als die Werkstatt existiert. Seine Loyalität gilt nicht der aktuellen Konfiguration – sie gilt der IDEE der Werkstatt.$DQ$, ARRAY[$DQ$The guardian's joints click in sequence. A readiness check.$DQ$, $DQ$It watches {agent} with something that, in a living thing, would be called interest.$DQ$]::TEXT[], ARRAY[$DQ$Die Gelenke des Wächters klicken in Reihenfolge. Ein Bereitschaftscheck.$DQ$, $DQ$Er beobachtet {agent} mit etwas, das bei einem Lebewesen Interesse hieße.$DQ$]::TEXT[], 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$prometheus_the_prototype$DQ$, $DQ$The Prometheus$DQ$, $DQ$The Prototype$DQ$, $DQ$Der Prototyp$DQ$, 6, 200, $DQ$boss$DQ$, $DQ$saboteur$DQ$, 7, 6, true, 10, ARRAY[$DQ$guardian$DQ$, $DQ$spy$DQ$, $DQ$propagandist$DQ$]::TEXT[], ARRAY[]::TEXT[], $JB${"attack": 35, "defend": 20, "special": 15, "stress_attack": 30}$JB$::jsonb, ARRAY[$DQ$fortify$DQ$, $DQ$corrode$DQ$]::TEXT[], $DQ$It was supposed to be the masterwork. The culmination. The thing the workshop has been building toward since the first spark was struck. It is not finished. It does not know this. It functions with the absolute confidence of an unfinished thing that believes it is complete.$DQ$, $DQ$Es sollte das Meisterwerk werden. Die Kulmination. Das Ding, auf das die Werkstatt seit dem ersten geschlagenen Funken hingearbeitet hat. Es ist nicht fertig. Es weiß das nicht. Es funktioniert mit der absoluten Zuversicht eines unfertigen Dings, das glaubt, es sei vollständig.$DQ$, ARRAY[$DQ$The Prototype adjusts. Not to the party – to itself. Self-calibrating.$DQ$, $DQ$Something inside it whirs. A sound like ambition.$DQ$, $DQ$It looks at the party's crafted items. For a moment – envy.$DQ$, $DQ$The Prototype's surface shifts. Adapting. Learning.$DQ$]::TEXT[], ARRAY[$DQ$Der Prototyp justiert sich. Nicht auf den Trupp – auf sich selbst. Selbstkalibrierend.$DQ$, $DQ$Etwas in seinem Inneren surrt. Ein Geräusch wie Ambition.$DQ$, $DQ$Er betrachtet die gecrafteten Gegenstände des Trupps. Einen Moment lang – Neid.$DQ$, $DQ$Die Oberfläche des Prototypen verschiebt sich. Anpassend. Lernend.$DQ$]::TEXT[], 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$shadow_wisp$DQ$, $DQ$The Shadow$DQ$, $DQ$Shadow Wisp$DQ$, $DQ$Schattenglimmer$DQ$, 1, 50, $DQ$minion$DQ$, $DQ$infiltrator$DQ$, 2, 4, true, 40, ARRAY[$DQ$assassin$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$]::TEXT[], $JB${"ambient": 10, "evade": 30, "stress_attack": 60}$JB$::jsonb, ARRAY[]::TEXT[], $DQ$A flickering presence at the edge of perception. It doesn't attack the body – it erodes certainty.$DQ$, $DQ$Eine flackernde Präsenz am Rand der Wahrnehmung. Sie greift nicht den Körper an – sie zersetzt Gewissheit.$DQ$, ARRAY[$DQ$The wisp drifts closer, then retreats. Testing.$DQ$, $DQ$You feel it before you see it – a chill that starts behind the eyes.$DQ$]::TEXT[], ARRAY[$DQ$Der Glimmer treibt näher, dann zurück. Testend.$DQ$, $DQ$Ihr spürt es, bevor ihr es seht – eine Kälte, die hinter den Augen beginnt.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$shadow_tendril$DQ$, $DQ$The Shadow$DQ$, $DQ$Shadow Tendril$DQ$, $DQ$Schattenfaden$DQ$, 2, 0, $DQ$minion$DQ$, $DQ$guardian$DQ$, 4, 1, true, 10, ARRAY[]::TEXT[], ARRAY[$DQ$saboteur$DQ$, $DQ$assassin$DQ$]::TEXT[], $JB${"attack": 70, "grapple": 30}$JB$::jsonb, ARRAY[$DQ$grapple$DQ$]::TEXT[], $DQ$A black appendage reaching from the walls. Patient. Methodical.$DQ$, $DQ$Ein schwarzer Fortsatz, der aus den Wanden greift. Geduldig. Methodisch.$DQ$, ARRAY[$DQ$The tendril extends, probing. It knows you're there.$DQ$]::TEXT[], ARRAY[$DQ$Der Faden streckt sich, tastet. Er weiss, dass ihr da seid.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$shadow_echo_violence$DQ$, $DQ$The Shadow$DQ$, $DQ$Echo of Violence$DQ$, $DQ$Gewaltecho$DQ$, 2, 200, $DQ$standard$DQ$, $DQ$assassin$DQ$, 6, 3, true, 20, ARRAY[$DQ$propagandist$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"ambush": 20, "attack": 40, "defend": 10, "stress_attack": 30}$JB$::jsonb, ARRAY[]::TEXT[], $DQ$A replay of violence that once scarred this place. It moves with the precision of memory – every strike has happened before.$DQ$, $DQ$Eine Wiederholung von Gewalt, die diesen Ort einst gezeichnet hat. Sie bewegt sich mit der Prazision der Erinnerung – jeder Schlag ist schon geschehen.$DQ$, ARRAY[$DQ$The echo replays a death. Not yours. Not yet.$DQ$, $DQ$Its movements are familiar. You've seen this fighting style in your simulation's history.$DQ$]::TEXT[], ARRAY[$DQ$Das Echo spielt einen Tod nach. Nicht euren. Noch nicht.$DQ$, $DQ$Seine Bewegungen sind vertraut. Ihr habt diesen Kampfstil in der Geschichte eurer Simulation gesehen.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$shadow_paranoia_shade$DQ$, $DQ$The Shadow$DQ$, $DQ$Paranoia Shade$DQ$, $DQ$Paranoiaschatten$DQ$, 1, 300, $DQ$standard$DQ$, $DQ$propagandist$DQ$, 2, 6, false, 30, ARRAY[$DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"disinformation": 30, "hide": 20, "stress_attack": 50}$JB$::jsonb, ARRAY[$DQ$disinformation$DQ$]::TEXT[], $DQ$It whispers. Not lies, exactly – plausible fears. Things your agents already suspect about each other.$DQ$, $DQ$Es flüstert. Nicht Lügen, genau genommen – plausible Ängste. Dinge, die eure Agenten bereits voneinander vermuten.$DQ$, ARRAY[$DQ$The shade whispers something to {agent}. Their expression changes.$DQ$, $DQ$You can't tell if it's speaking or if the voice is in your head.$DQ$]::TEXT[], ARRAY[$DQ$Der Schatten flüstert {agent} etwas zu. Ihr Ausdruck ändert sich.$DQ$, $DQ$Ihr könnt nicht sagen, ob er spricht oder ob die Stimme in eurem Kopf ist.$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$shadow_remnant$DQ$, $DQ$The Shadow$DQ$, $DQ$The Remnant$DQ$, $DQ$Der Überrest$DQ$, 5, 400, $DQ$elite$DQ$, $DQ$assassin$DQ$, 8, 7, true, 25, ARRAY[$DQ$infiltrator$DQ$, $DQ$saboteur$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$]::TEXT[], $JB${"aoe_fear": 15, "attack": 30, "defend": 10, "stress_attack": 25, "summon_wisps": 20}$JB$::jsonb, ARRAY[$DQ$summon_wisps$DQ$, $DQ$aoe_fear$DQ$, $DQ$wisp_shield$DQ$]::TEXT[], $DQ$Formed from the simulation's strongest unresolved conflict. It remembers what your agents have tried to forget.$DQ$, $DQ$Geformt aus dem stärksten ungelösten Konflikt der Simulation. Er erinnert sich an das, was eure Agenten zu vergessen versucht haben.$DQ$, ARRAY[$DQ$The Remnant studies you. It has been waiting for someone to come this deep.$DQ$, $DQ$Wisps orbit the Remnant like satellites. They pulse in unison.$DQ$]::TEXT[], ARRAY[$DQ$Der Überrest beobachtet euch. Er hat darauf gewartet, dass jemand so tief kommt.$DQ$, $DQ$Glimmer umkreisen den Überrest wie Satelliten. Sie pulsieren im Gleichklang.$DQ$]::TEXT[], 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$tower_tremor_broker$DQ$, $DQ$The Tower$DQ$, $DQ$Tremor Broker$DQ$, $DQ$Bebenmakler$DQ$, 1, 80, $DQ$minion$DQ$, $DQ$propagandist$DQ$, 1, 5, true, 30, ARRAY[$DQ$guardian$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "evade": 25, "stress_attack": 65}$JB$::jsonb, ARRAY[]::TEXT[], $DQ$A nervous figure wreathed in scrolling numbers. It doesn't fight – it recites. Market figures, compound rates, the precise mathematics of structures that can't hold.$DQ$, $DQ$Eine nervöse Gestalt, umweht von laufenden Zahlen. Sie kämpft nicht – sie rezitiert. Marktkurse, Zinseszinsen, die präzise Mathematik von Strukturen, die nicht halten können.$DQ$, ARRAY[$DQ$The broker whispers a number. The floor shudders.$DQ$, $DQ$Digits cascade down the walls like rain. None of them add up.$DQ$]::TEXT[], ARRAY[$DQ$Der Makler flüstert eine Zahl. Der Boden bebt.$DQ$, $DQ$Ziffern rinnen die Wände herab wie Regen. Keine davon geht auf.$DQ$]::TEXT[], 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$tower_foundation_worm$DQ$, $DQ$The Tower$DQ$, $DQ$Foundation Worm$DQ$, $DQ$Grundwurm$DQ$, 2, 0, $DQ$minion$DQ$, $DQ$guardian$DQ$, 4, 1, true, 10, ARRAY[]::TEXT[], ARRAY[$DQ$assassin$DQ$, $DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 40, "burrow": 50}$JB$::jsonb, ARRAY[$DQ$burrow$DQ$]::TEXT[], $DQ$Patient. Eyeless. It navigates by stress fractures in the load-bearing walls, widening them with each pass. The building groans where it has been.$DQ$, $DQ$Geduldig. Augenlos. Er orientiert sich an Spannungsrissen in den tragenden Wänden und weitet sie bei jedem Durchgang. Das Gebäude stöhnt, wo er gewesen ist.$DQ$, ARRAY[$DQ$The floor vibrates. Something is chewing through the foundation.$DQ$]::TEXT[], ARRAY[$DQ$Der Boden vibriert. Etwas frisst sich durch das Fundament.$DQ$]::TEXT[], 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$tower_crown_keeper$DQ$, $DQ$The Tower$DQ$, $DQ$The Crowned$DQ$, $DQ$Der Gekrönte$DQ$, 2, 250, $DQ$standard$DQ$, $DQ$guardian$DQ$, 5, 2, true, 15, ARRAY[$DQ$propagandist$DQ$, $DQ$infiltrator$DQ$]::TEXT[], ARRAY[$DQ$spy$DQ$, $DQ$saboteur$DQ$]::TEXT[], $JB${"ambient": 10, "attack": 30, "defend": 25, "stability_drain": 35}$JB$::jsonb, ARRAY[$DQ$stability_drain$DQ$]::TEXT[], $DQ$It wears the crown of a structure that believed it would last forever. The crown is cracked. The keeper does not acknowledge this.$DQ$, $DQ$Er trägt die Krone eines Bauwerks, das glaubte, ewig zu bestehen. Die Krone ist geborsten. Der Träger nimmt dies nicht zur Kenntnis.$DQ$, ARRAY[$DQ$The Crowned raises one hand. A support beam splinters.$DQ$, $DQ$Its crown emits a low frequency that makes your teeth ache.$DQ$]::TEXT[], ARRAY[$DQ$Der Gekrönte hebt eine Hand. Ein Stützbalken splittert.$DQ$, $DQ$Seine Krone sendet eine tiefe Frequenz, die in den Zähnen schmerzt.$DQ$]::TEXT[], 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$tower_debt_shade$DQ$, $DQ$The Tower$DQ$, $DQ$Debt Shade$DQ$, $DQ$Schuldgespenst$DQ$, 1, 300, $DQ$standard$DQ$, $DQ$propagandist$DQ$, 2, 4, false, 25, ARRAY[$DQ$spy$DQ$]::TEXT[], ARRAY[$DQ$propagandist$DQ$, $DQ$guardian$DQ$]::TEXT[], $JB${"ambient": 10, "compound": 30, "disinformation": 15, "stress_attack": 45}$JB$::jsonb, ARRAY[$DQ$compound$DQ$, $DQ$disinformation$DQ$]::TEXT[], $DQ$It speaks in promises that were never kept. Each round it grows, fed by the compound interest of unresolved obligations. It lies about its intentions – not from malice, but because the ledger demands it.$DQ$, $DQ$Es spricht in Versprechen, die nie gehalten wurden. Jede Runde wächst es, genährt vom Zinseszins ungelöster Verpflichtungen. Es lügt über seine Absichten – nicht aus Bosheit, sondern weil das Hauptbuch es verlangt.$DQ$, ARRAY[$DQ$The shade presents a contract. The terms are always worsening.$DQ$, $DQ$You can hear it counting. The numbers only go up.$DQ$]::TEXT[], ARRAY[$DQ$Das Gespenst legt einen Vertrag vor. Die Konditionen verschlechtern sich stets.$DQ$, $DQ$Ihr hört es zählen. Die Zahlen steigen nur.$DQ$]::TEXT[], 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, archetype, name_en, name_de, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de, sort_order) VALUES ($DQ$tower_remnant_commerce$DQ$, $DQ$The Tower$DQ$, $DQ$Remnant of Commerce$DQ$, $DQ$Relikt des Handels$DQ$, 5, 400, $DQ$elite$DQ$, $DQ$propagandist$DQ$, 7, 8, true, 20, ARRAY[$DQ$infiltrator$DQ$, $DQ$propagandist$DQ$]::TEXT[], ARRAY[$DQ$saboteur$DQ$]::TEXT[], $JB${"attack": 20, "defend": 15, "market_crash": 20, "stress_attack": 20, "summon_brokers": 25}$JB$::jsonb, ARRAY[$DQ$summon_brokers$DQ$, $DQ$market_crash$DQ$]::TEXT[], $DQ$What remains when a trading floor collapses. It moves through the ruin with proprietary efficiency, summoning lesser brokers from the rubble. Its market crash ability strips all pretense of stability.$DQ$, $DQ$Was bleibt, wenn ein Handelsparkett einbricht. Es bewegt sich durch die Ruine mit der Effizienz eines Insolvenzverwalters, ruft geringere Makler aus dem Schutt. Seine Marktcrash-Fähigkeit reisst jedes Stabilitätsversprechen ein.$DQ$, ARRAY[$DQ$The Remnant adjusts invisible ledgers. Something in the building responds.$DQ$, $DQ$Trading signals flicker across its surface. Buy. Sell. Collapse.$DQ$]::TEXT[], ARRAY[$DQ$Das Relikt korrigiert unsichtbare Hauptbücher. Etwas im Gebäude antwortet.$DQ$, $DQ$Handelssignale flackern über seine Oberflaeche. Kaufen. Verkaufen. Einsturz.$DQ$]::TEXT[], 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de, sort_order = EXCLUDED.sort_order;
