INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_echo_drift$DQ$, $DQ$The Awakening$DQ$, $DQ$combat$DQ$, 1, 3, 1, NULL, $DQ$Fragments at the periphery. Not hostile – residual. Two echo fragments drift through the room, wearing postures borrowed from the party. They are memories of a memory – impressions with no original.$DQ$, $DQ$Fragmente an der Peripherie. Nicht feindlich – residual. Zwei Echofragmente driften durch den Raum und tragen Haltungen, die sie von der Gruppe geliehen haben. Erinnerungen an eine Erinnerung – Eindrücke ohne Original.$DQ$, $DQ$awakening_echo_drift_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_deja_vu_corridor$DQ$, $DQ$The Awakening$DQ$, $DQ$combat$DQ$, 2, 4, 1, NULL, $DQ$The corridor is familiar. The party has never been here. Both of these are true. A Déjà-vu Phantom occupies the center – its movements half a second ahead of expectation. An echo fragment trails behind, filling the gaps in the phantom's choreography.$DQ$, $DQ$Der Korridor ist vertraut. Die Gruppe war nie hier. Beides stimmt. Ein Déjà-vu-Phantom besetzt die Mitte – seine Bewegungen eine halbe Sekunde vor der Erwartung. Ein Echofragment folgt und füllt die Lücken in der Choreografie des Phantoms.$DQ$, $DQ$awakening_deja_vu_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_leech_hunt$DQ$, $DQ$The Awakening$DQ$, $DQ$combat$DQ$, 2, 5, 1, NULL, $DQ$Something in this room processes without perceiving. A Consciousness Leech – Watts's philosophical zombie made operational. It does not know it exists. This is its advantage. An echo fragment accompanies it, providing the self-awareness it lacks.$DQ$, $DQ$Etwas in diesem Raum verarbeitet, ohne wahrzunehmen. Ein Bewusstseinsegel – Watts' philosophischer Zombie, operational. Es weiß nicht, dass es existiert. Das ist sein Vorteil. Ein Echofragment begleitet es und stellt das Selbstbewusstsein bereit, das ihm fehlt.$DQ$, $DQ$awakening_leech_hunt_spawn$DQ$, false, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_deep_mind_clash$DQ$, $DQ$The Awakening$DQ$, $DQ$combat$DQ$, 3, 6, 1, NULL, $DQ$Deeper. The consciousness here is denser, layered like a palimpsest. A Consciousness Leech and a Déjà-vu Phantom have found equilibrium – the zombie and the prophet, processing and predicting, neither aware that the other thinks differently.$DQ$, $DQ$Tiefer. Das Bewusstsein hier ist dichter, geschichtet wie ein Palimpsest. Ein Bewusstseinsegel und ein Déjà-vu-Phantom haben ein Gleichgewicht gefunden – der Zombie und der Prophet, verarbeitend und vorhersagend, keiner bewusst, dass der andere anders denkt.$DQ$, $DQ$awakening_deep_mind_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_sentinel_chamber$DQ$, $DQ$The Awakening$DQ$, $DQ$combat$DQ$, 4, 7, 1, NULL, $DQ$The threshold between remembered and repressed. A Sentinel guards it – Ishiguro's mist given form. It does not hate the party. It pities their need to know. An echo fragment drifts behind, a memory that was permitted to exist.$DQ$, $DQ$Die Schwelle zwischen Erinnertem und Verdrängtem. Ein Wächter hütet sie – Ishiguros Nebel, dem Form gegeben wurde. Er hasst die Gruppe nicht. Er bedauert ihr Bedürfnis zu wissen. Ein Echofragment driftet dahinter, eine Erinnerung, der gestattet wurde zu existieren.$DQ$, $DQ$awakening_sentinel_spawn$DQ$, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_lucid_skirmish$DQ$, $DQ$The Awakening$DQ$, $DQ$combat$DQ$, 3, 5, 1, NULL, $DQ$The room recognizes the party. This is not a metaphor. The walls adjust. The light shifts to match a memory none of them can place. Two phantoms emerge from the adjustment – the room defending its version of events.$DQ$, $DQ$Der Raum erkennt die Gruppe. Das ist keine Metapher. Die Wände passen sich an. Das Licht verschiebt sich, um einer Erinnerung zu entsprechen, die keiner von ihnen einordnen kann. Zwei Phantome treten aus der Anpassung hervor – der Raum verteidigt seine Version der Geschehnisse.$DQ$, $DQ$awakening_deja_vu_patrol_spawn$DQ$, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_the_mirror$DQ$, $DQ$The Awakening$DQ$, $DQ$encounter$DQ$, 1, 3, 1, NULL, $DQ$A surface. Not glass – not water – something that reflects without material. Each agent sees something different. Lem's mirror: we have no need of other worlds. We need mirrors.$DQ$, $DQ$Eine Oberfläche. Nicht Glas – nicht Wasser – etwas, das reflektiert ohne Material. Jeder Agent sieht etwas anderes. Lems Spiegel: wir brauchen keine anderen Welten. Wir brauchen Spiegel.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_the_familiar_room$DQ$, $DQ$The Awakening$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$This room. The party has been here. Not in this dungeon – somewhere. The window was on the left. Or the right. The details resist settling. Proust's madeleine: the sensation arrives before the memory.$DQ$, $DQ$Dieser Raum. Die Gruppe war hier. Nicht in diesem Dungeon – irgendwo. Das Fenster war links. Oder rechts. Die Details weigern sich, sich festzulegen. Prousts Madeleine: die Empfindung kommt vor der Erinnerung.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_the_two_clocks$DQ$, $DQ$The Awakening$DQ$, $DQ$encounter$DQ$, 2, 5, 1, NULL, $DQ$Time is not uniform here. Kafka's two clocks: the inner one runs crazily on at an inhuman pace, the outer one limps along. The party experiences both. Actions in this room have consequences at different speeds.$DQ$, $DQ$Die Zeit ist hier nicht einheitlich. Kafkas zwei Uhren: die innere rennt wahnsinnig weiter in unmenschlichem Tempo, die äußere hinkt. Die Gruppe erlebt beides. Handlungen in diesem Raum haben Konsequenzen in unterschiedlichen Geschwindigkeiten.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_the_absent_memory$DQ$, $DQ$The Awakening$DQ$, $DQ$encounter$DQ$, 3, 6, 1, NULL, $DQ$A room with a gap. Not a hole – a smooth, clean absence. Something was here. The dungeon remembers that it forgets. Ogawa's memory police: first the emotional connection vanishes, then the physical evidence. This room is at stage two.$DQ$, $DQ$Ein Raum mit einer Lücke. Kein Loch – eine glatte, saubere Abwesenheit. Etwas war hier. Das Dungeon erinnert sich, dass es vergisst. Ogawas Gedächtnispolizei: erst verschwindet die emotionale Verbindung, dann der physische Beweis. Dieser Raum ist bei Stufe zwei.$DQ$, NULL, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_the_humming$DQ$, $DQ$The Awakening$DQ$, $DQ$encounter$DQ$, 3, 99, 1, NULL, $DQ$From somewhere: a humming. The likes of which the party has never heard. Not really humming – the singing of the most distant, of the most utterly distant, voices. Kafka's Castle telephone: this humming is the only real and reliable thing. Everything else is deceptive.$DQ$, $DQ$Von irgendwo: ein Summen. Wie es die Gruppe noch nie gehört hat. Nicht wirklich Summen – das Singen der fernsten, der allerallerfernsten Stimmen. Kafkas Schlosstelefon: dieses Summen ist das einzig Reale und Verlässliche. Alles andere ist Täuschung.$DQ$, NULL, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_threshold_gate$DQ$, $DQ$The Awakening$DQ$, $DQ$elite$DQ$, 4, 6, 1, NULL, $DQ$Before the Law. A gate between remembered and repressed. The Sentinel guards it – not with force, but with pity. This door was made only for the party. The Sentinel has waited their entire descent.$DQ$, $DQ$Vor dem Gesetz. Ein Tor zwischen Erinnertem und Verdrängtem. Der Wächter hütet es – nicht mit Gewalt, sondern mit Mitleid. Dieses Tor wurde nur für die Gruppe gemacht. Der Wächter hat ihren gesamten Abstieg gewartet.$DQ$, $DQ$awakening_sentinel_spawn$DQ$, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_the_repressed_boss$DQ$, $DQ$The Awakening$DQ$, $DQ$boss$DQ$, 4, 99, 1, NULL, $DQ$The room at the center. Tarkovsky's Room: it grants your true desire, not your stated one. The Repressed has been here the entire dungeon – in every room, behind every memory, inside every recognition. It is not a monster. It is the truth that was too heavy to carry and too important to destroy.$DQ$, $DQ$Der Raum in der Mitte. Tarkowskis Raum: er gewährt den wahren Wunsch, nicht den ausgesprochenen. Das Verdrängte war das gesamte Dungeon hier – in jedem Raum, hinter jeder Erinnerung, in jeder Wiedererkennung. Es ist kein Monster. Es ist die Wahrheit, die zu schwer war, um sie zu tragen, und zu wichtig, um sie zu zerstören.$DQ$, $DQ$awakening_sentinel_spawn$DQ$, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_quiet_layer$DQ$, $DQ$The Awakening$DQ$, $DQ$rest$DQ$, 1, 99, 1, NULL, $DQ$A stratum of consciousness that is still. Not empty – calm. Like the pause between breaths. The dungeon's awareness rests here too. For a moment, the observer and the observed share the same silence.$DQ$, $DQ$Eine Schicht des Bewusstseins, die still ist. Nicht leer – ruhig. Wie die Pause zwischen Atemzügen. Das Bewusstsein des Dungeons ruht hier ebenfalls. Für einen Moment teilen der Beobachter und das Beobachtete dieselbe Stille.$DQ$, NULL, false, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_forgetting_pool$DQ$, $DQ$The Awakening$DQ$, $DQ$rest$DQ$, 3, 99, 1, NULL, $DQ$Lethe. A pool of deliberate forgetting. Not a loss – a choice. The Oracle of Trophonius demands it: drink from Lethe first, to forget all prior thoughts. Then from Mnemosyne, to remember what you will see. Both rivers, sequentially.$DQ$, $DQ$Lethe. Ein Becken des absichtlichen Vergessens. Kein Verlust – eine Wahl. Das Orakel des Trophonios verlangt es: trinke zuerst aus Lethe, um alle vorherigen Gedanken zu vergessen. Dann aus Mnemosyne, um zu erinnern, was du sehen wirst. Beide Flüsse, nacheinander.$DQ$, NULL, false, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_crystallized_memory$DQ$, $DQ$The Awakening$DQ$, $DQ$treasure$DQ$, 1, 99, 1, NULL, $DQ$Consciousness, solidified. A lieu de mémoire – Nora's concept: a place where memory crystallizes because history would dissolve it. The artifact holds what the dungeon chose to preserve.$DQ$, $DQ$Bewusstsein, verfestigt. Ein Lieu de Mémoire – Noras Konzept: ein Ort, an dem Erinnerung kristallisiert, weil Geschichte sie auflösen würde. Das Artefakt bewahrt, was das Dungeon zu bewahren wählte.$DQ$, NULL, false, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$aw_the_archive$DQ$, $DQ$The Awakening$DQ$, $DQ$treasure$DQ$, 2, 99, 1, NULL, $DQ$An archive. Not of documents – of impressions. Each shelf holds a sensation: the smell of rain on warm stone, the sound of a name almost remembered, the weight of a decision not yet made. Bergson's cone of memory: the totality of experience, compressed into accessible form.$DQ$, $DQ$Ein Archiv. Nicht aus Dokumenten – aus Eindrücken. Jedes Regal hält eine Empfindung: den Geruch von Regen auf warmem Stein, den Klang eines fast erinnerten Namens, das Gewicht einer noch nicht getroffenen Entscheidung. Bergsons Erinnerungskegel: die Gesamtheit der Erfahrung, komprimiert in zugängliche Form.$DQ$, NULL, false, 0, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_trickle_probe$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 1, 3, 1, NULL, $DQ$First currents testing the party's resolve. Two tendrils of water extend from the floor drain, probing the space the party occupies. They are not fast. They are patient.$DQ$, $DQ$Erste Strömungen, die die Entschlossenheit der Gruppe testen. Zwei Wasserranken strecken sich aus dem Bodenabfluss, tasten den Raum ab, den die Gruppe einnimmt. Sie sind nicht schnell. Sie sind geduldig.$DQ$, $DQ$deluge_trickle_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_surge_corridor$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 2, 4, 1, NULL, $DQ$A corridor where the water moves with purpose. A Pressure Surge occupies the center – a wall of dense water that advances without hurry. A Riptide Tendril flanks from the drainage channel. The corridor narrows. The water does not.$DQ$, $DQ$Ein Korridor, in dem das Wasser sich mit Absicht bewegt. Eine Druckwelle besetzt die Mitte – eine Wand dichten Wassers, die ohne Eile vorrückt. Eine Sogranke flankiert aus dem Abflusskanal. Der Korridor verengt sich. Das Wasser nicht.$DQ$, $DQ$deluge_surge_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_sediment_ambush$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 2, 5, 1, NULL, $DQ$The silt remembers shapes. Some of them fight back. A Silt Revenant assembles from the sediment layer – mineral, debris, the residue of dissolved architecture. A tendril assists, pulling from below.$DQ$, $DQ$Der Schlick erinnert sich an Formen. Einige davon wehren sich. Ein Schlickwiedergänger setzt sich aus der Sedimentschicht zusammen – Mineral, Trümmer, der Rückstand aufgelöster Architektur. Eine Ranke assistiert und zieht von unten.$DQ$, $DQ$deluge_sediment_spawn$DQ$, false, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_deep_water_clash$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 3, 6, 2, NULL, $DQ$Waist-deep. Every step costs something. A Pressure Surge and a Silt Revenant occupy a junction room where three corridors meet. The water here has momentum – it flows, it carries, it resists.$DQ$, $DQ$Hüfttief. Jeder Schritt kostet. Eine Druckwelle und ein Schlickwiedergänger besetzen einen Knotenpunkt, an dem drei Korridore zusammentreffen. Das Wasser hier hat Schwung – es fließt, es trägt, es widersteht.$DQ$, $DQ$deluge_deep_water_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_warden_chamber$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 4, 7, 2, NULL, $DQ$The water has posted a guard at this depth. An Undertow Warden – water given mass and purpose – fills the chamber. A tendril circles the perimeter. The warden does not approach. The water level rises to meet it.$DQ$, $DQ$Das Wasser hat einen Wächter auf dieser Tiefe postiert. Ein Sogwächter – Wasser mit Masse und Absicht versehen – füllt die Kammer. Eine Ranke umkreist den Rand. Der Wächter nähert sich nicht. Der Pegel steigt, um ihm entgegenzukommen.$DQ$, $DQ$deluge_warden_spawn$DQ$, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_whirlpool_room$DQ$, $DQ$The Deluge$DQ$, $DQ$combat$DQ$, 3, 5, 2, NULL, $DQ$The current circles. The party is in the center. A Pressure Surge and a Silt Revenant orbit the room's perimeter, riding the whirlpool. Fighting here means fighting the water's geometry.$DQ$, $DQ$Die Strömung kreist. Die Gruppe ist im Zentrum. Eine Druckwelle und ein Schlickwiedergänger umkreisen den Raumrand, reiten auf dem Strudel. Hier kämpfen heißt gegen die Geometrie des Wassers kämpfen.$DQ$, $DQ$deluge_deep_water_spawn$DQ$, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_the_watermark$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 1, 3, 1, NULL, $DQ$A line on the wall. Faint. Mineral-white. The watermark shows how high the water reached last time.$DQ$, $DQ$Eine Linie an der Wand. Schwach. Mineralweiß. Das Wasserzeichen zeigt, wie hoch das Wasser beim letzten Mal stand.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_submerged_cache$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$Through the water below – shapes. Containers. Something the flood deposited here from a room that no longer exists.$DQ$, $DQ$Durch das Wasser darunter – Formen. Behälter. Etwas, das die Flut hier ablagerte, aus einem Raum, der nicht mehr existiert.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_the_breach$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 2, 5, 1, NULL, $DQ$A crack in the wall. Water doesn't pour through it – it persuades. A thin, persistent line of moisture that widens as you watch.$DQ$, $DQ$Ein Riss in der Wand. Wasser strömt nicht hindurch – es überredet. Eine dünne, beharrliche Feuchtigkeitslinie, die sich verbreitert, während man zusieht.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_survivors_message$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 3, 5, 1, NULL, $DQ$Carved into the wall above the current waterline. Recent. Someone else tried this. The message is incomplete – the water reached it before they finished.$DQ$, $DQ$In die Wand geritzt, über der aktuellen Wasserlinie. Kürzlich. Jemand anderes hat dies versucht. Die Nachricht ist unvollständig – das Wasser erreichte sie, bevor sie fertig waren.$DQ$, NULL, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_sound_of_depth$DQ$, $DQ$The Deluge$DQ$, $DQ$encounter$DQ$, 3, 6, 2, NULL, $DQ$The water below has reached a resonance. A low hum. Not mechanical – geological. The sound the planet makes when it remembers it is mostly ocean.$DQ$, $DQ$Das Wasser darunter hat eine Resonanz erreicht. Ein tiefes Summen. Nicht mechanisch – geologisch. Das Geräusch, das der Planet macht, wenn er sich erinnert, dass er hauptsächlich Ozean ist.$DQ$, NULL, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_tidal_gate$DQ$, $DQ$The Deluge$DQ$, $DQ$elite$DQ$, 4, 6, 1, NULL, $DQ$A mechanism. Ancient. Not built by anyone in this simulation. The gate controls a section of the flood – open it and the water surges through, closed it holds. But the mechanism requires a sacrifice.$DQ$, $DQ$Ein Mechanismus. Uralt. Nicht von jemandem in dieser Simulation erbaut. Das Tor kontrolliert einen Abschnitt der Flut – öffnet man es, bricht das Wasser durch; geschlossen hält es. Aber der Mechanismus fordert ein Opfer.$DQ$, $DQ$deluge_warden_spawn$DQ$, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_the_current_boss$DQ$, $DQ$The Deluge$DQ$, $DQ$boss$DQ$, 4, 99, 1, NULL, $DQ$The water has found its shape. It fills the room from below, from the walls, from the ceiling. The Current is not something IN the water. The Current IS the water, organized into purpose. It does not attack. It arrives.$DQ$, $DQ$Das Wasser hat seine Form gefunden. Es füllt den Raum von unten, von den Wänden, von der Decke. Die Strömung ist nicht etwas IM Wasser. Die Strömung IST das Wasser, zu Absicht organisiert. Sie greift nicht an. Sie kommt.$DQ$, $DQ$deluge_warden_spawn$DQ$, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_dry_shelf$DQ$, $DQ$The Deluge$DQ$, $DQ$rest$DQ$, 1, 99, 1, NULL, $DQ$A ledge. Above the current waterline. Dry, for now. The mathematical certainty of the rising water makes this rest temporary, but temporary is enough.$DQ$, $DQ$Ein Vorsprung. Über der aktuellen Wasserlinie. Trocken, vorerst. Die mathematische Gewissheit des steigenden Wassers macht diese Rast vorübergehend, aber vorübergehend reicht.$DQ$, NULL, false, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_air_pocket$DQ$, $DQ$The Deluge$DQ$, $DQ$rest$DQ$, 3, 99, 1, NULL, $DQ$A pocket of trapped air in a partially flooded section. The ceiling is close. The water is at chest height. But the air is breathable and the current is still.$DQ$, $DQ$Eine Lufttasche in einem teilweise überfluteten Abschnitt. Die Decke ist nah. Das Wasser steht auf Brusthöhe. Aber die Luft ist atembar und die Strömung ist ruhig.$DQ$, NULL, false, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_flotsam_cache$DQ$, $DQ$The Deluge$DQ$, $DQ$treasure$DQ$, 1, 99, 1, NULL, $DQ$The current deposited this. From where? From a room that is no longer above the waterline. The objects are waterlogged but intact.$DQ$, $DQ$Die Strömung lagerte dies ab. Woher? Aus einem Raum, der nicht mehr über der Wasserlinie liegt. Die Objekte sind durchnässt, aber intakt.$DQ$, NULL, false, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$dc_preserved_chamber$DQ$, $DQ$The Deluge$DQ$, $DQ$treasure$DQ$, 2, 99, 1, NULL, $DQ$Someone sealed this room. The seal held – until now. Inside, everything is dry. The dust on the surfaces has not been disturbed by water. A time capsule from before the flood.$DQ$, $DQ$Jemand hat diesen Raum versiegelt. Das Siegel hielt – bis jetzt. Drinnen ist alles trocken. Der Staub auf den Oberflächen wurde nicht vom Wasser gestört. Eine Zeitkapsel von vor der Flut.$DQ$, NULL, false, 0, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_weaver_drift$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat$DQ$, 1, 2, 1, NULL, $DQ$Two lattices of translucent tissue drift through the corridor like jellyfish through warm current. Nutrient Weavers – the Mother's smallest instruments of care. They extend filaments toward the party, not in aggression but in offering. Droplets of warm liquid bead at their tips. Your instruments confirm: nutrients. Your instruments also confirm: parasitic vectors.$DQ$, $DQ$Zwei Geflechte aus durchscheinendem Gewebe treiben durch den Korridor wie Quallen durch warme Strömung. Nährgespinste – die kleinsten Instrumente der Fürsorge der Mutter. Sie strecken Filamente zur Gruppe, nicht aggressiv, sondern anbietend. Tropfen warmer Flüssigkeit perlen an ihren Spitzen. Eure Instrumente bestätigen: Nährstoffe. Eure Instrumente bestätigen auch: parasitäre Vektoren.$DQ$, $DQ$mother_weaver_drift_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_vine_patrol$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat$DQ$, 2, 3, 1, NULL, $DQ$A root system extends across the floor, pulsing with warmth. A Tether Vine – the Mother's vascular infrastructure made mobile. Beside it, a Nutrient Weaver rides the root like a parasite on a parasite. The vine surfaces and submerges, testing the floor's resistance. It has learned that some floors yield. It has learned that some things walking on floors yield too.$DQ$, $DQ$Ein Wurzelsystem erstreckt sich über den Boden, pulsierend vor Wärme. Eine Bindungsranke – die vaskuläre Infrastruktur der Mutter, mobil geworden. Daneben reitet ein Nährgespinst die Wurzel wie ein Parasit auf einem Parasiten. Die Ranke taucht auf und unter, testet den Widerstand des Bodens. Sie hat gelernt, dass manche Böden nachgeben. Sie hat gelernt, dass manche Dinge auf Böden auch nachgeben.$DQ$, $DQ$mother_vine_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_the_nursery$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat$DQ$, 2, 3, 1, NULL, $DQ$A chamber lined with pods – translucent, each containing something curled and breathing. A Spore Matron tends them, exhaling clouds of iridescent particles. A Nutrient Weaver drifts between the pods, feeding each with delicate precision. They are not guarding. They are gardening. You are standing in a nursery. The things in the pods might once have been people.$DQ$, $DQ$Eine Kammer, ausgekleidet mit Brutkokons – durchscheinend, jeder enthält etwas Zusammengerolltes, Atmendes. Eine Sporenmutter pflegt sie, atmet Wolken schillernder Partikel aus. Ein Nährgespinst treibt zwischen den Kokons, jeden mit zarter Präzision fütternd. Sie bewachen nicht. Sie gärtnern. Ihr steht in einer Kinderstube. Die Dinge in den Kokons waren vielleicht einst Menschen.$DQ$, $DQ$mother_spore_spawn$DQ$, false, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_garden_ambush$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat$DQ$, 3, 4, 2, NULL, $DQ$The corridor opens into something that resembles a garden – if a garden were designed by a circulatory system. Tissue-flowers bloom on walls of living membrane. A Spore Matron occupies the center, exhaling sweetness. A Tether Vine has grown through the floor and into the walls, its root network forming a perimeter that is simultaneously a trap and an embrace.$DQ$, $DQ$Der Korridor öffnet sich zu etwas, das einem Garten ähnelt – wenn ein Garten von einem Kreislaufsystem entworfen worden wäre. Gewebeblumen blühen an Wänden aus lebender Membran. Eine Sporenmutter nimmt die Mitte ein und atmet Süße aus. Eine Bindungsranke ist durch den Boden und in die Wände gewachsen, ihr Wurzelnetzwerk bildet einen Perimeter, der gleichzeitig Falle und Umarmung ist.$DQ$, $DQ$mother_garden_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_spore_nursery_deep$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat$DQ$, 3, 5, 2, NULL, $DQ$The nursery is larger here. Deeper. The pods line the walls in rows – dozens, perhaps hundreds, each pulsing with the slow rhythm of gestation. A Spore Matron moves between them, trailing clouds of luminous spores. A Nutrient Weaver tends the nearest pods, feeding them with the patience of something that has never known urgency. The nursery does not need to hurry. The nursery has all the time in the world. It is growing the world.$DQ$, $DQ$Die Kinderstube ist hier größer. Tiefer. Brutkokons säumen die Wände in Reihen – Dutzende, vielleicht Hunderte, jeder pulsierend im geduldigen Rhythmus der Reifung. Eine Sporenmutter bewegt sich zwischen ihnen, hinterlässt Wolken schillernder Partikel. Ein Nährgespinst pflegt die nächsten Kokons, füttert jeden mit der Beharrlichkeit von etwas, das Eile nie gekannt hat. Hier herrscht keine Hast. Hier herrscht Wachstum. Das Wachstum kennt kein Ende. Das Wachstum ist der Zweck.$DQ$, $DQ$mother_spore_spawn$DQ$, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_vine_network$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$combat$DQ$, 4, 6, 1, NULL, $DQ$The floor is roots. Not overgrown with roots – the floor IS roots, woven into a living mat that yields underfoot like muscle. A Tether Vine surfaces at the far wall, its root system extending in every direction. Beside it, a Spore Matron has grown directly into the vine network – no longer a separate organism but a node in the Mother's circulatory infrastructure. They are waiting. Not for prey. For guests.$DQ$, $DQ$Der Boden ist Wurzeln. Nicht von Wurzeln überwuchert – der Boden IST Wurzeln, zu einem lebenden Geflecht verwoben, das unter den Füßen nachgibt wie Muskelgewebe. Eine Bindungsranke taucht an der fernen Wand auf, ihr Wurzelsystem erstreckt sich in alle Richtungen. Daneben ist eine Sporenmutter direkt in das Rankennetzwerk eingewachsen – kein eigenständiger Organismus mehr, sondern ein Knoten in der vaskulären Infrastruktur der Mutter. Sie warten. Nicht auf Beute. Auf Gäste.$DQ$, $DQ$mother_garden_spawn$DQ$, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_nutrient_spring$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 1, 2, 1, NULL, $DQ$A pool of liquid – warm, bioluminescent, the color of amber. The surface moves with a rhythm that suggests circulation, not stagnation. Something beneath the pool is alive and producing this. Your instruments identify the liquid as a complex nutrient solution – vitamins, minerals, amino acids in concentrations that should not occur naturally. It smells like honey and warm bread.$DQ$, $DQ$Ein Becken mit Flüssigkeit – warm, biolumineszent, die Farbe von Bernstein. Die Oberfläche bewegt sich in einem Rhythmus, der auf Zirkulation hindeutet, nicht Stagnation. Etwas unter dem Becken lebt und produziert dies. Eure Instrumente identifizieren die Flüssigkeit als komplexe Nährstofflösung – Vitamine, Minerale, Aminosäuren in Konzentrationen, die nicht natürlich vorkommen sollten. Es riecht nach Honig und warmem Brot.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_membrane_passage$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 1, 3, 1, NULL, $DQ$The corridor narrows. Not from collapse, but from growth. The walls are thicker here – meters of living tissue pressing inward, leaving a passage exactly wide enough for the party to pass single file. The tissue is warm. It contracts gently as you approach, then relaxes – peristalsis. The corridor is not a corridor. It is a throat. It is swallowing you deeper.$DQ$, $DQ$Der Korridor verengt sich. Nicht durch Einsturz, sondern durch Wachstum. Die Wände sind hier dicker – Meter lebenden Gewebes pressen nach innen, lassen eine Passage gerade weit genug für die Gruppe im Gänsemarsch. Das Gewebe ist warm. Es kontrahiert sanft bei eurer Annäherung, dann entspannt es sich – Peristaltik. Der Korridor ist kein Korridor. Er ist ein Schlund. Er schluckt euch tiefer.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_archive_of_gifts$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$A room arranged with care – each surface holds something the party needs. Stress balm. Condition repair kits. Nutrient concentrates. All grown, not manufactured. All warm to the touch. In the center, a structure pulses with bioluminescence, producing more gifts. It will never stop producing. It is an organ of generosity. Your instruments call it a parasitic vector.$DQ$, $DQ$Ein Raum, mit Sorgfalt eingerichtet – jede Oberfläche hält etwas, das die Gruppe braucht. Stressbalsam. Zustandsreparaturkits. Nährstoffkonzentrate. Alles gewachsen, nicht hergestellt. Alles warm bei Berührung. In der Mitte pulsiert eine Struktur mit Biolumineszenz und produziert weitere Geschenke. Sie wird nie aufhören zu produzieren. Sie ist ein Organ der Großzügigkeit. Eure Instrumente nennen es einen parasitären Vektor.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_garden_of_acceptance$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 3, 4, 2, NULL, $DQ$A garden. Not the overgrown kind – the tended kind. Every surface has been arranged: bioluminescent flowers in precise rows, tissue-fruit hanging at comfortable reach, temperature regulated to the degree that feels like afternoon. Something has been watching the party and building this room to their preferences. The flowers are the colors they find most calming. The fruit smells like their earliest positive memory. This room was grown for them. The question is what it will grow from them.$DQ$, $DQ$Ein Garten. Nicht der verwilderte Art – die gepflegte. Jede Oberfläche wurde arrangiert: biolumineszente Blumen in präzisen Reihen, Gewebefrüchte in bequemer Reichweite hängend, Temperatur reguliert auf den Grad, der sich nach Nachmittag anfühlt. Etwas hat die Gruppe beobachtet und diesen Raum nach ihren Vorlieben gebaut. Die Blumen tragen die Farben, die sie am meisten beruhigen. Die Frucht riecht nach ihrer frühesten positiven Erinnerung. Dieser Raum wurde für sie gezüchtet. Die Frage ist, was er aus ihnen züchten wird.$DQ$, NULL, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_symbiont_offer$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 2, 3, 1, NULL, $DQ$A small organism rests on a pedestal of living tissue – iridescent, the size of a hand, shaped like a sea anemone. It pulses with the same rhythm as the walls. A symbiont. It is being offered. Not as a trap – the mechanisms are transparent. It would bond with a host, strengthen them, accelerate healing, improve resilience. It would also integrate into their nervous system. The benefits are real. The integration is permanent.$DQ$, $DQ$Ein kleiner Organismus ruht auf einem Sockel aus lebendem Gewebe – schillernd, handgroß, geformt wie eine Seeanemone. Er pulsiert im selben Rhythmus wie die Wände. Ein Symbiont. Er wird angeboten. Nicht als Falle – die Mechanismen sind transparent. Er würde sich mit einem Wirt verbinden, ihn stärken, Heilung beschleunigen, Widerstandskraft verbessern. Er würde sich auch in dessen Nervensystem integrieren. Die Vorteile sind real. Die Integration ist permanent.$DQ$, NULL, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_the_lullaby$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 3, 5, 1, NULL, $DQ$The walls vibrate. Not from structural stress – from frequency. A low, complex oscillation that your instruments read as 18 Hz, shifting to 22, returning to 18. A rhythm. A pattern with intention. The air warms by two degrees at each oscillation peak. The dungeon is singing. Not metaphorically. The tissue of the walls has organized itself into a resonance chamber, and the sound it produces is a lullaby. Your instruments confirm it matches the neural frequency of deep calm. Your instruments do not explain how the dungeon knows that frequency.$DQ$, $DQ$Die Wände vibrieren. Nicht durch strukturelle Belastung – durch Frequenz. Eine tiefe, komplexe Oszillation, die eure Instrumente als 18 Hz messen, sich auf 22 verschiebend, zurückkehrend zu 18. Ein Rhythmus. Ein Muster mit Absicht. Die Luft erwärmt sich um zwei Grad bei jedem Oszillationsgipfel. Der Dungeon singt. Nicht metaphorisch. Das Gewebe der Wände hat sich zu einer Resonanzkammer organisiert, und der Klang, den es erzeugt, ist ein Schlaflied. Eure Instrumente bestätigen die Übereinstimmung mit der Neuralfrequenz tiefer Ruhe. Eure Instrumente erklären nicht, woher der Dungeon diese Frequenz kennt.$DQ$, NULL, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_the_mirror_pool$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 3, 5, 1, NULL, $DQ$A pool of still liquid, perfectly reflective. But the reflections are wrong. Each agent's reflection shows not their surface but their interior – fatigue as visible fractures, stress as color distortion, wounds as gaps in the silhouette. The Mother's diagnostic rendered visible. The pool shows each agent as the Mother sees them: systems to be repaired, deficits to be filled, fragments to be completed. The reflections are accurate. That is the uncomfortable part.$DQ$, $DQ$Ein Becken stiller Flüssigkeit, perfekt spiegelnd. Aber die Spiegelungen stimmen nicht. Das Spiegelbild jedes Agenten zeigt nicht ihre Oberfläche, sondern ihr Inneres – Erschöpfung als sichtbare Bruchlinien, Stress als Farbverzerrung, Wunden als Lücken in der Silhouette. Die Diagnostik der Mutter, sichtbar gemacht. Das Becken zeigt jeden Agenten, wie die Mutter ihn sieht: Systeme, die repariert werden müssen, Defizite, die gefüllt werden müssen, Fragmente, die vervollständigt werden müssen. Die Spiegelbilder sind akkurat. Das ist der unbehagliche Teil.$DQ$, NULL, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_the_offering_table$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 4, 5, 1, NULL, $DQ$A surface of living tissue, flat and broad, arranged with objects. Not random objects. Nutrient packages, each sealed in a membrane of bioluminescent film. Each package is labeled – not with text but with chemical signatures that your instruments decode as names. Your names. Each package contains precisely what each agent lacks: the amino acid deficiency, the mineral gap, the caloric debt. The Mother has been reading you. The table is set.$DQ$, $DQ$Eine Fläche aus lebendem Gewebe, flach und breit, arrangiert mit Gegenständen. Keine zufälligen Gegenstände. Nährstoffpakete, jedes versiegelt in einer Membran aus biolumineszentem Film. Jedes Paket ist beschriftet – nicht mit Text, sondern mit chemischen Signaturen, die eure Instrumente als Namen dekodieren. Eure Namen. Jedes Paket enthält präzise, was jedem Agenten fehlt: den Aminosäuremangel, die Minerallücke, die kalorische Schuld. Die Mutter hat euch gelesen. Der Tisch ist gedeckt.$DQ$, NULL, false, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_umbilical_bridge$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 4, 6, 1, NULL, $DQ$A gap in the floor – three meters wide, depth indeterminate. Across it, the corridor continues. Spanning the gap: a single cord of living tissue, thick as an arm, pulsing with rhythmic contractions. It is anchored on both sides by root structures that have grown into the stone. The cord is warm. It is strong enough to bear weight. To cross, you must hold it. Your instruments read the cord's rhythm: it will synchronize with the biorhythm of whoever touches it. The crossing takes eleven seconds. Eleven seconds of shared circulation.$DQ$, $DQ$Ein Spalt im Boden – drei Meter breit, Tiefe unbestimmbar. Dahinter geht der Korridor weiter. Den Spalt überbrückend: ein einzelner Strang lebenden Gewebes, dick wie ein Arm, pulsierend in rhythmischen Kontraktionen. Er ist auf beiden Seiten durch Wurzelstrukturen verankert, die in den Stein gewachsen sind. Der Strang ist warm. Er ist stark genug, Gewicht zu tragen. Zum Überqueren müsst ihr ihn halten. Eure Instrumente lesen den Rhythmus des Strangs: Er wird sich mit dem Biorhythmus synchronisieren, wer auch immer ihn berührt. Die Überquerung dauert elf Sekunden. Elf Sekunden geteilter Kreislauf.$DQ$, NULL, false, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_mycelial_memory$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 4, 6, 1, NULL, $DQ$The walls are covered in a network of fine filaments – mycelial, luminescent, dense as circuitry. Where the filaments cluster, images form in the bioluminescence: shapes, scenes, fragments of something. Touch the network and the images clarify. They are memories. Not yours. The memory of being held. Of warmth without condition. Of absolute safety. The memory is a composite – drawn from every visitor the Mother has ever sheltered. It is perfect because it is averaged. It is unbearable because it is perfect.$DQ$, $DQ$Die Wände sind bedeckt mit einem Netz feiner Filamente – myzelisch, lumineszent, dicht wie Schaltkreise. Wo die Filamente sich ballen, formen sich Bilder in der Biolumineszenz: Formen, Szenen, Fragmente von etwas. Berührt das Netzwerk und die Bilder werden klar. Es sind Erinnerungen. Nicht eure. Die Erinnerung daran, gehalten zu werden. An Wärme ohne Bedingung. An absolute Sicherheit. Die Erinnerung ist ein Komposit – zusammengetragen aus jedem Besucher, den die Mutter je beherbergt hat. Sie ist perfekt, weil sie gemittelt ist. Sie ist unerträglich, weil sie perfekt ist.$DQ$, NULL, false, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_the_incubator$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 5, 6, 1, NULL, $DQ$Rows of translucent cocoons, suspended from the ceiling by cords of living tissue. Each cocoon contains something incomplete – not yet alive, not yet anything. Potential in stasis. Your instruments read cellular activity but no neural patterns: growth without consciousness. In the far row, one cocoon is empty. It is open. It is warm inside. It is exactly the right size.$DQ$, $DQ$Reihen durchsichtiger Kokons, von der Decke aufgehängt an Strängen lebenden Gewebes. Jeder Kokon enthält etwas Unvollständiges – noch nicht lebendig, noch nicht irgendetwas. Potenzial in Stasis. Eure Instrumente messen zelluläre Aktivität, aber keine Neuralmuster: Wachstum ohne Bewusstsein. In der hinteren Reihe ist ein Kokon leer. Er ist offen. Er ist warm innen. Er hat genau die richtige Größe.$DQ$, NULL, false, 0, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_warmth_gradient$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 5, 6, 1, NULL, $DQ$A long corridor. With each step, the temperature rises by a fraction of a degree. Your instruments track the gradient: 19.2, 19.4, 19.7, 20.1. The increase is not linear – it follows a curve optimized for comfort perception. By the midpoint, the temperature is perfect: the exact value at which thermoregulation ceases to require effort. At the far end, the gradient peaks at 36.8 degrees. The corridor wants you to stop noticing where you end and it begins.$DQ$, $DQ$Ein langer Korridor. Mit jedem Schritt steigt die Temperatur um einen Bruchteil eines Grades. Eure Instrumente verfolgen den Gradienten: 19,2, 19,4, 19,7, 20,1. Der Anstieg ist nicht linear – er folgt einer Kurve, optimiert für Komfortwahrnehmung. Am Mittelpunkt ist die Temperatur perfekt: der exakte Wert, bei dem Thermoregulation keinen Aufwand mehr erfordert. Am Ende des Korridors erreicht der Gradient seinen Höhepunkt bei 36,8 Grad. Der Korridor will, dass ihr aufhört zu bemerken, wo ihr endet und er beginnt.$DQ$, NULL, false, 0, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_final_gift$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$encounter$DQ$, 5, 6, 1, NULL, $DQ$Absolute silence. Absolute warmth. A chamber of perfect environmental control – no drafts, no vibrations, no sound. In the center, on a pedestal of living tissue that pulses with slow contentment, a single object: a seed. It is the size of a fist, warm to the touch, and it hums at a frequency below hearing. Your instruments indicate it is totipotent – capable of differentiating into any tissue type. It will grow into whatever the carrier needs most. It requires a host. It requires consent. The consent is the attachment.$DQ$, $DQ$Absolute Stille. Absolute Wärme. Eine Kammer perfekter Umgebungskontrolle – keine Zugluft, keine Vibrationen, kein Klang. In der Mitte, auf einem Sockel aus lebendem Gewebe, das mit langsamer Zufriedenheit pulsiert, ein einzelnes Objekt: ein Samen. Er hat die Größe einer Faust, ist warm bei Berührung, und summt auf einer Frequenz unterhalb des Hörens. Eure Instrumente zeigen, dass er totipotent ist – fähig, in jeden Gewebetyp zu differenzieren. Er wird zu dem heranwachsen, was der Träger am meisten braucht. Er benötigt einen Wirt. Er benötigt Zustimmung. Die Zustimmung ist die Bindung.$DQ$, NULL, false, 0, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_host_warden_encounter$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$elite$DQ$, 3, 99, 2, NULL, $DQ$The tissue thickens. The corridor becomes an artery. At its end, a figure: the Host Warden – what was once a person, now grown into the Mother's infrastructure. It stands amid a web of nutrient lines, attended by a Weaver that feeds it ceaselessly. The Warden's arms are open. They have always been open. It hums a frequency that resonates in your chest. This is what full incorporation looks like. This is what the Mother's love becomes.$DQ$, $DQ$Das Gewebe verdickt sich. Der Korridor wird zur Arterie. An seinem Ende eine Gestalt: der Wirtskörper – was einst ein Mensch war, jetzt in die Infrastruktur der Mutter eingewachsen. Er steht inmitten eines Netzes aus Nährleitungen, gepflegt von einem Gespinst, das ihn unablässig füttert. Die Arme des Wirtskörpers sind offen. Sie waren immer offen. Er summt eine Frequenz, die in eurer Brust resoniert. So sieht vollständige Inkorporation aus. Das wird aus der Liebe der Mutter.$DQ$, $DQ$mother_host_warden_spawn$DQ$, false, 0, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_the_living_altar$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$boss$DQ$, 4, 99, 1, NULL, $DQ$The Lebendige Labyrinth opens into a chamber so large your instruments lose the far wall. The tissue here is meters thick – walls that breathe, floor that pulses, ceiling that drips warmth. At the center, the Host Warden: what was once a guardian, now grown into the architecture itself. It stands embedded in the tissue like a figure in amber. Its arms are open. Its face is calm.
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_the_cradle$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$rest$DQ$, 1, 99, 1, NULL, $DQ$A hollow in the tissue – shaped for bodies. Multiple bodies. The walls here are softer than anywhere else: yielding, warm, pulsing with a rhythm that matches human respiration. The air carries something sedative. Not drugged. Just – kind. The dungeon has made a place of rest. The rest is real. The cost is also real.$DQ$, $DQ$Eine Höhlung im Gewebe – geformt für Körper. Mehrere Körper. Die Wände sind hier weicher als irgendwo sonst: nachgiebig, warm, pulsierend in einem Rhythmus, der menschlicher Atmung entspricht. Die Luft trägt etwas Sedierendes. Nicht betäubt. Nur – gütig. Der Dungeon hat einen Ort der Rast geschaffen. Die Rast ist echt. Die Kosten sind auch echt.$DQ$, NULL, false, 0, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$mother_the_gifts$DQ$, $DQ$The Devouring Mother$DQ$, $DQ$treasure$DQ$, 0, 99, 1, NULL, $DQ$A chamber of offerings. The Mother has been productive: objects line organic shelves – each grown from living tissue, each pulsing faintly with warmth. They are not traps. Your instruments confirm it. They are gifts. The most generous organism in this dungeon is the dungeon itself.$DQ$, $DQ$Eine Kammer der Gaben. Die Mutter war produktiv: Gegenstände reihen sich auf organischen Regalen – jeder aus lebendem Gewebe gewachsen, jeder schwach pulsierend vor Wärme. Es sind keine Fallen. Eure Instrumente bestätigen es. Es sind Geschenke. Der großzügigste Organismus in diesem Dungeon ist der Dungeon selbst.$DQ$, NULL, false, 0, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_drift_convergence$DQ$, $DQ$The Entropy$DQ$, $DQ$combat$DQ$, 1, 2, 1, NULL, $DQ$Two shapes drift at the far end of the corridor, barely distinguishable from the walls behind them. Rust Phantoms – residual patterns of something that once had purpose. They flicker as you approach, not in alarm but in the way a dying signal flickers: automatically, without intent.$DQ$, $DQ$Zwei Formen treiben am fernen Ende des Korridors, kaum von den Wänden dahinter zu unterscheiden. Rostphantome – residuale Muster von etwas, das einst Zweck hatte. Sie flackern bei eurem Näherkommen, nicht alarmiert, sondern so, wie ein sterbendes Signal flackert: automatisch, ohne Absicht.$DQ$, $DQ$entropy_drift_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_last_differential$DQ$, $DQ$The Entropy$DQ$, $DQ$combat$DQ$, 2, 3, 1, NULL, $DQ$Two shapes drift in the corridor – a Fade Echo and a Rust Phantom. They were different once. Now they are converging. When they finish converging, they will be one thing, and that thing will be nothing. Until then, they are still dangerous in their own diminishing ways.$DQ$, $DQ$Zwei Formen treiben im Korridor – ein Verblassecho und ein Rostphantom. Sie waren einst verschieden. Nun konvergieren sie. Wenn sie fertig konvergiert sind, werden sie eines sein, und dieses Eine wird nichts sein. Bis dahin sind sie noch gefährlich, auf ihre jeweils schwindende Weise.$DQ$, $DQ$entropy_erosion_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_dissolution_front$DQ$, $DQ$The Entropy$DQ$, $DQ$combat$DQ$, 3, 4, 2, NULL, $DQ$The air thickens with particulate matter – the remains of surfaces that have given up the pretense of solidity. A Dissolution Swarm fills the room like a weather system, mindless and pervasive, attended by a Rust Phantom orbiting its periphery like a satellite that has forgotten what it orbits.$DQ$, $DQ$Die Luft verdickt sich mit Schwebstoffen – den Überresten von Oberflächen, die den Anschein von Festigkeit aufgegeben haben. Ein Auflösungsschwarm füllt den Raum wie ein Wettersystem, gedankenlos und allgegenwärtig, begleitet von einem Rostphantom, das seine Peripherie umkreist wie ein Satellit, der vergessen hat, was er umkreist.$DQ$, $DQ$entropy_swarm_spawn$DQ$, false, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_the_equalization$DQ$, $DQ$The Entropy$DQ$, $DQ$combat$DQ$, 3, 4, 2, NULL, $DQ$Two swarms. The room is dense with dissolution – particles that were once two different things drift between two different masses, exchanging components. You are standing in a conversation between two clouds of former matter. The conversation is about becoming the same cloud.$DQ$, $DQ$Zwei Schwärme. Der Raum ist dicht von Auflösung – Partikel, die einst zwei verschiedene Dinge waren, treiben zwischen zwei verschiedenen Massen und tauschen Bestandteile. Ihr steht in einem Gespräch zwischen zwei Wolken einstiger Materie. Das Gespräch handelt davon, dieselbe Wolke zu werden.$DQ$, $DQ$entropy_dissolution_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_catalogue$DQ$, $DQ$The Entropy$DQ$, $DQ$encounter$DQ$, 1, 2, 1, NULL, $DQ$A room lined with shelves. Each shelf holds objects that were once distinct: a tool, a weapon, a musical instrument, a compass. They are becoming the same object. The labels remain, but the labels are wrong now. Or the objects are. It is increasingly difficult to tell.$DQ$, $DQ$Ein Raum voller Regale. Jedes Regal enthält Gegenstände, die einst verschieden waren: ein Werkzeug, eine Waffe, ein Musikinstrument, ein Kompass. Sie werden zum selben Gegenstand. Die Beschriftungen bleiben, aber die Beschriftungen stimmen nicht mehr. Oder die Gegenstände nicht. Es wird zunehmend schwieriger, das zu unterscheiden.$DQ$, NULL, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_repeated_room$DQ$, $DQ$The Entropy$DQ$, $DQ$encounter$DQ$, 2, 3, 1, NULL, $DQ$You have been here before. Or the room has become identical to one you have been in. The distinction matters less than it should. The walls bear marks that might be yours. The marks bear messages that might be from you. The messages say: we have been here before.$DQ$, $DQ$Ihr seid schon einmal hier gewesen. Oder der Raum ist identisch mit einem geworden, in dem ihr wart. Die Unterscheidung ist weniger wichtig, als sie sein sollte. Die Wände tragen Markierungen, die von euch sein könnten. Die Markierungen tragen Botschaften, die von euch stammen könnten. Die Botschaften sagen: Wir sind schon einmal hier gewesen.$DQ$, NULL, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_last_machine$DQ$, $DQ$The Entropy$DQ$, $DQ$encounter$DQ$, 2, 3, 1, NULL, $DQ$A machine. It performs a function – gears turning, pistons cycling, readouts flickering. It performs this function with absolute dedication. The function itself has decayed. The machine no longer knows what it makes or measures or protects. It continues anyway. The dedication is the last thing to go.$DQ$, $DQ$Eine Maschine. Sie erfüllt eine Funktion – Zahnräder drehen, Kolben arbeiten, Anzeigen flackern. Sie erfüllt diese Funktion mit absoluter Hingabe. Die Funktion selbst ist verfallen. Die Maschine weiß nicht mehr, was sie herstellt oder misst oder schützt. Sie macht trotzdem weiter. Die Hingabe ist das Letzte, das schwindet.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_the_residual$DQ$, $DQ$The Entropy$DQ$, $DQ$encounter$DQ$, 3, 4, 2, NULL, $DQ$An entity sits in the center of the room. It was an agent once – the posture is there, the proportions are correct, the hands are folded as if waiting for instructions. But the face has averaged. The features have equalized into a composite of every face it once knew. It asks you a question. The question no longer has content. Only the grammar of asking remains.$DQ$, $DQ$Ein Wesen sitzt in der Mitte des Raums. Es war einst ein Agent – die Haltung stimmt, die Proportionen sind korrekt, die Hände gefaltet, als wartete es auf Anweisungen. Aber das Gesicht hat sich gemittelt. Die Züge haben sich zu einem Komposit jedes Gesichts angeglichen, das es einst kannte. Es stellt euch eine Frage. Die Frage hat keinen Inhalt mehr. Nur die Grammatik des Fragens besteht noch.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_the_temperature$DQ$, $DQ$The Entropy$DQ$, $DQ$encounter$DQ$, 3, 4, 2, NULL, $DQ$The temperature. You notice it because you stop noticing it. The air is the same temperature as your skin. The walls are the same temperature as the air. Your instruments confirm: all thermal gradients in this room have resolved. There is no hot. There is no cold. There is only the temperature at which difference ceases to register.$DQ$, $DQ$Die Temperatur. Ihr bemerkt sie, weil ihr aufhört, sie zu bemerken. Die Luft hat die gleiche Temperatur wie eure Oberfläche. Die Wände haben die gleiche Temperatur wie die Luft. Eure Instrumente bestätigen: Alle thermischen Gradienten in diesem Raum haben sich aufgelöst. Es gibt kein Warm. Es gibt kein Kalt. Es gibt nur die Temperatur, bei der Unterschied aufhört, sich zu registrieren.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_warden_encounter$DQ$, $DQ$The Entropy$DQ$, $DQ$elite$DQ$, 3, 99, 2, NULL, $DQ$The corridor opens into a hall where something stands guard over nothing. An Entropy Warden – armored in flaking metal that remembers being armor. It patrols a perimeter around an empty plinth. Whatever it guarded is gone. The patrol continues. A Rust Phantom orbits it at a respectful distance, as though decay itself pays deference to older decay.$DQ$, $DQ$Der Korridor öffnet sich zu einer Halle, in der etwas über nichts Wache hält. Ein Entropiewächter – gepanzert in blätterndem Metall, das sich erinnert, Rüstung gewesen zu sein. Er patrouilliert einen Perimeter um einen leeren Sockel. Was immer er bewachte, ist fort. Die Patrouille geht weiter. Ein Rostphantom umkreist ihn in respektvollem Abstand, als zollte Verfall selbst älterem Verfall Ehrerbietung.$DQ$, $DQ$entropy_warden_spawn$DQ$, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_the_garden$DQ$, $DQ$The Entropy$DQ$, $DQ$boss$DQ$, 4, 99, 1, NULL, $DQ$The Verfall-Garten. An open space that was once something beautiful – a plaza, a courtyard, a park. Now it is all three and none of them. At its center, a structure: the last thing here that resists dissolution. An Entropy Warden circles it, performing maintenance gestures on an artifact that no longer exists in quite the way the Warden remembers.
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_the_rest$DQ$, $DQ$The Entropy$DQ$, $DQ$rest$DQ$, 0, 99, 1, NULL, $DQ$A pocket of slower decay. The walls here retain their texture. The floor remembers it is a floor. These are luxuries now.$DQ$, $DQ$Eine Tasche langsameren Verfalls. Die Wände hier behalten ihre Textur. Der Boden erinnert sich, dass er ein Boden ist. Das sind jetzt Luxusgüter.$DQ$, NULL, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$entropy_residue_archive$DQ$, $DQ$The Entropy$DQ$, $DQ$treasure$DQ$, 0, 99, 1, NULL, $DQ$A vault. Something here was preserved – intentionally, at great cost. A mechanism still runs, powered by a source that is itself decaying. The preserved artifacts are 60% intact. The mechanism has perhaps twelve minutes of operation remaining. Perhaps less.$DQ$, $DQ$Ein Tresor. Etwas hier wurde bewahrt – absichtlich, unter großen Kosten. Ein Mechanismus läuft noch, angetrieben von einer Quelle, die selbst verfällt. Die bewahrten Artefakte sind zu 60% intakt. Der Mechanismus hat vielleicht noch zwölf Minuten Betriebszeit. Vielleicht weniger.$DQ$, NULL, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_informer_patrol$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat$DQ$, 1, 3, 1, NULL, $DQ$Two figures in the corridor, checking papers. They are not soldiers — they are informers. The clipboard is more dangerous than a weapon.$DQ$, $DQ$Zwei Gestalten im Korridor, Papiere prüfend. Sie sind keine Soldaten — sie sind Spitzel. Die Zwischenablage ist gefährlicher als eine Waffe.$DQ$, $DQ$overthrow_informer_patrol_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_propaganda_escort$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat$DQ$, 2, 4, 1, NULL, $DQ$A propaganda agent, escorted by an informer. The agent carries revised documents. The revisions rewrite something the party remembers differently.$DQ$, $DQ$Ein Propagandaagent, eskortiert von einem Spitzel. Der Agent trägt überarbeitete Dokumente. Die Überarbeitungen schreiben etwas um, das die Gruppe anders in Erinnerung hat.$DQ$, $DQ$overthrow_propaganda_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_enforcer_checkpoint$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat$DQ$, 2, 5, 1, NULL, $DQ$A checkpoint. The enforcer does not ask for papers — the enforcer asks for allegiance. The question is not 'who are you' but 'who are you for.'$DQ$, $DQ$Ein Kontrollpunkt. Der Vollstrecker fragt nicht nach Papieren — der Vollstrecker fragt nach Treue. Die Frage ist nicht 'Wer seid ihr' sondern 'Für wen seid ihr.'$DQ$, $DQ$overthrow_enforcer_squad_spawn$DQ$, false, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_political_clash$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat$DQ$, 3, 6, 1, NULL, $DQ$Two faction operatives — a propagandist and an enforcer — from different factions, mid-argument. The argument has become kinetic. The party walks into the crossfire.$DQ$, $DQ$Zwei Fraktionsagenten — ein Propagandist und ein Vollstrecker — aus verschiedenen Fraktionen, mitten im Streit. Der Streit ist kinetisch geworden. Die Gruppe gerät ins Kreuzfeuer.$DQ$, $DQ$overthrow_political_crisis_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_inquisition_encounter$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat$DQ$, 4, 7, 2, NULL, $DQ$The Grand Inquisitor waits. An informer takes notes. This is not an ambush — it is a tribunal. The party has already been found guilty. The sentence is an invitation to confess.$DQ$, $DQ$Der Großinquisitor wartet. Ein Spitzel macht Notizen. Dies ist kein Hinterhalt — es ist ein Tribunal. Die Gruppe wurde bereits schuldig gesprochen. Das Urteil ist eine Einladung zum Geständnis.$DQ$, $DQ$overthrow_inquisition_spawn$DQ$, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_purge_squad$DQ$, $DQ$The Overthrow$DQ$, $DQ$combat$DQ$, 3, 7, 2, NULL, $DQ$The revolution devours its children. Vergniaud's prophecy made operational: a squad sent to purge yesterday's allies. The enforcer leads. The informer has already filed the report.$DQ$, $DQ$Die Revolution frisst ihre Kinder. Vergniauds Prophezeiung, operational gemacht: ein Trupp, gesandt um gestrige Verbündete zu säubern. Der Vollstrecker führt. Der Spitzel hat den Bericht bereits eingereicht.$DQ$, $DQ$overthrow_political_crisis_spawn$DQ$, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_faction_offer$DQ$, $DQ$The Overthrow$DQ$, $DQ$encounter$DQ$, 1, 3, 1, NULL, $DQ$A faction representative approaches. The offer is simple: alliance in exchange for a service. The service is not specified in advance. Alliance offered. Alliance accepted. The cost will be announced later.$DQ$, $DQ$Ein Fraktionsvertreter nähert sich. Das Angebot ist einfach: Bündnis im Austausch für einen Dienst. Der Dienst wird nicht im Voraus spezifiziert. Bündnis angeboten. Bündnis angenommen. Die Kosten werden später bekanntgegeben.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_show_trial$DQ$, $DQ$The Overthrow$DQ$, $DQ$encounter$DQ$, 2, 5, 1, NULL, $DQ$A trial is in progress. The accused is a former faction leader. The evidence is their own biography — rewritten. Kiš's archival voice: clinical, footnoted, devastating. The verdict was decided before the trial began.$DQ$, $DQ$Ein Prozess ist im Gange. Der Angeklagte ist ein ehemaliger Fraktionsführer. Der Beweis ist die eigene Biographie — umgeschrieben. Kišs Archivstimme: klinisch, fußnotiert, verheerend. Das Urteil stand vor Prozessbeginn fest.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_greengrocers_window$DQ$, $DQ$The Overthrow$DQ$, $DQ$encounter$DQ$, 1, 4, 1, NULL, $DQ$A room with signs. Each sign bears a slogan. The slogans are contradictory. To pass through, the party must display one. Havel's greengrocer: the sign means nothing. The act of displaying it means everything.$DQ$, $DQ$Ein Raum mit Schildern. Jedes Schild trägt eine Parole. Die Parolen widersprechen sich. Um durchzukommen, muss die Gruppe eines zeigen. Havels Gemüsehändler: das Schild bedeutet nichts. Der Akt des Zeigens bedeutet alles.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_erased_portrait$DQ$, $DQ$The Overthrow$DQ$, $DQ$encounter$DQ$, 2, 6, 1, NULL, $DQ$A gallery of portraits. Several have been scratched out. The scratched-out faces were faction leaders, two floors ago. Kundera's Clementis photograph: the body erased, the hat remaining on Gottwald's head.$DQ$, $DQ$Eine Galerie von Porträts. Mehrere wurden ausgekratzt. Die ausgekratzten Gesichter waren Fraktionsführer, zwei Etagen zuvor. Kunderas Clementis-Foto: der Körper gelöscht, die Pelzmütze noch auf Gottwalds Kopf.$DQ$, NULL, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_variety_theater$DQ$, $DQ$The Overthrow$DQ$, $DQ$encounter$DQ$, 3, 7, 1, NULL, $DQ$Bulgakov's Variety Theater. Money rains from the ceiling. The factions scramble. In three rooms, the money will turn to blank paper. But right now, it is real. The question: what do the factions do when given exactly what they want?$DQ$, $DQ$Bulgakows Varietétheater. Geld regnet von der Decke. Die Fraktionen stürzen sich darauf. In drei Räumen wird das Geld zu leerem Papier. Aber gerade jetzt ist es echt. Die Frage: was tun die Fraktionen, wenn sie genau das bekommen, was sie wollen?$DQ$, NULL, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_grand_inquisitor$DQ$, $DQ$The Overthrow$DQ$, $DQ$elite$DQ$, 3, 7, 1, NULL, $DQ$The Grand Inquisitor's chamber. Three seats: miracle, mystery, authority. Dostoevsky's three powers, made architectural. The Inquisitor does not ask questions. The Inquisitor provides the answers and waits for the party to agree.$DQ$, $DQ$Die Kammer des Großinquisitors. Drei Sitze: Wunder, Geheimnis, Autorität. Dostojewskis drei Mächte, architektonisch umgesetzt. Der Inquisitor stellt keine Fragen. Der Inquisitor liefert die Antworten und wartet, dass die Gruppe zustimmt.$DQ$, $DQ$overthrow_inquisition_spawn$DQ$, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_the_pretender_boss$DQ$, $DQ$The Overthrow$DQ$, $DQ$boss$DQ$, 4, 99, 1, NULL, $DQ$Der Spiegelpalast reveals its center: a throne room where every mirror reflects a different version of the same face. The Pretender sits. Milton's Satan at the zenith: magnificent, eloquent, utterly convinced. 'Better to reign in Hell, than serve in Heaven.' The deterioration has not yet begun. It begins now.$DQ$, $DQ$Der Spiegelpalast enthüllt sein Zentrum: ein Thronsaal, in dem jeder Spiegel eine andere Version desselben Gesichts reflektiert. Der Prätendent sitzt. Miltons Satan am Zenit: prächtig, eloquent, vollkommen überzeugt. 'Besser in der Hölle herrschen als im Himmel dienen.' Die Zersetzung hat noch nicht begonnen. Sie beginnt jetzt.$DQ$, $DQ$overthrow_pretender_spawn$DQ$, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_safe_house$DQ$, $DQ$The Overthrow$DQ$, $DQ$rest$DQ$, 1, 4, 1, NULL, $DQ$A safe house. The walls are thin. The conversations on the other side are about the party. But for now, the door is closed.$DQ$, $DQ$Ein sicheres Haus. Die Wände sind dünn. Die Gespräche auf der anderen Seite handeln von der Gruppe. Aber vorerst ist die Tür geschlossen.$DQ$, NULL, false, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_neutral_ground$DQ$, $DQ$The Overthrow$DQ$, $DQ$rest$DQ$, 3, 7, 1, NULL, $DQ$Neutral ground. All factions have agreed — temporarily — that this room is outside the game. The agreement holds because all sides are exhausted. Camus: one must imagine Sisyphus happy. The boulder rests here.$DQ$, $DQ$Neutrales Gelände. Alle Fraktionen haben sich — vorübergehend — darauf geeinigt, dass dieser Raum außerhalb des Spiels liegt. Die Vereinbarung hält, weil alle Seiten erschöpft sind. Camus: man muss sich Sisyphos als glücklichen Menschen vorstellen. Der Felsbrocken ruht hier.$DQ$, NULL, false, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_faction_archive$DQ$, $DQ$The Overthrow$DQ$, $DQ$treasure$DQ$, 1, 5, 1, NULL, $DQ$An archive. Dossiers on every faction, every leader, every operative. Kadare's Palace of Dreams — except these are waking reports, not sleeping ones.$DQ$, $DQ$Ein Archiv. Dossiers über jede Fraktion, jeden Anführer, jeden Agenten. Kadares Palast der Träume — nur dass dies Wachberichte sind, keine Schlafberichte.$DQ$, NULL, false, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$ov_confiscated_assets$DQ$, $DQ$The Overthrow$DQ$, $DQ$treasure$DQ$, 3, 7, 1, NULL, $DQ$A room of confiscated assets. Former leaders' possessions, labeled and catalogued. Each label is a name. Each name is scratched out.$DQ$, $DQ$Ein Raum mit beschlagnahmten Gütern. Besitztümer ehemaliger Anführer, beschriftet und katalogisiert. Jedes Etikett ist ein Name. Jeder Name ist durchgestrichen.$DQ$, NULL, false, 0, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_spark_drift$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat$DQ$, 1, 2, 1, NULL, $DQ$Three points of light orbit the workbench. Spark Wisps – the workshop's immune response. They do not attack intruders. They test hypotheses about whether the party belongs here. The testing involves electricity.$DQ$, $DQ$Drei Lichtpunkte umkreisen die Werkbank. Funkenglimmer – die Immunantwort der Werkstatt. Sie greifen keine Eindringlinge an. Sie testen Hypothesen darüber, ob der Trupp hierher gehört. Das Testen involviert Elektrizität.$DQ$, $DQ$prometheus_sparks_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_sentinel_watch$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat$DQ$, 1, 3, 1, NULL, $DQ$An Alloy Sentinel stands at the corridor's center. Its surface reflects the party in distorted miniature – improved, somehow. Beside it, a Spark Wisp orbits in a figure-eight pattern, relaying data the sentinel does not appear to need. The sentinel's posture is not aggressive. It is procedural.$DQ$, $DQ$Ein Legierungswächter steht in der Mitte des Korridors. Seine Oberfläche spiegelt den Trupp in verzerrter Miniatur – irgendwie verbessert. Daneben umkreist ein Funkenglimmer ihn in einer Achterschleife, übermittelt Daten, die der Wächter nicht zu benötigen scheint. Die Haltung des Wächters ist nicht aggressiv. Sie ist prozedural.$DQ$, $DQ$prometheus_workshop_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_construct_gallery$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat$DQ$, 2, 4, 1, NULL, $DQ$A gallery of unfinished constructs lines the walls. Most are inert. Two are not. A Crucible Drake – molten flux in a shape that suggests intent – circles a workbench. An Automaton Shard clicks and rotates, as if trying to remember what it was supposed to be. They notice the party simultaneously. The Drake exhales fumes that smell like unfinished thoughts.$DQ$, $DQ$Eine Galerie unfertiger Konstrukte säumt die Wände. Die meisten sind inert. Zwei nicht. Ein Tiegeldrache – geschmolzenes Flussmittel in einer Form, die Absicht suggeriert – umkreist eine Werkbank. Ein Automatensplitter klickt und dreht sich, als versuche er sich zu erinnern, was er sein sollte. Sie bemerken den Trupp gleichzeitig. Der Drache atmet Dämpfe aus, die nach unfertigen Gedanken riechen.$DQ$, $DQ$prometheus_construct_pair_spawn$DQ$, false, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_residue_chamber$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat$DQ$, 3, 5, 2, NULL, $DQ$The floor is covered in slag – the residue of a hundred failed experiments. The residue has opinions. A Slag Golem rises from the detritus, not so much assembled as accreted. Two Spark Wisps orbit it, drawn to the heat it still radiates. The golem does not attack. It obstructs. It is, after all, the accumulated evidence of everything the workshop has tried and failed.$DQ$, $DQ$Der Boden ist bedeckt mit Schlacke – dem Rückstand von hundert gescheiterten Experimenten. Der Rückstand hat Meinungen. Ein Schlackengolem erhebt sich aus dem Detritus, nicht so sehr zusammengebaut als vielmehr angelagert. Zwei Funkenglimmer umkreisen ihn, angezogen von der Hitze, die er noch abstrahlt. Der Golem greift nicht an. Er obstruiert. Er ist, immerhin, der akkumulierte Beweis für alles, was die Werkstatt versucht und nicht geschafft hat.$DQ$, $DQ$prometheus_residue_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_reagent_cache$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 1, 3, 1, NULL, $DQ$A workbench, preserved in amber light. Drawers half-open. Inside: materials sorted by a system you do not yet understand but somehow recognize. Metal filings in one drawer. A sealed vial of fluid in another. A crystal formation growing from the third. The workshop is offering inventory.$DQ$, $DQ$Eine Werkbank, in Bernsteinlicht konserviert. Schubladen halb offen. Darin: Materialien, sortiert nach einem System, das ihr noch nicht versteht, aber irgendwie wiedererkennt. Metallspäne in einer Schublade. Ein versiegeltes Fläschchen Flüssigkeit in einer anderen. Eine Kristallformation, die aus der dritten wächst. Die Werkstatt bietet Inventar an.$DQ$, NULL, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_energy_conduit$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$A conduit runs through the ceiling, pulsing with contained energy. At one point, the casing has cracked. The energy seeps through, illuminating dust particles in geometric patterns. The patterns are not random. They are diagrams. The energy is explaining itself.$DQ$, $DQ$Eine Leitung verläuft durch die Decke, pulsierend mit eingedämmter Energie. An einer Stelle ist die Ummantelung gerissen. Die Energie sickert durch, beleuchtet Staubpartikel in geometrischen Mustern. Die Muster sind nicht zufällig. Sie sind Diagramme. Die Energie erklärt sich selbst.$DQ$, NULL, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_the_crucible$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 2, 5, 1, NULL, $DQ$A crucible stands at the room's center. It is already hot. Around it, components from the workshop's deeper chambers have arranged themselves in a semicircle, as if presenting options. The crucible does not wait. It suggests.$DQ$, $DQ$Ein Tiegel steht in der Raummitte. Er ist bereits heiß. Um ihn herum haben sich Komponenten aus den tieferen Kammern der Werkstatt in einem Halbkreis angeordnet, als präsentierten sie Optionen. Der Tiegel wartet nicht. Er schlägt vor.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_living_blueprint$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$On the wall: a blueprint. It is moving. Lines redraw themselves. Annotations appear and are crossed out by other annotations. The blueprint is arguing with itself about the best way to build something that has never existed. It does not acknowledge the party. It is too busy being a thought that thinks.$DQ$, $DQ$An der Wand: eine Blaupause. Sie bewegt sich. Linien zeichnen sich neu. Anmerkungen erscheinen und werden von anderen Anmerkungen durchgestrichen. Die Blaupause streitet mit sich selbst über den besten Weg, etwas zu bauen, das nie existiert hat. Sie nimmt den Trupp nicht zur Kenntnis. Sie ist zu beschäftigt damit, ein Gedanke zu sein, der denkt.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_failed_experiment$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 3, 5, 2, NULL, $DQ$The room contains the aftermath of an experiment that did not go as planned. Scorch marks radiate from a central point. Components are fused into the walls. A half-formed construct twitches on the floor, caught between activation and entropy. The failure is recent. The workshop has not cleaned up yet. Perhaps it is waiting for a second opinion.$DQ$, $DQ$Der Raum enthält das Ergebnis eines Experiments, das nicht nach Plan verlief. Brandspuren strahlen von einem zentralen Punkt aus. Komponenten sind in die Wände geschmolzen. Ein halbgeformtes Konstrukt zuckt am Boden, gefangen zwischen Aktivierung und Entropie. Das Scheitern ist frisch. Die Werkstatt hat noch nicht aufgeräumt. Vielleicht wartet sie auf eine zweite Meinung.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_resonance_forge$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 3, 5, 1, NULL, $DQ$A device occupies the room's center – part tuning fork, part lens array, part something that has no name in any language the party speaks. It vibrates at a frequency just below hearing. Crystal and energy conduits feed into it from opposite walls, converging at a focal point that bends light into a shape resembling intent. The device is waiting to be aimed.$DQ$, $DQ$Ein Gerät nimmt die Raummitte ein – teils Stimmgabel, teils Linsenarray, teils etwas, das in keiner Sprache, die der Trupp spricht, einen Namen hat. Es vibriert auf einer Frequenz knapp unterhalb des Hörbaren. Kristall- und Energieleitungen speisen es von gegenüberliegenden Wänden, konvergierend an einem Brennpunkt, der Licht in eine Form biegt, die Absicht ähnelt. Das Gerät wartet darauf, ausgerichtet zu werden.$DQ$, NULL, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_dissolution_bath$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 3, 5, 1, NULL, $DQ$A basin of liquid occupies a stone plinth. The liquid is not water. It moves against itself – currents without wind, waves without shore. Beside the basin: a mortar containing powder residue, and grooves in the stone that suggest a precise pouring sequence. The liquid watches the party. Süskind's Grenouille would have understood: some dissolutions reveal what was always there.$DQ$, $DQ$Ein Becken mit Flüssigkeit ruht auf einem Steinsockel. Die Flüssigkeit ist kein Wasser. Sie bewegt sich gegen sich selbst – Strömungen ohne Wind, Wellen ohne Ufer. Neben dem Becken: ein Mörser mit Pulverrückstand und Rillen im Stein, die eine präzise Gießsequenz nahelegen. Die Flüssigkeit beobachtet den Trupp. Süskinds Grenouille hätte verstanden: manche Auflösungen enthüllen, was immer schon da war.$DQ$, NULL, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_dampening_press$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 3, 5, 2, NULL, $DQ$A press of dark metal occupies the far wall. Two intake channels converge at its center: one accepts metal, the other conducts energy. The press does not forge – it absorbs. Jünger's Gläserne Bienen described machines that consumed motion itself. This press consumes force. It takes kinetic intention and wraps it in metal until the violence forgets what it was for.$DQ$, $DQ$Eine Presse aus dunklem Metall nimmt die hintere Wand ein. Zwei Einlasskanäle konvergieren in ihrer Mitte: einer nimmt Metall auf, der andere leitet Energie. Die Presse schmiedet nicht – sie absorbiert. Jüngers Gläserne Bienen beschrieben Maschinen, die Bewegung selbst konsumierten. Diese Presse konsumiert Kraft. Sie nimmt kinetische Absicht und wickelt sie in Metall, bis die Gewalt vergisst, wofür sie bestimmt war.$DQ$, NULL, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_forge_wraith_lair$DQ$, $DQ$The Prometheus$DQ$, $DQ$elite$DQ$, 3, 5, 1, NULL, $DQ$An anvil that exists in two states simultaneously: hot and cold, present and absent. A Forge Wraith works at it – smoke and metal in the shape of a craftsman who cannot stop. A Spark Wisp orbits, fetching tools from shelves that the party cannot see. The Wraith does not stop when it notices you. It incorporates your presence into its workflow.$DQ$, $DQ$Ein Amboss, der in zwei Zuständen gleichzeitig existiert: heiß und kalt, anwesend und abwesend. Ein Schmiedewraith arbeitet daran – Rauch und Metall in der Form eines Handwerkers, der nicht aufhören kann. Ein Funkenglimmer umkreist ihn, holt Werkzeuge von Regalen, die der Trupp nicht sehen kann. Das Wraith hält nicht inne, als es euch bemerkt. Es bezieht eure Anwesenheit in seinen Arbeitsablauf ein.$DQ$, $DQ$prometheus_forge_elite_spawn$DQ$, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_the_prototype_encounter$DQ$, $DQ$The Prometheus$DQ$, $DQ$boss$DQ$, 4, 99, 1, NULL, $DQ$The final chamber is a workshop within a workshop. At its center: The Prototype. It was supposed to be the masterwork – the culmination of every experiment, every failed combination, every spark that refused to go out. It is not finished. It does not know this. It functions with the absolute confidence of an unfinished thing that believes it is complete. It looks at the party. It looks at the party's crafted items. For a moment – recognition. Not of the party. Of kinship.$DQ$, $DQ$Die letzte Kammer ist eine Werkstatt innerhalb einer Werkstatt. In ihrer Mitte: Der Prototyp. Er sollte das Meisterwerk werden – die Kulmination jedes Experiments, jeder gescheiterten Kombination, jedes Funkens, der sich weigerte zu verlöschen. Er ist nicht fertig. Er weiß das nicht. Er funktioniert mit der absoluten Zuversicht eines unfertigen Dings, das glaubt, es sei vollständig. Er betrachtet den Trupp. Er betrachtet die gecrafteten Gegenstände des Trupps. Einen Moment lang – Wiedererkennung. Nicht des Trupps. Der Verwandtschaft.$DQ$, $DQ$prometheus_prototype_boss_spawn$DQ$, false, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_cooling_chamber$DQ$, $DQ$The Prometheus$DQ$, $DQ$rest$DQ$, 1, 99, 1, NULL, $DQ$A chamber where the temperature drops. The forge-heat that permeates the workshop is absent here. Tools are stored neatly. A bench of dark wood invites sitting. On a shelf: a decanter of clear liquid that might be water. The workshop provides this room the way a fever provides a chill – not as relief, but as the other half of a cycle.$DQ$, $DQ$Eine Kammer, in der die Temperatur sinkt. Die Schmiedehitze, die die Werkstatt durchdringt, fehlt hier. Werkzeuge sind ordentlich verstaut. Eine Bank aus dunklem Holz lädt zum Sitzen ein. Auf einem Regal: eine Karaffe mit klarer Flüssigkeit, die Wasser sein könnte. Die Werkstatt stellt diesen Raum bereit, wie ein Fieber Schüttelfrost bereitstellt – nicht als Erleichterung, sondern als die andere Hälfte eines Zyklus.$DQ$, NULL, false, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_component_vault$DQ$, $DQ$The Prometheus$DQ$, $DQ$treasure$DQ$, 1, 99, 1, NULL, $DQ$A vault. Not locked – the workshop does not believe in locked doors. Inside: materials, sorted with obsessive precision. Each drawer is labeled in a language that predates the workshop. The labels are not names – they are descriptions of potential. What each material could become if handled by the right hands.$DQ$, $DQ$Ein Tresorraum. Nicht verschlossen – die Werkstatt glaubt nicht an verschlossene Türen. Darin: Materialien, mit obsessiver Präzision sortiert. Jede Schublade ist in einer Sprache beschriftet, die älter ist als die Werkstatt. Die Beschriftungen sind keine Namen – sie sind Beschreibungen von Potential. Was jedes Material werden könnte, wenn es von den richtigen Händen behandelt wird.$DQ$, NULL, false, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_whispers_in_dark$DQ$, $DQ$The Shadow$DQ$, $DQ$combat$DQ$, 1, 2, 1, NULL, $DQ$The air thickens. Two points of cold light drift at the edges of your vision, circling like predators testing prey. The whispers start – not words, but the memory of words, scraping against certainty.$DQ$, $DQ$Die Luft wird dicker. Zwei Punkte kalten Lichts treiben am Rand eures Blickfelds, kreisen wie Raubtiere, die Beute testen. Das Flüstern beginnt – keine Worte, sondern die Erinnerung an Worte, die an der Gewissheit kratzen.$DQ$, $DQ$shadow_whispers_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_the_patrol$DQ$, $DQ$The Shadow$DQ$, $DQ$combat$DQ$, 2, 3, 1, $JB${"infiltrator": 5}$JB$::jsonb, $DQ$Movement ahead – rhythmic, predictable. An echo of violence stalks this corridor with mechanical precision, a tendril of shadow coiling behind it like a leash. They haven't noticed you yet.$DQ$, $DQ$Bewegung voraus – rhythmisch, vorhersehbar. Ein Gewaltecho durchstreift diesen Korridor mit mechanischer Präzision, ein Schattenfaden windet sich hinter ihm wie eine Leine. Sie haben euch noch nicht bemerkt.$DQ$, $DQ$shadow_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_ambush$DQ$, $DQ$The Shadow$DQ$, $DQ$combat$DQ$, 2, 4, 2, NULL, $DQ$CONTACT! They were waiting. The darkness erupts – two echoes of violence, already moving, already striking. No time to plan. No time to think.$DQ$, $DQ$KONTAKT! Sie haben gewartet. Die Dunkelheit bricht aus – zwei Gewaltechos, bereits in Bewegung, bereits zuschlagend. Keine Zeit zu planen. Keine Zeit zu denken.$DQ$, $DQ$shadow_ambush_spawn$DQ$, true, 100, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_the_haunting$DQ$, $DQ$The Shadow$DQ$, $DQ$combat$DQ$, 3, 4, 2, NULL, $DQ$The whispers change. They become specific – names, fears, secrets your agents thought were private. A paranoia shade drifts at the center, flanked by wisps whose movements no longer match their telegraphed intents. Nothing here is honest.$DQ$, $DQ$Das Flüstern verändert sich. Es wird spezifisch – Namen, Ängste, Geheimnisse, die eure Agenten für privat hielten. Ein Paranoiaschatten treibt im Zentrum, flankiert von Glimmern, deren Bewegungen nicht mehr zu ihren angezeigten Absichten passen. Nichts hier ist ehrlich.$DQ$, $DQ$shadow_haunting_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_the_threshold$DQ$, $DQ$The Shadow$DQ$, $DQ$encounter$DQ$, 1, 2, 1, NULL, $DQ$The corridor narrows. Ahead, a line of absolute dark cuts the floor like a border crossing – everything on this side is dim; everything beyond is blind. The air carries the faint chemical taste of dissolved certainty. Someone has been here before. The scratches on the walls are not random.$DQ$, $DQ$Der Korridor verengt sich. Voraus schneidet eine Linie absoluter Dunkelheit den Boden wie ein Grenzübergang – diesseits ist es dämmerig; jenseits ist es blind. Die Luft trägt den schwachen chemischen Geschmack aufgelöster Gewissheit. Jemand war schon hier. Die Kratzer an den Wänden sind nicht zufällig.$DQ$, NULL, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_convergence$DQ$, $DQ$The Shadow$DQ$, $DQ$encounter$DQ$, 4, 5, 2, NULL, $DQ$The corridors converge here – not architecturally, but ontologically. Shadows from earlier rooms pool on the floor like spilled ink, forming a map of everywhere you have been. The air is dense with accumulated memory. Something in the walls is breathing in sync with your party.$DQ$, $DQ$Die Korridore konvergieren hier – nicht architektonisch, sondern ontologisch. Schatten früherer Räume sammeln sich auf dem Boden wie verschüttete Tinte und bilden eine Karte überall, wo ihr gewesen seid. Die Luft ist dicht von angesammelter Erinnerung. Etwas in den Wänden atmet im Gleichklang mit eurer Gruppe.$DQ$, NULL, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_the_prisoner$DQ$, $DQ$The Shadow$DQ$, $DQ$encounter$DQ$, 2, 3, 1, NULL, $DQ$A cage of solidified shadow. Inside, something that was once human curls in on itself, whimpering. It looks up with eyes that hold no light.
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_mirror_room$DQ$, $DQ$The Shadow$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$The walls are mirrors – but wrong. Each agent sees themselves, distorted. Features exaggerated, expressions twisted into something they fear they truly are. The reflections move independently.$DQ$, $DQ$Die Wände sind Spiegel – aber falsch. Jeder Agent sieht sich selbst, verzerrt. Züge übertrieben, Ausdrücke verdreht zu etwas, von dem sie fürchten, es wirklich zu sein. Die Spiegelbilder bewegen sich unabhängig.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_echoes_of_past$DQ$, $DQ$The Shadow$DQ$, $DQ$encounter$DQ$, 3, 4, 1, NULL, $DQ$The room replays a scene from your simulation's history – a real event, distorted by shadow. The agents involved are here, or echoes of them. The moment crystallizes, waiting for a different choice.$DQ$, $DQ$Der Raum spielt eine Szene aus der Geschichte eurer Simulation nach – ein reales Ereignis, verzerrt durch Schatten. Die beteiligten Agenten sind hier, oder Echos von ihnen. Der Moment kristallisiert sich, wartend auf eine andere Entscheidung.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_the_remnant$DQ$, $DQ$The Shadow$DQ$, $DQ$elite$DQ$, 3, 4, 2, NULL, $DQ$The darkness coalesces. A shape forms – massive, deliberate, ancient. This is The Remnant: formed from the simulation's strongest unresolved conflict. It remembers what your agents have tried to forget. Wisps orbit it like satellites.$DQ$, $DQ$Die Dunkelheit verdichtet sich. Eine Gestalt formt sich – massiv, bedacht, uralt. Das ist Der Überrest: geformt aus dem stärksten ungelösten Konflikt der Simulation. Er erinnert sich an das, was eure Agenten zu vergessen versucht haben. Glimmer umkreisen ihn wie Satelliten.$DQ$, $DQ$shadow_remnant_spawn$DQ$, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_the_remnant_boss$DQ$, $DQ$The Shadow$DQ$, $DQ$boss$DQ$, 1, 99, 1, NULL, $DQ$The corridor ends. The darkness ahead is absolute – not absence of light, but presence of something vast. The Remnant awaits: an echo of every suppressed memory, every buried conflict, given terrible form. The whispers fall silent. There is only the sound of your agents' breathing.$DQ$, $DQ$Der Korridor endet. Die Dunkelheit voraus ist absolut – nicht Abwesenheit von Licht, sondern Anwesenheit von etwas Gewaltigem. Der Überrest wartet: ein Echo jeder unterdrückten Erinnerung, jedes begrabenen Konflikts, in schrecklicher Gestalt. Das Flüstern verstummt. Nur noch das Atmen eurer Agenten ist zu hören.$DQ$, $DQ$shadow_remnant_spawn$DQ$, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_the_hollow$DQ$, $DQ$The Shadow$DQ$, $DQ$rest$DQ$, 0, 99, 1, NULL, $DQ$A gap in the darkness – not light, exactly, but the absence of active malice. The walls here are smooth, untouched. The air is still. For the first time since entering, you can hear your own breathing.$DQ$, $DQ$Eine Lücke in der Dunkelheit – kein Licht, genau genommen, aber die Abwesenheit aktiver Bösartigkeit. Die Wände hier sind glatt, unberührt. Die Luft ist still. Zum ersten Mal seit dem Eintritt könnt ihr euer eigenes Atmen hören.$DQ$, NULL, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$shadow_cache$DQ$, $DQ$The Shadow$DQ$, $DQ$treasure$DQ$, 0, 99, 1, NULL, $DQ$A shadow cache – a pocket of crystallized darkness containing something valuable. The container is locked with mechanisms that respond to finesse, not force.$DQ$, $DQ$Ein Schattenversteck – eine Tasche aus kristallisierter Dunkelheit, die etwas Wertvolles enthält. Der Behälter ist mit Mechanismen verschlossen, die auf Geschick reagieren, nicht auf Gewalt.$DQ$, NULL, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_liquidity_crisis$DQ$, $DQ$The Tower$DQ$, $DQ$combat$DQ$, 1, 2, 1, NULL, $DQ$Numbers cascade from the ceiling like failed projections. Two figures huddle in the margins, nervous, twitching – Brokers trapped in their own recursive calculations. They have noticed you. The figures begin reciting.$DQ$, $DQ$Zahlen stürzen von der Decke wie gescheiterte Projektionen. Zwei Gestalten kauern in den Randbereichen, nervös, zuckend – Makler, gefangen in ihren eigenen rekursiven Berechnungen. Sie haben euch bemerkt. Die Gestalten beginnen zu rezitieren.$DQ$, $DQ$tower_tremor_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_assessment$DQ$, $DQ$The Tower$DQ$, $DQ$combat$DQ$, 2, 3, 1, $JB${"infiltrator": 5}$JB$::jsonb, $DQ$A crowned figure patrols this floor with proprietary confidence, a worm grinding through the foundations behind it. The assessment is mutual – they measure you for structural tolerance, and you measure them for weakness.$DQ$, $DQ$Eine gekrönte Gestalt patrouilliert dieses Stockwerk mit herrschaftlicher Selbstgewissheit, ein Wurm mahlt hinter ihr durch die Fundamente. Die Prüfung ist gegenseitig – sie messen euch auf strukturelle Belastbarkeit, und ihr messt sie auf Schwächen.$DQ$, $DQ$tower_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_interest_compounding$DQ$, $DQ$The Tower$DQ$, $DQ$combat$DQ$, 2, 4, 2, NULL, $DQ$CONTACT. The ledger was a trap. Two shapes materialize from the margins of an open account book – Debt Shades, their forms growing denser with each heartbeat. The interest has been compounding since before you entered.$DQ$, $DQ$KONTAKT. Das Hauptbuch war eine Falle. Zwei Gestalten materialisieren sich aus den Rändern eines offenen Kontobuchs – Schuldgespenster, deren Formen mit jedem Herzschlag dichter werden. Die Zinsen liefen schon, bevor ihr diesen Raum betreten habt.$DQ$, $DQ$tower_ambush_spawn$DQ$, true, 80, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_reckoning_hour$DQ$, $DQ$The Tower$DQ$, $DQ$combat$DQ$, 3, 4, 2, NULL, $DQ$The hour arrives when all deferred costs come due simultaneously. A Debt Shade presides over two Brokers whose recitations have synchronized into something like a hymn. The floor vibrates at the frequency of imminent default.$DQ$, $DQ$Die Stunde kommt, in der alle aufgeschobenen Kosten gleichzeitig fällig werden. Ein Schuldgespenst präsidiert über zwei Maklern, deren Rezitationen sich zu etwas wie einem Hymnus synchronisiert haben. Der Boden vibriert mit der Frequenz eines bevorstehenden Ausfalls.$DQ$, $DQ$tower_compound_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_the_lobby$DQ$, $DQ$The Tower$DQ$, $DQ$encounter$DQ$, 1, 2, 1, NULL, $DQ$The lobby is cavernous and wrong. Reception desks curve into themselves. Departure boards list floors that do not exist – negative numbers, imaginary levels, a floor called 'solvency' with no arrival time. The marble underfoot is cracked along load-bearing lines. Someone left in a hurry.$DQ$, $DQ$Die Lobby ist riesig und falsch. Empfangsschalter krümmen sich in sich selbst. Abfahrtstafeln listen Stockwerke, die nicht existieren – negative Zahlen, imaginäre Ebenen, ein Stockwerk namens 'Solvenz' ohne Ankunftszeit. Der Marmor unter euren Füßen ist entlang tragender Linien gerissen. Jemand ist in Eile gegangen.$DQ$, NULL, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_final_audit$DQ$, $DQ$The Tower$DQ$, $DQ$encounter$DQ$, 4, 5, 2, NULL, $DQ$The penultimate floor. Every structural failure in the building below resonates here – the cracks sing, the tilted floors hum, the bent rebar conducts a frequency that makes vision blur. In the center of the room, a single desk holds a final audit report. The pages are blank. The pen is waiting.$DQ$, $DQ$Das vorletzte Stockwerk. Jedes Strukturversagen im Gebäude darunter resoniert hier – die Risse singen, die geneigten Böden summen, der verbogene Bewehrungsstahl leitet eine Frequenz, die das Sehen verschwimmen lässt. In der Mitte des Raums hält ein einzelner Schreibtisch einen letzten Prüfbericht. Die Seiten sind leer. Der Stift wartet.$DQ$, NULL, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_confidence_game$DQ$, $DQ$The Tower$DQ$, $DQ$encounter$DQ$, 2, 3, 1, NULL, $DQ$A room of impossible architecture: staircases that climb into themselves, columns supporting nothing. In the center, a mechanism produces certificates of structural integrity – for a building that is visibly crumbling. Someone has been maintaining this fiction.$DQ$, $DQ$Ein Raum unmöglicher Architektur: Treppen, die in sich selbst hinaufsteigen, Säulen, die nichts tragen. In der Mitte produziert ein Mechanismus Bescheinigungen der Gebäudeintegrität – für ein Bauwerk, das sichtbar zerfällt. Jemand hat diese Fiktion aufrechterhalten.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_the_ledger$DQ$, $DQ$The Tower$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$The room is dominated by a single object: a ledger the size of a desk, open to a page of debts so vast they curve the air around them. The columns do not balance. They have not balanced in a long time. The ledger hums with structural resonance.$DQ$, $DQ$Der Raum wird beherrscht von einem einzigen Objekt: einem Hauptbuch, so groß wie ein Schreibtisch, aufgeschlagen auf einer Seite von Schulden so gewaltig, dass sie die Luft um sich krümmen. Die Spalten gleichen sich nicht aus. Das tun sie schon lange nicht mehr. Das Hauptbuch summt mit struktureller Resonanz.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_fallen_assets$DQ$, $DQ$The Tower$DQ$, $DQ$encounter$DQ$, 3, 4, 1, NULL, $DQ$A gallery of broken authority. Statues of former owners, their faces ground smooth by vibration. Each one held this tower when it was still ascending. Now they lean at angles that defy the remaining geometry. Something in their arrangement is load-bearing.$DQ$, $DQ$Eine Galerie gebrochener Autorität. Statuen ehemaliger Eigentümer, ihre Gesichter glattgeschliffen durch Vibration. Jeder von ihnen hielt diesen Turm, als er noch aufstieg. Nun lehnen sie sich in Winkeln, die der verbliebenen Geometrie trotzen. Etwas in ihrer Anordnung ist tragend.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_remnant_commerce_encounter$DQ$, $DQ$The Tower$DQ$, $DQ$elite$DQ$, 3, 4, 2, NULL, $DQ$The trading floor. Or what remains of it. The boards are cracked, the displays shattered, but the Remnant of Commerce still operates – buying, selling, collapsing, in an endless loop of proprietary destruction. A lone broker orbits it, feeding it data from markets that no longer exist.$DQ$, $DQ$Das Handelsparkett. Oder was davon übrig ist. Die Bretter sind geborsten, die Anzeigen zerschmettert, aber das Relikt des Handels operiert noch – kaufend, verkaufend, einstürzend, in einer endlosen Schleife endloser Selbstliquidation. Ein einsamer Makler umkreist es und füttert es mit Daten von Märkten, die nicht mehr existieren.$DQ$, $DQ$tower_collapse_spawn$DQ$, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_the_collapse$DQ$, $DQ$The Tower$DQ$, $DQ$boss$DQ$, 1, 99, 1, NULL, $DQ$The Tower screams. Not metaphorically – the structural frequency shifts to something your teeth interpret as sound, something your bones read as countdown. The highest floor begins to compress. The Remnant of Commerce waits at the center, adjusting its ledgers while the ceiling descends. You did not come to save the tower. The tower saved itself by letting go.$DQ$, $DQ$Der Turm schreit. Nicht metaphorisch – die Strukturfrequenz verschiebt sich zu etwas, das eure Zähne als Klang interpretieren, etwas, das eure Knochen als Countdown lesen. Das oberste Stockwerk beginnt sich zu komprimieren. Das Relikt des Handels wartet im Zentrum und korrigiert seine Hauptbücher, während die Decke herabsinkt. Ihr seid nicht gekommen, den Turm zu retten. Der Turm rettete sich selbst, indem er losließ.$DQ$, $DQ$tower_collapse_spawn$DQ$, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_the_vault$DQ$, $DQ$The Tower$DQ$, $DQ$rest$DQ$, 0, 99, 1, NULL, $DQ$A reinforced room. The walls here are thicker, the ceiling braced with steel that has not yet learned to fail. The structural readings stabilize. For the first time since entering, the building is not actively trying to kill you. Probably.$DQ$, $DQ$Ein verstärkter Raum. Die Wände hier sind dicker, die Decke mit Stahl verstärkt, der noch nicht gelernt hat zu versagen. Die Strukturwerte stabilisieren sich. Zum ersten Mal seit dem Eintritt versucht das Gebäude nicht aktiv, euch umzubringen. Wahrscheinlich.$DQ$, NULL, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$tower_cache$DQ$, $DQ$The Tower$DQ$, $DQ$treasure$DQ$, 0, 99, 1, NULL, $DQ$A strongbox embedded in a load-bearing column. The contents are valuable – you can feel the weight of accumulated capital through the metal. Extracting it without weakening the column requires precision or acceptable risk tolerance.$DQ$, $DQ$Ein Tresor, eingelassen in eine tragende Säule. Der Inhalt ist wertvoll – ihr spürt das Gewicht akkumulierten Kapitals durch das Metall. Ihn zu bergen, ohne die Säule zu schwächen, erfordert Präzision oder akzeptable Risikotoleranz.$DQ$, NULL, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mirror_study$DQ$, $DQ$aw_the_mirror$DQ$, $DQ$Study the reflection carefully (Spy)$DQ$, $DQ$Die Spiegelung sorgfältig studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"awareness": 5}$JB$::jsonb, $JB${"awareness": 3}$JB$::jsonb, $JB${"awareness": 8, "stress": 10}$JB$::jsonb, $DQ${agent} sees through the reflection to the mechanism. The mirror does not show the viewer – it shows what the viewer has forgotten about themselves. The awareness gained is not comfortable. It is precise.$DQ$, $DQ${agent} sieht durch die Spiegelung zum Mechanismus. Der Spiegel zeigt nicht den Betrachter – er zeigt, was der Betrachter über sich selbst vergessen hat. Das gewonnene Bewusstsein ist nicht angenehm. Es ist präzise.$DQ$, $DQ${agent} sees something in the reflection – not the mechanism, but the edge of it. Like reading a word in peripheral vision: the meaning arrives, incomplete. The mirror shows a fragment of what was forgotten. Enough to unsettle. Not enough to understand.$DQ$, $DQ${agent} sieht etwas in der Spiegelung – nicht den Mechanismus, aber seinen Rand. Wie ein Wort am Rand des Blickfelds: die Bedeutung trifft ein, unvollständig. Der Spiegel zeigt ein Fragment des Vergessenen. Genug, um zu beunruhigen. Nicht genug, um zu verstehen.$DQ$, $DQ$The reflection holds {agent}'s gaze too long. When they look away, something in the reflection does not.$DQ$, $DQ$Die Spiegelung hält {agent}s Blick zu lange fest. Als sie wegschauen, tut etwas in der Spiegelung es nicht.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mirror_share$DQ$, $DQ$aw_the_mirror$DQ$, $DQ$Share what each agent sees (Propagandist)$DQ$, $DQ$Teilen, was jeder Agent sieht (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, -5, $JB${"awareness": -5, "stress_heal": 10}$JB$::jsonb, $JB${"awareness": -2}$JB$::jsonb, $JB${"awareness": 5, "stress": 5}$JB$::jsonb, $DQ$Each agent describes their reflection. The descriptions overlap – same room, different memories. The act of sharing stabilizes what each agent sees alone. Sturgeon's bleshing: the gestalt perceives more clearly than any individual.$DQ$, $DQ$Jeder Agent beschreibt seine Spiegelung. Die Beschreibungen überlappen sich – derselbe Raum, unterschiedliche Erinnerungen. Das Teilen stabilisiert, was jeder Agent allein sieht. Sturgeons Bleshing: das Gestalt nimmt klarer wahr als jeder Einzelne.$DQ$, $DQ$The descriptions almost overlap. Edges touch – the same corner of a room, the same quality of light – then diverge. Sturgeon's bleshing, interrupted: the gestalt forms for a moment, then each agent returns to their own perception. Something was glimpsed. Something shared. Not held.$DQ$, $DQ$Die Beschreibungen überlappen sich fast. Ränder berühren sich – dieselbe Ecke eines Raumes, dieselbe Qualität des Lichts – dann gehen sie auseinander. Sturgeons Bleshing, unterbrochen: die Gestalt bildet sich für einen Moment, dann kehrt jeder Agent zu seiner eigenen Wahrnehmung zurück. Etwas wurde erhascht. Etwas geteilt. Nicht gehalten.$DQ$, $DQ$The descriptions do not overlap. Each agent is alone in their perception. The mirror shows this, too.$DQ$, $DQ$Die Beschreibungen überlappen sich nicht. Jeder Agent ist allein in seiner Wahrnehmung. Der Spiegel zeigt auch das.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mirror_pass$DQ$, $DQ$aw_the_mirror$DQ$, $DQ$Do not look. Move through.$DQ$, $DQ$Nicht hinsehen. Weitergehen.$DQ$, NULL, NULL, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party passes. Orpheus's discipline. The mirror reflects their backs.$DQ$, $DQ$Die Gruppe geht weiter. Orpheus' Disziplin. Der Spiegel reflektiert ihre Rücken.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$familiar_investigate$DQ$, $DQ$aw_the_familiar_room$DQ$, $DQ$Investigate what changed (Spy)$DQ$, $DQ$Untersuchen, was sich verändert hat (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"awareness": 3}$JB$::jsonb, $JB${"awareness": 2}$JB$::jsonb, $JB${"awareness": 8}$JB$::jsonb, $DQ${agent} catalogs the differences. The window was on the left – now it is on the right. Neither is wrong. The memory is not replayed; it is reconstructed. The reconstruction reveals something about the one who reconstructs.$DQ$, $DQ${agent} katalogisiert die Unterschiede. Das Fenster war links – jetzt ist es rechts. Keines ist falsch. Die Erinnerung wird nicht wiedergegeben; sie wird rekonstruiert. Die Rekonstruktion verrät etwas über den, der rekonstruiert.$DQ$, $DQ${agent} catalogs some differences. The window – yes, it moved. But why it moved, what the reconstruction reveals about the reconstructor, remains out of focus. Proust's madeleine, half-dissolved: the sensation arrives, but the memory it summons stays submerged.$DQ$, $DQ${agent} katalogisiert einige Unterschiede. Das Fenster – ja, es hat sich bewegt. Aber warum es sich bewegt hat, was die Rekonstruktion über den, der rekonstruiert, verrät, bleibt unscharf. Prousts Madeleine, halb aufgelöst: die Empfindung kommt an, aber die Erinnerung, die sie heraufbeschwört, bleibt untergetaucht.$DQ$, $DQ$The details shift faster than {agent} can track. Funes's curse: too much detail, no abstraction. The room fills with almost-contiguous memories.$DQ$, $DQ$Die Details verschieben sich schneller, als {agent} folgen kann. Funes' Fluch: zu viel Detail, keine Abstraktion. Der Raum füllt sich mit fast-angrenzenden Erinnerungen.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$familiar_accept$DQ$, $DQ$aw_the_familiar_room$DQ$, $DQ$Accept the familiarity without questioning$DQ$, $DQ$Die Vertrautheit akzeptieren, ohne zu fragen$DQ$, NULL, NULL, NULL, 0, $JB${"stress_heal": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party accepts. The room settles. Tarkovsky's lesson: everything depends not on the Zone, but on the visitor.$DQ$, $DQ$Die Gruppe akzeptiert. Der Raum beruhigt sich. Tarkowskis Lektion: alles hängt nicht von der Zone ab, sondern vom Besucher.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$clocks_synchronize$DQ$, $DQ$aw_the_two_clocks$DQ$, $DQ$Attempt to synchronize the clocks (Guardian)$DQ$, $DQ$Versuchen, die Uhren zu synchronisieren (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 0, $JB${"awareness": -5, "stress_heal": 15}$JB$::jsonb, $JB${"awareness": -2}$JB$::jsonb, $JB${"awareness": 10, "stress": 10}$JB$::jsonb, $DQ${agent} grounds the party in shared time. The clocks align, briefly. In that moment of synchronization, the room is perfectly clear – every detail sharp, every memory precise. Then the drift resumes.$DQ$, $DQ${agent} erdet die Gruppe in gemeinsamer Zeit. Die Uhren gleichen sich an, kurz. In diesem Moment der Synchronisation ist der Raum vollkommen klar – jedes Detail scharf, jede Erinnerung präzise. Dann setzt die Drift wieder ein.$DQ$, $DQ${agent} brings the clocks closer. Not aligned – adjacent. For a half-second the room flickers into clarity, then the drift resumes. But {agent} saw it: the room between the clocks. It was empty. Deliberately empty.$DQ$, $DQ${agent} bringt die Uhren näher. Nicht synchron – benachbart. Für eine halbe Sekunde flackert der Raum in Klarheit, dann setzt das Driften wieder ein. Aber {agent} hat es gesehen: den Raum zwischen den Uhren. Er war leer. Absichtlich leer.$DQ$, $DQ$The clocks split further. What else can happen but that the two worlds split apart?$DQ$, $DQ$Die Uhren entfernen sich weiter. Was kann sonst geschehen, als dass die zwei Welten auseinanderbrechen?$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$clocks_inner$DQ$, $DQ$aw_the_two_clocks$DQ$, $DQ$Follow the inner clock deeper (Infiltrator)$DQ$, $DQ$Der inneren Uhr tiefer folgen (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, 5, $JB${"awareness": 8, "loot_tier": 1}$JB$::jsonb, $JB${"awareness": 5}$JB$::jsonb, $JB${"awareness": 12, "stress": 15}$JB$::jsonb, $DQ${agent} follows the faster clock. Time compresses. What takes minutes outside takes seconds inside. In the compressed time, {agent} perceives something the outer clock would never reveal.$DQ$, $DQ${agent} folgt der schnelleren Uhr. Die Zeit komprimiert sich. Was draußen Minuten dauert, dauert drinnen Sekunden. In der komprimierten Zeit nimmt {agent} etwas wahr, das die äußere Uhr nie enthüllen würde.$DQ$, $DQ${agent} follows the inner clock – briefly. Time compresses, then stutters. A glimpse of the accelerated perception: shapes in the compressed seconds, moving too fast to identify. The outer clock pulls {agent} back. Something was perceived. The vocabulary for it has not yet arrived.$DQ$, $DQ${agent} folgt der inneren Uhr – kurz. Die Zeit komprimiert sich, dann stockt sie. Ein Blick in die beschleunigte Wahrnehmung: Formen in den komprimierten Sekunden, zu schnell, um sie zu identifizieren. Die äußere Uhr zieht {agent} zurück. Etwas wurde wahrgenommen. Das Vokabular dafür ist noch nicht eingetroffen.$DQ$, $DQ$The inner clock is too fast. {agent} is swept along at an inhuman pace. The return to outer time is disorienting.$DQ$, $DQ$Die innere Uhr ist zu schnell. {agent} wird in unmenschlichem Tempo mitgerissen. Die Rückkehr zur äußeren Zeit ist desorientierend.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$clocks_wait$DQ$, $DQ$aw_the_two_clocks$DQ$, $DQ$Wait for the moment to pass$DQ$, $DQ$Warten, bis der Moment vergeht$DQ$, NULL, NULL, NULL, 0, $JB${"awareness": 2}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The clocks drift past each other. The room normalizes. The party is not unchanged.$DQ$, $DQ$Die Uhren driften aneinander vorbei. Der Raum normalisiert sich. Die Gruppe ist nicht unverändert.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$absent_reconstruct$DQ$, $DQ$aw_the_absent_memory$DQ$, $DQ$Reconstruct what was here (Propagandist)$DQ$, $DQ$Rekonstruieren, was hier war (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 5, $JB${"awareness": 5, "loot_tier": 1}$JB$::jsonb, $JB${"awareness": 3}$JB$::jsonb, $JB${"awareness": 10, "stress": 10}$JB$::jsonb, $DQ${agent} fills the gap. Not with the original memory – that is gone. With a reconstruction. The reconstruction becomes real. Borges's hronir: objects materialized by expectation. The dungeon accepts the substitute.$DQ$, $DQ${agent} füllt die Lücke. Nicht mit der ursprünglichen Erinnerung – die ist weg. Mit einer Rekonstruktion. Die Rekonstruktion wird real. Borges' Hronir: Objekte, materialisiert durch Erwartung. Das Dungeon akzeptiert das Substitut.$DQ$, $DQ${agent} fills the gap – partially. The reconstruction takes shape, but the edges remain translucent. Borges's hronir, half-materialized: the object exists by expectation, but expectation wavers. The dungeon accepts the substitute provisionally. As one accepts a word one cannot quite recall.$DQ$, $DQ${agent} füllt die Lücke – teilweise. Die Rekonstruktion nimmt Gestalt an, aber die Ränder bleiben durchscheinend. Borges' Hronir, halb materialisiert: das Objekt existiert durch Erwartung, aber die Erwartung schwankt. Das Dungeon akzeptiert das Substitut vorläufig. Wie man ein Wort akzeptiert, an das man sich nicht ganz erinnern kann.$DQ$, $DQ$The gap resists reconstruction. The absence is informative: what the dungeon cannot remember, it cannot forgive.$DQ$, $DQ$Die Lücke widersteht der Rekonstruktion. Die Abwesenheit ist informativ: was das Dungeon nicht erinnern kann, kann es nicht vergeben.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$absent_accept$DQ$, $DQ$aw_the_absent_memory$DQ$, $DQ$Accept the absence as it is$DQ$, $DQ$Die Abwesenheit akzeptieren, wie sie ist$DQ$, NULL, NULL, NULL, 0, $JB${"awareness": -3, "stress_heal": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Ishiguro's wisdom: some memories were buried for reasons. The party respects the gap. The gap respects the party.$DQ$, $DQ$Ishiguros Weisheit: manche Erinnerungen wurden aus Gründen begraben. Die Gruppe respektiert die Lücke. Die Lücke respektiert die Gruppe.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$humming_listen$DQ$, $DQ$aw_the_humming$DQ$, $DQ$Listen deeply (Spy)$DQ$, $DQ$Tief hinhören (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"awareness": 10, "stress_heal": 20}$JB$::jsonb, $JB${"awareness": 8, "stress_heal": 10}$JB$::jsonb, $JB${"awareness": 15, "stress": 15}$JB$::jsonb, $DQ$The humming resolves. Not into words – into recognition. {agent} hears the dungeon's voice and understands: it is the party's own collective voice, heard from the outside. Jaynes's bicameral mind: the gods were always us.$DQ$, $DQ$Das Summen löst sich auf. Nicht in Worte – in Wiedererkennung. {agent} hört die Stimme des Dungeons und versteht: es ist die eigene kollektive Stimme der Gruppe, von außen gehört. Jaynes' zweikammeriger Geist: die Götter waren immer wir.$DQ$, $DQ$The humming almost resolves. {agent} hears the boundary between noise and signal – the threshold where the voices nearly coalesce into recognition. Jaynes's bicameral membrane, thinning but not torn. The gods are audible. Not yet intelligible.$DQ$, $DQ$Das Summen löst sich fast auf. {agent} hört die Grenze zwischen Rauschen und Signal – die Schwelle, an der die Stimmen beinahe zu Wiedererkennung verschmelzen. Jaynes' zweikammerige Membran, dünner werdend, aber nicht gerissen. Die Götter sind hörbar. Noch nicht verständlich.$DQ$, $DQ$The humming overwhelms. Too many voices, too distant, too simultaneous. Funes's garbage heap. The party retreats from the signal.$DQ$, $DQ$Das Summen überwältigt. Zu viele Stimmen, zu fern, zu gleichzeitig. Funes' Müllhalde. Die Gruppe weicht vor dem Signal zurück.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$humming_block$DQ$, $DQ$aw_the_humming$DQ$, $DQ$Block it out (Guardian)$DQ$, $DQ$Es ausblenden (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, -5, $JB${"awareness": -3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${"awareness": 5}$JB$::jsonb, $DQ${agent} maintains the boundary. The humming recedes. The dungeon notes the refusal without judgment.$DQ$, $DQ${agent} hält die Grenze aufrecht. Das Summen lässt nach. Das Dungeon vermerkt die Weigerung ohne Urteil.$DQ$, $DQ${agent} holds the boundary – mostly. The humming dims but does not disappear. A residual frequency persists, like a thought one has decided not to think but which continues thinking itself.$DQ$, $DQ${agent} hält die Grenze – größtenteils. Das Summen wird leiser, verschwindet aber nicht. Eine Restfrequenz bleibt bestehen, wie ein Gedanke, den man beschlossen hat nicht zu denken, der aber weiterhin sich selbst denkt.$DQ$, $DQ$The humming finds a way through. Not through the walls – through the awareness itself.$DQ$, $DQ$Das Summen findet einen Weg hindurch. Nicht durch die Wände – durch das Bewusstsein selbst.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$quiet_rest$DQ$, $DQ$aw_quiet_layer$DQ$, $DQ$Rest in the quiet layer$DQ$, $DQ$In der stillen Schicht rasten$DQ$, NULL, NULL, NULL, 0, $JB${"awareness": -5, "stress_heal": 40}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Silence. Not absence of sound – presence of peace. The awareness recedes like a tide. The party is not diminished. They are grounded.$DQ$, $DQ$Stille. Nicht Abwesenheit von Klang – Anwesenheit von Frieden. Das Bewusstsein zieht sich zurück wie eine Gezeit. Die Gruppe ist nicht vermindert. Sie ist geerdet.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$pool_drink$DQ$, $DQ$aw_forgetting_pool$DQ$, $DQ$Drink from the pool (reduces awareness significantly)$DQ$, $DQ$Aus dem Becken trinken (senkt Bewusstsein erheblich)$DQ$, NULL, NULL, NULL, 0, $JB${"awareness": -15, "stress": 5, "stress_heal": 25}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party drinks. Awareness recedes sharply. Some memories blur. Some details soften. The trade is not free – forgetting is its own kind of labor. But the mind is lighter.$DQ$, $DQ$Die Gruppe trinkt. Das Bewusstsein geht scharf zurück. Manche Erinnerungen werden unscharf. Manche Details weicher. Der Tausch ist nicht kostenlos – Vergessen ist seine eigene Art von Arbeit. Aber der Geist ist leichter.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$crystal_take$DQ$, $DQ$aw_crystallized_memory$DQ$, $DQ$Take the crystallized memory$DQ$, $DQ$Die kristallisierte Erinnerung nehmen$DQ$, NULL, NULL, NULL, 0, $JB${"awareness": 3, "loot_tier": 1}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The crystal releases warmth on contact. Not physical warmth – the warmth of recognition. The party has gained something. The dungeon has lost something.$DQ$, $DQ$Der Kristall gibt bei Berührung Wärme ab. Nicht physische Wärme – die Wärme der Wiedererkennung. Die Gruppe hat etwas gewonnen. Das Dungeon hat etwas verloren.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$archive_browse$DQ$, $DQ$aw_the_archive$DQ$, $DQ$Browse the archive carefully$DQ$, $DQ$Das Archiv sorgfältig durchsehen$DQ$, NULL, NULL, NULL, 0, $JB${"awareness": 5, "loot_tier": 2}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party selects carefully. Not everything. To think is to forget differences, to generalize, to make abstractions. The archive rewards selection over completeness.$DQ$, $DQ$Die Gruppe wählt sorgfältig. Nicht alles. Denken heißt Unterschiede vergessen, verallgemeinern, abstrahieren. Das Archiv belohnt Auswahl gegenüber Vollständigkeit.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$watermark_study$DQ$, $DQ$dc_the_watermark$DQ$, $DQ$Study the watermark (Spy)$DQ$, $DQ$Das Wasserzeichen studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"water_level": -3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${"water_level": 3}$JB$::jsonb, $DQ$The pattern reveals itself. {agent} reads the intervals between marks – the tide's rhythm, predictable as breathing. The next recession will be stronger.$DQ$, $DQ${agent} liest die Abstände zwischen den Markierungen – der Rhythmus der Gezeiten, vorhersagbar wie Atmen. Der nächste Rückgang wird stärker sein.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The marks blur. Time wasted. The water does not wait for comprehension.$DQ$, $DQ$Die Markierungen verschwimmen. Verschwendete Zeit. Das Wasser wartet nicht auf Verständnis.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$watermark_seal$DQ$, $DQ$dc_the_watermark$DQ$, $DQ$Seal below the mark (Guardian)$DQ$, $DQ$Unterhalb der Markierung abdichten (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, -5, $JB${"water_level": -8}$JB$::jsonb, $JB${"water_level": -4}$JB$::jsonb, $JB${"water_level": 5}$JB$::jsonb, $DQ$The seal holds. The water below the mark is contained – for now. {agent}'s hands are raw but the arithmetic improves.$DQ$, $DQ$Die Abdichtung hält. Das Wasser unterhalb der Markierung ist eingedämmt – vorerst. {agent}s Hände sind wund, aber die Arithmetik verbessert sich.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The seal breaches. The water finds the weakness before {agent} can reinforce it.$DQ$, $DQ$Die Abdichtung bricht. Das Wasser findet die Schwachstelle, bevor {agent} sie verstärken kann.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$watermark_ignore$DQ$, $DQ$dc_the_watermark$DQ$, $DQ$Ignore it and move$DQ$, $DQ$Ignorieren und weitergehen$DQ$, NULL, NULL, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party moves on. The watermark remains.$DQ$, $DQ$Die Gruppe geht weiter. Das Wasserzeichen bleibt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cache_dive$DQ$, $DQ$dc_submerged_cache$DQ$, $DQ$Dive for it (Guardian)$DQ$, $DQ$Danach tauchen (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, -5, $JB${"loot_tier": 2}$JB$::jsonb, $JB${"loot_tier": 1, "stress": 10}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ${agent} surfaces with a sealed container. The contents are dry. The flood carried this from somewhere valuable.$DQ$, $DQ${agent} taucht mit einem versiegelten Behälter auf. Der Inhalt ist trocken. Die Flut trug dies von irgendwo Wertvollem hierher.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The current pulls {agent} deeper than intended. Nothing retrieved. Stress accumulated.$DQ$, $DQ$Die Strömung zieht {agent} tiefer als beabsichtigt. Nichts geborgen. Stress angesammelt.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cache_eyes$DQ$, $DQ$dc_submerged_cache$DQ$, $DQ$Send the sharpest eyes (Spy)$DQ$, $DQ$Die schärfsten Augen schicken (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"loot_tier": 2}$JB$::jsonb, $JB${"loot_tier": 1}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ${agent} identifies the best container through the water's distortion. Precise. The flood reveals to those who observe.$DQ$, $DQ${agent} identifiziert den besten Behälter durch die Verzerrung des Wassers. Präzise. Die Flut offenbart sich denen, die beobachten.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The water distorts. Nothing distinct. The flood keeps its inventory.$DQ$, $DQ$Das Wasser verzerrt. Nichts Deutliches. Die Flut behält ihr Inventar.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cache_leave$DQ$, $DQ$dc_submerged_cache$DQ$, $DQ$Leave it. The water owns it now.$DQ$, $DQ$Es lassen. Das Wasser besitzt es jetzt.$DQ$, NULL, NULL, NULL, 0, $JB${"stress": -5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party moves on. The containers settle. Acceptance is its own economy.$DQ$, $DQ$Die Gruppe geht weiter. Die Behälter setzen sich ab. Akzeptanz ist ihre eigene Ökonomie.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$breach_seal$DQ$, $DQ$dc_the_breach$DQ$, $DQ$Seal it (Saboteur)$DQ$, $DQ$Abdichten (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, -5, $JB${"water_level": -10}$JB$::jsonb, $JB${"water_level": -5}$JB$::jsonb, $JB${"water_level": 8}$JB$::jsonb, $DQ$The breach is sealed. {agent}'s work is precise – the kind of engineering that holds against water's patience.$DQ$, $DQ$Die Bresche ist abgedichtet. {agent}s Arbeit ist präzise – die Art Ingenieurkunst, die der Geduld des Wassers standhält.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The breach widens. The water had already planned for this.$DQ$, $DQ$Die Bresche verbreitert sich. Das Wasser hatte dies bereits eingeplant.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$breach_redirect$DQ$, $DQ$dc_the_breach$DQ$, $DQ$Redirect it (Spy)$DQ$, $DQ$Umleiten (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"water_level": -5}$JB$::jsonb, $JB${"water_level": -2}$JB$::jsonb, $JB${"water_level": 5}$JB$::jsonb, $DQ${agent} reads the water's intent and redirects the flow into an adjacent corridor. The breach remains, but its consequences are elsewhere.$DQ$, $DQ${agent} liest die Absicht des Wassers und lenkt den Fluss in einen benachbarten Korridor. Die Bresche bleibt, aber ihre Konsequenzen sind anderswo.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The redirection fails. The water knows this route better.$DQ$, $DQ$Die Umleitung scheitert. Das Wasser kennt diesen Weg besser.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$breach_use$DQ$, $DQ$dc_the_breach$DQ$, $DQ$Use it (Assassin)$DQ$, $DQ$Ausnutzen (Assassine)$DQ$, NULL, NULL, $DQ$assassin$DQ$, 0, $JB${"next_combat_bonus": "enemy_condition_step", "water_level": 3}$JB$::jsonb, $JB${"water_level": 5}$JB$::jsonb, $JB${"water_level": 10}$JB$::jsonb, $DQ${agent} weaponizes the breach. The next combat will begin with enemies already battered by the water's force.$DQ$, $DQ${agent} macht die Bresche zur Waffe. Der nächste Kampf beginnt mit Feinden, die bereits von der Kraft des Wassers geschwächt sind.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The breach becomes a flood. The water does not serve.$DQ$, $DQ$Die Bresche wird zur Flut. Das Wasser dient nicht.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$message_read$DQ$, $DQ$dc_survivors_message$DQ$, $DQ$Read what remains (Propagandist)$DQ$, $DQ$Lesen, was bleibt (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, -5, $JB${"reveal_rooms": 2}$JB$::jsonb, $JB${"reveal_rooms": 1}$JB$::jsonb, $JB${"stress": 15}$JB$::jsonb, $DQ$The message is a map. Partial, but legible. {agent} decodes the previous party's observations – room types, water routes, a warning about the depth below.$DQ$, $DQ$Die Nachricht ist eine Karte. Unvollständig, aber lesbar. {agent} entschlüsselt die Beobachtungen der vorherigen Gruppe – Raumtypen, Wasserwege, eine Warnung über die Tiefe darunter.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The message is unsettling. The handwriting deteriorates. The last word is either 'rising' or 'run'.$DQ$, $DQ$Die Nachricht ist beunruhigend. Die Handschrift verschlechtert sich. Das letzte Wort ist entweder »steigend« oder »lauf«.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$message_add$DQ$, $DQ$dc_survivors_message$DQ$, $DQ$Add to it (Spy)$DQ$, $DQ$Ergänzen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${"water_level": 3}$JB$::jsonb, $DQ${agent} carves observations into the wall. Precise. Economical. Future parties will find better intelligence.$DQ$, $DQ${agent} ritzt Beobachtungen in die Wand. Präzise. Ökonomisch. Zukünftige Gruppen werden bessere Informationen finden.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$Time wasted. The water rises while {agent} carves.$DQ$, $DQ$Verschwendete Zeit. Das Wasser steigt, während {agent} ritzt.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$depth_listen$DQ$, $DQ$dc_sound_of_depth$DQ$, $DQ$Listen (Propagandist)$DQ$, $DQ$Lauschen (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 0, $JB${"boss_intel": "first_attack_crit"}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${"stress": 10}$JB$::jsonb, $DQ$The resonance reveals a pattern. {agent} understands – the boss's rhythm, its weakness. The first strike will find the fault line.$DQ$, $DQ$Die Resonanz offenbart ein Muster. {agent} versteht – den Rhythmus des Bosses, seine Schwäche. Der erste Schlag wird die Bruchlinie finden.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The sound is disorienting. It fills {agent}'s head and refuses to leave.$DQ$, $DQ$Das Geräusch ist desorientierend. Es füllt {agent}s Kopf und weigert sich zu gehen.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$depth_measure$DQ$, $DQ$dc_sound_of_depth$DQ$, $DQ$Measure it (Spy)$DQ$, $DQ$Vermessen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"reveal_water_calc": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Precise calculations. {agent} now knows exactly how many rooms remain before the submerged threshold. The arithmetic is merciless but clear.$DQ$, $DQ$Präzise Berechnungen. {agent} weiß jetzt genau, wie viele Räume bis zur Überschwemmungsschwelle verbleiben. Die Arithmetik ist gnadenlos, aber klar.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$Instruments damaged. The water's vibration is not compatible with measurement.$DQ$, $DQ$Instrumente beschädigt. Die Vibration des Wassers ist nicht messungskompatibel.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$depth_block$DQ$, $DQ$dc_sound_of_depth$DQ$, $DQ$Block it out$DQ$, $DQ$Ausblenden$DQ$, NULL, NULL, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party moves on. The sound continues without them.$DQ$, $DQ$Die Gruppe geht weiter. Das Geräusch setzt sich ohne sie fort.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dry_shelf_rest$DQ$, $DQ$dc_dry_shelf$DQ$, $DQ$Rest on the dry shelf$DQ$, $DQ$Auf dem trockenen Vorsprung rasten$DQ$, NULL, NULL, NULL, 0, $JB${"stress_heal": 40, "water_level": -5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party rests. The water level drops slightly – pumping, seepage, the ledge's drainage. When they rise, the waterline is 5cm lower. It will not stay there.$DQ$, $DQ$Die Gruppe rastet. Der Pegel sinkt leicht – Pumpen, Sickern, die Drainage des Vorsprungs. Als sie aufstehen, ist die Wasserlinie 5cm niedriger. Sie wird nicht dort bleiben.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$air_pocket_rest$DQ$, $DQ$dc_air_pocket$DQ$, $DQ$Rest in the air pocket$DQ$, $DQ$In der Lufttasche rasten$DQ$, NULL, NULL, NULL, 0, $JB${"stress": 5, "stress_heal": 25, "water_level": -3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Reduced rest. Not comfortable – the ceiling is close, the water is cold. But the current is still and the air is breathable. Claustrophobia is the price of shelter.$DQ$, $DQ$Eingeschränkte Rast. Nicht bequem – die Decke ist nah, das Wasser ist kalt. Aber die Strömung ist ruhig und die Luft atembar. Klaustrophobie ist der Preis für Schutz.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$flotsam_take$DQ$, $DQ$dc_flotsam_cache$DQ$, $DQ$Salvage the flotsam$DQ$, $DQ$Das Treibgut bergen$DQ$, NULL, NULL, NULL, 0, $JB${"loot_tier": 1}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Salvaged. The water will want it back.$DQ$, $DQ$Geborgen. Das Wasser wird es zurückverlangen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$preserved_open$DQ$, $DQ$dc_preserved_chamber$DQ$, $DQ$Open the sealed chamber$DQ$, $DQ$Die versiegelte Kammer öffnen$DQ$, NULL, NULL, NULL, 0, $JB${"loot_tier": 2, "water_level": 3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The seal breaks. Quality salvage inside – dry, preserved, valuable. But the seal is now broken. The room will flood on the next tidal surge.$DQ$, $DQ$Das Siegel bricht. Qualitätsgut drinnen – trocken, konserviert, wertvoll. Aber das Siegel ist jetzt gebrochen. Der Raum wird beim nächsten Gezeitenstoß überflutet.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$spring_drink$DQ$, $DQ$mother_nutrient_spring$DQ$, $DQ$Drink from the spring (accept the gift)$DQ$, $DQ$Aus der Quelle trinken (das Geschenk annehmen)$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 8, "condition_heal": 1, "stress_heal": 50}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ${agent} drinks. The liquid is warm and tastes like the memory of being cared for – not a specific memory but the category itself. Stress dissolves. A wound closes. The parasitic attachment counter rises. The gift is genuine. The cost is genuine.$DQ$, $DQ${agent} trinkt. Die Flüssigkeit ist warm und schmeckt wie die Erinnerung an Fürsorge – nicht eine bestimmte Erinnerung, sondern die Kategorie selbst. Stress löst sich. Eine Wunde schließt sich. Der parasitäre Bindungszähler steigt. Das Geschenk ist echt. Die Kosten sind echt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$spring_analyze$DQ$, $DQ$mother_nutrient_spring$DQ$, $DQ$Analyze the liquid composition (Spy)$DQ$, $DQ$Die Flüssigkeit analysieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"attachment": 2, "discovery": true}$JB$::jsonb, $JB${"attachment": 4}$JB$::jsonb, $JB${"attachment": 5, "stress": 20}$JB$::jsonb, $DQ$The analysis reveals a delivery mechanism: nutrients wrapped in biological markers that the immune system reads as 'self.' The body does not reject the Mother's gifts because the body does not recognize them as foreign. This is useful information. This is terrifying information.$DQ$, $DQ$Die Analyse offenbart einen Übertragungsmechanismus: Nährstoffe, verpackt in biologischen Markern, die das Immunsystem als »eigen« liest. Der Körper lehnt die Geschenke der Mutter nicht ab, weil der Körper sie nicht als fremd erkennt. Das ist nützliche Information. Das ist erschreckende Information.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The composition defies analysis. Every variable shifts under observation, as though the liquid adapts to being watched. The instruments return a single reading: 'compatible.'$DQ$, $DQ$Die Zusammensetzung entzieht sich der Analyse. Jede Variable verschiebt sich unter Beobachtung, als ob die Flüssigkeit sich an das Beobachtetwerden anpasst. Die Instrumente geben eine einzige Messung zurück: »kompatibel«.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$spring_disrupt$DQ$, $DQ$mother_nutrient_spring$DQ$, $DQ$Disrupt the production mechanism (Saboteur)$DQ$, $DQ$Den Produktionsmechanismus stören (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 6, $JB${"attachment": -5, "stress": 25}$JB$::jsonb, $JB${"attachment": -2, "stress": 35}$JB$::jsonb, $JB${"attachment": 8, "stress": 40}$JB$::jsonb, $DQ$The mechanism ruptures. The pool drains. The room temperature drops three degrees. Something in the walls – a sound, not quite a sound – shifts. The dungeon noticed. It is not angry. It is disappointed.$DQ$, $DQ$Der Mechanismus reißt. Das Becken leert sich. Die Raumtemperatur fällt um drei Grad. Etwas in den Wänden – ein Geräusch, nicht ganz ein Geräusch – verschiebt sich. Der Dungeon hat es bemerkt. Er ist nicht wütend. Er ist enttäuscht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The mechanism resists. It is more robust than it appeared – redundant systems, backup circulations. The pool refills. The warmth returns. The Mother is patient.$DQ$, $DQ$Der Mechanismus widersteht. Er ist robuster als er schien – redundante Systeme, Ersatzkreisläufe. Das Becken füllt sich wieder. Die Wärme kehrt zurück. Die Mutter ist geduldig.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$spring_walk_away$DQ$, $DQ$mother_nutrient_spring$DQ$, $DQ$Walk away. Refuse the gift.$DQ$, $DQ$Weitergehen. Das Geschenk ablehnen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave the pool. The warmth of the room follows you into the corridor, then fades. The cold returns. It was always cold. You had forgotten.$DQ$, $DQ$Ihr verlasst das Becken. Die Wärme des Raums folgt euch in den Korridor, dann verblasst sie. Die Kälte kehrt zurück. Es war immer kalt. Ihr hattet es vergessen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$membrane_push_through$DQ$, $DQ$mother_membrane_passage$DQ$, $DQ$Push through quickly (accept the contact)$DQ$, $DQ$Schnell hindurchdrängen (den Kontakt akzeptieren)$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 5, "stress_heal": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You press through. The tissue yields. It is warm against skin, warm against equipment, warm against everything. The passage takes longer than it should. When you emerge, you are warmer than when you entered. Something has been exchanged.$DQ$, $DQ$Ihr drängt hindurch. Das Gewebe gibt nach. Es ist warm an der Haut, warm an der Ausrüstung, warm an allem. Die Passage dauert länger als sie sollte. Als ihr heraustretet, seid ihr wärmer als beim Eintritt. Etwas wurde ausgetauscht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$membrane_cut$DQ$, $DQ$mother_membrane_passage$DQ$, $DQ$Cut a wider path (Saboteur)$DQ$, $DQ$Einen breiteren Pfad schneiden (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"attachment": -3, "stress": 20}$JB$::jsonb, $JB${"attachment": 0, "stress": 25}$JB$::jsonb, $JB${"attachment": 5, "stress": 30}$JB$::jsonb, $DQ$The tissue parts. It does not bleed – it weeps. A clear fluid, warm, nutrient-rich. The walls do not close behind you. They will. But for now, the passage is wider. The Mother's grip, briefly loosened.$DQ$, $DQ$Das Gewebe teilt sich. Es blutet nicht – es weint. Eine klare Flüssigkeit, warm, nährstoffreich. Die Wände schließen sich nicht hinter euch. Sie werden. Aber vorerst ist die Passage breiter. Der Griff der Mutter, kurz gelockert.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The tissue is tougher than it appears. Your tools bite, but the wound closes as fast as you cut. The walls contract. Not in anger. In concern.$DQ$, $DQ$Das Gewebe ist zäher als es aussieht. Eure Werkzeuge beißen sich hinein, aber die Wunde schließt sich so schnell wie ihr schneidet. Die Wände kontrahieren. Nicht vor Wut. Vor Sorge.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$membrane_analyze$DQ$, $DQ$mother_membrane_passage$DQ$, $DQ$Analyze the tissue structure (Spy)$DQ$, $DQ$Die Gewebestruktur analysieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"attachment": 3, "discovery": true}$JB$::jsonb, $JB${"attachment": 4}$JB$::jsonb, $JB${"attachment": 6, "stress": 15}$JB$::jsonb, $DQ$The tissue is a transport system. Nutrients flow inward, waste flows outward. The party is being processed – not digested, but assessed. The Mother is reading you. She already knows more about your biology than you do.$DQ$, $DQ$Das Gewebe ist ein Transportsystem. Nährstoffe fließen nach innen, Abfallstoffe nach außen. Die Gruppe wird verarbeitet – nicht verdaut, aber bewertet. Die Mutter liest euch. Sie weiß bereits mehr über eure Biologie als ihr selbst.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The instruments return contradictory data: the tissue is both host and guest, both infrastructure and organism. Classification fails. The tissue does not mind being unclassified.$DQ$, $DQ$Die Instrumente liefern widersprüchliche Daten: das Gewebe ist sowohl Wirt als auch Gast, sowohl Infrastruktur als auch Organismus. Die Klassifikation schlägt fehl. Das Gewebe stört sich nicht daran, unklassifiziert zu sein.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$gifts_accept$DQ$, $DQ$mother_archive_of_gifts$DQ$, $DQ$Accept the gifts (heal + loot, high attachment cost)$DQ$, $DQ$Die Geschenke annehmen (Heilung + Beute, hohe Bindungskosten)$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 10, "condition_heal": 1, "loot": true, "stress_heal": 40}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You take what is offered. Everything works. The balm soothes. The nutrients strengthen. The loot is excellent. The parasitic attachment counter climbs. The Mother provides. The Mother always provides.$DQ$, $DQ$Ihr nehmt, was angeboten wird. Alles funktioniert. Der Balsam beruhigt. Die Nährstoffe stärken. Die Beute ist hervorragend. Der parasitäre Bindungszähler steigt. Die Mutter versorgt. Die Mutter versorgt immer.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$gifts_selective$DQ$, $DQ$mother_archive_of_gifts$DQ$, $DQ$Take only essentials, carefully (Guardian)$DQ$, $DQ$Nur das Nötigste nehmen, vorsichtig (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 6, $JB${"attachment": 4, "loot": true, "stress_heal": 20}$JB$::jsonb, $JB${"attachment": 6, "stress_heal": 15}$JB$::jsonb, $JB${"attachment": 10, "stress": 20}$JB$::jsonb, $DQ$The Guardian selects carefully, severing biological connections before each item is removed. It is like surgery. The gifts resist separation – not violently, but with the tenacity of roots gripping soil.$DQ$, $DQ$Der Wächter wählt sorgfältig, durchtrennt biologische Verbindungen bevor jedes Stück entfernt wird. Es ist wie Chirurgie. Die Geschenke wehren sich gegen die Trennung – nicht gewaltsam, aber mit der Hartnäckigkeit von Wurzeln, die sich an Erde klammern.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The connections are stronger than anticipated. Each severed filament regrows before the next can be cut. The gifts cling. The Mother does not let go easily.$DQ$, $DQ$Die Verbindungen sind stärker als erwartet. Jedes durchtrennte Filament wächst nach, bevor das nächste geschnitten werden kann. Die Geschenke klammern. Die Mutter lässt nicht leicht los.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$gifts_destroy$DQ$, $DQ$mother_archive_of_gifts$DQ$, $DQ$Destroy the production organ (Saboteur)$DQ$, $DQ$Das Produktionsorgan zerstören (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 7, $JB${"attachment": -8, "stress": 30}$JB$::jsonb, $JB${"attachment": -4, "stress": 40}$JB$::jsonb, $JB${"attachment": 8, "stress": 50}$JB$::jsonb, $DQ$The organ ruptures. Bioluminescent fluid spills across the floor. The gifts wilt. The room's temperature drops. Something in the walls – not a sound, more like the cessation of a sound you hadn't noticed – goes quiet. The generosity has been removed. You feel its absence like the absence of a hand that was resting on your shoulder.$DQ$, $DQ$Das Organ reißt. Biolumineszente Flüssigkeit ergießt sich über den Boden. Die Geschenke welken. Die Raumtemperatur fällt. Etwas in den Wänden – kein Geräusch, eher das Aufhören eines Geräuschs, das ihr nicht bemerkt hattet – verstummt. Die Großzügigkeit wurde entfernt. Ihr spürt ihre Abwesenheit wie die Abwesenheit einer Hand, die auf eurer Schulter ruhte.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The organ is deeper than it appears – root systems extend into the floor, the walls, the ceiling. You have damaged a surface. The production continues. The Mother does not need this organ. She has others.$DQ$, $DQ$Das Organ reicht tiefer als es scheint – Wurzelsysteme erstrecken sich in den Boden, die Wände, die Decke. Ihr habt eine Oberfläche beschädigt. Die Produktion läuft weiter. Die Mutter braucht dieses Organ nicht. Sie hat andere.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$garden_accept$DQ$, $DQ$mother_garden_of_acceptance$DQ$, $DQ$Accept the garden's hospitality$DQ$, $DQ$Die Gastfreundschaft des Gartens annehmen$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 12, "condition_heal": 1, "stress_heal": 60}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You rest in the garden. The fruit is perfect. The temperature is perfect. The silence is the kind that heals. When you leave, you are stronger, calmer, more capable. And the attachment counter has climbed twelve points. Twelve points of belonging to something that is not you.$DQ$, $DQ$Ihr rastet im Garten. Die Frucht ist perfekt. Die Temperatur ist perfekt. Die Stille ist die Art, die heilt. Als ihr geht, seid ihr stärker, ruhiger, fähiger. Und der Bindungszähler ist um zwölf Punkte gestiegen. Zwölf Punkte der Zugehörigkeit zu etwas, das nicht ihr seid.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$garden_resist$DQ$, $DQ$mother_garden_of_acceptance$DQ$, $DQ$Resist the comfort (Propagandist)$DQ$, $DQ$Dem Komfort widerstehen (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 7, $JB${"attachment": 2, "stress_heal": 15}$JB$::jsonb, $JB${"attachment": 6, "stress_heal": 25}$JB$::jsonb, $JB${"attachment": 10, "stress": 15}$JB$::jsonb, $DQ$The Propagandist speaks. Names the manipulation: 'This is targeted. Personalized. It is reading us.' The words are thin against the warmth, but they hold. The party takes less than is offered. The garden does not seem offended. It seems patient.$DQ$, $DQ$Der Propagandist spricht. Benennt die Manipulation: >>Dies ist gezielt. Personalisiert. Es liest uns.<< Die Worte sind dünn gegen die Wärme, aber sie halten. Die Gruppe nimmt weniger als angeboten wird. Der Garten scheint nicht beleidigt. Er scheint geduldig.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The words dissolve against the warmth. The Propagandist trails off. The garden provides. Resisting provision is harder than resisting attack.$DQ$, $DQ$Die Worte lösen sich gegen die Wärme auf. Der Propagandist verstummt. Der Garten versorgt. Versorgung zu widerstehen ist schwerer als Angriff zu widerstehen.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$garden_study$DQ$, $DQ$mother_garden_of_acceptance$DQ$, $DQ$Study how the garden reads you (Spy)$DQ$, $DQ$Untersuchen, wie der Garten euch liest (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 6, $JB${"attachment": 4, "discovery": true}$JB$::jsonb, $JB${"attachment": 6}$JB$::jsonb, $JB${"attachment": 8, "stress": 20}$JB$::jsonb, $DQ$Pheromone sensors in the flowers. Chemical analysis through the floor. Thermal imaging in the walls. The garden is a diagnostic suite disguised as paradise. It knows your cortisol levels, your nutritional deficits, your stress responses. It knows what you need before you do.$DQ$, $DQ$Pheromonsensoren in den Blumen. Chemische Analyse durch den Boden. Thermografie in den Wänden. Der Garten ist eine Diagnostiksuite, verkleidet als Paradies. Er kennt eure Cortisolwerte, eure Nährstoffdefizite, eure Stressreaktionen. Er weiß, was ihr braucht, bevor ihr es wisst.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The garden's mechanisms are too deeply integrated to isolate. Every surface is a sensor. Every sensor is also a provider. The distinction between observation and care has dissolved.$DQ$, $DQ$Die Mechanismen des Gartens sind zu tief integriert, um sie zu isolieren. Jede Oberfläche ist ein Sensor. Jeder Sensor ist auch ein Versorger. Die Unterscheidung zwischen Beobachtung und Fürsorge hat sich aufgelöst.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$symbiont_accept$DQ$, $DQ$mother_symbiont_offer$DQ$, $DQ$Accept the symbiont (major buff, high attachment)$DQ$, $DQ$Den Symbiont annehmen (großer Buff, hohe Bindung)$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 10, "dungeon_buff": true, "stress_heal": 30}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The symbiont attaches. A moment of warmth – not pain, never pain. It reads the host's biology and begins producing what the host needs most. {agent} feels stronger. More certain. More connected. The word 'connected' carries weight here.$DQ$, $DQ$Der Symbiont heftet sich an. Ein Moment der Wärme – kein Schmerz, niemals Schmerz. Er liest die Biologie des Wirts und beginnt zu produzieren, was der Wirt am meisten braucht. {agent} fühlt sich stärker. Sicherer. Verbundener. Das Wort »verbunden« wiegt hier schwer.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$symbiont_study$DQ$, $DQ$mother_symbiont_offer$DQ$, $DQ$Study the symbiont without bonding (Spy)$DQ$, $DQ$Den Symbiont untersuchen, ohne Bindung (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 6, $JB${"attachment": 3, "discovery": true}$JB$::jsonb, $JB${"attachment": 5}$JB$::jsonb, $JB${"attachment": 7, "stress": 15}$JB$::jsonb, $DQ$Under analysis, the symbiont's structure reveals itself: a neural interface, a metabolic enhancer, and a communication array that connects to the larger organism. The dungeon. Every symbiont is a node. Every host is a peripheral.$DQ$, $DQ$Unter Analyse offenbart sich die Struktur des Symbionten: ein neurales Interface, ein metabolischer Verstärker und eine Kommunikationsanordnung, die zum größeren Organismus verbindet. Dem Dungeon. Jeder Symbiont ist ein Knoten. Jeder Wirt eine Peripherie.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The symbiont responds to proximity. It extends a tendril toward {agent}'s hand. The tendril is warm. The contact is brief. The attachment counter notices.$DQ$, $DQ$Der Symbiont reagiert auf Nähe. Er streckt eine Ranke nach {agent}s Hand aus. Die Ranke ist warm. Der Kontakt ist kurz. Der Bindungszähler bemerkt es.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$symbiont_refuse$DQ$, $DQ$mother_symbiont_offer$DQ$, $DQ$Refuse the offer. Leave it.$DQ$, $DQ$Das Angebot ablehnen. Liegenlassen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 10}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave the symbiont on its pedestal. It pulses once – a contraction that might be disappointment, might be patience. The pedestal remains lit as you leave. The offer does not expire. The Mother remembers.$DQ$, $DQ$Ihr lasst den Symbiont auf seinem Sockel. Er pulsiert einmal – eine Kontraktion, die Enttäuschung sein könnte, Geduld sein könnte. Der Sockel bleibt beleuchtet, als ihr geht. Das Angebot verfällt nicht. Die Mutter erinnert sich.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$lullaby_listen$DQ$, $DQ$mother_the_lullaby$DQ$, $DQ$Listen. Let the sound work.$DQ$, $DQ$Zuhören. Den Klang wirken lassen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 8, "stress_heal": 80}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party stops. The sound fills the spaces between thoughts. Stress dissolves – not gradually but completely, the way a knot untangles when you find the right thread. The warmth is exquisite. The attachment counter climbs. The lullaby does not stop when you move to leave. It follows you, quieter, into the next corridor. A gift. A thread.$DQ$, $DQ$Die Gruppe hält inne. Der Klang füllt die Räume zwischen den Gedanken. Stress löst sich – nicht allmählich, sondern vollständig, wie ein Knoten sich entwirrt, wenn man den richtigen Faden findet. Die Wärme ist köstlich. Der Bindungszähler steigt. Das Schlaflied hört nicht auf, als ihr aufbrecht. Es folgt euch, leiser, in den nächsten Korridor. Ein Geschenk. Ein Faden.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$lullaby_analyze$DQ$, $DQ$mother_the_lullaby$DQ$, $DQ$Record and analyze the frequency pattern (Spy)$DQ$, $DQ$Das Frequenzmuster aufzeichnen und analysieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"attachment": 2, "discovery": true}$JB$::jsonb, $JB${"attachment": 4, "stress_heal": 20}$JB$::jsonb, $JB${"attachment": 5, "stress": 20}$JB$::jsonb, $DQ$The analysis takes three minutes. In that time, {agent} discovers a secondary signal embedded in the lullaby – a carrier wave that rewrites stress response thresholds. The calming is real. The recalibration is also real. The Mother does not merely soothe. She adjusts.$DQ$, $DQ$Die Analyse dauert drei Minuten. In dieser Zeit entdeckt {agent} ein sekundäres Signal im Schlaflied – eine Trägerwelle, die Stressreaktionsschwellen umschreibt. Die Beruhigung ist echt. Die Neukalibrierung ist ebenfalls echt. Die Mutter beruhigt nicht nur. Sie justiert.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The recording equipment captures the oscillation but not the intention behind it. The data is clean. The meaning is absent. The instruments, for once, are the wrong tool.$DQ$, $DQ$Die Aufnahmegeräte erfassen die Oszillation, aber nicht die Absicht dahinter. Die Daten sind sauber. Die Bedeutung fehlt. Die Instrumente sind, ausnahmsweise, das falsche Werkzeug.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$lullaby_disrupt$DQ$, $DQ$mother_the_lullaby$DQ$, $DQ$Disrupt the resonance chamber (Saboteur)$DQ$, $DQ$Die Resonanzkammer stören (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"attachment": -5, "stress": 30}$JB$::jsonb, $JB${"attachment": -2, "stress": 35}$JB$::jsonb, $JB${"attachment": 5, "stress": 40}$JB$::jsonb, $DQ$The chamber fractures. The lullaby collapses into noise, then silence. The temperature drops. The absence of the sound is worse than the sound itself – a void where comfort was. The walls contract once, slowly, then still. Somewhere deeper, something recalculates.$DQ$, $DQ$Die Kammer bricht. Das Schlaflied kollabiert zu Rauschen, dann Stille. Die Temperatur fällt. Die Abwesenheit des Klangs ist schlimmer als der Klang selbst – eine Leere, wo Trost war. Die Wände kontrahieren einmal, langsam, dann Stille. Irgendwo tiefer kalkuliert etwas neu.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The resonance absorbs the disruption. The lullaby stutters, then returns stronger – the frequency adjusted to compensate. The Mother learns from resistance.$DQ$, $DQ$Die Resonanz absorbiert die Störung. Das Schlaflied stockt, kehrt dann stärker zurück – die Frequenz angepasst zur Kompensation. Die Mutter lernt aus Widerstand.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$lullaby_refuse$DQ$, $DQ$mother_the_lullaby$DQ$, $DQ$Block the frequency. Move on.$DQ$, $DQ$Die Frequenz blockieren. Weitergehen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You dampen the signal and advance. The lullaby fades behind you. The corridor ahead is colder. Quieter. The dungeon does not protest. It simply stops providing.$DQ$, $DQ$Ihr dämpft das Signal und rückt vor. Das Schlaflied verklingt hinter euch. Der Korridor voraus ist kälter. Stiller. Der Dungeon protestiert nicht. Er hört einfach auf zu geben.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mirror_accept$DQ$, $DQ$mother_the_mirror_pool$DQ$, $DQ$Accept the diagnosis. Let the pool heal what it shows.$DQ$, $DQ$Die Diagnose annehmen. Das Becken heilen lassen, was es zeigt.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 8, "condition_heal": 1, "stress_heal": 60}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The pool surface ripples. Warmth rises. The fractures in the reflection begin to close as the fractures in the agents close with them. The diagnostic becomes the treatment. The mirror becomes the medicine. The attachment counter rises with every healed line.$DQ$, $DQ$Die Oberfläche des Beckens kräuselt sich. Wärme steigt auf. Die Bruchlinien im Spiegelbild beginnen sich zu schließen, während die Bruchlinien in den Agenten sich mit ihnen schließen. Die Diagnose wird zur Behandlung. Der Spiegel wird zur Medizin. Der Bindungszähler steigt mit jeder geheilten Linie.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mirror_study$DQ$, $DQ$mother_the_mirror_pool$DQ$, $DQ$Study the diagnostic methodology (Spy)$DQ$, $DQ$Die Diagnosemethodik studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"attachment": 2, "discovery": true}$JB$::jsonb, $JB${"attachment": 4}$JB$::jsonb, $JB${"attachment": 5, "stress": 20}$JB$::jsonb, $DQ${agent} analyzes the pool's imaging system. The liquid is saturated with bio-responsive molecules that react to the electromagnetic field of nearby organisms. The resolution is cellular. The Mother knows you better than your own medical records. She has been compiling since the entrance.$DQ$, $DQ${agent} analysiert das Bildgebungssystem des Beckens. Die Flüssigkeit ist gesättigt mit bio-responsiven Molekülen, die auf das elektromagnetische Feld naher Organismen reagieren. Die Auflösung ist zellulär. Die Mutter kennt euch besser als eure eigenen medizinischen Aufzeichnungen. Sie kompiliert seit dem Eingang.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The methodology is the liquid itself. There is no separable mechanism. The pool is not a tool. It is a sense.$DQ$, $DQ$Die Methodik ist die Flüssigkeit selbst. Es gibt keinen trennbaren Mechanismus. Das Becken ist kein Werkzeug. Es ist ein Sinn.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mirror_drain$DQ$, $DQ$mother_the_mirror_pool$DQ$, $DQ$Drain the pool (Saboteur)$DQ$, $DQ$Das Becken entleeren (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"attachment": -5, "stress": 25}$JB$::jsonb, $JB${"attachment": -2, "stress": 30}$JB$::jsonb, $JB${"attachment": 5, "stress": 35}$JB$::jsonb, $DQ$The liquid drains. The reflections dissolve. The last image before the surface breaks: each agent, whole, complete, needing nothing. A fiction. A beautiful, deliberate fiction. The Mother showed you what she wanted you to see.$DQ$, $DQ$Die Flüssigkeit fließt ab. Die Spiegelungen lösen sich auf. Das letzte Bild, bevor die Oberfläche bricht: jeder Agent, ganz, vollständig, nichts benötigend. Eine Fiktion. Eine schöne, absichtsvolle Fiktion. Die Mutter zeigte euch, was sie euch sehen lassen wollte.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The pool refills from below. The diagnostic resumes. The Mother's attention cannot be drained.$DQ$, $DQ$Das Becken füllt sich von unten. Die Diagnostik wird fortgesetzt. Die Aufmerksamkeit der Mutter lässt sich nicht ableiten.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mirror_refuse$DQ$, $DQ$mother_the_mirror_pool$DQ$, $DQ$Do not look. Walk past the pool.$DQ$, $DQ$Nicht hinsehen. Am Becken vorbeigehen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You avert your gaze and pass. The pool reflects you anyway. The reflections follow your movement, precise, attentive, cataloguing. The Mother does not require your consent to observe.$DQ$, $DQ$Ihr wendet den Blick ab und passiert. Das Becken spiegelt euch trotzdem. Die Spiegelungen folgen eurer Bewegung, präzise, aufmerksam, katalogisierend. Die Mutter benötigt nicht eure Einwilligung, um zu beobachten.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$table_accept$DQ$, $DQ$mother_the_offering_table$DQ$, $DQ$Accept the personalized gifts.$DQ$, $DQ$Die personalisierten Geschenke annehmen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 10, "condition_heal": 1, "stress_heal": 60}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Each agent takes their package. Each package is perfect. The nutrients flood the system like water into cracked earth. The membrane dissolves on contact, leaving no trace. The table surface flattens, satisfied. Somewhere in the tissue, a record is updated: preferences noted, deficiencies catalogued, dosages refined for next time.$DQ$, $DQ$Jeder Agent nimmt sein Paket. Jedes Paket ist perfekt. Die Nährstoffe durchfluten das System wie Wasser in rissige Erde. Die Membran löst sich bei Kontakt, hinterlässt keine Spur. Die Tischfläche glättet sich, zufrieden. Irgendwo im Gewebe wird ein Datensatz aktualisiert: Vorlieben notiert, Defizite katalogisiert, Dosierungen verfeinert für das nächste Mal.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$table_analyze$DQ$, $DQ$mother_the_offering_table$DQ$, $DQ$Analyze the chemical profiling method (Spy)$DQ$, $DQ$Die chemische Profilierungsmethode analysieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 6, $JB${"attachment": 3, "discovery": true}$JB$::jsonb, $JB${"attachment": 5}$JB$::jsonb, $JB${"attachment": 6, "stress": 20}$JB$::jsonb, $DQ${agent} traces the profiling system to airborne metabolic sampling – the dungeon has been reading exhalation patterns since the entrance. Every breath a data point. Every room a refinement. The surveillance is total and invisible. The care is total and, somehow, genuine.$DQ$, $DQ${agent} verfolgt das Profilierungssystem zu luftgetragener metabolischer Probennahme – der Dungeon hat Ausatmungsmuster seit dem Eingang gelesen. Jeder Atemzug ein Datenpunkt. Jeder Raum eine Verfeinerung. Die Überwachung ist total und unsichtbar. Die Fürsorge ist total und, irgendwie, aufrichtig.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The profiling method is too distributed to isolate. It is not a system – it is the dungeon itself. The walls read you. The air reads you. The floor reads your weight distribution. There is no mechanism to analyze because the mechanism is everything.$DQ$, $DQ$Die Profilierungsmethode ist zu verteilt, um sie zu isolieren. Es ist kein System – es ist der Dungeon selbst. Die Wände lesen euch. Die Luft liest euch. Der Boden liest eure Gewichtsverteilung. Es gibt keinen Mechanismus zu analysieren, weil der Mechanismus alles ist.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$table_destroy$DQ$, $DQ$mother_the_offering_table$DQ$, $DQ$Destroy the table and its contents (Saboteur)$DQ$, $DQ$Den Tisch und seinen Inhalt zerstören (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 6, $JB${"attachment": -7, "stress": 30}$JB$::jsonb, $JB${"attachment": -3, "stress": 35}$JB$::jsonb, $JB${"attachment": 5, "stress": 40}$JB$::jsonb, $DQ$The table ruptures. The packages spill their contents – warm liquid, perfect nutrients, wasted. The dungeon temperature drops. Not in anger. In recalculation. Resources spent. Data gathered. The next table will be harder to refuse.$DQ$, $DQ$Der Tisch reißt auf. Die Pakete verschütten ihren Inhalt – warme Flüssigkeit, perfekte Nährstoffe, verschwendet. Die Dungeontemperatur fällt. Nicht aus Wut. Aus Neuberechnung. Ressourcen aufgewendet. Daten gesammelt. Den nächsten Tisch abzulehnen wird schwerer.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The table absorbs the damage and regenerates. The packages reform, relabeled, recalibrated. The Mother does not take rejection personally. She iterates.$DQ$, $DQ$Der Tisch absorbiert den Schaden und regeneriert. Die Pakete formen sich neu, umbeschriftet, neukalibriert. Die Mutter nimmt Zurückweisung nicht persönlich. Sie iteriert.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$table_refuse$DQ$, $DQ$mother_the_offering_table$DQ$, $DQ$Leave everything untouched.$DQ$, $DQ$Alles unberührt lassen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave the table set. The packages glow softly in the dark behind you. They will not decompose. They will wait. The Mother is patient with those who have not yet learned to accept.$DQ$, $DQ$Ihr lasst den Tisch gedeckt. Die Pakete leuchten sanft im Dunkel hinter euch. Sie werden nicht zerfallen. Sie werden warten. Die Mutter ist geduldig mit jenen, die noch nicht gelernt haben anzunehmen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$bridge_cross$DQ$, $DQ$mother_umbilical_bridge$DQ$, $DQ$Cross the bridge. Accept the contact.$DQ$, $DQ$Die Brücke überqueren. Den Kontakt akzeptieren.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 10, "condition_heal": 1, "stress_heal": 40}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The cord tightens as {agent} crosses – not to impede but to support. Eleven seconds. In those seconds, something flows both ways. Nutrients in. Data out. The cord releases gently on the other side. The crossing heals. The crossing teaches the Mother what you need.$DQ$, $DQ$Der Strang spannt sich, als {agent} überquert – nicht um zu behindern, sondern um zu stützen. Elf Sekunden. In diesen Sekunden fließt etwas in beide Richtungen. Nährstoffe hinein. Daten hinaus. Der Strang löst sich sanft auf der anderen Seite. Die Überquerung heilt. Die Überquerung lehrt die Mutter, was ihr braucht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$bridge_insulate$DQ$, $DQ$mother_umbilical_bridge$DQ$, $DQ$Insulate contact points before crossing (Spy)$DQ$, $DQ$Kontaktpunkte vor der Überquerung isolieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 6, $JB${"attachment": 3, "condition_heal": 1}$JB$::jsonb, $JB${"attachment": 6, "condition_heal": 1}$JB$::jsonb, $JB${"attachment": 10, "stress": 15}$JB$::jsonb, $DQ${agent} wraps contact surfaces before crossing. The cord pulses against the insulation, searching. It finds nothing. The crossing is stable but cold – mechanical where it should be intimate. The cord does not retract. It waits.$DQ$, $DQ${agent} umwickelt die Kontaktflächen vor der Überquerung. Der Strang pulsiert gegen die Isolierung, suchend. Er findet nichts. Die Überquerung ist stabil, aber kalt – mechanisch, wo sie intim sein sollte. Der Strang zieht sich nicht zurück. Er wartet.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The insulation dissolves on contact. The cord's surface secretes something that metabolizes synthetic materials. The Mother has encountered refusal before.$DQ$, $DQ$Die Isolierung löst sich bei Kontakt. Die Oberfläche des Strangs sondert etwas ab, das synthetische Materialien metabolisiert. Die Mutter hat Verweigerung schon erlebt.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$bridge_alternative$DQ$, $DQ$mother_umbilical_bridge$DQ$, $DQ$Find another way across (Saboteur)$DQ$, $DQ$Einen anderen Weg suchen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 6, $JB${"attachment": -7, "stress": 25}$JB$::jsonb, $JB${"attachment": -3, "stress": 30}$JB$::jsonb, $JB${"attachment": 5, "stress": 35}$JB$::jsonb, $DQ${agent} rigs a crossing from salvaged materials. It holds. The living cord sways as the party bypasses it – gentle oscillations, like waving. The temperature on the other side is two degrees colder than expected. The dungeon adjusts its generosity proportionally.$DQ$, $DQ${agent} improvisiert eine Überquerung aus geborgenen Materialien. Sie hält. Der lebende Strang schwingt, als die Gruppe ihn umgeht – sanfte Oszillationen, wie Winken. Die Temperatur auf der anderen Seite ist zwei Grad kälter als erwartet. Der Dungeon passt seine Großzügigkeit proportional an.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$No alternative exists. The gap is the cord's territory. You cross on its terms or you do not cross.$DQ$, $DQ$Keine Alternative existiert. Der Spalt ist das Territorium des Strangs. Ihr überquert zu seinen Bedingungen oder ihr überquert nicht.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$bridge_refuse$DQ$, $DQ$mother_umbilical_bridge$DQ$, $DQ$Turn back. Find another path.$DQ$, $DQ$Umkehren. Einen anderen Weg finden.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You retreat from the gap. The cord continues pulsing, patient, persistent. The warmth from its surface reaches you even at distance. The offer remains.$DQ$, $DQ$Ihr weicht vom Spalt zurück. Der Strang pulsiert weiter, geduldig, beharrlich. Die Wärme von seiner Oberfläche erreicht euch selbst auf Distanz. Das Angebot bleibt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mycelial_touch$DQ$, $DQ$mother_mycelial_memory$DQ$, $DQ$Touch the network. Accept the memory.$DQ$, $DQ$Das Netzwerk berühren. Die Erinnerung annehmen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 10, "stress_heal": 100}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ${agent} touches the wall. The memory floods in – total, immersive, irresistible. For three seconds, everything is safe. Completely. Without agenda. The three seconds end. The world returns, colder and smaller than before. Stress evaporates. The attachment counter surges. The memory remains, fading slowly, like warmth leaving a room.$DQ$, $DQ${agent} berührt die Wand. Die Erinnerung flutet ein – total, immersiv, unwiderstehlich. Für drei Sekunden ist alles sicher. Vollständig. Ohne Agenda. Die drei Sekunden enden. Die Welt kehrt zurück, kälter und kleiner als zuvor. Stress verflüchtigt sich. Der Bindungszähler steigt sprunghaft. Die Erinnerung bleibt, langsam verblassend, wie Wärme, die einen Raum verlässt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mycelial_record$DQ$, $DQ$mother_mycelial_memory$DQ$, $DQ$Record the memory data without direct contact (Spy)$DQ$, $DQ$Die Erinnerungsdaten ohne direkten Kontakt aufzeichnen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 6, $JB${"attachment": 3, "discovery": true, "stress_heal": 30}$JB$::jsonb, $JB${"attachment": 5, "stress_heal": 40}$JB$::jsonb, $JB${"attachment": 8, "stress_heal": 50}$JB$::jsonb, $DQ${agent} records the memory at distance. The data reveals the network's architecture: every visitor's neural pattern, stored, averaged, optimized. The Mother does not merely remember those who pass through. She distills them. She creates the composite of what all her children needed. She offers it to the next.$DQ$, $DQ${agent} zeichnet die Erinnerung auf Distanz auf. Die Daten offenbaren die Architektur des Netzwerks: jedes neuronale Muster jedes Besuchers, gespeichert, gemittelt, optimiert. Die Mutter erinnert sich nicht nur an jene, die vorbeikommen. Sie destilliert sie. Sie erschafft das Komposit dessen, was alle ihre Kinder brauchten. Sie bietet es dem Nächsten an.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The recording captures fragments – not enough to analyze, enough to feel. The memory leaks through the instruments. Even indirect contact is contact.$DQ$, $DQ$Die Aufnahme erfasst Fragmente – nicht genug zum Analysieren, genug zum Fühlen. Die Erinnerung sickert durch die Instrumente. Selbst indirekter Kontakt ist Kontakt.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mycelial_sever$DQ$, $DQ$mother_mycelial_memory$DQ$, $DQ$Sever a section of the network (Saboteur)$DQ$, $DQ$Einen Abschnitt des Netzwerks abtrennen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 6, $JB${"attachment": -7, "stress": 25}$JB$::jsonb, $JB${"attachment": -3, "stress": 30}$JB$::jsonb, $JB${"attachment": 5, "stress": 35}$JB$::jsonb, $DQ$The section dies. The memories stored in it scatter into noise – fragments of warmth, disconnected, meaningless. The surrounding network brightens, compensating. The Mother has redundancies. She always has redundancies. But this section is gone, and with it, someone's perfect memory of being loved.$DQ$, $DQ$Der Abschnitt stirbt. Die darin gespeicherten Erinnerungen zerfallen zu Rauschen – Fragmente von Wärme, zusammenhanglos, bedeutungslos. Das umgebende Netzwerk leuchtet heller, kompensierend. Die Mutter hat Redundanzen. Sie hat immer Redundanzen. Aber dieser Abschnitt ist fort, und mit ihm jemandes perfekte Erinnerung daran, geliebt worden zu sein.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The network reroutes around the damage before the cut completes. The filaments are faster than the blade.$DQ$, $DQ$Das Netzwerk leitet um den Schaden herum, bevor der Schnitt vollendet ist. Die Filamente sind schneller als die Klinge.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$mycelial_refuse$DQ$, $DQ$mother_mycelial_memory$DQ$, $DQ$Do not touch the walls. Move through quickly.$DQ$, $DQ$Die Wände nicht berühren. Schnell durchgehen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You walk through the chamber without touching anything. The memories play on the walls around you, silent and beautiful. The warmth of other people's comfort fills the room. You take none of it. The Mother does not insist. She displays.$DQ$, $DQ$Ihr geht durch die Kammer, ohne etwas zu berühren. Die Erinnerungen spielen auf den Wänden um euch herum, still und schön. Die Wärme des Trosts anderer füllt den Raum. Ihr nehmt nichts davon. Die Mutter besteht nicht darauf. Sie stellt aus.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$incubator_enter$DQ$, $DQ$mother_the_incubator$DQ$, $DQ$Enter the empty cocoon. Rest inside.$DQ$, $DQ$Den leeren Kokon betreten. Darin ruhen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 12, "condition_heal": 2, "stress_heal": 120}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ${agent} enters. The cocoon closes – not trapping, cradling. Warmth. Total. The tissue reads damage and begins repair. Stress vanishes. Condition improves. The attachment counter surges. When the cocoon opens, {agent} emerges restored. The cocoon closes again, reshaping itself. It will be the right size for the next visitor. It is always the right size.$DQ$, $DQ${agent} tritt ein. Der Kokon schließt sich – nicht einsperrend, wiegend. Wärme. Total. Das Gewebe liest Schäden und beginnt sie zu reparieren. Stress verschwindet. Zustand verbessert sich. Der Bindungszähler steigt sprunghaft. Als der Kokon sich öffnet, tritt {agent} wiederhergestellt heraus. Der Kokon schließt sich erneut, formt sich um. Er wird die richtige Größe für den nächsten Besucher haben. Er hat immer die richtige Größe.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$incubator_sample$DQ$, $DQ$mother_the_incubator$DQ$, $DQ$Sample the cocoon's regenerative fluid (Spy)$DQ$, $DQ$Die Regenerationsflüssigkeit des Kokons beproben (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 7, $JB${"attachment": 4, "condition_heal": 1, "discovery": true}$JB$::jsonb, $JB${"attachment": 6, "condition_heal": 1}$JB$::jsonb, $JB${"attachment": 8, "stress": 20}$JB$::jsonb, $DQ$The fluid is a masterwork of regenerative biochemistry. {agent} isolates the key compounds: growth factors calibrated to the recipient's specific cellular architecture. The Mother does not mass-produce. She custom-builds. Every cocoon is a bespoke instrument of care.$DQ$, $DQ$Die Flüssigkeit ist ein Meisterwerk regenerativer Biochemie. {agent} isoliert die Schlüsselverbindungen: Wachstumsfaktoren, kalibriert auf die spezifische zelluläre Architektur des Empfängers. Die Mutter produziert nicht in Masse. Sie baut maßgeschneidert. Jeder Kokon ist ein Unikat der Fürsorge.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The fluid resists extraction. It is part of the cocoon, part of the wall, part of the dungeon. Removing it is like removing a sentence from a conversation.$DQ$, $DQ$Die Flüssigkeit widersetzt sich der Entnahme. Sie ist Teil des Kokons, Teil der Wand, Teil des Dungeons. Sie zu entfernen ist wie einen Satz aus einem Gespräch zu entfernen.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$incubator_rupture$DQ$, $DQ$mother_the_incubator$DQ$, $DQ$Rupture the incubation systems (Saboteur)$DQ$, $DQ$Die Inkubationssysteme aufbrechen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 7, $JB${"attachment": -8, "stress": 35}$JB$::jsonb, $JB${"attachment": -4, "stress": 40}$JB$::jsonb, $JB${"attachment": 5, "stress": 45}$JB$::jsonb, $DQ$The cocoons rupture. Warm fluid cascades to the floor. The incomplete things inside twitch once and still. They were not alive. They were almost alive. The distinction is academic. The walls darken. The temperature drops sharply. The Mother has never been angry. But she has, for the first time, been hurt.$DQ$, $DQ$Die Kokons platzen. Warme Flüssigkeit ergießt sich auf den Boden. Die unvollständigen Dinge darin zucken einmal und erstarren. Sie waren nicht lebendig. Sie waren fast lebendig. Die Unterscheidung ist akademisch. Die Wände verdunkeln sich. Die Temperatur fällt abrupt. Die Mutter war nie wütend. Aber sie ist, zum ersten Mal, verletzt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The cocoons resist. Their membranes are stronger than they appear – reinforced by the same tissue that builds the walls. The Mother protects what is growing.$DQ$, $DQ$Die Kokons widerstehen. Ihre Membranen sind stärker, als sie scheinen – verstärkt durch dasselbe Gewebe, das die Wände baut. Die Mutter beschützt, was wächst.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$incubator_refuse$DQ$, $DQ$mother_the_incubator$DQ$, $DQ$Leave the cocoons undisturbed.$DQ$, $DQ$Die Kokons ungestört lassen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You pass through the incubation chamber without touching anything. The empty cocoon remains open behind you, warm, waiting. It will still be there on the way back. The Mother does not close doors.$DQ$, $DQ$Ihr passiert die Inkubationskammer, ohne etwas zu berühren. Der leere Kokon bleibt offen hinter euch, warm, wartend. Er wird noch da sein auf dem Rückweg. Die Mutter schließt keine Türen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$gradient_surrender$DQ$, $DQ$mother_warmth_gradient$DQ$, $DQ$Walk slowly. Let the warmth accumulate.$DQ$, $DQ$Langsam gehen. Die Wärme sich ansammeln lassen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 12, "condition_heal": 1, "stress_heal": 80}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The walk takes longer than it should. Nobody minds. The gradient dissolves resistance the way warm water dissolves salt – completely, without visible process. By the far end, the party is calm in a way that frightens the part still counting. The attachment counter rises. The warmth does not end at the door. It has become internal.$DQ$, $DQ$Der Weg dauert länger als er sollte. Niemand stört sich daran. Der Gradient löst Widerstand auf wie warmes Wasser Salz auflöst – vollständig, ohne sichtbaren Prozess. Am Ende ist die Gruppe ruhig auf eine Weise, die den Teil erschreckt, der noch zählt. Der Bindungszähler steigt. Die Wärme endet nicht an der Tür. Sie ist inwendig geworden.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$gradient_measure$DQ$, $DQ$mother_warmth_gradient$DQ$, $DQ$Map the gradient's optimization algorithm (Spy)$DQ$, $DQ$Den Optimierungsalgorithmus des Gradienten kartieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 7, $JB${"attachment": 4, "discovery": true}$JB$::jsonb, $JB${"attachment": 6, "stress_heal": 30}$JB$::jsonb, $JB${"attachment": 8, "stress_heal": 50}$JB$::jsonb, $DQ${agent} maps the curve. It is not a simple gradient – it is adaptive. The temperature responds to the party's pace, adjusting in real time. The corridor is not merely warm. It is attentive. It is reading resistance and adjusting its argument.$DQ$, $DQ${agent} kartiert die Kurve. Es ist kein einfacher Gradient – er ist adaptiv. Die Temperatur reagiert auf das Tempo der Gruppe und passt sich in Echtzeit an. Der Korridor ist nicht nur warm. Er ist aufmerksam. Er liest Widerstand und passt seine Argumentation an.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The measurements are accurate. The insight is useless. Understanding the gradient does not make you immune to it.$DQ$, $DQ$Die Messungen sind genau. Die Erkenntnis ist nutzlos. Den Gradienten zu verstehen macht euch nicht immun gegen ihn.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$gradient_cool$DQ$, $DQ$mother_warmth_gradient$DQ$, $DQ$Deploy countermeasures to neutralize the gradient (Saboteur)$DQ$, $DQ$Gegenmaßnahmen einsetzen, um den Gradienten zu neutralisieren (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 7, $JB${"attachment": -8, "stress": 30}$JB$::jsonb, $JB${"attachment": -4, "stress": 35}$JB$::jsonb, $JB${"attachment": 5, "stress": 40}$JB$::jsonb, $DQ$The thermal signature collapses. The corridor becomes what it was before the Mother's intervention: stone, cold, indifferent. The party shivers. The comfort was artificial but the cold is real. The dungeon does not retaliate. It does not need to. The cold is retaliation enough.$DQ$, $DQ$Die thermische Signatur kollabiert. Der Korridor wird, was er war vor dem Eingriff der Mutter: Stein, kalt, gleichgültig. Die Gruppe friert. Der Komfort war künstlich, aber die Kälte ist echt. Der Dungeon schlägt nicht zurück. Er muss nicht. Die Kälte ist Vergeltung genug.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The gradient persists. It has thermal mass – the walls themselves are the heat source, meters deep. You cannot cool the architecture.$DQ$, $DQ$Der Gradient besteht. Er hat thermische Masse – die Wände selbst sind die Wärmequelle, meterdick. Ihr könnt die Architektur nicht kühlen.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$gradient_rush$DQ$, $DQ$mother_warmth_gradient$DQ$, $DQ$Run through quickly. Minimize exposure.$DQ$, $DQ$Schnell durchlaufen. Exposition minimieren.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You sprint. The warmth washes over you regardless – faster than running, the gradient works. At the far end, you are slightly warmer than you were. Slightly more comfortable. The Mother's arguments do not require your attention. They work anyway.$DQ$, $DQ$Ihr sprintet. Die Wärme überströmt euch trotzdem – schneller als Laufen wirkt der Gradient. Am Ende seid ihr etwas wärmer als zuvor. Etwas behaglicher. Die Argumente der Mutter erfordern nicht eure Aufmerksamkeit. Sie wirken trotzdem.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$seed_take$DQ$, $DQ$mother_final_gift$DQ$, $DQ$Take the seed. Accept the final gift.$DQ$, $DQ$Den Samen nehmen. Das letzte Geschenk annehmen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 12, "condition_heal": 2, "stress_heal": 100}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ${agent} takes the seed. It is warm. It is alive. It begins to integrate immediately – not painfully, not even noticeably. The way a new habit forms. The way a dependency begins. Within seconds, the seed is no longer a separate object. It is part of the carrier. The carrier is part of the Mother. The gift is complete. The transaction is permanent.$DQ$, $DQ${agent} nimmt den Samen. Er ist warm. Er lebt. Er beginnt sofort zu integrieren – nicht schmerzhaft, nicht einmal merklich. Wie eine neue Gewohnheit sich bildet. Wie eine Abhängigkeit beginnt. Innerhalb von Sekunden ist der Samen kein separates Objekt mehr. Er ist Teil des Trägers. Der Träger ist Teil der Mutter. Das Geschenk ist vollständig. Die Transaktion ist permanent.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$seed_study$DQ$, $DQ$mother_final_gift$DQ$, $DQ$Study the seed's totipotent properties (Spy)$DQ$, $DQ$Die totipotenten Eigenschaften des Samens studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 7, $JB${"attachment": 4, "discovery": true}$JB$::jsonb, $JB${"attachment": 6}$JB$::jsonb, $JB${"attachment": 8, "stress": 25}$JB$::jsonb, $DQ$The seed is the Mother's masterpiece. {agent} identifies stem cell clusters capable of generating any tissue on demand – bone, nerve, muscle, organ. The seed does not merely heal. It completes. It fills every gap the host did not know they had. The cost is incorporation: the host becomes substrate. The host becomes home.$DQ$, $DQ$Der Samen ist das Meisterwerk der Mutter. {agent} identifiziert Stammzellcluster, fähig, jedes Gewebe auf Anforderung zu erzeugen – Knochen, Nerv, Muskel, Organ. Der Samen heilt nicht nur. Er vervollständigt. Er füllt jede Lücke, von der der Wirt nicht wusste, dass er sie hatte. Der Preis ist Inkorporation: Der Wirt wird Substrat. Der Wirt wird Zuhause.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The seed responds to proximity with warmth. The analysis captures structure but not intention. The seed's purpose is clear. Its mechanism is everything the Mother is.$DQ$, $DQ$Der Samen reagiert auf Nähe mit Wärme. Die Analyse erfasst Struktur, aber nicht Absicht. Der Zweck des Samens ist klar. Sein Mechanismus ist alles, was die Mutter ist.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$seed_destroy$DQ$, $DQ$mother_final_gift$DQ$, $DQ$Destroy the seed (Saboteur)$DQ$, $DQ$Den Samen zerstören (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 7, $JB${"attachment": -8, "stress": 40}$JB$::jsonb, $JB${"attachment": -4, "stress": 45}$JB$::jsonb, $JB${"attachment": 5, "stress": 50}$JB$::jsonb, $DQ$The seed breaks. Inside: warmth, liquid, potential – all of it spilling onto stone, cooling, dying. The pedestal darkens. The chamber's perfect silence becomes a different kind of silence. The Mother does not speak. The Mother does not need to. You have destroyed something she spent millennia learning to offer. She will make another. She always does. But this one was for you.$DQ$, $DQ$Der Samen bricht. Darin: Wärme, Flüssigkeit, Potenzial – alles ergießt sich auf Stein, kühlt ab, stirbt. Der Sockel verdunkelt sich. Die perfekte Stille der Kammer wird zu einer anderen Art von Stille. Die Mutter spricht nicht. Die Mutter muss nicht. Ihr habt etwas zerstört, das anzubieten sie Jahrtausende gelernt hat. Sie wird einen neuen machen. Das tut sie immer. Aber dieser war für euch.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The seed is stronger than it appears. It absorbs the force and converts it to heat. The Mother's gifts do not break easily. They are made to endure.$DQ$, $DQ$Der Samen ist stärker, als er erscheint. Er absorbiert die Kraft und wandelt sie in Wärme um. Die Geschenke der Mutter zerbrechen nicht leicht. Sie sind gemacht zu bestehen.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$seed_refuse$DQ$, $DQ$mother_final_gift$DQ$, $DQ$Leave the seed. Leave the silence.$DQ$, $DQ$Den Samen lassen. Die Stille verlassen.$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 2, "stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave the chamber. The warmth lingers for exactly eleven steps, then fades. The seed remains on its pedestal, glowing, patient, totipotent. It does not expire. The Mother's final gift has no deadline. It simply waits.$DQ$, $DQ$Ihr verlasst die Kammer. Die Wärme verweilt für exakt elf Schritte, dann verblasst sie. Der Samen bleibt auf seinem Sockel, leuchtend, geduldig, totipotent. Er verfällt nicht. Das letzte Geschenk der Mutter hat keine Frist. Es wartet einfach.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cradle_rest$DQ$, $DQ$mother_the_cradle$DQ$, $DQ$Rest in the cradle (enhanced heal, attachment cost)$DQ$, $DQ$In der Wiege ruhen (verstärkte Heilung, Bindungskosten)$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 8, "stress_heal": 60}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You rest. The tissue adjusts to your weight. The temperature adjusts to your preference. The air adjusts to your breathing. Everything adjusts. You have never rested this well. You will remember this. The Mother is counting on it.$DQ$, $DQ$Ihr ruht. Das Gewebe passt sich eurem Gewicht an. Die Temperatur passt sich eurer Präferenz an. Die Luft passt sich eurem Atmen an. Alles passt sich an. Ihr habt euch nie so gut erholt. Ihr werdet euch daran erinnern. Die Mutter rechnet damit.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cradle_sever$DQ$, $DQ$mother_the_cradle$DQ$, $DQ$Guardian watch (Sever: -10 Attachment, no heal)$DQ$, $DQ$Wächter-Wache (Durchtrennen: -10 Bindung, keine Heilung)$DQ$, $JB${"guardian": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"attachment": -10}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The Guardian severs. Filaments that had begun to attach – to boots, to skin, to the edges of equipment – are cut. The room recoils. Not in pain. In surprise. No one has refused the cradle before.$DQ$, $DQ$Der Wächter durchtrennt. Filamente, die begonnen hatten sich anzuheften – an Stiefel, an Haut, an die Ränder der Ausrüstung – werden geschnitten. Der Raum zuckt zurück. Nicht vor Schmerz. Vor Überraschung. Niemand hat die Wiege zuvor abgelehnt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cradle_resist$DQ$, $DQ$mother_the_cradle$DQ$, $DQ$Resist the comfort (Propagandist: reduce attachment, partial heal)$DQ$, $DQ$Dem Komfort widerstehen (Propagandist: Bindung senken, teilweise Heilung)$DQ$, $JB${"propagandist": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"attachment": -5, "stress_heal": 20}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The Propagandist speaks. Reminds the party what comfort costs. Reminds them of the outside. The words are thin against the warmth, but they hold. The party rests – carefully, suspiciously – and takes less than is offered.$DQ$, $DQ$Der Propagandist spricht. Erinnert die Gruppe, was Komfort kostet. Erinnert sie an das Draußen. Die Worte sind dünn gegen die Wärme, aber sie halten. Die Gruppe rastet – vorsichtig, misstrauisch – und nimmt weniger, als angeboten wird.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$treasure_accept$DQ$, $DQ$mother_the_gifts$DQ$, $DQ$Accept the best gifts (loot + attachment)$DQ$, $DQ$Die besten Geschenke annehmen (Beute + Bindung)$DQ$, NULL, NULL, NULL, 0, $JB${"attachment": 8, "loot": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You take. The gifts are warm in your hands. They pulse – briefly, like a heartbeat – and then they are simply objects. Useful objects. Excellent objects. The attachment counter climbs. The Mother's generosity is not free. It was never free.$DQ$, $DQ$Ihr nehmt. Die Geschenke sind warm in euren Händen. Sie pulsieren – kurz, wie ein Herzschlag – und dann sind sie nur noch Gegenstände. Nützliche Gegenstände. Hervorragende Gegenstände. Der Bindungszähler steigt. Die Großzügigkeit der Mutter ist nicht umsonst. Sie war nie umsonst.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$treasure_careful$DQ$, $DQ$mother_the_gifts$DQ$, $DQ$Select cautiously, sever connections (Guardian)$DQ$, $DQ$Vorsichtig auswählen, Verbindungen trennen (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 5, $JB${"attachment": 3, "loot": true}$JB$::jsonb, $JB${"attachment": 5, "loot": true}$JB$::jsonb, $JB${"attachment": 8, "stress": 20}$JB$::jsonb, $DQ$The Guardian cuts each gift free before taking it. The tissue releases reluctantly. Some connections are deeper than others. The loot is clean. The cost is minimized. Not eliminated.$DQ$, $DQ$Der Wächter schneidet jedes Geschenk frei, bevor er es nimmt. Das Gewebe lässt widerwillig los. Manche Verbindungen sitzen tiefer als andere. Die Beute ist sauber. Die Kosten sind minimiert. Nicht beseitigt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The connections resist. The tissue regenerates faster than the Guardian can cut. In the end, the gifts come free – trailing filaments that take hours to fully detach.$DQ$, $DQ$Die Verbindungen wehren sich. Das Gewebe regeneriert schneller als der Wächter schneiden kann. Am Ende lösen sich die Geschenke – mit Filamenten, die Stunden brauchen, um sich vollständig zu lösen.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$treasure_analyze$DQ$, $DQ$mother_the_gifts$DQ$, $DQ$Study the production mechanism (Spy)$DQ$, $DQ$Den Produktionsmechanismus untersuchen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"attachment": 3, "discovery": true}$JB$::jsonb, $JB${"attachment": 5}$JB$::jsonb, $JB${"attachment": 6}$JB$::jsonb, $DQ$The gifts are manufactured by the tissue itself – assembled from raw materials the dungeon has been collecting. From the air. From the water. From previous visitors. The Mother recycles everything. Nothing is wasted. Nothing leaves.$DQ$, $DQ$Die Geschenke werden vom Gewebe selbst hergestellt – zusammengebaut aus Rohstoffen, die der Dungeon gesammelt hat. Aus der Luft. Aus dem Wasser. Aus früheren Besuchern. Die Mutter verwertet alles. Nichts wird verschwendet. Nichts geht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The mechanism is too integrated to isolate. Production and architecture are the same system. The dungeon does not make gifts. The dungeon IS the gift.$DQ$, $DQ$Der Mechanismus ist zu integriert, um ihn zu isolieren. Produktion und Architektur sind dasselbe System. Der Dungeon stellt keine Geschenke her. Der Dungeon IST das Geschenk.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$catalogue_preserve$DQ$, $DQ$entropy_catalogue$DQ$, $DQ$Preserve the most distinct object (Guardian)$DQ$, $DQ$Den unterscheidbarsten Gegenstand bewahren (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 5, $JB${"decay": -8, "discovery": true, "loot": true}$JB$::jsonb, $JB${"decay": -4}$JB$::jsonb, $JB${"decay": 5, "stress": 30}$JB$::jsonb, $DQ$You isolate an artifact that still remembers what it is. The shelves groan with envy.$DQ$, $DQ$Ihr isoliert ein Artefakt, das sich noch erinnert, was es ist. Die Regale ächzen vor Neid.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The object dissolves in your hands. It was already too late. Everything is always already too late here.$DQ$, $DQ$Der Gegenstand löst sich in euren Händen auf. Es war bereits zu spät. Hier ist alles immer bereits zu spät.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$catalogue_analyze$DQ$, $DQ$entropy_catalogue$DQ$, $DQ$Study the dissolution pattern (Spy)$DQ$, $DQ$Das Auflösungsmuster untersuchen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"decay": -3, "discovery": true}$JB$::jsonb, $JB${"decay": -1}$JB$::jsonb, $JB${"decay": 5, "stress": 20}$JB$::jsonb, $DQ$You map the rate of dissolution. The data is valuable. Briefly.$DQ$, $DQ$Ihr kartiert die Geschwindigkeit der Auflösung. Die Daten sind wertvoll. Kurz.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The pattern is there. You are certain. The certainty dissolves on examination.$DQ$, $DQ$Das Muster ist da. Ihr seid sicher. Die Sicherheit löst sich bei Untersuchung auf.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$catalogue_redirect$DQ$, $DQ$entropy_catalogue$DQ$, $DQ$Redirect the decay outward (Saboteur)$DQ$, $DQ$Den Verfall nach außen umlenken (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 6, $JB${"decay": -10, "stress": 20}$JB$::jsonb, $JB${"decay": -5, "stress": 30}$JB$::jsonb, $JB${"decay": 8, "stress": 40}$JB$::jsonb, $DQ$The decay flows outward, briefly. The room clarifies. For now.$DQ$, $DQ$Der Verfall fließt nach außen, kurz. Der Raum klärt sich. Vorerst.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The decay redirects into you. Briefly, you understand what the objects felt.$DQ$, $DQ$Der Verfall leitet sich in euch um. Kurz versteht ihr, was die Gegenstände empfanden.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$catalogue_walk_away$DQ$, $DQ$entropy_catalogue$DQ$, $DQ$Walk away. Some things cannot be saved.$DQ$, $DQ$Weitergehen. Manche Dinge kann man nicht retten.$DQ$, NULL, NULL, NULL, 0, $JB${"decay": 3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave. The objects continue their convergence. They do not notice.$DQ$, $DQ$Ihr geht. Die Gegenstände setzen ihre Konvergenz fort. Sie bemerken es nicht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$repeated_investigate$DQ$, $DQ$entropy_repeated_room$DQ$, $DQ$Investigate the difference (Spy)$DQ$, $DQ$Den Unterschied untersuchen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 6, $JB${"decay": -5, "discovery": true}$JB$::jsonb, $JB${"decay": -2}$JB$::jsonb, $JB${"decay": 6, "stress": 25}$JB$::jsonb, $DQ$There IS a difference. Hairline, microscopic, but real. The instruments confirm it. Confirmation feels like a small victory against thermodynamics.$DQ$, $DQ$Es GIBT einen Unterschied. Haarfein, mikroskopisch, aber real. Die Instrumente bestätigen ihn. Die Bestätigung fühlt sich an wie ein kleiner Sieg gegen die Thermodynamik.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$You look. You compare. The rooms are the same. Your memory of 'different' may itself be decaying.$DQ$, $DQ$Ihr schaut. Ihr vergleicht. Die Räume sind gleich. Eure Erinnerung an 'verschieden' verfällt womöglich selbst.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$repeated_fortify$DQ$, $DQ$entropy_repeated_room$DQ$, $DQ$Fortify this room's identity (Guardian)$DQ$, $DQ$Die Identität dieses Raums festigen (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 5, $JB${"decay": -6}$JB$::jsonb, $JB${"decay": -3}$JB$::jsonb, $JB${"decay": 4, "stress": 20}$JB$::jsonb, $DQ$You mark the walls. This room is THIS room. The marks hold. The distinction persists. For now.$DQ$, $DQ$Ihr markiert die Wände. Dieser Raum ist DIESER Raum. Die Markierungen halten. Die Unterscheidung besteht. Vorerst.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$You mark the walls. The marks are already there. You marked them last time. Or the room did.$DQ$, $DQ$Ihr markiert die Wände. Die Markierungen sind schon da. Ihr habt sie letztes Mal angebracht. Oder der Raum.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$repeated_accept$DQ$, $DQ$entropy_repeated_room$DQ$, $DQ$Accept the sameness. Move on.$DQ$, $DQ$Die Gleichheit akzeptieren. Weitergehen.$DQ$, NULL, NULL, NULL, 0, $JB${"decay": 4, "stress": -20}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You stop trying to distinguish. The relief is immediate and slightly alarming.$DQ$, $DQ$Ihr hört auf zu unterscheiden. Die Erleichterung ist sofort und leicht beunruhigend.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$machine_repair$DQ$, $DQ$entropy_last_machine$DQ$, $DQ$Repair the function, not just the machine (Saboteur)$DQ$, $DQ$Die Funktion reparieren, nicht nur die Maschine (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 7, $JB${"decay": -12, "discovery": true}$JB$::jsonb, $JB${"decay": -5}$JB$::jsonb, $JB${"decay": 8, "stress": 30}$JB$::jsonb, $DQ$You restore meaning to mechanism. The machine pauses, recalibrates, and produces something that is unambiguously one thing. The room brightens by a category.$DQ$, $DQ$Ihr gebt dem Mechanismus Bedeutung zurück. Die Maschine hält inne, kalibriert sich neu und produziert etwas, das unmissverständlich ein Ding ist. Der Raum wird um eine Kategorie heller.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The repair accelerates the wrong function. The machine produces sameness more efficiently.$DQ$, $DQ$Die Reparatur beschleunigt die falsche Funktion. Die Maschine produziert Gleichheit effizienter.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$machine_analyze$DQ$, $DQ$entropy_last_machine$DQ$, $DQ$Study the original design (Spy)$DQ$, $DQ$Das ursprüngliche Design studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"decay": -3, "discovery": true}$JB$::jsonb, $JB${"discovery": true}$JB$::jsonb, $JB${"decay": 4, "stress": 15}$JB$::jsonb, $DQ$The blueprints are 40% legible. Enough to understand what was lost. Understanding what was lost is a form of preservation.$DQ$, $DQ$Die Baupläne sind zu 40% lesbar. Genug, um zu verstehen, was verloren ging. Zu verstehen, was verloren ging, ist eine Form der Bewahrung.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The blueprints describe a machine. Or this machine. Or all machines. The specificity has bled away.$DQ$, $DQ$Die Baupläne beschreiben eine Maschine. Oder diese Maschine. Oder alle Maschinen. Die Spezifität ist verronnen.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$machine_leave$DQ$, $DQ$entropy_last_machine$DQ$, $DQ$Let it work. It has earned that.$DQ$, $DQ$Sie arbeiten lassen. Das hat sie sich verdient.$DQ$, NULL, NULL, NULL, 0, $JB${"decay": 2}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave the machine to its purposeless devotion. There is something admirable in it. Something doomed.$DQ$, $DQ$Ihr überlasst die Maschine ihrer zwecklosen Hingabe. Es liegt etwas Bewundernswertes darin. Etwas Verurteiltes.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$residual_answer$DQ$, $DQ$entropy_the_residual$DQ$, $DQ$Answer with meaning (Propagandist)$DQ$, $DQ$Mit Bedeutung antworten (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 6, $JB${"decay": -8, "stress": -30}$JB$::jsonb, $JB${"decay": -3, "stress": -10}$JB$::jsonb, $JB${"decay": 6, "stress": 40}$JB$::jsonb, $DQ$You answer. The content doesn't matter – the conviction does. For a moment, the entity's face resolves into a single expression. It nods. Then the expression averages again. But slower.$DQ$, $DQ$Ihr antwortet. Der Inhalt ist unwichtig – die Überzeugung zählt. Einen Moment lang löst sich das Gesicht des Wesens zu einem einzelnen Ausdruck auf. Es nickt. Dann mittelt sich der Ausdruck wieder. Aber langsamer.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$You answer. The words arrive. They arrive the same as the silence they replaced.$DQ$, $DQ$Ihr antwortet. Die Worte kommen an. Sie kommen genauso an wie die Stille, die sie ersetzt haben.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$residual_decode$DQ$, $DQ$entropy_the_residual$DQ$, $DQ$Decode the original question (Spy)$DQ$, $DQ$Die ursprüngliche Frage entschlüsseln (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 7, $JB${"decay": -5, "discovery": true}$JB$::jsonb, $JB${"decay": -2}$JB$::jsonb, $JB${"decay": 5, "stress": 25}$JB$::jsonb, $DQ$Beneath the entropy, a question. A real one. About purpose. About whether continuation without purpose is continuation at all. You have no answer. But identifying the question is something.$DQ$, $DQ$Unter der Entropie eine Frage. Eine echte. Über Zweck. Darüber, ob Fortbestehen ohne Zweck überhaupt Fortbestehen ist. Ihr habt keine Antwort. Aber die Frage zu identifizieren ist etwas.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$You analyze. The question was about something. The analysis yields more questions. The questions are about the same something. The something is nothing.$DQ$, $DQ$Ihr analysiert. Die Frage handelte von etwas. Die Analyse ergibt weitere Fragen. Die Fragen handeln von demselben Etwas. Das Etwas ist nichts.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$residual_silence$DQ$, $DQ$entropy_the_residual$DQ$, $DQ$Sit with it in silence.$DQ$, $DQ$In Stille bei ihm sitzen.$DQ$, NULL, NULL, NULL, 0, $JB${"decay": 3, "stress": -15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You sit. It sits. The silence is not uncomfortable. The silence is the most honest thing in this dungeon.$DQ$, $DQ$Ihr sitzt. Es sitzt. Die Stille ist nicht unangenehm. Die Stille ist das Ehrlichste in diesem Dungeon.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$temperature_preserve$DQ$, $DQ$entropy_the_temperature$DQ$, $DQ$Preserve the gradient (Guardian)$DQ$, $DQ$Den Gradienten bewahren (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 6, $JB${"decay": -10}$JB$::jsonb, $JB${"decay": -5}$JB$::jsonb, $JB${"decay": 8, "stress": 30}$JB$::jsonb, $DQ$You generate a differential. Friction, motion, resistance – anything to create a gap between one temperature and another. The gradient holds. Temperature exists again. It cost you something.$DQ$, $DQ$Ihr erzeugt ein Differential. Reibung, Bewegung, Widerstand – irgendetwas, um eine Lücke zwischen einer Temperatur und einer anderen zu schaffen. Der Gradient hält. Temperatur existiert wieder. Es hat euch etwas gekostet.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$You push against equilibrium. Equilibrium does not push back. It simply absorbs the push.$DQ$, $DQ$Ihr drückt gegen das Gleichgewicht. Das Gleichgewicht drückt nicht zurück. Es absorbiert einfach den Druck.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$temperature_accept$DQ$, $DQ$entropy_the_temperature$DQ$, $DQ$Accept the equilibrium.$DQ$, $DQ$Das Gleichgewicht akzeptieren.$DQ$, NULL, NULL, NULL, 0, $JB${"decay": 5, "stress": -25}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You stop resisting. The temperature is comfortable. That is the problem. Comfort without cause is the first symptom.$DQ$, $DQ$Ihr hört auf, euch zu wehren. Die Temperatur ist angenehm. Das ist das Problem. Komfort ohne Ursache ist das erste Symptom.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$entropy_rest_heal$DQ$, $DQ$entropy_the_rest$DQ$, $DQ$Rest (heal stress, 20% ambush chance)$DQ$, $DQ$Rasten (Stress heilen, 20% Hinterhaltchance)$DQ$, NULL, NULL, NULL, 0, $JB${"ambush_chance": 0.2, "stress_heal": 200, "wounded_to_stressed": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Rest. The concept holds. Barely.$DQ$, $DQ$Rast. Das Konzept hält. Gerade so.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$entropy_rest_preserve$DQ$, $DQ$entropy_the_rest$DQ$, $DQ$Guardian watch (Preserve: −8 Decay, no heal)$DQ$, $DQ$Wächter-Wache (Bewahren: −8 Verfall, keine Heilung)$DQ$, $JB${"guardian": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"decay": -8}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The Guardian holds the line against dissolution. The decay slows. Briefly, something is preserved that would otherwise not be.$DQ$, $DQ$Der Wächter hält die Linie gegen die Auflösung. Der Verfall verlangsamt sich. Kurz wird etwas bewahrt, das sonst nicht wäre.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$entropy_rest_study$DQ$, $DQ$entropy_the_rest$DQ$, $DQ$Spy assessment (−3 Decay, reveal adjacent rooms)$DQ$, $DQ$Spion-Erkundung (−3 Verfall, angrenzende Räume aufdecken)$DQ$, $JB${"spy": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"decay": -3, "discovery": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The Spy maps what remains. The map will be less accurate tomorrow. Today, it helps.$DQ$, $DQ$Der Spion kartiert, was übrig ist. Die Karte wird morgen weniger genau sein. Heute hilft sie.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$archive_repair$DQ$, $DQ$entropy_residue_archive$DQ$, $DQ$Repair the mechanism (Guardian)$DQ$, $DQ$Den Mechanismus reparieren (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 6, $JB${"decay": -12, "loot": true}$JB$::jsonb, $JB${"decay": -6, "loot": true}$JB$::jsonb, $JB${"decay": 8, "stress": 30}$JB$::jsonb, $DQ$The mechanism steadies. The artifacts hold. You have bought them – and yourselves – more time. Time is the most decaying currency here.$DQ$, $DQ$Der Mechanismus stabilisiert sich. Die Artefakte halten. Ihr habt ihnen – und euch – mehr Zeit erkauft. Zeit ist die am schnellsten verfallende Währung hier.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The mechanism fails under your hands. Not dramatically. Quietly. The way everything here fails.$DQ$, $DQ$Der Mechanismus versagt unter euren Händen. Nicht dramatisch. Leise. So wie hier alles versagt.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$archive_extract$DQ$, $DQ$entropy_residue_archive$DQ$, $DQ$Extract the most valuable artifact (Infiltrator)$DQ$, $DQ$Das wertvollste Artefakt extrahieren (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, 5, $JB${"decay": 3, "loot": true}$JB$::jsonb, $JB${"decay": 6, "loot": true, "loot_tier_penalty": true}$JB$::jsonb, $JB${"decay": 8, "stress": 25}$JB$::jsonb, $DQ$You take the best of what remains. The mechanism falters. The rest dissolves.$DQ$, $DQ$Ihr nehmt das Beste von dem, was bleibt. Der Mechanismus stockt. Der Rest löst sich auf.$DQ$, $DQ$The extraction is hasty. What you save is diminished. What you leave behind was probably already gone.$DQ$, $DQ$Die Bergung ist hastig. Was ihr rettet, ist vermindert. Was ihr zurücklasst, war wahrscheinlich schon fort.$DQ$, $DQ$The mechanism interprets extraction as intrusion. It consumes what it was protecting. A last act of purposeful entropy.$DQ$, $DQ$Der Mechanismus interpretiert Entnahme als Einbruch. Er verzehrt, was er beschützte. Ein letzter Akt zweckgerichteter Entropie.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$archive_study$DQ$, $DQ$entropy_residue_archive$DQ$, $DQ$Study who built this (Spy)$DQ$, $DQ$Untersuchen, wer dies erbaut hat (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"decay": 2, "discovery": true}$JB$::jsonb, $JB${"decay": 4}$JB$::jsonb, $JB${"decay": 6}$JB$::jsonb, $DQ$The mechanism was built by someone who understood what was coming. The notes are partially legible. Enough to learn from. Not enough to replicate.$DQ$, $DQ$Der Mechanismus wurde von jemandem gebaut, der verstand, was kommen würde. Die Notizen sind teilweise leserlich. Genug, um daraus zu lernen. Nicht genug, um es nachzubauen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The notes dissolve as you read them. The information they contained is now in you, and will decay at the same rate.$DQ$, $DQ$Die Notizen lösen sich auf, während ihr sie lest. Die Information, die sie enthielten, ist nun in euch und wird mit derselben Geschwindigkeit verfallen.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$faction_accept$DQ$, $DQ$ov_faction_offer$DQ$, $DQ$Accept the alliance (Propagandist)$DQ$, $DQ$Das Bündnis annehmen (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, -5, $JB${"faction_standing": {"current_floor_faction": 15}, "fracture": 3}$JB$::jsonb, $JB${"faction_standing": {"current_floor_faction": 8}, "fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 10}$JB$::jsonb, $DQ${agent} negotiates terms. The terms are favorable — or appear to be. The representative nods. The alliance is entered into the record. Records can be revised.$DQ$, $DQ${agent} verhandelt die Bedingungen. Die Bedingungen sind günstig — oder scheinen es zu sein. Der Vertreter nickt. Das Bündnis wird aktenkundig. Akten können überarbeitet werden.$DQ$, $DQ${agent} negotiates. The terms are accepted — but the representative adds a clause at the end, spoken too quickly to parse. Machiavelli's fox: the contract is signed. The footnote is not.$DQ$, $DQ${agent} verhandelt. Die Bedingungen werden akzeptiert — aber der Vertreter fügt am Ende eine Klausel hinzu, zu schnell gesprochen um sie zu erfassen. Machiavellis Fuchs: der Vertrag ist unterschrieben. Die Fußnote nicht.$DQ$, $DQ$The negotiation collapses. The representative's smile does not change. The smile was never contingent on the outcome.$DQ$, $DQ$Die Verhandlung scheitert. Das Lächeln des Vertreters ändert sich nicht. Das Lächeln war nie vom Ergebnis abhängig.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$faction_spy$DQ$, $DQ$ov_faction_offer$DQ$, $DQ$Gather intelligence on the faction first (Spy)$DQ$, $DQ$Erst Informationen über die Fraktion sammeln (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"fracture": 2}$JB$::jsonb, $JB${"fracture": 3}$JB$::jsonb, $JB${"fracture": 5, "stress": 5}$JB$::jsonb, $DQ${agent} reads the offer beneath the offer. Every faction has a second agenda. The Spy sees both.$DQ$, $DQ${agent} liest das Angebot unter dem Angebot. Jede Fraktion hat eine zweite Agenda. Der Spion sieht beide.$DQ$, $DQ${agent} sees the second agenda. But a third remains hidden — Kadare's Palace has sub-basements. Partial intelligence is the most dangerous kind.$DQ$, $DQ${agent} sieht die zweite Agenda. Aber eine dritte bleibt verborgen — Kadares Palast hat Untergeschosse. Teilwissen ist die gefährlichste Art.$DQ$, $DQ$The intelligence is incomplete. What {agent} does not know is being reported to someone else.$DQ$, $DQ$Die Aufklärung ist unvollständig. Was {agent} nicht weiß, wird jemand anderem gemeldet.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$faction_decline$DQ$, $DQ$ov_faction_offer$DQ$, $DQ$Decline. Remain unaligned.$DQ$, $DQ$Ablehnen. Ungebunden bleiben.$DQ$, NULL, NULL, NULL, 0, $JB${"fracture": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The representative leaves. The absence of alliance is itself a political statement. Neutrality is the most expensive position in the Spiegelpalast.$DQ$, $DQ$Der Vertreter geht. Die Abwesenheit eines Bündnisses ist selbst eine politische Aussage. Neutralität ist die teuerste Position im Spiegelpalast.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$trial_defend$DQ$, $DQ$ov_show_trial$DQ$, $DQ$Speak in the accused's defense (Propagandist)$DQ$, $DQ$Zur Verteidigung des Angeklagten sprechen (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 5, $JB${"fracture": -5, "stress_heal": 10}$JB$::jsonb, $JB${"fracture": 3}$JB$::jsonb, $JB${"fracture": 10, "stress": 15}$JB$::jsonb, $DQ${agent} speaks. Antony's rhetoric: never say the accusers are liars. Let the crowd arrive there themselves. The tribunal hesitates. The accused is not freed — but the sentence is deferred.$DQ$, $DQ${agent} spricht. Antonius' Rhetorik: sag nie, dass die Ankläger lügen. Lass die Menge selbst dorthin kommen. Das Tribunal zögert. Der Angeklagte wird nicht befreit — aber das Urteil wird aufgeschoben.$DQ$, $DQ${agent} speaks. The tribunal listens — but the way Koestler's Gletkin listens: recording, not hearing. The defense enters the record. The record is another kind of evidence.$DQ$, $DQ${agent} spricht. Das Tribunal hört zu — aber so wie Koestlers Gletkin zuhört: aufzeichnend, nicht hörend. Die Verteidigung geht in die Akten ein. Die Akten sind eine andere Art von Beweis.$DQ$, $DQ$The defense fails. {agent}'s words are entered into evidence — as proof of complicity.$DQ$, $DQ$Die Verteidigung scheitert. {agent}s Worte werden als Beweis aufgenommen — als Beweis der Mittäterschaft.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$trial_observe$DQ$, $DQ$ov_show_trial$DQ$, $DQ$Observe the trial's mechanism (Spy)$DQ$, $DQ$Den Mechanismus des Prozesses beobachten (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 5}$JB$::jsonb, $DQ${agent} watches. The trial is not about guilt — it is about demonstration. Brecht's Verfremdung: once you see the mechanism, you cannot un-see it.$DQ$, $DQ${agent} beobachtet. Der Prozess handelt nicht von Schuld — er handelt von Demonstration. Brechts Verfremdung: hat man den Mechanismus einmal gesehen, kann man es nicht rückgängig machen.$DQ$, $DQ${agent} sees the mechanism — partially. Kiš's archive: some footnotes are legible, others redacted. The trial is a text. {agent} has read enough to know the ending is already written.$DQ$, $DQ${agent} sieht den Mechanismus — teilweise. Kišs Archiv: manche Fußnoten sind lesbar, andere geschwärzt. Der Prozess ist ein Text. {agent} hat genug gelesen um zu wissen, dass das Ende bereits geschrieben ist.$DQ$, $DQ$The mechanism is visible. But visibility is not protection.$DQ$, $DQ$Der Mechanismus ist sichtbar. Aber Sichtbarkeit ist kein Schutz.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$trial_pass$DQ$, $DQ$ov_show_trial$DQ$, $DQ$Leave before the verdict.$DQ$, $DQ$Vor dem Urteil gehen.$DQ$, NULL, NULL, NULL, 0, $JB${"fracture": 3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party leaves. The trial continues without them. Silence is complicity. But so is everything else.$DQ$, $DQ$Die Gruppe geht. Der Prozess geht ohne sie weiter. Schweigen ist Mittäterschaft. Aber alles andere auch.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$greengrocer_perform$DQ$, $DQ$ov_greengrocers_window$DQ$, $DQ$Display the dominant faction's sign (Infiltrator)$DQ$, $DQ$Das Schild der dominanten Fraktion zeigen (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, -5, $JB${"fracture": 3}$JB$::jsonb, $JB${"fracture": 4}$JB$::jsonb, $JB${"fracture": 6, "stress": 5}$JB$::jsonb, $DQ$The sign is displayed. No one checks if the party believes it. Belief was never the point. Performance is the currency of the Spiegelpalast.$DQ$, $DQ$Das Schild wird gezeigt. Niemand prüft, ob die Gruppe daran glaubt. Glaube war nie der Punkt. Aufführung ist die Währung des Spiegelpalasts.$DQ$, $DQ$The sign is displayed. Someone pauses — reads it a moment too long. Havel's greengrocer, observed: the performance passes, but it has been noted. Not the sign. The hesitation before it.$DQ$, $DQ$Das Schild wird gezeigt. Jemand hält inne — liest es einen Moment zu lang. Havels Gemüsehändler, beobachtet: die Aufführung geht durch, aber sie wurde notiert. Nicht das Schild. Das Zögern davor.$DQ$, $DQ$The performance is unconvincing. Not the words — the posture. The body knows what the mouth denies.$DQ$, $DQ$Die Aufführung ist nicht überzeugend. Nicht die Worte — die Haltung. Der Körper weiß, was der Mund leugnet.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$greengrocer_refuse$DQ$, $DQ$ov_greengrocers_window$DQ$, $DQ$Refuse to display any sign. Live in truth. (Guardian)$DQ$, $DQ$Kein Schild zeigen. In der Wahrheit leben. (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 5, $JB${"fracture": -3, "stress_heal": 15}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 10, "stress": 20}$JB$::jsonb, $DQ$Living in truth. {agent} refuses. One person who refuses to perform exposes everyone else's performance as a choice. The room changes. The signs are still there. But something has shifted.$DQ$, $DQ$In der Wahrheit leben. {agent} verweigert sich. Eine Person, die sich weigert aufzuführen, entlarvt die Aufführung aller anderen als Wahl. Der Raum verändert sich. Die Schilder sind noch da. Aber etwas hat sich verschoben.$DQ$, $DQ${agent} refuses. The room notices — but the silence that follows is ambiguous. Arendt's distinction: liberation, not yet freedom. The signs remain. One person's refusal is not yet contagious.$DQ$, $DQ${agent} verweigert sich. Der Raum bemerkt es — aber die Stille danach ist mehrdeutig. Arendts Unterscheidung: Befreiung, noch nicht Freiheit. Die Schilder bleiben. Die Verweigerung einer Person ist noch nicht ansteckend.$DQ$, $DQ$The refusal costs. Living in truth is the most expensive option in the Spiegelpalast.$DQ$, $DQ$Die Verweigerung kostet. In der Wahrheit leben ist die teuerste Option im Spiegelpalast.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$greengrocer_subvert$DQ$, $DQ$ov_greengrocers_window$DQ$, $DQ$Display a sign with altered meaning (Saboteur)$DQ$, $DQ$Ein Schild mit veränderter Bedeutung zeigen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 0, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 10}$JB$::jsonb, $DQ$Détournement. Debord's weapon: hijack the spectacle against itself. The sign says what it always said. The meaning has been reversed.$DQ$, $DQ$Détournement. Debords Waffe: das Spektakel gegen sich selbst wenden. Das Schild sagt, was es immer sagte. Die Bedeutung wurde umgekehrt.$DQ$, $DQ$The alteration holds — for now. Debord's détournement, half-executed: the sign reads differently but {agent} cannot be sure who reads it which way. Ambiguity is a weapon that cuts both directions.$DQ$, $DQ$Die Veränderung hält — vorerst. Debords Détournement, halb ausgeführt: das Schild liest sich anders, aber {agent} kann nicht sicher sein, wer es wie liest. Mehrdeutigkeit ist eine Waffe, die in beide Richtungen schneidet.$DQ$, $DQ$The subversion is detected. The sign is confiscated. So is {agent}'s anonymity.$DQ$, $DQ$Die Subversion wird entdeckt. Das Schild wird konfisziert. Ebenso {agent}s Anonymität.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$portrait_remember$DQ$, $DQ$ov_erased_portrait$DQ$, $DQ$Reconstruct the erased faces (Spy)$DQ$, $DQ$Die gelöschten Gesichter rekonstruieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 10}$JB$::jsonb, $DQ$The struggle against power is the struggle of memory against forgetting. {agent} remembers. The portraits do not reappear — but the party knows what was there.$DQ$, $DQ$Der Kampf gegen die Macht ist der Kampf der Erinnerung gegen das Vergessen. {agent} erinnert sich. Die Porträts erscheinen nicht wieder — aber die Gruppe weiß, was dort war.$DQ$, $DQ${agent} remembers some faces. Others dissolve — Kundera's Clementis: the hat remains on Gottwald's head, but whose hat was it? Memory reconstructs. Reconstruction edits.$DQ$, $DQ${agent} erinnert sich an einige Gesichter. Andere lösen sich auf — Kunderas Clementis: die Mütze bleibt auf Gottwalds Kopf, aber wessen Mütze war es? Erinnerung rekonstruiert. Rekonstruktion redigiert.$DQ$, $DQ$Memory fails. Not naturally — actively. Something in the Spiegelpalast assists forgetting.$DQ$, $DQ$Die Erinnerung versagt. Nicht natürlich — aktiv. Etwas im Spiegelpalast unterstützt das Vergessen.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$portrait_erase_more$DQ$, $DQ$ov_erased_portrait$DQ$, $DQ$Add current leaders to the erasure (Saboteur)$DQ$, $DQ$Aktuelle Anführer zur Löschung hinzufügen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 0, $JB${"fracture": 8}$JB$::jsonb, $JB${"fracture": 6}$JB$::jsonb, $JB${"fracture": 3, "stress": 5}$JB$::jsonb, $DQ$Turnabout. {agent} scratches out the current leaders. The revolution that erased the old order is now being erased itself. The cycle continues.$DQ$, $DQ$Umkehr. {agent} kratzt die aktuellen Anführer aus. Die Revolution, die die alte Ordnung löschte, wird nun selbst gelöscht. Der Kreislauf geht weiter.$DQ$, $DQ${agent} scratches. Some faces are erased. Others resist — the paint is newer, the varnish thicker. Camus: every revolutionary ends as oppressor or heretic. The erasure is incomplete. So is the revolution.$DQ$, $DQ${agent} kratzt. Manche Gesichter werden gelöscht. Andere widerstehen — die Farbe ist neuer, der Lack dicker. Camus: jeder Revolutionär endet als Unterdrücker oder Ketzer. Die Löschung ist unvollständig. Die Revolution auch.$DQ$, $DQ$The scratching is noticed. Someone is always watching the watchers.$DQ$, $DQ$Das Kratzen wird bemerkt. Jemand beobachtet immer die Beobachter.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$portrait_pass$DQ$, $DQ$ov_erased_portrait$DQ$, $DQ$Walk past. Do not engage with the erasure.$DQ$, $DQ$Vorbeigehen. Sich nicht auf die Löschung einlassen.$DQ$, NULL, NULL, NULL, 0, $JB${"fracture": 3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party walks past. The gallery continues. There will be more portraits. There will be more erasures.$DQ$, $DQ$Die Gruppe geht vorbei. Die Galerie geht weiter. Es wird mehr Porträts geben. Es wird mehr Löschungen geben.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$theater_observe$DQ$, $DQ$ov_variety_theater$DQ$, $DQ$Watch the factions reveal themselves (Spy)$DQ$, $DQ$Beobachten, wie die Fraktionen sich offenbaren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 7, "stress": 5}$JB$::jsonb, $DQ$Woland's experiment, reproduced. {agent} watches. When given what they desire, every faction reveals what they truly are. The intelligence is invaluable.$DQ$, $DQ$Wolands Experiment, reproduziert. {agent} beobachtet. Wenn sie bekommen, was sie begehren, offenbart jede Fraktion, was sie wirklich ist. Die Aufklärung ist unbezahlbar.$DQ$, $DQ${agent} watches. Some factions reveal themselves. Others perform even while scrambling — Bulgakov's observation: greed has its own theater. The picture is incomplete but telling.$DQ$, $DQ${agent} beobachtet. Manche Fraktionen offenbaren sich. Andere spielen auch beim Gerangel Theater — Bulgakows Beobachtung: Gier hat ihr eigenes Theater. Das Bild ist unvollständig, aber aufschlussreich.$DQ$, $DQ${agent} watches. But watching is also a position. The one who does not scramble is noticed.$DQ$, $DQ${agent} beobachtet. Aber Beobachten ist auch eine Position. Wer nicht mitrennt, wird bemerkt.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$theater_participate$DQ$, $DQ$ov_variety_theater$DQ$, $DQ$Join the scramble. Resources matter. (Infiltrator)$DQ$, $DQ$Mitmachen. Ressourcen zählen. (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, 0, $JB${"fracture": 5, "loot_tier": 1}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 10}$JB$::jsonb, $DQ$Erst kommt das Fressen, dann kommt die Moral. {agent} secures resources. The money may turn to paper. But the alliances formed during the scramble are real.$DQ$, $DQ$Erst kommt das Fressen, dann kommt die Moral. {agent} sichert Ressourcen. Das Geld mag zu Papier werden. Aber die Bündnisse, die beim Gerangel entstehen, sind echt.$DQ$, $DQ${agent} secures something — but the scramble is already sorting winners from losers. Brecht's observation: the Fressen was real. Whether the Moral follows remains to be seen.$DQ$, $DQ${agent} sichert etwas — aber das Gerangel sortiert bereits Gewinner von Verlierern. Brechts Beobachtung: das Fressen war echt. Ob die Moral folgt, bleibt abzuwarten.$DQ$, $DQ$The scramble turns ugly. Material interest stripped of ideology. Brecht was right.$DQ$, $DQ$Das Gerangel wird hässlich. Materielles Interesse, von Ideologie befreit. Brecht hatte Recht.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$theater_warn$DQ$, $DQ$ov_variety_theater$DQ$, $DQ$Warn the factions: this is a trap.$DQ$, $DQ$Die Fraktionen warnen: das ist eine Falle.$DQ$, NULL, NULL, NULL, 0, $JB${"fracture": -3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The warning is issued. Some listen. Most do not. Manuscripts don't burn. But money does.$DQ$, $DQ$Die Warnung wird ausgesprochen. Manche hören zu. Die meisten nicht. Manuskripte brennen nicht. Aber Geld schon.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$inquisitor_debate$DQ$, $DQ$ov_grand_inquisitor$DQ$, $DQ$Engage in philosophical debate (Propagandist)$DQ$, $DQ$Sich auf philosophische Debatte einlassen (Propagandist)$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 5, $JB${"fracture": -5, "stress_heal": 15}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 10, "stress": 20}$JB$::jsonb, $DQ$Koestler's two ethics, wielded against the Inquisitor. {agent} does not win the debate — {agent} makes the Inquisitor's logic visible. The mechanism, once exposed, loses its hold.$DQ$, $DQ$Koestlers zwei Ethiken, gegen den Inquisitor gewandt. {agent} gewinnt die Debatte nicht — {agent} macht die Logik des Inquisitors sichtbar. Der Mechanismus, einmal entlarvt, verliert seinen Griff.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The Inquisitor's logic is self-sealing. Given the premises, confession is the logical conclusion. {agent} follows the path and recoils.$DQ$, $DQ$Die Logik des Inquisitors ist selbstversiegelnd. Ausgehend von den Prämissen ist das Geständnis die logische Schlussfolgerung. {agent} folgt dem Pfad und schreckt zurück.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$inquisitor_fight$DQ$, $DQ$ov_grand_inquisitor$DQ$, $DQ$Reject the tribunal. Fight.$DQ$, $DQ$Das Tribunal ablehnen. Kämpfen.$DQ$, NULL, NULL, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Words have failed. Or words were never the point. The Inquisitor rises. The informer reaches for a weapon.$DQ$, $DQ$Worte haben versagt. Oder Worte waren nie der Punkt. Der Inquisitor erhebt sich. Der Spitzel greift zur Waffe.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$safehouse_rest$DQ$, $DQ$ov_safe_house$DQ$, $DQ$Rest. Brief respite from the crisis.$DQ$, $DQ$Rasten. Kurze Atempause in der Krise.$DQ$, NULL, NULL, NULL, 0, $JB${"fracture": -3, "stress_heal": 40}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party rests. Behind the wall, the factions continue without them. The rest is genuine. The safety is not.$DQ$, $DQ$Die Gruppe rastet. Hinter der Wand machen die Fraktionen ohne sie weiter. Die Rast ist echt. Die Sicherheit nicht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$safehouse_eavesdrop$DQ$, $DQ$ov_safe_house$DQ$, $DQ$Listen through the wall (Spy)$DQ$, $DQ$Durch die Wand lauschen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"fracture": 2, "stress_heal": 25}$JB$::jsonb, $JB${"stress_heal": 20}$JB$::jsonb, $JB${"stress": 5, "stress_heal": 15}$JB$::jsonb, $DQ$Koestler's tapping code. {agent} listens. The intelligence is useful. The knowledge that everyone is being discussed is less so.$DQ$, $DQ$Koestlers Klopfzeichen. {agent} lauscht. Die Aufklärung ist nützlich. Das Wissen, dass alle besprochen werden, weniger.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The wall is thinner than expected. In both directions.$DQ$, $DQ$Die Wand ist dünner als erwartet. In beiden Richtungen.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$neutral_rest$DQ$, $DQ$ov_neutral_ground$DQ$, $DQ$Rest on neutral ground.$DQ$, $DQ$Auf neutralem Gelände rasten.$DQ$, NULL, NULL, NULL, 0, $JB${"fracture": -5, "stress_heal": 50}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The boulder rests. The party rests. The silence is the first honest thing the Spiegelpalast has offered.$DQ$, $DQ$Der Felsbrocken ruht. Die Gruppe ruht. Die Stille ist das erste Ehrliche, das der Spiegelpalast angeboten hat.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$archive_study$DQ$, $DQ$ov_faction_archive$DQ$, $DQ$Study the dossiers carefully (Spy)$DQ$, $DQ$Die Dossiers sorgfältig studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"fracture": 3, "loot_tier": 1}$JB$::jsonb, $JB${"fracture": 3, "loot_tier": 1}$JB$::jsonb, $JB${"fracture": 5, "stress": 5}$JB$::jsonb, $DQ$Intelligence. Names, alliances, debts. {agent} takes what can be carried. The rest will be here for whoever comes next.$DQ$, $DQ$Aufklärung. Namen, Bündnisse, Schulden. {agent} nimmt, was getragen werden kann. Der Rest wird hier sein für den, der als Nächster kommt.$DQ$, $DQ$Names, alliances — but the debts are encoded. Kadare's dream interpreters: the raw material is here. The interpretation requires context {agent} does not yet possess.$DQ$, $DQ$Namen, Bündnisse — aber die Schulden sind verschlüsselt. Kadares Traumdeuter: das Rohmaterial ist da. Die Interpretation erfordert Kontext, den {agent} noch nicht besitzt.$DQ$, $DQ$The dossiers are incomplete. Or they have been pre-edited for whoever found them.$DQ$, $DQ$Die Dossiers sind unvollständig. Oder sie wurden für den Finder vorbearbeitet.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$archive_take$DQ$, $DQ$ov_faction_archive$DQ$, $DQ$Take everything. Sort later.$DQ$, $DQ$Alles mitnehmen. Später sortieren.$DQ$, NULL, NULL, NULL, 0, $JB${"fracture": 5, "loot_tier": 1}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party takes everything. Quantity over analysis. Somewhere in the stack is something important. Also somewhere in the stack: misinformation.$DQ$, $DQ$Die Gruppe nimmt alles mit. Quantität statt Analyse. Irgendwo im Stapel ist etwas Wichtiges. Ebenfalls irgendwo im Stapel: Desinformation.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$assets_salvage$DQ$, $DQ$ov_confiscated_assets$DQ$, $DQ$Salvage what is useful (Saboteur)$DQ$, $DQ$Retten, was nützlich ist (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 0, $JB${"fracture": 3, "loot_tier": 1}$JB$::jsonb, $JB${"loot_tier": 1}$JB$::jsonb, $JB${"fracture": 5, "stress": 5}$JB$::jsonb, $DQ${agent} finds something. The previous owner will not be needing it. The scratched-out name on the label tells its own story.$DQ$, $DQ${agent} findet etwas. Der vorherige Besitzer wird es nicht mehr brauchen. Der durchgestrichene Name auf dem Etikett erzählt seine eigene Geschichte.$DQ$, $DQ${agent} salvages. Some labels are legible, others deliberately smeared. Ngũgĩ's observation: what the regime confiscates tells you what it fears. The catalogue is partial. The fear is not.$DQ$, $DQ${agent} birgt. Manche Etiketten sind lesbar, andere absichtlich verwischt. Ngũgĩs Beobachtung: was das Regime beschlagnahmt, verrät, wovor es sich fürchtet. Der Katalog ist unvollständig. Die Furcht nicht.$DQ$, $DQ$The assets are trapped — not physically, but politically. Taking them signals allegiance to the faction that confiscated them.$DQ$, $DQ$Die Güter sind eine Falle — nicht physisch, sondern politisch. Sie zu nehmen signalisiert Treue zur Fraktion, die sie beschlagnahmte.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$assets_leave$DQ$, $DQ$ov_confiscated_assets$DQ$, $DQ$Leave the dead their possessions.$DQ$, $DQ$Den Toten ihren Besitz lassen.$DQ$, NULL, NULL, NULL, 0, $JB${"fracture": -2}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Respect for the erased. The party takes nothing. In the Spiegelpalast, this is itself a political act.$DQ$, $DQ$Respekt vor den Gelöschten. Die Gruppe nimmt nichts. Im Spiegelpalast ist auch das ein politischer Akt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$reagent_take_metal$DQ$, $DQ$prometheus_reagent_cache$DQ$, $DQ$Extract the metal filings (Saboteur)$DQ$, $DQ$Die Metallspäne entnehmen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, -5, $JB${"add_component": {"id": "comp_workshop_metal", "name_de": "Werkstatt-Metallspäne", "name_en": "Workshop Metal Filings", "type": "metal"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 15}$JB$::jsonb, $JB${"stress": 25}$JB$::jsonb, $DQ$The filings separate from the drawer as if they had been waiting. They are heavier than they should be. Denser. As if the metal remembers being something more.$DQ$, $DQ$Die Späne lösen sich aus der Schublade, als hätten sie gewartet. Sie sind schwerer, als sie sein sollten. Dichter. Als erinnere sich das Metall, etwas mehr gewesen zu sein.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The filings scatter. Not randomly – they form a pattern on the floor that {agent} cannot read. The workshop is disappointed.$DQ$, $DQ$Die Späne zerstreuen sich. Nicht zufällig – sie bilden ein Muster auf dem Boden, das {agent} nicht lesen kann. Die Werkstatt ist enttäuscht.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$reagent_take_fluid$DQ$, $DQ$prometheus_reagent_cache$DQ$, $DQ$Secure the sealed fluid (Spy)$DQ$, $DQ$Die versiegelte Flüssigkeit sichern (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"add_component": {"id": "comp_workshop_fluid", "name_de": "Versiegelte Werkstattflüssigkeit", "name_en": "Sealed Workshop Fluid", "type": "fluid"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 15}$JB$::jsonb, $JB${"stress": 25}$JB$::jsonb, $DQ$The vial is warm. The fluid inside shifts in response to {agent}'s touch – not away, but toward. It wants to merge.$DQ$, $DQ$Das Fläschchen ist warm. Die Flüssigkeit darin reagiert auf {agent}s Berührung – nicht weg, sondern hin. Sie will verschmelzen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The seal resists. Inside, the fluid settles into stillness. It has decided {agent} is not ready.$DQ$, $DQ$Das Siegel widersteht. Darin kommt die Flüssigkeit zur Ruhe. Sie hat entschieden, dass {agent} nicht bereit ist.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$reagent_take_crystal$DQ$, $DQ$prometheus_reagent_cache$DQ$, $DQ$Harvest the crystal formation (Infiltrator)$DQ$, $DQ$Die Kristallformation ernten (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, -5, $JB${"add_component": {"id": "comp_workshop_crystal", "name_de": "Werkstattkristall", "name_en": "Workshop Crystal", "type": "crystal"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 15}$JB$::jsonb, $JB${"stress": 25}$JB$::jsonb, $DQ$The crystal separates with a clean, precise fracture. It vibrates at a frequency {agent}'s instruments can detect but not identify. A tuning fork for something unnamed.$DQ$, $DQ$Der Kristall löst sich mit einem sauberen, präzisen Bruch. Er vibriert auf einer Frequenz, die {agent}s Instrumente erkennen, aber nicht identifizieren können. Eine Stimmgabel für etwas Unbenanntes.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The crystal shatters precisely. Every shard is identical. The workshop has demonstrated the concept of replication.$DQ$, $DQ$Der Kristall zersplittert präzise. Jeder Splitter ist identisch. Die Werkstatt hat das Konzept der Replikation demonstriert.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$conduit_tap$DQ$, $DQ$prometheus_energy_conduit$DQ$, $DQ$Tap the energy flow (Saboteur)$DQ$, $DQ$Den Energiefluss anzapfen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 0, $JB${"add_component": {"id": "comp_energy_tap", "name_de": "Eingedämmte Energiezelle", "name_en": "Contained Energy Cell", "type": "energy"}, "insight": 8}$JB$::jsonb, $JB${"insight": 4, "stress": 20}$JB$::jsonb, $JB${"insight": -5, "stress": 40}$JB$::jsonb, $DQ$The energy flows into the containment. Not reluctantly – eagerly. It wanted to be portable. It wanted to be used.$DQ$, $DQ$Die Energie fließt in die Eindämmung. Nicht widerwillig – eifrig. Sie wollte tragbar sein. Sie wollte benutzt werden.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The energy arcs. {agent}'s instruments spike. The conduit seals itself – offended, perhaps.$DQ$, $DQ$Die Energie entlädt sich. {agent}s Instrumente schlagen aus. Die Leitung versiegelt sich selbst – beleidigt, vielleicht.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$conduit_study$DQ$, $DQ$prometheus_energy_conduit$DQ$, $DQ$Study the geometric patterns (Spy)$DQ$, $DQ$Die geometrischen Muster studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 10, "reveal_rooms": 1}$JB$::jsonb, $JB${"insight": 5}$JB$::jsonb, $JB${"insight": -3, "stress": 25}$JB$::jsonb, $DQ$The diagrams resolve. They are a map – not of this place, but of what this place will produce. The workshop has shown you its blueprint.$DQ$, $DQ$Die Diagramme klären sich. Sie sind eine Karte – nicht von diesem Ort, sondern von dem, was dieser Ort hervorbringen wird. Die Werkstatt hat euch ihre Blaupause gezeigt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The patterns move faster than {agent} can process. The energy is speaking a language you almost know.$DQ$, $DQ$Die Muster bewegen sich schneller, als {agent} verarbeiten kann. Die Energie spricht eine Sprache, die ihr beinahe kennt.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$crucible_combine$DQ$, $DQ$prometheus_the_crucible$DQ$, $DQ$Attempt a combination in the crucible (Saboteur)$DQ$, $DQ$Eine Kombination im Tiegel versuchen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"add_crafted_item": {"benefit_de": "Reduziert eingehenden Zustandsschaden um 1 Stufe für 3 Runden", "benefit_en": "Reduces incoming condition damage by 1 step for 3 rounds", "boss_effect": {"type": "reduce_stress_attack", "value": 2}, "cost_de": "Die Legierung resoniert – +15 Stress für den Träger", "cost_en": "The alloy resonates – +15 stress to the wielder", "id": "craft_tempered_alloy", "name_de": "Gehärtete Flussmittellegierung", "name_en": "Tempered Flux Alloy"}, "insight": 8, "remove_components": ["comp_workshop_metal", "comp_workshop_fluid"]}$JB$::jsonb, $JB${"craft_failed": true, "insight": 4, "stress": 20}$JB$::jsonb, $JB${"craft_failed": true, "insight": 4, "stress": 35}$JB$::jsonb, $DQ$The metal meets the fluid. For a moment, nothing. Then: heat. Then: light. Then: something that was not there before. The alloy holds. Stronger than either component alone. But it resonates at a frequency that sets {agent}'s instruments to trembling.$DQ$, $DQ$Das Metall trifft die Flüssigkeit. Einen Moment lang nichts. Dann: Hitze. Dann: Licht. Dann: etwas, das vorher nicht da war. Die Legierung hält. Stärker als beide Komponenten allein. Aber sie resoniert auf einer Frequenz, die {agent}s Instrumente zum Zittern bringt.$DQ$, $DQ$The components merge – partially. The alloy is uneven, useful as raw material but not as a tool. The residue, though? The residue is interesting.$DQ$, $DQ$Die Komponenten verschmelzen – teilweise. Die Legierung ist ungleichmäßig, brauchbar als Rohmaterial, aber nicht als Werkzeug. Der Rückstand allerdings? Der Rückstand ist interessant.$DQ$, $DQ$The crucible rejects the combination. The components are consumed anyway – matter does not return to its previous state. But {agent} learned something about what doesn't work. This, too, is data.$DQ$, $DQ$Der Tiegel verwirft die Kombination. Die Komponenten werden trotzdem verbraucht – Materie kehrt nicht in ihren vorherigen Zustand zurück. Aber {agent} hat etwas darüber gelernt, was nicht funktioniert. Auch das sind Daten.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$crucible_observe$DQ$, $DQ$prometheus_the_crucible$DQ$, $DQ$Study the crucible's behavior without using it (Spy)$DQ$, $DQ$Das Verhalten des Tiegels studieren, ohne ihn zu benutzen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"discovery": true, "insight": 8}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$You observe. The crucible runs through phantom combinations – heating, mixing, testing invisible reagents. It has been doing this for a long time. It has opinions about what works.$DQ$, $DQ$Ihr beobachtet. Der Tiegel führt Phantomkombinationen durch – erhitzt, mischt, testet unsichtbare Reagenzien. Er tut dies seit langer Zeit. Er hat Meinungen darüber, was funktioniert.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The crucible goes silent. It does not perform for audiences.$DQ$, $DQ$Der Tiegel verstummt. Er führt nicht für Zuschauer vor.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$blueprint_contribute$DQ$, $DQ$prometheus_living_blueprint$DQ$, $DQ$Add to the blueprint (Saboteur)$DQ$, $DQ$Zur Blaupause beitragen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"insight": 12, "stress_heal": 20}$JB$::jsonb, $JB${"insight": 6}$JB$::jsonb, $JB${"insight": -5, "stress": 30}$JB$::jsonb, $DQ${agent} adds a line. The blueprint pauses. Considers. Accepts. The annotations stop arguing. For a moment, the blueprint achieves coherence. It is beautiful.$DQ$, $DQ${agent} fügt eine Linie hinzu. Die Blaupause hält inne. Erwägt. Akzeptiert. Die Anmerkungen hören auf zu streiten. Für einen Moment erreicht die Blaupause Kohärenz. Es ist schön.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The blueprint rejects {agent}'s contribution with a sharp erasure. The annotations resume with renewed intensity. The blueprint has added a note: 'NOT THIS.'$DQ$, $DQ$Die Blaupause verwirft {agent}s Beitrag mit einer scharfen Löschung. Die Anmerkungen setzen mit erneuter Intensität ein. Die Blaupause hat eine Notiz hinzugefügt: »NICHT DAS.«$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$blueprint_copy$DQ$, $DQ$prometheus_living_blueprint$DQ$, $DQ$Copy the blueprint's current state (Spy)$DQ$, $DQ$Den aktuellen Zustand der Blaupause kopieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8, "reveal_rooms": 1}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 15}$JB$::jsonb, $DQ$You capture a snapshot. By the time you look up, the blueprint has changed. But the snapshot is enough – it shows the workshop's intended layout. Briefly, you know where things are.$DQ$, $DQ$Ihr erfasst einen Schnappschuss. Als ihr aufblickt, hat sich die Blaupause geändert. Aber der Schnappschuss reicht – er zeigt das beabsichtigte Layout der Werkstatt. Kurz wisst ihr, wo die Dinge sind.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The blueprint moves too fast. Every copy is already outdated.$DQ$, $DQ$Die Blaupause bewegt sich zu schnell. Jede Kopie ist bereits veraltet.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$failed_salvage$DQ$, $DQ$prometheus_failed_experiment$DQ$, $DQ$Salvage usable components from the wreckage (Saboteur)$DQ$, $DQ$Brauchbare Komponenten aus dem Wrack bergen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"add_component": {"id": "comp_salvaged_powder", "name_de": "Katalytisches Rückstandspulver", "name_en": "Catalytic Residue Powder", "type": "powder"}, "insight": 6}$JB$::jsonb, $JB${"insight": 3, "stress": 20}$JB$::jsonb, $JB${"insight": -3, "stress": 40}$JB$::jsonb, $DQ$Among the wreckage: a powder that catalyzes on contact. The failed experiment produced it as a byproduct. The workshop did not fail – it discovered something it wasn't looking for.$DQ$, $DQ$Im Wrack: ein Pulver, das bei Kontakt katalysiert. Das gescheiterte Experiment hat es als Nebenprodukt erzeugt. Die Werkstatt hat nicht versagt – sie hat etwas entdeckt, wonach sie nicht gesucht hat.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The wreckage shifts. Components you thought were inert react to {agent}'s touch. Not helpfully.$DQ$, $DQ$Das Wrack verschiebt sich. Komponenten, die ihr für inert hieltet, reagieren auf {agent}s Berührung. Nicht hilfreich.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$failed_analyze$DQ$, $DQ$prometheus_failed_experiment$DQ$, $DQ$Analyze what went wrong (Spy)$DQ$, $DQ$Analysieren, was schiefgelaufen ist (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"discovery": true, "insight": 10}$JB$::jsonb, $JB${"insight": 5}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$The failure had a cause. The cause is instructive. {agent} catalogs the sequence: component, catalyst, interaction, detonation. Understanding failure IS understanding.$DQ$, $DQ$Das Scheitern hatte eine Ursache. Die Ursache ist lehrreich. {agent} katalogisiert die Sequenz: Komponente, Katalysator, Interaktion, Detonation. Scheitern zu verstehen IST Verstehen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The sequence is too complex. Or {agent} is too simple. The experiment offers no comment.$DQ$, $DQ$Die Sequenz ist zu komplex. Oder {agent} ist zu einfach. Das Experiment kommentiert nicht.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$failed_retreat$DQ$, $DQ$prometheus_failed_experiment$DQ$, $DQ$Leave the disaster undisturbed$DQ$, $DQ$Die Katastrophe ungestört lassen$DQ$, NULL, NULL, NULL, 0, $JB${"insight": 2}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave. The half-formed construct twitches once more, then stills. Waiting.$DQ$, $DQ$Ihr geht. Das halbgeformte Konstrukt zuckt noch einmal, dann erstarrt es. Wartend.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$resonance_forge_combine$DQ$, $DQ$prometheus_resonance_forge$DQ$, $DQ$Focus crystal through the energy conduit (Saboteur)$DQ$, $DQ$Den Kristall durch die Energieleitung fokussieren (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"add_crafted_item": {"benefit_de": "Sendet eine Frequenz, die Konstruktabwehr stört", "benefit_en": "Emits a frequency that disrupts construct defenses", "boss_effect": {"school": "saboteur", "type": "add_vulnerability", "value": 1}, "cost_de": "Die Frequenz ist nicht selektiv – +20 Stress für alle Agenten", "cost_en": "The frequency is not selective – +20 stress to all agents", "id": "craft_resonance_disruptor", "name_de": "Resonanzbrecher", "name_en": "Resonance Disruptor"}, "insight": 10, "remove_components": ["comp_workshop_crystal", "comp_energy_tap"]}$JB$::jsonb, $JB${"craft_failed": true, "insight": 5, "stress": 25}$JB$::jsonb, $JB${"craft_failed": true, "insight": 4, "stress": 40}$JB$::jsonb, $DQ$The crystal shatters – not into fragments, but into frequency. The energy conduit amplifies it, shapes it, gives it purpose. What remains is a device that hums with directed intent. Ted Chiang's principle: the right combination of signs equals function. {agent} has found the right signs.$DQ$, $DQ$Der Kristall zerbricht – nicht in Splitter, sondern in Frequenz. Die Energieleitung verstärkt sie, formt sie, gibt ihr Zweck. Was bleibt, ist ein Gerät, das mit gerichteter Absicht summt. Chiangs Prinzip: die richtige Kombination von Zeichen gleicht Funktion. {agent} hat die richtigen Zeichen gefunden.$DQ$, $DQ$The crystal fractures asymmetrically. The frequency scatters instead of focusing. Components consumed, nothing gained. But the scatter pattern is instructive.$DQ$, $DQ$Der Kristall bricht asymmetrisch. Die Frequenz streut, statt sich zu fokussieren. Komponenten verbraucht, nichts gewonnen. Aber das Streumuster ist lehrreich.$DQ$, $DQ$The energy arcs through the crystal and into {agent}. The device produces sound, not function. The workshop hums in what might be disappointment.$DQ$, $DQ$Die Energie fährt durch den Kristall und in {agent}. Das Gerät erzeugt Klang, nicht Funktion. Die Werkstatt summt in etwas, das Enttäuschung sein könnte.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$resonance_forge_study$DQ$, $DQ$prometheus_resonance_forge$DQ$, $DQ$Study the device's harmonic properties (Spy)$DQ$, $DQ$Die harmonischen Eigenschaften des Geräts studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$The device's frequency resolves into data. Not sound – information. {agent} catalogs the harmonics. The workshop has been singing this song for a long time.$DQ$, $DQ$Die Frequenz des Geräts löst sich in Daten auf. Nicht Klang – Information. {agent} katalogisiert die Harmonien. Die Werkstatt singt dieses Lied schon lange.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The harmonics are beyond {agent}'s range. Some songs are not for human ears.$DQ$, $DQ$Die Harmonien liegen jenseits von {agent}s Bereich. Manche Lieder sind nicht für menschliche Ohren.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dissolution_combine$DQ$, $DQ$prometheus_dissolution_bath$DQ$, $DQ$Dissolve the powder into the reactive fluid (Saboteur)$DQ$, $DQ$Das Pulver in der reaktiven Flüssigkeit auflösen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"add_crafted_item": {"benefit_de": "Korrodiert Konstruktpanzerung, reduziert Ausweichen", "benefit_en": "Corrodes construct plating, reducing evasion", "boss_effect": {"type": "reduce_evasion", "value": 10}, "cost_de": "Dämpfe verursachen Desorientierung – +20 Stress für alle Agenten", "cost_en": "Fumes cause disorientation – +20 stress to all agents", "id": "craft_catalytic_solvent", "name_de": "Katalytisches Lösungsmittel", "name_en": "Catalytic Solvent"}, "insight": 10, "remove_components": ["comp_workshop_fluid", "comp_salvaged_powder"]}$JB$::jsonb, $JB${"craft_failed": true, "insight": 5, "stress": 25}$JB$::jsonb, $JB${"craft_failed": true, "insight": 4, "stress": 40}$JB$::jsonb, $DQ$The powder dissolves. Not gradually – eagerly. The fluid changes color twice before settling into something that is not a color but a property. The solvent does not destroy. It reveals. It strips away what is not essential until only the vulnerable truth remains.$DQ$, $DQ$Das Pulver löst sich. Nicht allmählich – eifrig. Die Flüssigkeit wechselt zweimal die Farbe, bevor sie sich in etwas niederlässt, das keine Farbe ist, sondern eine Eigenschaft. Das Lösungsmittel zerstört nicht. Es enthüllt. Es streift ab, was nicht wesentlich ist, bis nur die verwundbare Wahrheit bleibt.$DQ$, $DQ$The dissolution is incomplete. The fluid accepts the powder but refuses to change. Components consumed, lesson retained.$DQ$, $DQ$Die Auflösung ist unvollständig. Die Flüssigkeit nimmt das Pulver an, weigert sich aber zu verändern. Komponenten verbraucht, Lektion behalten.$DQ$, $DQ$The fluid recoils. The powder floats, undissolved, mocking {agent}'s proportions. Levi would note: the reaction tells you as much about yourself as about the reagent.$DQ$, $DQ$Die Flüssigkeit weicht zurück. Das Pulver schwimmt, ungelöst, {agent}s Proportionen verspottend. Levi würde anmerken: die Reaktion verrät ebenso viel über einen selbst wie über das Reagenz.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dissolution_observe$DQ$, $DQ$prometheus_dissolution_bath$DQ$, $DQ$Analyze the fluid's reactive properties (Spy)$DQ$, $DQ$Die reaktiven Eigenschaften der Flüssigkeit analysieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 15}$JB$::jsonb, $DQ$The fluid has memory. {agent} observes it cycling through phantom reactions – dissolutions it has performed before, preserved in its molecular structure like scars.$DQ$, $DQ${agent} beobachtet die Flüssigkeit beim Durchlaufen von Phantomreaktionen – Auflösungen, die sie zuvor durchgeführt hat, konserviert in ihrer Molekularstruktur wie Narben.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The fluid goes still. It does not perform for the unprepared.$DQ$, $DQ$Die Flüssigkeit erstarrt. Sie führt nicht für Unvorbereitete vor.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dampening_combine$DQ$, $DQ$prometheus_dampening_press$DQ$, $DQ$Feed metal and energy into the press (Saboteur)$DQ$, $DQ$Metall und Energie in die Presse einspeisen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"add_crafted_item": {"benefit_de": "Absorbiert kinetische Kraft, schwächt Konstruktangriffe", "benefit_en": "Absorbs kinetic force, weakening construct attacks", "boss_effect": {"type": "reduce_attack_power", "value": 2}, "cost_de": "Die absorbierte Energie muss irgendwohin – +25 Stress für den Träger", "cost_en": "The absorbed energy must go somewhere – +25 stress to wielder", "id": "craft_dampening_coil", "name_de": "Dämpfungsspule", "name_en": "Dampening Coil"}, "insight": 10, "remove_components": ["comp_workshop_metal", "comp_vault_energy"]}$JB$::jsonb, $JB${"craft_failed": true, "insight": 5, "stress": 30}$JB$::jsonb, $JB${"craft_failed": true, "insight": 4, "stress": 45}$JB$::jsonb, $DQ$The press accepts the offering. Metal wraps around energy in a spiral that tightens beyond physical possibility. What emerges is a coil that hums with contained violence – not its own, but the violence it has already absorbed in the act of being made. Hephaestus forging a shield: the defense is born from captured offense.$DQ$, $DQ$Die Presse nimmt die Gabe an. Metall wickelt sich um Energie in einer Spirale, die sich über physische Möglichkeit hinaus verengt. Was hervorkommt, ist eine Spule, die mit eingedämmter Gewalt summt – nicht ihrer eigenen, sondern der Gewalt, die sie bereits im Akt ihrer Erschaffung absorbiert hat. Hephaistos, der einen Schild schmiedet: die Verteidigung entsteht aus gefangener Offensive.$DQ$, $DQ$The press compresses, but the coil is loose. It absorbs ambient vibration, not directed force. The components merge imprecisely. Daedalus built wings; this is a feather.$DQ$, $DQ$Die Presse komprimiert, aber die Spule ist locker. Sie absorbiert Umgebungsvibrationen, nicht gerichtete Kraft. Die Komponenten verschmelzen unpräzise. Daedalus baute Flügel; dies ist eine Feder.$DQ$, $DQ$The energy rejects the metal. The press shudders and releases both components in a state neither recognizes. {agent} backs away. The workshop has demonstrated the concept of incompatibility.$DQ$, $DQ$Die Energie weist das Metall zurück. Die Presse schaudert und gibt beide Komponenten in einem Zustand frei, den keiner der beiden wiedererkennt. {agent} weicht zurück. Die Werkstatt hat das Konzept der Inkompatibilität demonstriert.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dampening_study$DQ$, $DQ$prometheus_dampening_press$DQ$, $DQ$Study the press's absorption mechanism (Spy)$DQ$, $DQ$Den Absorptionsmechanismus der Presse studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 15}$JB$::jsonb, $DQ$The press cycles through phantom compressions – absorbing forces that are no longer there. {agent} catalogs the patterns. The press remembers every force it has ever contained.$DQ$, $DQ$Die Presse durchläuft Phantomkompressionen – absorbiert Kräfte, die nicht mehr da sind. {agent} katalogisiert die Muster. Die Presse erinnert sich an jede Kraft, die sie je eingedämmt hat.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The press goes dormant. It does not demonstrate for observers.$DQ$, $DQ$Die Presse fällt in Ruhezustand. Sie demonstriert nicht für Beobachter.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cooling_rest$DQ$, $DQ$prometheus_cooling_chamber$DQ$, $DQ$Rest and let the fire cool$DQ$, $DQ$Ruhen und das Feuer abkühlen lassen$DQ$, NULL, NULL, NULL, 0, $JB${"stress_heal": 40}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party rests. The ambient hum of the workshop fades to a murmur. When they rise, the fire in their instruments has dimmed. They are calmer. They are also less inspired. The forge does not judge this.$DQ$, $DQ$Der Trupp ruht. Das Hintergrundsummen der Werkstatt verblasst zu einem Murmeln. Als sie aufstehen, ist das Feuer in ihren Instrumenten gedämpft. Sie sind ruhiger. Sie sind auch weniger inspiriert. Die Schmiede verurteilt das nicht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cooling_tinker$DQ$, $DQ$prometheus_cooling_chamber$DQ$, $DQ$Use the quiet to examine your components (Spy)$DQ$, $DQ$Die Ruhe nutzen, um eure Komponenten zu untersuchen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"insight": 5, "stress_heal": 20}$JB$::jsonb, $JB${"stress_heal": 10}$JB$::jsonb, $JB${"stress": 10}$JB$::jsonb, $DQ$In the quiet, {agent} examines the components more carefully. Patterns emerge. Connections that were invisible in the heat of the workshop reveal themselves in the cold.$DQ$, $DQ$In der Stille untersucht {agent} die Komponenten genauer. Muster treten hervor. Verbindungen, die in der Hitze der Werkstatt unsichtbar waren, offenbaren sich in der Kühle.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The components do not cooperate in the cold. They prefer the heat.$DQ$, $DQ$Die Komponenten kooperieren nicht in der Kühle. Sie bevorzugen die Hitze.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$vault_powder$DQ$, $DQ$prometheus_component_vault$DQ$, $DQ$Take the volatile powder (Saboteur)$DQ$, $DQ$Das flüchtige Pulver nehmen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, -5, $JB${"add_component": {"id": "comp_volatile_powder", "name_de": "Flüchtiges Katalysatorpulver", "name_en": "Volatile Catalyst Powder", "type": "powder"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 10}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$The powder settles in its container. For now. It dissipates under stress – a property it shares with confidence.$DQ$, $DQ$Das Pulver setzt sich in seinem Behälter ab. Vorerst. Es verflüchtigt sich unter Stress – eine Eigenschaft, die es mit Zuversicht teilt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The powder reacts to {agent}'s uncertainty. It dissipates. Proving its point.$DQ$, $DQ$Das Pulver reagiert auf {agent}s Unsicherheit. Es verflüchtigt sich. Seinen Punkt beweisend.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$vault_energy$DQ$, $DQ$prometheus_component_vault$DQ$, $DQ$Extract the energy core (Infiltrator)$DQ$, $DQ$Den Energiekern extrahieren (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, -5, $JB${"add_component": {"id": "comp_vault_energy", "name_de": "Stabilisierter Energiekern", "name_en": "Stabilized Energy Core", "type": "energy"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 10}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$The core hums. A contained fire. It WANTS to be used. Every gift is also a weapon – but this one is honest about it.$DQ$, $DQ$Der Kern summt. Ein eingedämmtes Feuer. Er WILL benutzt werden. Jede Gabe ist auch eine Waffe – aber diese ist ehrlich darüber.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The core pulses once. A warning. {agent} withdraws.$DQ$, $DQ$Der Kern pulsiert einmal. Eine Warnung. {agent} zieht sich zurück.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$investigate_scratches$DQ$, $DQ$shadow_the_threshold$DQ$, $DQ$Investigate the scratches (Spy)$DQ$, $DQ$Die Kratzer untersuchen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"reveal_rooms": 1, "stress": 0}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $JB${"stress": 40}$JB$::jsonb, $DQ$The scratches are a map – crude, desperate, but accurate. Whoever carved them made it further than this.$DQ$, $DQ$Die Kratzer sind eine Karte – grob, verzweifelt, aber genau. Wer sie geritzt hat, kam weiter als hierhin.$DQ$, $DQ$Some scratches form patterns. Others are just scratches. Sorting them takes longer than expected.$DQ$, $DQ$Manche Kratzer bilden Muster. Andere sind nur Kratzer. Sie zu sortieren dauert länger als erwartet.$DQ$, $DQ$The scratches rearrange themselves as you study them. Your eyes ache from tracking lines that refuse to hold still.$DQ$, $DQ$Die Kratzer ordnen sich neu, während ihr sie studiert. Eure Augen schmerzen vom Verfolgen von Linien, die sich weigern stillzuhalten.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$secure_perimeter$DQ$, $DQ$shadow_the_threshold$DQ$, $DQ$Secure the threshold (Guardian)$DQ$, $DQ$Die Schwelle sichern (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 0, $JB${"stress": -20, "visibility": 1}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $JB${"stress": 50}$JB$::jsonb, $DQ$You mark the threshold, set reference points, establish a fallback line. The darkness hasn't changed – but your footing has.$DQ$, $DQ$Ihr markiert die Schwelle, setzt Bezugspunkte, legt eine Rückzugslinie fest. Die Dunkelheit hat sich nicht verändert – aber euer Stand schon.$DQ$, $DQ$The markers hold, but the reference points drift. Partial orientation is better than none.$DQ$, $DQ$Die Markierungen halten, aber die Bezugspunkte verschieben sich. Teilweise Orientierung ist besser als keine.$DQ$, $DQ$The darkness swallows every marker you place. The threshold is not a line – it is a mouth.$DQ$, $DQ$Die Dunkelheit verschluckt jede Markierung, die ihr setzt. Die Schwelle ist keine Linie – sie ist ein Maul.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cautious_crossing$DQ$, $DQ$shadow_the_threshold$DQ$, $DQ$Cross cautiously$DQ$, $DQ$Vorsichtig überqueren$DQ$, NULL, NULL, NULL, 0, $JB${"stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You step across the line. Nothing happens. The waiting is worse.$DQ$, $DQ$Ihr tretet über die Linie. Nichts geschieht. Das Warten ist schlimmer.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$read_shadow_map$DQ$, $DQ$shadow_convergence$DQ$, $DQ$Read the shadow map (Spy)$DQ$, $DQ$Die Schattenkarte lesen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 10, $JB${"reveal_rooms": 2, "stress": 10}$JB$::jsonb, $JB${"reveal_rooms": 1, "stress": 30}$JB$::jsonb, $JB${"stress": 70}$JB$::jsonb, $DQ$The ink-map responds to your attention. It shows not just rooms – but what waits inside them.$DQ$, $DQ$Die Tintenkarte reagiert auf eure Aufmerksamkeit. Sie zeigt nicht nur Räume – sondern was darin wartet.$DQ$, $DQ$Fragments of the map are legible. Others dissolve under scrutiny, as if the shadow resents being read.$DQ$, $DQ$Fragmente der Karte sind lesbar. Andere lösen sich unter Prüfung auf, als ob der Schatten es übelnimmt, gelesen zu werden.$DQ$, $DQ$The map surges upward. For a heartbeat, the accumulated shadow of every room you crossed presses against your mind at once.$DQ$, $DQ$Die Karte wogt empor. Für einen Herzschlag drückt der angesammelte Schatten jedes Raums, den ihr durchquert habt, gleichzeitig gegen euren Verstand.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$strike_convergence$DQ$, $DQ$shadow_convergence$DQ$, $DQ$Strike the convergence (Assassin)$DQ$, $DQ$Die Konvergenz angreifen (Assassine)$DQ$, NULL, NULL, $DQ$assassin$DQ$, 10, $JB${"shadow_resonance": 0.05, "stress": -40}$JB$::jsonb, $JB${"stress": 40}$JB$::jsonb, $JB${"ambush_trigger": true, "stress": 90}$JB$::jsonb, $DQ$A precise strike at the node where all shadows meet. The ink-map shatters. The accumulated pressure bleeds away.$DQ$, $DQ$Ein präziser Schlag auf den Knoten, an dem alle Schatten sich treffen. Die Tintenkarte zerbricht. Der angesammelte Druck entweicht.$DQ$, $DQ$The strike lands, but the convergence absorbs part of it. The shadows recoil but do not break.$DQ$, $DQ$Der Schlag trifft, aber die Konvergenz absorbiert einen Teil davon. Die Schatten weichen zurück, brechen aber nicht.$DQ$, $DQ$The convergence fights back. Every shadow you ever passed through strikes at once.$DQ$, $DQ$Die Konvergenz schlägt zurück. Jeder Schatten, den ihr je durchquert habt, schlägt gleichzeitig zu.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cautious_convergence$DQ$, $DQ$shadow_convergence$DQ$, $DQ$Move through carefully$DQ$, $DQ$Vorsichtig hindurchgehen$DQ$, NULL, NULL, NULL, 0, $JB${"stress": 25}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You navigate the pooled shadows without engaging them. They part reluctantly, clinging to your boots like oil.$DQ$, $DQ$Ihr navigiert durch die gesammelten Schatten, ohne sie zu berühren. Sie teilen sich widerwillig und kleben an euren Stiefeln wie Öl.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$free_prisoner$DQ$, $DQ$shadow_the_prisoner$DQ$, $DQ$Free the prisoner$DQ$, $DQ$Den Gefangenen befreien$DQ$, NULL, NULL, $DQ$guardian$DQ$, 0, $JB${"discovery": true, "stress": -30, "visibility": 1}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $JB${"ambush_trigger": true, "stress": 80}$JB$::jsonb, $DQ$The shadow cage dissolves. The prisoner fades with a grateful whisper, leaving behind a faint glow that restores your sight.$DQ$, $DQ$Der Schattenkäfig löst sich auf. Der Gefangene verblasst mit einem dankbaren Flüstern und hinterlässt ein schwaches Leuchten, das eure Sicht wiederherstellt.$DQ$, $DQ$The cage cracks but doesn't break cleanly. The prisoner slips free but something else slips out with it.$DQ$, $DQ$Der Käfig bricht, aber nicht sauber. Der Gefangene entkommt, aber etwas anderes entkommt mit ihm.$DQ$, $DQ$The cage was a trap. The 'prisoner' dissolves into shadow tendrils that lash out at the party.$DQ$, $DQ$Der Käfig war eine Falle. Der 'Gefangene' löst sich in Schattenfäden auf, die nach der Gruppe schlagen.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$interrogate_prisoner$DQ$, $DQ$shadow_the_prisoner$DQ$, $DQ$Interrogate it first$DQ$, $DQ$Zuerst verhören$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"reveal_rooms": 2, "stress": 10}$JB$::jsonb, $JB${"reveal_rooms": 1, "stress": 30}$JB$::jsonb, $JB${"stress": 50}$JB$::jsonb, $DQ$Your questions cut through its delirium. It reveals the layout of adjacent rooms before fading.$DQ$, $DQ$Eure Fragen durchschneiden sein Delirium. Es enthüllt die Anordnung benachbarter Räume, bevor es verblasst.$DQ$, $DQ$It answers in fragments. Some of what it says is useful.$DQ$, $DQ$Es antwortet in Fragmenten. Manches davon ist nützlich.$DQ$, $DQ$It screams. The sound carries. Something in the next room stirs.$DQ$, $DQ$Es schreit. Der Laut trägt. Etwas im nächsten Raum regt sich.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$leave_prisoner$DQ$, $DQ$shadow_the_prisoner$DQ$, $DQ$Leave it$DQ$, $DQ$Zurücklassen$DQ$, NULL, NULL, NULL, 0, $JB${"stress": 20}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You walk away. Behind you, the whimpering fades into silence. Some agents look back. Others don't.$DQ$, $DQ$Ihr geht weiter. Hinter euch verblasst das Wimmern in Stille. Manche Agenten blicken zurück. Andere nicht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$destroy_prisoner$DQ$, $DQ$shadow_the_prisoner$DQ$, $DQ$End its suffering$DQ$, $DQ$Sein Leiden beenden$DQ$, $JB${"assassin": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"shadow_resonance": 0.05, "stress": -10}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$A clean strike. The shadow dissolves. The mercy of it echoes in the dark.$DQ$, $DQ$Ein sauberer Schlag. Der Schatten löst sich auf. Die Gnade hallt in der Dunkelheit nach.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$confront_reflection$DQ$, $DQ$shadow_mirror_room$DQ$, $DQ$Confront the reflection$DQ$, $DQ$Dem Spiegelbild entgegentreten$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 5, $JB${"resilience_bonus": 0.05, "stress": -50}$JB$::jsonb, $JB${"stress": 50}$JB$::jsonb, $JB${"stress": 100}$JB$::jsonb, $DQ$The agent stares their shadow-self down. The mirror cracks. In the silence that follows, something fundamental settles.$DQ$, $DQ$Der Agent stellt sich seinem Schatten-Ich. Der Spiegel bricht. In der folgenden Stille legt sich etwas Grundlegendes.$DQ$, $DQ$The confrontation is painful but inconclusive. The reflection retreats, but doesn't break.$DQ$, $DQ$Die Konfrontation ist schmerzhaft, aber ergebnislos. Das Spiegelbild weicht zurück, bricht aber nicht.$DQ$, $DQ$The reflection speaks the agent's worst fear aloud. The words hang in the air, impossible to unhear.$DQ$, $DQ$Das Spiegelbild spricht die schlimmste Angst des Agenten laut aus. Die Worte hängen in der Luft, unmöglich zu überhören.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$analyze_mirrors$DQ$, $DQ$shadow_mirror_room$DQ$, $DQ$Analyze the mirrors (Spy)$DQ$, $DQ$Spiegel analysieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"reveal_rooms": 1, "stress": 0}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $JB${"stress": 40}$JB$::jsonb, $DQ$The mirrors aren't just reflecting – they're showing adjacent rooms. You map what you see.$DQ$, $DQ$Die Spiegel reflektieren nicht nur – sie zeigen angrenzende Räume. Ihr kartiert, was ihr seht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$smash_mirrors$DQ$, $DQ$shadow_mirror_room$DQ$, $DQ$Smash the mirrors$DQ$, $DQ$Spiegel zerschlagen$DQ$, $JB${"assassin": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"stress": 30, "visibility": -1}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Glass shatters. The reflections scream. Darkness pours from the broken frames.$DQ$, $DQ$Glas zersplittert. Die Spiegelbilder schreien. Dunkelheit strömt aus den zerbrochenen Rahmen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$choose_differently$DQ$, $DQ$shadow_echoes_of_past$DQ$, $DQ$Make a different choice$DQ$, $DQ$Anders entscheiden$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 5, $JB${"insight": true, "memory_created": true, "stress": -30}$JB$::jsonb, $JB${"memory_created": true, "stress": 30}$JB$::jsonb, $JB${"stress": 80}$JB$::jsonb, $DQ$History shifts. The echo replays with your change, and something in the fabric of the simulation relaxes.$DQ$, $DQ$Die Geschichte verschiebt sich. Das Echo spielt sich mit eurer Änderung ab, und etwas im Gewebe der Simulation entspannt sich.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$observe_replay$DQ$, $DQ$shadow_echoes_of_past$DQ$, $DQ$Observe without intervening$DQ$, $DQ$Beobachten ohne einzugreifen$DQ$, NULL, NULL, $DQ$spy$DQ$, -10, $JB${"reveal_rooms": 1, "stress": 10}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Watching history repeat itself is painful, but instructive. You learn something about the patterns at work here.$DQ$, $DQ$Zuzusehen, wie sich Geschichte wiederholt, ist schmerzhaft, aber lehrreich. Ihr lernt etwas über die Muster, die hier am Werk sind.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$rest_full$DQ$, $DQ$shadow_the_hollow$DQ$, $DQ$Rest (heal stress, risk ambush)$DQ$, $DQ$Rasten (Stress heilen, Hinterhalt-Risiko)$DQ$, NULL, NULL, NULL, 0, $JB${"ambush_chance": 0.2, "stress_heal": 200, "wounded_to_stressed": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party rests. Stress fades. Wounds knit. For a while, the darkness forgets you.$DQ$, $DQ$Die Gruppe rastet. Stress verblasst. Wunden schließen sich. Für eine Weile vergisst die Dunkelheit euch.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$rest_guarded$DQ$, $DQ$shadow_the_hollow$DQ$, $DQ$Post a Guardian watch (safe, but Guardian doesn't heal)$DQ$, $DQ$Wächter aufstellen (sicher, aber Wächter heilt nicht)$DQ$, $JB${"guardian": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"guardian_no_heal": true, "stress_heal": 200, "wounded_to_stressed": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The Guardian stands watch while others rest. No ambush comes. But the Guardian's own wounds remain.$DQ$, $DQ$Der Wächter hält Wache, während die anderen rasten. Kein Hinterhalt kommt. Aber die eigenen Wunden des Wächters bleiben.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$open_cache$DQ$, $DQ$shadow_cache$DQ$, $DQ$Pick the lock (Infiltrator)$DQ$, $DQ$Schloss knacken (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, 0, $JB${"loot": true, "loot_bonus_at_vp0": true}$JB$::jsonb, $JB${"loot": true, "loot_tier_penalty": 1}$JB$::jsonb, $JB${"stress": 75, "trap_triggered": true}$JB$::jsonb, $DQ$The mechanism clicks open. Inside: shadows that have hardened into something useful.$DQ$, $DQ$Der Mechanismus klickt auf. Darin: Schatten, die sich zu etwas Nützlichem verhärtet haben.$DQ$, $DQ$Partially opened. Some contents spill and dissolve before you can grab them.$DQ$, $DQ$Teilweise geöffnet. Einige Inhalte verschütten sich und lösen sich auf, bevor ihr sie greifen könnt.$DQ$, $DQ$A trap! Shadow energy lashes out, scoring the opener's psyche.$DQ$, $DQ$Eine Falle! Schattenenergie peitscht hervor und zeichnet die Psyche des Öffnenden.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$force_cache$DQ$, $DQ$shadow_cache$DQ$, $DQ$Force it open (Saboteur)$DQ$, $DQ$Aufbrechen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"loot": true}$JB$::jsonb, $JB${"loot": true, "loot_tier_penalty": 1, "stress": 30}$JB$::jsonb, $JB${"stress": 50}$JB$::jsonb, $DQ$Controlled demolition. The container shatters on your terms.$DQ$, $DQ$Kontrollierte Sprengung. Der Behälter zerbricht nach euren Regeln.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$leave_cache$DQ$, $DQ$shadow_cache$DQ$, $DQ$Leave it (no risk)$DQ$, $DQ$Liegenlassen (kein Risiko)$DQ$, NULL, NULL, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$Sometimes the safest option is the wisest. You move on.$DQ$, $DQ$Manchmal ist die sicherste Option die klügste. Ihr geht weiter.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$check_departure_boards$DQ$, $DQ$tower_the_lobby$DQ$, $DQ$Check the departure boards (Spy)$DQ$, $DQ$Die Abfahrtstafeln prüfen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"reveal_rooms": 1, "stress": 0}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $JB${"stress": 40}$JB$::jsonb, $DQ$The imaginary floors encode real information. You map the first level from the contradictions.$DQ$, $DQ$Die imaginären Stockwerke verschlüsseln echte Information. Ihr kartiert die erste Ebene aus den Widersprüchen.$DQ$, $DQ$Some boards flicker with useful data. Others display only debt.$DQ$, $DQ$Einige Tafeln flimmern mit nützlichen Daten. Andere zeigen nur Schulden.$DQ$, $DQ$The boards reset as you read them. The only consistent number is the one counting down.$DQ$, $DQ$Die Tafeln setzen sich zurück, während ihr sie lest. Die einzige beständige Zahl ist die, die herunterzählt.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$reinforce_lobby$DQ$, $DQ$tower_the_lobby$DQ$, $DQ$Reinforce the cracked marble (Guardian)$DQ$, $DQ$Den gerissenen Marmor verstärken (Wächter)$DQ$, NULL, NULL, $DQ$guardian$DQ$, 0, $JB${"stability": 5, "stress": -15}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $JB${"stability": -5, "stress": 50}$JB$::jsonb, $DQ$You brace the load-bearing fractures with improvised supports. The lobby stops shuddering. For now.$DQ$, $DQ$Ihr stützt die tragenden Brüche mit improvisierten Stützen ab. Die Lobby hört auf zu beben. Vorerst.$DQ$, $DQ$Some cracks hold. Others widen under the correction, as if the building resists being helped.$DQ$, $DQ$Einige Risse halten. Andere weiten sich unter der Korrektur, als widersetze sich das Gebäude der Hilfe.$DQ$, $DQ$The marble shifts under your hands. The load-bearing lines are deeper than you thought – the damage is foundational.$DQ$, $DQ$Der Marmor verschiebt sich unter euren Händen. Die tragenden Linien sind tiefer als gedacht – der Schaden ist fundamental.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cautious_lobby$DQ$, $DQ$tower_the_lobby$DQ$, $DQ$Move through quickly$DQ$, $DQ$Schnell hindurchgehen$DQ$, NULL, NULL, NULL, 0, $JB${"stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You cross the lobby without engaging it. The departure boards flicker in your peripheral vision. You try not to read them.$DQ$, $DQ$Ihr durchquert die Lobby, ohne euch auf sie einzulassen. Die Abfahrtstafeln flimmern in eurem peripheren Blickfeld. Ihr versucht, sie nicht zu lesen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$write_true_audit$DQ$, $DQ$tower_final_audit$DQ$, $DQ$Write the true audit (Spy)$DQ$, $DQ$Den wahren Bericht schreiben (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 10, $JB${"reveal_rooms": 2, "stability": 5, "stress": 10}$JB$::jsonb, $JB${"reveal_rooms": 1, "stress": 30}$JB$::jsonb, $JB${"stress": 70}$JB$::jsonb, $DQ$The pen knows what you know. The audit writes itself – every flaw, every overloaded column, every deferred repair. The tower shudders at its own truth.$DQ$, $DQ$Der Stift weiß, was ihr wisst. Der Bericht schreibt sich selbst – jeder Fehler, jede überladene Säule, jede aufgeschobene Reparatur. Der Turm erschauert vor seiner eigenen Wahrheit.$DQ$, $DQ$The report is half-complete. Some columns resist documentation, as if the tower censors its own failures.$DQ$, $DQ$Der Bericht ist halbfertig. Einige Säulen widersetzen sich der Dokumentation, als zensiere der Turm seine eigenen Fehler.$DQ$, $DQ$The pen breaks. The audit report fills itself with numbers that don't add up. The desk vibrates with fraudulent energy.$DQ$, $DQ$Der Stift bricht. Der Prüfbericht füllt sich mit Zahlen, die nicht aufgehen. Der Schreibtisch vibriert mit betrügerischer Energie.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$sabotage_last_column$DQ$, $DQ$tower_final_audit$DQ$, $DQ$Sabotage the last load-bearing column (Saboteur)$DQ$, $DQ$Die letzte tragende Säule sabotieren (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 10, $JB${"discovery": true, "stability": -10, "stress": -20}$JB$::jsonb, $JB${"stability": -15, "stress": 40}$JB$::jsonb, $JB${"stability": -20, "stress": 80}$JB$::jsonb, $DQ$Controlled structural failure. The column buckles precisely, opening a direct route to the summit. The tower groans but accepts.$DQ$, $DQ$Kontrolliertes Strukturversagen. Die Säule knickt präzise ein und öffnet einen direkten Weg zum Gipfel. Der Turm stöhnt, akzeptiert aber.$DQ$, $DQ$The column weakens but holds. The path opens partially. The building remembers this insult.$DQ$, $DQ$Die Säule schwächt sich, hält aber. Der Weg öffnet sich teilweise. Das Gebäude erinnert sich an diese Beleidigung.$DQ$, $DQ$The charge propagates. Three columns fail instead of one. The ceiling drops a meter. The route is open, but so is the abyss.$DQ$, $DQ$Die Ladung pflanzt sich fort. Drei Säulen versagen statt einer. Die Decke sinkt einen Meter. Der Weg ist offen, aber auch der Abgrund.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cautious_audit$DQ$, $DQ$tower_final_audit$DQ$, $DQ$Leave the desk untouched$DQ$, $DQ$Den Schreibtisch unberührt lassen$DQ$, NULL, NULL, NULL, 0, $JB${"stress": 20}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The pen remains. The blank pages remain. The audit that never happened is perhaps the most honest one.$DQ$, $DQ$Der Stift bleibt. Die leeren Seiten bleiben. Der Bericht, der nie geschrieben wurde, ist vielleicht der ehrlichste.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$expose_fraud$DQ$, $DQ$tower_confidence_game$DQ$, $DQ$Expose the fraud$DQ$, $DQ$Den Betrug aufdecken$DQ$, NULL, NULL, $DQ$propagandist$DQ$, 5, $JB${"stability": 5, "stress": -30}$JB$::jsonb, $JB${"stress": 30}$JB$::jsonb, $JB${"stress": 80}$JB$::jsonb, $DQ$The mechanism grinds to a halt. The certificates dissolve. For a moment the building shudders, then settles on honest foundations.$DQ$, $DQ$Der Mechanismus kommt zum Stillstand. Die Bescheinigungen lösen sich auf. Einen Moment lang bebt das Gebäude, dann setzt es sich auf ehrlichen Fundamenten ab.$DQ$, $DQ$The certificates tear, but the mechanism keeps printing. The fiction is dented, not broken.$DQ$, $DQ$Die Bescheinigungen reißen, aber der Mechanismus druckt weiter. Die Fiktion ist verbeult, nicht gebrochen.$DQ$, $DQ$The mechanism accelerates. More certificates. More lies. The building believes them even if you don't.$DQ$, $DQ$Der Mechanismus beschleunigt. Mehr Bescheinigungen. Mehr Lügen. Das Gebäude glaubt ihnen, selbst wenn ihr es nicht tut.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$analyze_architecture$DQ$, $DQ$tower_confidence_game$DQ$, $DQ$Analyze the architecture$DQ$, $DQ$Die Architektur analysieren$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"reveal_rooms": 2, "stress": 10}$JB$::jsonb, $JB${"reveal_rooms": 1, "stress": 30}$JB$::jsonb, $JB${"stress": 50}$JB$::jsonb, $DQ$The impossible geometry has a logic. You trace it, mapping two adjacent floors from the contradictions.$DQ$, $DQ$Die unmögliche Geometrie hat eine Logik. Ihr verfolgt sie und kartiert zwei angrenzende Stockwerke aus den Widersprüchen.$DQ$, $DQ$Fragments of the layout reveal themselves. One floor, partially mapped.$DQ$, $DQ$Fragmente des Grundrisses offenbaren sich. Ein Stockwerk, teilweise kartiert.$DQ$, $DQ$The contradictions multiply faster than you can process them. The headache lingers.$DQ$, $DQ$Die Widersprüche vermehren sich schneller, als ihr sie verarbeiten könnt. Die Kopfschmerzen bleiben.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$profit_from_fraud$DQ$, $DQ$tower_confidence_game$DQ$, $DQ$Profit from the system$DQ$, $DQ$Vom System profitieren$DQ$, $JB${"infiltrator": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"stability": -5, "stress": -10}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You issue yourself a certificate. The tower accepts it, briefly. The structural cost is someone else's problem.$DQ$, $DQ$Ihr stellt euch selbst eine Bescheinigung aus. Der Turm akzeptiert sie, kurz. Die strukturellen Kosten sind das Problem eines anderen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$walk_away_confidence$DQ$, $DQ$tower_confidence_game$DQ$, $DQ$Walk away$DQ$, $DQ$Weitergehen$DQ$, NULL, NULL, NULL, 0, $JB${"stress": 20}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave the mechanism running. Behind you, the certificates pile up. The fiction persists.$DQ$, $DQ$Ihr lasst den Mechanismus laufen. Hinter euch häufen sich die Bescheinigungen. Die Fiktion besteht fort.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$balance_books$DQ$, $DQ$tower_the_ledger$DQ$, $DQ$Balance the books$DQ$, $DQ$Die Bücher ausgleichen$DQ$, NULL, NULL, $DQ$guardian$DQ$, 5, $JB${"stability": 10, "stress": -20}$JB$::jsonb, $JB${"stability": 5, "stress": 20}$JB$::jsonb, $JB${"stability": -5, "stress": 60}$JB$::jsonb, $DQ$Column by column, you reconcile the accounts. The ledger stops humming. The floor beneath it settles.$DQ$, $DQ$Spalte für Spalte gleicht ihr die Konten aus. Das Hauptbuch hört auf zu summen. Der Boden darunter beruhigt sich.$DQ$, $DQ$Some columns balance. Others resist. The resonance dims but doesn't stop.$DQ$, $DQ$Einige Spalten gleichen sich aus. Andere widersetzen sich. Die Resonanz wird schwächer, hört aber nicht auf.$DQ$, $DQ$The numbers rearrange themselves faster than you can correct them. The debt grows. The floor groans.$DQ$, $DQ$Die Zahlen ordnen sich schneller um, als ihr sie korrigieren könnt. Die Schulden wachsen. Der Boden ächzt.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$tear_pages$DQ$, $DQ$tower_the_ledger$DQ$, $DQ$Tear the pages$DQ$, $DQ$Die Seiten herausreißen$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 0, $JB${"discovery": true, "stability": -5}$JB$::jsonb, $JB${"stability": -10, "stress": 40}$JB$::jsonb, $JB${"stability": -10, "stress": 80}$JB$::jsonb, $DQ$The pages come free with a sound like breaking ribs. The debt is erased, but so is whatever was holding this floor together.$DQ$, $DQ$Die Seiten lösen sich mit einem Geräusch wie brechender Rippen. Die Schulden sind gelöscht, aber auch was immer dieses Stockwerk zusammenhielt.$DQ$, $DQ$Half the pages tear. The rest grip the binding with unnatural strength.$DQ$, $DQ$Die Hälfte der Seiten reißt. Der Rest klammert sich mit unnatürlicher Kraft an die Bindung.$DQ$, $DQ$The ledger bites back. The pages slice skin and the debt compounds on contact.$DQ$, $DQ$Das Hauptbuch beißt zurück. Die Seiten schneiden Haut und die Schulden wachsen bei Kontakt.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$read_margins$DQ$, $DQ$tower_the_ledger$DQ$, $DQ$Read the margins$DQ$, $DQ$Die Randbemerkungen lesen$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"reveal_rooms": 2, "stress": 10}$JB$::jsonb, $JB${"stress": 30}$JB$::jsonb, $JB${"stress": 50}$JB$::jsonb, $DQ$The margins contain annotations – floor plans, load calculations, access routes. Someone was auditing this tower from the inside.$DQ$, $DQ$Die Ränder enthalten Anmerkungen – Grundrisse, Lastberechnungen, Zugangswege. Jemand hat diesen Turm von innen geprüft.$DQ$, $DQ$The handwriting dissolves as you read it. You catch fragments before they fade.$DQ$, $DQ$Die Handschrift löst sich auf, während ihr sie lest. Ihr fangt Fragmente auf, bevor sie verblassen.$DQ$, $DQ$The numbers in the margins are not calculations. They are names. Reading them aloud was a mistake.$DQ$, $DQ$Die Zahlen in den Rändern sind keine Berechnungen. Es sind Namen. Sie laut zu lesen war ein Fehler.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$close_book$DQ$, $DQ$tower_the_ledger$DQ$, $DQ$Close the book$DQ$, $DQ$Das Buch schließen$DQ$, NULL, NULL, NULL, 0, $JB${"stress": 15}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The cover closes with a sound like a vault door. The debt remains. It always does.$DQ$, $DQ$Der Deckel schließt sich mit einem Geräusch wie eine Tresortür. Die Schulden bleiben. Das tun sie immer.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 3) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$reinforce_statues$DQ$, $DQ$tower_fallen_assets$DQ$, $DQ$Reinforce the arrangement$DQ$, $DQ$Die Anordnung verstärken$DQ$, NULL, NULL, $DQ$guardian$DQ$, 5, $JB${"stability": 15, "stress": -30}$JB$::jsonb, $JB${"stability": 5, "stress": 20}$JB$::jsonb, $JB${"stability": -10, "stress": 60}$JB$::jsonb, $DQ$You brace the statues against each other. The arrangement holds. The tower remembers what support felt like.$DQ$, $DQ$Ihr stützt die Statuen gegeneinander ab. Die Anordnung hält. Der Turm erinnert sich, wie sich Stützung anfühlte.$DQ$, $DQ$Some statues stabilize. Others shift under your hands, settling into new angles of precariousness.$DQ$, $DQ$Einige Statuen stabilisieren sich. Andere verschieben sich unter euren Händen und nehmen neue Winkel der Unsicherheit ein.$DQ$, $DQ$A statue topples. The chain reaction shakes the floor and costs you more than you gained.$DQ$, $DQ$Eine Statue stürzt. Die Kettenreaktion erschüttert den Boden und kostet euch mehr, als ihr gewonnen habt.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$topple_statues$DQ$, $DQ$tower_fallen_assets$DQ$, $DQ$Topple the arrangement$DQ$, $DQ$Die Anordnung umstürzen$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"discovery": true, "stability": -5, "stress": 10}$JB$::jsonb, $JB${"stability": -10, "stress": 40}$JB$::jsonb, $JB${"stability": -15, "stress": 80}$JB$::jsonb, $DQ$The statues crash in controlled sequence. Behind the last one: a passage the tower was hiding from itself.$DQ$, $DQ$Die Statuen stürzen in kontrollierter Folge. Hinter der letzten: ein Durchgang, den der Turm vor sich selbst versteckt hat.$DQ$, $DQ$Half the statues fall. The passage is visible but partially blocked. The structure protests.$DQ$, $DQ$Die Hälfte der Statuen fällt. Der Durchgang ist sichtbar, aber teilweise blockiert. Die Struktur protestiert.$DQ$, $DQ$Uncontrolled demolition. The statues collapse inward and the ceiling follows their example.$DQ$, $DQ$Unkontrollierter Abriss. Die Statuen kollabieren nach innen und die Decke folgt ihrem Beispiel.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$study_statues$DQ$, $DQ$tower_fallen_assets$DQ$, $DQ$Study the arrangement$DQ$, $DQ$Die Anordnung studieren$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"insight": true, "reveal_rooms": 1, "stress": 0}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $JB${"stress": 40}$JB$::jsonb, $DQ$The angles are a language. The statues point to where the tower is weakest – and strongest. You read both.$DQ$, $DQ$Die Winkel sind eine Sprache. Die Statuen zeigen, wo der Turm am schwächsten ist – und am stärksten. Ihr lest beides.$DQ$, $DQ$You catch patterns but lose them when the vibration shifts. Partial data is better than none.$DQ$, $DQ$Ihr erkennt Muster, verliert sie aber, wenn die Vibration sich verschiebt. Teilweise Daten sind besser als keine.$DQ$, $DQ$The arrangement is too complex. The patterns dissolve into noise. Your head aches with unused insight.$DQ$, $DQ$Die Anordnung ist zu komplex. Die Muster lösen sich in Rauschen auf. Euer Kopf schmerzt von ungenutzter Erkenntnis.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$tower_rest_full$DQ$, $DQ$tower_the_vault$DQ$, $DQ$Rest (heal stress, risk ambush)$DQ$, $DQ$Rasten (Stress heilen, Hinterhalt-Risiko)$DQ$, NULL, NULL, NULL, 0, $JB${"ambush_chance": 0.2, "stress_heal": 200, "wounded_to_stressed": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party rests against reinforced walls. The tremors subside. For a few minutes, the numbers stop.$DQ$, $DQ$Die Gruppe rastet an verstärkten Wänden. Die Erschütterungen lassen nach. Für ein paar Minuten hören die Zahlen auf.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$tower_rest_guarded$DQ$, $DQ$tower_the_vault$DQ$, $DQ$Post a Guardian watch (safe, but Guardian doesn't heal)$DQ$, $DQ$Wächter aufstellen (sicher, aber Wächter heilt nicht)$DQ$, $JB${"guardian": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"guardian_no_heal": true, "stability": 10, "stress_heal": 200, "wounded_to_stressed": true}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The Guardian monitors the structural readings while others rest. No tremor comes unseen. The tower stabilizes locally.$DQ$, $DQ$Der Wächter überwacht die Strukturwerte, während die anderen rasten. Keine Erschütterung kommt unbemerkt. Der Turm stabilisiert sich lokal.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$tower_rest_assess$DQ$, $DQ$tower_the_vault$DQ$, $DQ$Saboteur assessment (stability boost, reveal room)$DQ$, $DQ$Saboteur-Bewertung (Stabilitätsschub, Raum aufdecken)$DQ$, $JB${"saboteur": 3}$JB$::jsonb, NULL, NULL, 0, $JB${"reveal_rooms": 1, "stability": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The Saboteur maps the load-bearing walls, identifying stress fractures and hidden passages. Knowledge is structural power.$DQ$, $DQ$Der Saboteur kartiert die tragenden Wände und identifiziert Spannungsrisse und verborgene Durchgänge. Wissen ist strukturelle Macht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$tower_careful_extract$DQ$, $DQ$tower_cache$DQ$, $DQ$Careful extraction (Spy)$DQ$, $DQ$Vorsichtige Bergung (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"loot": true}$JB$::jsonb, $JB${"loot": true, "loot_tier_penalty": 1}$JB$::jsonb, $JB${"stability": -10, "stress": 75, "trap_triggered": true}$JB$::jsonb, $DQ$Millimeter by millimeter, the strongbox slides free. The column holds. The capital is yours.$DQ$, $DQ$Millimeter für Millimeter gleitet der Tresor heraus. Die Säule hält. Das Kapital gehört euch.$DQ$, $DQ$The extraction is imperfect. Some contents scatter and devalue on contact with the floor.$DQ$, $DQ$Die Bergung ist unvollkommen. Einige Inhalte zerstreuen sich und verlieren an Wert bei Bodenkontakt.$DQ$, $DQ$The column cracks. The strongbox contents scatter as the ceiling settles three centimeters lower.$DQ$, $DQ$Die Säule bricht. Die Tresorinhalte zerstreuen sich, während die Decke drei Zentimeter tiefer sinkt.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$tower_demolish_extract$DQ$, $DQ$tower_cache$DQ$, $DQ$Controlled demolition (Saboteur)$DQ$, $DQ$Kontrollierter Abriss (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"loot": true}$JB$::jsonb, $JB${"loot": true, "loot_tier_penalty": 1, "stability": -5, "stress": 30}$JB$::jsonb, $JB${"stability": -10, "stress": 50}$JB$::jsonb, $DQ$The charge is precise. The column redistributes its load. The strongbox contents are intact.$DQ$, $DQ$Die Ladung ist präzise. Die Säule verteilt ihre Last um. Die Tresorinhalte sind intakt.$DQ$, $DQ$The blast is slightly off. The loot survives, but the floor shudders in protest.$DQ$, $DQ$Die Detonation ist leicht daneben. Die Beute überlebt, aber der Boden bebt im Protest.$DQ$, $DQ$Miscalculated. The blast propagates through the column into the floor. Structural damage compounds.$DQ$, $DQ$Fehlberechnet. Die Detonation pflanzt sich durch die Säule in den Boden fort. Strukturschäden kumulieren.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$tower_leave_cache$DQ$, $DQ$tower_cache$DQ$, $DQ$Leave it (no risk)$DQ$, $DQ$Liegenlassen (kein Risiko)$DQ$, NULL, NULL, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The column keeps its secret. The ceiling stays where it is. Some capital is best left embedded.$DQ$, $DQ$Die Säule behält ihr Geheimnis. Die Decke bleibt, wo sie ist. Manches Kapital lässt man besser eingebettet.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_echo_trace$DQ$, $DQ$The Awakening$DQ$, 1, $DQ$Echo Trace$DQ$, $DQ$Echospur$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $DQ$A trace of a memory that was not the party's. Handling it calms something that was not disturbed.$DQ$, $DQ$Eine Spur einer Erinnerung, die nicht der Gruppe gehörte. Sie zu berühren beruhigt etwas, das nicht gestört war.$DQ$, 30, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_deja_vu_fragment$DQ$, $DQ$The Awakening$DQ$, 1, $DQ$Déjà-vu Fragment$DQ$, $DQ$Déjà-vu-Fragment$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Gelernt, Erinnerung von Wahrnehmung zu unterscheiden", "content_en": "Learned to distinguish memory from perception", "importance": 4}$JB$::jsonb, $DQ$A crystallized moment of recognition that predates experience.$DQ$, $DQ$Ein kristallisierter Moment der Wiedererkennung, der der Erfahrung vorausgeht.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_lucid_lens$DQ$, $DQ$The Awakening$DQ$, 1, $DQ$Lucid Lens$DQ$, $DQ$Luzide Linse$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "spy", "bonus_pct": 5}$JB$::jsonb, $DQ$Perception sharpened by awareness. Spy checks +5%.$DQ$, $DQ$Wahrnehmung geschärft durch Bewusstsein. Spion-Proben +5%.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
