INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_mnemosyne_draught$DQ$, $DQ$The Awakening$DQ$, 2, $DQ$Mnemosyne Draught$DQ$, $DQ$Mnemosyne-Trunk$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 100, "when": "after_dungeon"}$JB$::jsonb, $DQ$From the river of memory. Drinking it restores what the descent consumed. The taste is of recognition.$DQ$, $DQ$Aus dem Fluss der Erinnerung. Ihn zu trinken stellt wieder her, was der Abstieg verbrauchte. Der Geschmack ist Wiedererkennung.$DQ$, 30, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_collective_impression$DQ$, $DQ$The Awakening$DQ$, 2, $DQ$Collective Impression$DQ$, $DQ$Kollektiver Eindruck$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Kollektives Bewusstsein erfahren – gleichzeitig durch mehrere Perspektiven wahrgenommen", "content_en": "Experienced shared consciousness – perceived through multiple perspectives simultaneously", "importance": 6}$JB$::jsonb, $DQ$A memory that belongs to no single agent but to the party as gestalt.$DQ$, $DQ$Eine Erinnerung, die keinem einzelnen Agenten gehört, sondern der Gruppe als Gestalt.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_philemon_whisper$DQ$, $DQ$The Awakening$DQ$, 2, $DQ$Philemon's Whisper$DQ$, $DQ$Philemons Flüstern$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "propagandist", "bonus_pct": 10}$JB$::jsonb, $DQ$Thoughts are like animals in the forest – not generated by the thinker. Propagandist checks +10%.$DQ$, $DQ$Gedanken sind wie Tiere im Wald – nicht vom Denker erzeugt. Propagandist-Proben +10%.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_zone_map$DQ$, $DQ$The Awakening$DQ$, 2, $DQ$Zone Map$DQ$, $DQ$Zonenkarte$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "infiltrator", "bonus_pct": 10}$JB$::jsonb, $DQ$Everything depends not on the Zone, but on the visitor. A map of the consciousness topology. Infiltrator checks +10%.$DQ$, $DQ$Alles hängt nicht von der Zone ab, sondern vom Besucher. Eine Karte der Bewusstseinstopologie. Infiltrator-Proben +10%.$DQ$, 20, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_insight$DQ$, $DQ$The Awakening$DQ$, 3, $DQ$Awakening Insight$DQ$, $DQ$Erwachens-Erkenntnis$DQ$, $DQ$personality_modifier$DQ$, $JB${"big_five_delta": 0.1, "player_choice": true}$JB$::jsonb, $DQ$The deepest insight. A shift in personality so fundamental it cannot be unlearned. Modify one agent's Big Five personality dimension by 0.1. The choice of which dimension is yours – and irreversible.$DQ$, $DQ$Die tiefste Erkenntnis. Eine Persönlichkeitsverschiebung so fundamental, dass sie nicht verlernt werden kann. Verändere eine Big-Five-Persönlichkeitsdimension eines Agenten um 0.1. Die Wahl der Dimension ist deine – und unwiderruflich.$DQ$, 40, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_individuation_key$DQ$, $DQ$The Awakening$DQ$, 3, $DQ$Individuation Key$DQ$, $DQ$Individuationsschlüssel$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "spy", "boost": 1}$JB$::jsonb, $DQ$Jung's key to individuation: the conscious integration of unconscious material. Perception permanently deepened. Spy aptitude +1.$DQ$, $DQ$Jungs Schlüssel zur Individuation: die bewusste Integration unbewussten Materials. Wahrnehmung dauerhaft vertieft. Spion-Aptitude +1.$DQ$, 35, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$awakening_collective_resonance$DQ$, $DQ$The Awakening$DQ$, 3, $DQ$Collective Resonance$DQ$, $DQ$Kollektive Resonanz$DQ$, $DQ$simulation_modifier$DQ$, $JB${"boost_amount": 0.15, "description_de": "Das kollektive Bewusstsein sickert in die Simulation. Alle Agenten erhalten +15% Moral für 10 Herzschlag-Ticks.", "description_en": "The collective consciousness bleeds into the simulation. All agents gain +15% morale for 10 heartbeat ticks.", "duration_ticks": 10, "morale_boost": true}$JB$::jsonb, $DQ$The collective consciousness resonates outward from the dungeon into the simulation itself. All agents gain +15% morale for 10 heartbeat ticks.$DQ$, $DQ$Das kollektive Bewusstsein resoniert nach außen vom Dungeon in die Simulation selbst. Alle Agenten erhalten +15% Moral für 10 Herzschlag-Ticks.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_brine_residue$DQ$, $DQ$The Deluge$DQ$, 1, $DQ$Brine Residue$DQ$, $DQ$Salzrückstand$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $DQ$Crystallized from evaporated floodwater. Holding it steadies the pulse. A mineral memory of when the water was calm.$DQ$, $DQ$Kristallisiert aus verdunstetem Flutwasser. Es in der Hand zu halten beruhigt den Puls. Eine mineralische Erinnerung daran, als das Wasser ruhig war.$DQ$, 30, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
