INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_seal_fragment$DQ$, $DQ$The Deluge$DQ$, 1, $DQ$Seal Fragment$DQ$, $DQ$Dichtungsfragment$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "guardian", "check_bonus": 5, "scope": "this_dungeon"}$JB$::jsonb, $DQ$A piece of whatever held the water back before the party arrived. Guardian checks +5%.$DQ$, $DQ$Ein Stück dessen, was das Wasser zurückhielt, bevor die Gruppe ankam. Wächter-Proben +5%.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_current_map$DQ$, $DQ$The Deluge$DQ$, 1, $DQ$Current Map$DQ$, $DQ$Strömungskarte$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "spy", "check_bonus": 5, "scope": "this_dungeon"}$JB$::jsonb, $DQ$A trace of the water's preferred paths. Spy checks +5%.$DQ$, $DQ$Eine Spur der bevorzugten Wege des Wassers. Spion-Proben +5%.$DQ$, 20, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_pressure_ward$DQ$, $DQ$The Deluge$DQ$, 2, $DQ$Pressure Ward$DQ$, $DQ$Druckschutz$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 120, "when": "after_dungeon"}$JB$::jsonb, $DQ$Equalized pressure from a sealed chamber. The relief is physical – the tension in the chest that was always there, gone.$DQ$, $DQ$Ausgeglichener Druck aus einer versiegelten Kammer. Die Erleichterung ist physisch – die Spannung in der Brust, die immer da war, weg.$DQ$, 30, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_salvage_record$DQ$, $DQ$The Deluge$DQ$, 2, $DQ$Salvage Record$DQ$, $DQ$Bergungsprotokoll$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Ein vollständiges Protokoll dessen, was die Flut trug und wo sie es ablagerte. Das Verständnis der Logik der Flut verändert die Beziehung des Agenten zum Verlust.", "content_en": "A complete record of what the flood carried and where it deposited. Understanding the flood's logic changes the agent's relationship to loss.", "importance": 7}$JB$::jsonb, $DQ$A complete record of what the flood carried and where it deposited. Understanding the flood's logic changes the agent's relationship to loss.$DQ$, $DQ$Ein vollständiges Protokoll dessen, was die Flut trug und wo sie es ablagerte. Das Verständnis der Logik der Flut verändert die Beziehung des Agenten zum Verlust.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_flood_barrier_shard$DQ$, $DQ$The Deluge$DQ$, 2, $DQ$Flood Barrier Shard$DQ$, $DQ$Flutsperrensplitter$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "saboteur", "scope": "this_dungeon", "stress_damage_bonus": 0.5}$JB$::jsonb, $DQ$A fragment of the barrier that held for 200 years. Applied to sabotage, the particle physics of resistance.$DQ$, $DQ$Ein Fragment der Sperre, die 200 Jahre hielt. Auf Sabotage angewandt, die Teilchenphysik des Widerstands.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
