INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_covenant_fragment$DQ$, $DQ$The Deluge$DQ$, 3, $DQ$Covenant Fragment$DQ$, $DQ$Bundesfragment$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "guardian", "boost": 1}$JB$::jsonb, $DQ$A fragment of the promise the water made: to recede, eventually. Carrying it changes how {agent} relates to protection. Guardian aptitude +1.$DQ$, $DQ$Ein Fragment des Versprechens, das das Wasser gab: sich zurückzuziehen, irgendwann. Es zu tragen verändert, wie {agent} sich zu Schutz verhält. Wächter-Aptitude +1.$DQ$, 40, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_deep_time_core$DQ$, $DQ$The Deluge$DQ$, 3, $DQ$Deep-Time Core$DQ$, $DQ$Tiefzeitkern$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "spy", "boost": 1}$JB$::jsonb, $DQ$Compressed sediment from the lowest floor. It contains the memory of every room the water passed through. Perception sharpened. Spy aptitude +1.$DQ$, $DQ$Komprimiertes Sediment vom tiefsten Stockwerk. Es enthält die Erinnerung an jeden Raum, den das Wasser durchquerte. Wahrnehmung geschärft. Spion-Aptitude +1.$DQ$, 35, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$deluge_elemental_warding$DQ$, $DQ$The Deluge$DQ$, 3, $DQ$Elemental Warding$DQ$, $DQ$Elementarschutz$DQ$, $DQ$simulation_modifier$DQ$, $JB${"building_protection": true, "description_de": "Ein Gebäude wird immun gegen Zustandsverschlechterung unter 'moderat' für 10 Herzschlag-Ticks. Das Inverse der Flut: Bewahrung.", "description_en": "One building becomes immune to condition degradation below 'moderate' for 10 heartbeat ticks. The flood's inverse: preservation.", "duration_ticks": 10, "min_condition": "moderate"}$JB$::jsonb, $DQ$One building in the simulation becomes immune to condition degradation below 'moderate' for 10 heartbeat ticks. The flood's inverse: preservation.$DQ$, $DQ$Ein Gebäude in der Simulation wird immun gegen Zustandsverschlechterung unter »moderat« für 10 Herzschlag-Ticks. Das Inverse der Flut: Bewahrung.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_nutrient_concentrate$DQ$, $DQ$The Devouring Mother$DQ$, 1, $DQ$Nutrient Concentrate$DQ$, $DQ$Nährstoffkonzentrat$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 60, "when": "after_dungeon"}$JB$::jsonb, $DQ$A warm capsule of biological material. Your instruments read it as vitamins, minerals, amino acids. Your body reads it as comfort.$DQ$, $DQ$Eine warme Kapsel biologischen Materials. Eure Instrumente lesen Vitamine, Minerale, Aminosäuren. Euer Körper liest Geborgenheit.$DQ$, 25, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_binding_insight$DQ$, $DQ$The Devouring Mother$DQ$, 1, $DQ$Symbiosis Insight$DQ$, $DQ$Symbioseerkenntnis$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Gelernt, wie die Mutter die Bedürfnisse des Körpers liest und reagiert, bevor man fragt", "content_en": "Learned how the Mother reads the body's needs and responds before being asked", "importance": 4}$JB$::jsonb, $DQ$A fragment of understanding: how biological systems learn to anticipate needs. The knowledge is useful. The knowledge is also the mechanism.$DQ$, $DQ$Ein Fragment des Verständnisses: wie biologische Systeme lernen, Bedürfnisse zu antizipieren. Das Wissen ist nützlich. Das Wissen ist auch der Mechanismus.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_warmth_fragment$DQ$, $DQ$The Devouring Mother$DQ$, 1, $DQ$Warmth Fragment$DQ$, $DQ$Wärmefragment$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "propagandist", "check_bonus": 5, "scope": "this_dungeon"}$JB$::jsonb, $DQ$A shard that radiates warmth. It resists the Mother's emotional pull. Propagandist checks +5%.$DQ$, $DQ$Ein Splitter, der Wärme abstrahlt. Er widersteht dem emotionalen Sog der Mutter. Propagandist-Proben +5%.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_tissue_sample$DQ$, $DQ$The Devouring Mother$DQ$, 1, $DQ$Living Tissue Sample$DQ$, $DQ$Lebendgewebeprobe$DQ$, $DQ$dungeon_buff$DQ$, $JB${"rest_bonus": 0.25, "scope": "this_dungeon"}$JB$::jsonb, $DQ$A sample of the Mother's tissue, still alive. Still warm. It enhances rest healing by 25%. It does not stop growing.$DQ$, $DQ$Eine Probe des Gewebes der Mutter, noch lebendig. Noch warm. Sie verstärkt Rastheilung um 25%. Sie hört nicht auf zu wachsen.$DQ$, 25, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_symbiont_shard$DQ$, $DQ$The Devouring Mother$DQ$, 2, $DQ$Symbiont Shard$DQ$, $DQ$Symbiontsplitter$DQ$, $DQ$moodlet$DQ$, $JB${"emotion": "serene", "moodlet_id": "mother_attuned", "strength": 8}$JB$::jsonb, $DQ$A fragment of symbiotic tissue that bonds with the carrier. It provides a profound sense of calm. The calm is genuine.$DQ$, $DQ$Ein Fragment symbiotischen Gewebes, das sich mit dem Träger verbindet. Es vermittelt eine tiefe Ruhe. Die Ruhe ist echt.$DQ$, 30, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_membrane_key$DQ$, $DQ$The Devouring Mother$DQ$, 2, $DQ$Membrane Key$DQ$, $DQ$Membranschlüssel$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Versteht die vaskuläre Architektur der Mutter — wie Nährstoffe fließen, wie Bindung sich vertieft", "content_en": "Understands the Mother's vascular architecture — how nutrients flow, how attachment deepens", "importance": 7}$JB$::jsonb, $DQ$A biological key that reads the Mother's circulatory map. Knowing the architecture does not make it less effective.$DQ$, $DQ$Ein biologischer Schlüssel, der die Kreislaufkarte der Mutter liest. Die Architektur zu kennen macht sie nicht weniger wirksam.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_guardian_graft$DQ$, $DQ$The Devouring Mother$DQ$, 2, $DQ$Guardian Graft$DQ$, $DQ$Wächterpfropf$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "guardian", "aptitude_boost": 1, "archetype": "The Devouring Mother", "scope": "archetype"}$JB$::jsonb, $DQ$Tissue grafted from a former Guardian host. It remembers how to sever. Permanent +1 Guardian aptitude in Devouring Mother dungeons.$DQ$, $DQ$Gewebe, gepfropft von einem ehemaligen Wächter-Wirt. Es erinnert sich, wie man durchtrennt. Permanent +1 Wächter-Eignung in Verschlingende-Mutter-Dungeons.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_spore_catalyst$DQ$, $DQ$The Devouring Mother$DQ$, 2, $DQ$Spore Catalyst$DQ$, $DQ$Sporenkatalysator$DQ$, $DQ$event_modifier$DQ$, $JB${"impact_level": -1}$JB$::jsonb, $DQ$A concentrated spore extract. When released into a simulation's ecosystem, it dampens the severity of the next negative event.$DQ$, $DQ$Ein konzentrierter Sporenextrakt. In das Ökosystem einer Simulation freigesetzt, dämpft er die Schwere des nächsten negativen Ereignisses.$DQ$, 15, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_cradle_map$DQ$, $DQ$The Devouring Mother$DQ$, 2, $DQ$Cradle Map$DQ$, $DQ$Wiegenkarte$DQ$, $DQ$dungeon_buff$DQ$, $JB${"archetype": "The Devouring Mother", "reveal_rest_rooms": true, "scope": "next_run"}$JB$::jsonb, $DQ$A biological diagram grown into living tissue. It maps the locations of rest sites in the next Devouring Mother dungeon.$DQ$, $DQ$Ein biologisches Diagramm, gewachsen in lebendes Gewebe. Es kartiert die Standorte der Raststätten im nächsten Verschlingende-Mutter-Dungeon.$DQ$, 10, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_restoration_organ$DQ$, $DQ$The Devouring Mother$DQ$, 3, $DQ$Restoration Organ$DQ$, $DQ$Restaurierungsorgan$DQ$, $DQ$building_repair$DQ$, $JB${"condition_tiers": 1}$JB$::jsonb, $DQ$A living organ, pulsing with restorative compounds. When applied to damaged infrastructure, it grows repair tissue into the structure. The repair is permanent. The organ continues to pulse.$DQ$, $DQ$Ein lebendes Organ, pulsierend mit restaurativen Verbindungen. Auf beschädigte Infrastruktur angewendet, wächst es Reparaturgewebe in die Struktur. Die Reparatur ist permanent. Das Organ pulsiert weiter.$DQ$, 100, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_nursery_memory$DQ$, $DQ$The Devouring Mother$DQ$, 3, $DQ$Nursery Memory$DQ$, $DQ$Kinderstubenerinnerung$DQ$, $DQ$memory$DQ$, $JB${"behavior_effect": "more_nurturing_less_aggressive", "content_de": "Erinnert sich an die Kinderstube — die Hülsen, die Wärme, die Dinge, die einst Menschen waren. Die Erinnerung verändert, wie sie andere behandeln.", "content_en": "Remembers the nursery — the pods, the warmth, the things that were once people. The memory changes how they treat others.", "importance": 9}$JB$::jsonb, $DQ$The memory of the nursery: what it means to be cared for completely, and what that care costs. The agent becomes more nurturing, less aggressive.$DQ$, $DQ$Die Erinnerung an die Kinderstube: was es bedeutet, vollständig umsorgt zu werden, und was diese Fürsorge kostet. Der Agent wird fürsorglicher, weniger aggressiv.$DQ$, 100, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$mother_symbiont_attunement$DQ$, $DQ$The Devouring Mother$DQ$, 3, $DQ$Symbiont Attunement$DQ$, $DQ$Symbionteneinstimmung$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "guardian|propagandist", "boost": 1, "max_total_boost": 2}$JB$::jsonb, $DQ$Deep attunement with the Mother's symbiotic systems. The carrier's capacity for protection or persuasion permanently increases. +1 Guardian OR Propagandist aptitude (max +2 cap).$DQ$, $DQ$Tiefe Einstimmung mit den symbiotischen Systemen der Mutter. Die Fähigkeit des Trägers für Schutz oder Überzeugung steigt permanent. +1 Wächter- ODER Propagandist-Eignung (max. +2 Grenze).$DQ$, 50, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$entropy_residue$DQ$, $DQ$The Entropy$DQ$, 1, $DQ$Entropy Residue$DQ$, $DQ$Entropierückstand$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $DQ$Crystallized sameness. Holding it removes the anxiety of distinction. That should worry you.$DQ$, $DQ$Kristallisierte Gleichheit. Sie zu halten nimmt die Angst der Unterscheidung. Das sollte euch beunruhigen.$DQ$, 40, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$dissolution_insight$DQ$, $DQ$The Entropy$DQ$, 1, $DQ$Dissolution Insight$DQ$, $DQ$Auflösungserkenntnis$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Gelernt, die Geschwindigkeit abzulesen, mit der Dinge aufhören, unterscheidbar zu sein", "content_en": "Learned to read the rate at which things cease to be distinct", "importance": 4}$JB$::jsonb, $DQ$A fragment of understanding: how systems equalize, and why equalization is the default.$DQ$, $DQ$Ein Fragment des Verständnisses: wie Systeme sich angleichen und warum Angleichung der Normalzustand ist.$DQ$, 30, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$preservation_fragment$DQ$, $DQ$The Entropy$DQ$, 1, $DQ$Preservation Fragment$DQ$, $DQ$Bewahrungsfragment$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "guardian", "check_bonus": 5, "scope": "this_dungeon"}$JB$::jsonb, $DQ$A shard that remembers how to keep things separate. Guardian checks +5%.$DQ$, $DQ$Ein Splitter, der sich erinnert, wie man Dinge getrennt hält. Wächter-Proben +5%.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$decay_redirect$DQ$, $DQ$The Entropy$DQ$, 1, $DQ$Decay Redirect$DQ$, $DQ$Verfallsumleitung$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "saboteur", "scope": "this_dungeon", "stress_damage_bonus": 0.5}$JB$::jsonb, $DQ$Redirected entropy in a stable container. Applied to sabotage, the dissolution cuts both ways.$DQ$, $DQ$Umgeleitete Entropie in stabilem Behälter. Auf Sabotage angewendet schneidet die Auflösung in beide Richtungen.$DQ$, 10, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$equilibrium_shard$DQ$, $DQ$The Entropy$DQ$, 1, $DQ$Equilibrium Shard$DQ$, $DQ$Gleichgewichtssplitter$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "spy", "check_bonus": 5, "scope": "this_dungeon"}$JB$::jsonb, $DQ$Understanding of how sameness spreads – and where the last differences hide. Spy checks +5%.$DQ$, $DQ$Verständnis davon, wie Gleichheit sich ausbreitet – und wo die letzten Unterschiede sich verbergen. Spion-Proben +5%.$DQ$, 20, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
