INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$vestige_of_purpose$DQ$, $DQ$The Entropy$DQ$, 1, $DQ$Vestige of Purpose$DQ$, $DQ$Überrest des Zwecks$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Einen Gegenstand gefunden, der noch wusste, wofür er war. Die Erinnerung an Zweck überdauert den Zweck selbst.", "content_en": "Found an object that still knew what it was for. The memory of purpose persists longer than purpose itself.", "importance": 4}$JB$::jsonb, $DQ$A fragment of understanding gained from something that refused to forget.$DQ$, $DQ$Ein Fragment des Verständnisses, gewonnen von etwas, das sich weigerte zu vergessen.$DQ$, 25, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
