INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$dissolution_fragment$DQ$, $DQ$The Entropy$DQ$, 2, $DQ$Dissolution Fragment$DQ$, $DQ$Auflösungsfragment$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Entropie aus erster Hand bezeugt. Verstanden, dass Bewahrung nicht das Gegenteil von Verfall ist – sie ist Verfall, langsamer.", "content_en": "Witnessed entropy firsthand. Understood that preservation is not the opposite of decay – it is decay, slower.", "importance": 7}$JB$::jsonb, $DQ$Creates a high-importance Reflection Memory about dissolution and persistence.$DQ$, $DQ$Erzeugt eine hochbedeutende Reflexionserinnerung über Auflösung und Beharrung.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
