INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$entropy_catalyst$DQ$, $DQ$The Entropy$DQ$, 2, $DQ$Entropy Catalyst$DQ$, $DQ$Entropiekatalysator$DQ$, $DQ$event_modifier$DQ$, $JB${"impact_level_reduction": 1, "scope": "one_event"}$JB$::jsonb, $DQ$Can reduce one Event's impact_level by 1. What dissolves boundaries can also dissolve consequences.$DQ$, $DQ$Kann den Einflussgrad eines Ereignisses um 1 senken. Was Grenzen auflöst, kann auch Konsequenzen auflösen.$DQ$, 15, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$restoration_blueprint$DQ$, $DQ$The Entropy$DQ$, 2, $DQ$Restoration Blueprint$DQ$, $DQ$Restaurierungsbauplan$DQ$, $DQ$next_dungeon_bonus$DQ$, $JB${"all_rooms_revealed": true, "scope": "next_entropy_dungeon", "start_decay": 0}$JB$::jsonb, $DQ$Next Entropy dungeon: all rooms pre-revealed. Knowledge persists where matter cannot.$DQ$, $DQ$Nächster Entropie-Dungeon: Alle Räume vorher enthüllt. Wissen besteht, wo Materie es nicht kann.$DQ$, 10, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$restoration_fragment$DQ$, $DQ$The Entropy$DQ$, 3, $DQ$Restoration Fragment$DQ$, $DQ$Restaurierungsfragment$DQ$, $DQ$building_repair$DQ$, $JB${"condition_improvement": 1, "scope": "one_building"}$JB$::jsonb, $DQ$Improves one building's condition by one tier. Salvaged from the Verfall-Garten – proof that entropy can be reversed, once, at great cost.$DQ$, $DQ$Verbessert den Zustand eines Gebäudes um eine Stufe. Geborgen aus dem Verfall-Garten – Beweis, dass Entropie umkehrbar ist, einmal, unter großen Kosten.$DQ$, 100, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$garden_memory$DQ$, $DQ$The Entropy$DQ$, 3, $DQ$Garden Memory$DQ$, $DQ$Gartenerinnerung$DQ$, $DQ$memory$DQ$, $JB${"behavior_effect": "more_patient_less_impulsive", "content_de": "Durch den Verfall-Garten gegangen und zurückgekehrt. Gelernt, dass Geduld nicht Passivität ist – sie ist die disziplinierte Weigerung, die gegebene Verfallsrate zu akzeptieren.", "content_en": "Walked through the Verfall-Garten and returned. Learned that patience is not passivity – it is the disciplined refusal to accept the given rate of dissolution.", "importance": 9}$JB$::jsonb, $DQ$High-importance Memory: affects agent autonomous behavior (more patient, less impulsive).$DQ$, $DQ$Hochbedeutende Erinnerung: beeinflusst autonomes Verhalten (geduldiger, weniger impulsiv).$DQ$, 100, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
