INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_faction_dossier$DQ$, $DQ$The Overthrow$DQ$, 1, $DQ$Faction Dossier$DQ$, $DQ$Fraktionsdossier$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $DQ$Names, alliances, debts. Kadare's Palace of Dreams made portable. Knowledge is not power — knowledge is the absence of fear.$DQ$, $DQ$Namen, Bündnisse, Schulden. Kadares Palast der Träume, tragbar gemacht. Wissen ist nicht Macht — Wissen ist die Abwesenheit von Furcht.$DQ$, 30, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_propaganda_leaflet$DQ$, $DQ$The Overthrow$DQ$, 1, $DQ$Propaganda Leaflet$DQ$, $DQ$Propagandaflugblatt$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "propagandist", "boost": 5, "duration_rooms": 5}$JB$::jsonb, $DQ$Squealer's latest revision. The words are wrong but the technique is instructive.$DQ$, $DQ$Schwatzwutz' neueste Überarbeitung. Die Worte sind falsch, aber die Technik ist lehrreich.$DQ$, 30, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_informers_list$DQ$, $DQ$The Overthrow$DQ$, 1, $DQ$Informer's List$DQ$, $DQ$Spitzelliste$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "spy", "boost": 5, "duration_rooms": 5}$JB$::jsonb, $DQ$A list of names. Some are informers. Some are targets. The difference is a matter of perspective.$DQ$, $DQ$Eine Namensliste. Manche sind Spitzel. Manche sind Ziele. Der Unterschied ist eine Frage der Perspektive.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_safe_conduct$DQ$, $DQ$The Overthrow$DQ$, 1, $DQ$Safe Conduct Pass$DQ$, $DQ$Geleitbrief$DQ$, $DQ$dungeon_buff$DQ$, $JB${"duration_rooms": 4, "stress_resist": 0.1}$JB$::jsonb, $DQ$Signed by a faction leader. Valid until the faction leader is replaced. Which could be any moment.$DQ$, $DQ$Unterschrieben von einem Fraktionsführer. Gültig, bis der Fraktionsführer ersetzt wird. Was jederzeit sein könnte.$DQ$, 15, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_decoded_cipher$DQ$, $DQ$The Overthrow$DQ$, 2, $DQ$Decoded Cipher$DQ$, $DQ$Entschlüsselte Chiffre$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 100, "when": "after_dungeon"}$JB$::jsonb, $DQ$Faction communications, decoded. The content is less important than the fact of decoding. Manuscripts don't burn. But codes can be broken.$DQ$, $DQ$Fraktionskommunikation, entschlüsselt. Der Inhalt ist weniger wichtig als die Tatsache der Entschlüsselung. Manuskripte brennen nicht. Aber Codes können geknackt werden.$DQ$, 25, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_seal_of_office$DQ$, $DQ$The Overthrow$DQ$, 2, $DQ$Seal of Office$DQ$, $DQ$Amtssiegel$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "propagandist", "boost": 10, "duration_rooms": 8}$JB$::jsonb, $DQ$An official seal. The office no longer exists. The seal still carries weight — authority persists after the authority is gone.$DQ$, $DQ$Ein Amtssiegel. Das Amt existiert nicht mehr. Das Siegel hat noch Gewicht — Autorität besteht fort, nachdem die Autorität vergangen ist.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_double_agents_testimony$DQ$, $DQ$The Overthrow$DQ$, 2, $DQ$Double Agent's Testimony$DQ$, $DQ$Aussage des Doppelagenten$DQ$, $DQ$dungeon_buff$DQ$, $JB${"duration_rooms": 6, "stress_resist": 0.15}$JB$::jsonb, $DQ$Ngũgĩ's informer-hero: the traitor whose confession is the most heroic act. This testimony protects because it reveals — and revelation is armor.$DQ$, $DQ$Ngũgĩs Spitzel-Held: der Verräter, dessen Geständnis die heldenhafteste Tat ist. Diese Aussage schützt, weil sie enthüllt — und Enthüllung ist Rüstung.$DQ$, 25, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_erased_photograph$DQ$, $DQ$The Overthrow$DQ$, 2, $DQ$Erased Photograph$DQ$, $DQ$Gelöschtes Foto$DQ$, $DQ$memory$DQ$, $JB${"memory_text_de": "Ein Foto mit ausgekratztem Gesicht. Die Mütze bleibt.", "memory_text_en": "A photograph with a scratched-out face. The hat remains."}$JB$::jsonb, $DQ$Kundera's Clementis photograph. The body erased, the fur hat remaining on Gottwald's head. Evidence that something was, before it was unmade.$DQ$, $DQ$Kunderas Clementis-Foto. Der Körper gelöscht, die Pelzmütze noch auf Gottwalds Kopf. Beweis, dass etwas war, bevor es ungemacht wurde.$DQ$, 25, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_authority_fragment$DQ$, $DQ$The Overthrow$DQ$, 3, $DQ$Authority Fragment$DQ$, $DQ$Autoritätsfragment$DQ$, $DQ$simulation_modifier$DQ$, $JB${"boost_amount": 1, "description_de": "Ein Fragment legitimer Autorität, aus dem Spiegelpalast geborgen. Erhöht die Sicherheitsstufe einer Zone um 1 Stufe für 10 Herzschlag-Ticks.", "description_en": "A fragment of legitimate authority, salvaged from the Spiegelpalast. Upgrades one zone's security level by 1 tier for 10 heartbeat ticks.", "duration_ticks": 10, "security_boost": true}$JB$::jsonb, $DQ$Spec loot: upgrades one zone's security_level by 1 tier for 10 heartbeat ticks. Authority, portable.$DQ$, $DQ$Spezifikationsbeute: erhöht die Sicherheitsstufe einer Zone um 1 Stufe für 10 Herzschlag-Ticks. Autorität, tragbar.$DQ$, 40, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_colossus_splinter$DQ$, $DQ$The Overthrow$DQ$, 3, $DQ$Colossus Splinter$DQ$, $DQ$Koloss-Splitter$DQ$, $DQ$simulation_modifier$DQ$, $JB${"boost_amount": 0.15, "description_de": "La Boéties Koloss: der Tyrann, dessen Sockel weggezogen wurde. Ein Splitter des Gefallenen. Alle Agenten erhalten +15% Moral für 10 Herzschlag-Ticks.", "description_en": "La Boétie's Colossus: the tyrant whose pedestal was pulled away. A splinter of the fallen. All agents gain +15% morale for 10 heartbeat ticks.", "duration_ticks": 10, "morale_boost": true}$JB$::jsonb, $DQ$A splinter from the Colossus that fell of its own weight. La Boétie's proof: tyranny requires consent. All agents gain +15% morale for 10 heartbeat ticks.$DQ$, $DQ$Ein Splitter des Kolosses, der unter seinem eigenen Gewicht fiel. La Boéties Beweis: Tyrannei braucht Zustimmung. Alle Agenten erhalten +15% Moral für 10 Herzschlag-Ticks.$DQ$, 35, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$overthrow_mirror_shard$DQ$, $DQ$The Overthrow$DQ$, 3, $DQ$Mirror Shard of the Spiegelpalast$DQ$, $DQ$Spiegelscherbe des Spiegelpalasts$DQ$, $DQ$personality_modifier$DQ$, $JB${"delta": 5, "description_de": "Der Spiegel zeigt, was der Betrachter will, nicht was er ist. Offenheit +5.", "description_en": "The mirror shows what the viewer wants, not what the viewer is. Openness +5.", "trait": "openness"}$JB$::jsonb, $DQ$A shard of the Spiegelpalast's central mirror. It still reflects — but what it reflects is no longer the room.$DQ$, $DQ$Eine Scherbe des zentralen Spiegels im Spiegelpalast. Sie reflektiert noch — aber was sie reflektiert, ist nicht mehr der Raum.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_spark_residue$DQ$, $DQ$The Prometheus$DQ$, 1, $DQ$Spark Residue$DQ$, $DQ$Funkenrückstand$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $DQ$Crystallized energy from a defeated construct. It hums at a frequency that calms the nervous system.$DQ$, $DQ$Kristallisierte Energie eines besiegten Konstrukts. Sie summt auf einer Frequenz, die das Nervensystem beruhigt.$DQ$, 40, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_workshop_insight$DQ$, $DQ$The Prometheus$DQ$, 1, $DQ$Workshop Insight$DQ$, $DQ$Werkstatterkenntnis$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Die Selbstorganisationsprinzipien der Werkstatt beobachtet. Materie hat Präferenzen.", "content_en": "Observed the workshop's self-organizing principles. Matter has preferences.", "importance": 5}$JB$::jsonb, $DQ$A fragment of understanding: how the workshop thinks. How materials choose their partners.$DQ$, $DQ$Ein Fragment des Verständnisses: wie die Werkstatt denkt. Wie Materialien ihre Partner wählen.$DQ$, 30, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_calibration_shard$DQ$, $DQ$The Prometheus$DQ$, 1, $DQ$Calibration Shard$DQ$, $DQ$Kalibrierungssplitter$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "saboteur", "check_bonus": 5, "scope": "this_dungeon"}$JB$::jsonb, $DQ$A precisely fractured crystal. Saboteur checks +5% – the workshop approves of hands that build.$DQ$, $DQ$Ein präzise gebrochener Kristall. Saboteur-Proben +5% – die Werkstatt billigt Hände, die bauen.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_forge_ember$DQ$, $DQ$The Prometheus$DQ$, 1, $DQ$Forge Ember$DQ$, $DQ$Schmiedeglut$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "infiltrator", "scope": "this_dungeon", "stress_damage_bonus": 0.5}$JB$::jsonb, $DQ$A contained ember from the workshop's forge. It makes delicate work easier – and more dangerous.$DQ$, $DQ$Eine eingedämmte Glut aus der Schmiede der Werkstatt. Sie macht feine Arbeit leichter – und gefährlicher.$DQ$, 10, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_tempered_lens$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Tempered Observation Lens$DQ$, $DQ$Gehärtete Beobachtungslinse$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "spy", "boost": 1}$JB$::jsonb, $DQ$A lens forged in the workshop's crucible. It reveals patterns invisible to the unaugmented eye. Spy aptitude +1.$DQ$, $DQ$Eine in der Werkstattschmelze geschmiedete Linse. Sie enthüllt Muster, die für das unverstärkte Auge unsichtbar sind. Spion-Aptitude +1.$DQ$, 25, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_catalytic_compound$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Catalytic Compound$DQ$, $DQ$Katalytische Verbindung$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "saboteur", "boost": 1}$JB$::jsonb, $DQ$A compound that accelerates material reactions. The workshop's gift to hands that dare to combine. Saboteur aptitude +1.$DQ$, $DQ$Eine Verbindung, die Materialreaktionen beschleunigt. Das Geschenk der Werkstatt an Hände, die es wagen zu kombinieren. Saboteur-Aptitude +1.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_resonance_tuner$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Resonance Tuner$DQ$, $DQ$Resonanzstimmer$DQ$, $DQ$moodlet$DQ$, $JB${"description_de": "Die Befriedigung der Schöpfung – etwas Neues existiert wegen dem, was ihr getan habt.", "description_en": "The satisfaction of creation – something new exists because of what you did.", "mood_delta": 15}$JB$::jsonb, $DQ$A device that harmonizes with the bearer's frequency. It provides comfort. It also provides dependency.$DQ$, $DQ$Ein Gerät, das mit der Frequenz des Trägers harmoniert. Es bietet Trost. Es bietet auch Abhängigkeit.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_alloy_fragment$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Experimental Alloy Fragment$DQ$, $DQ$Experimentelles Legierungsfragment$DQ$, $DQ$next_dungeon_bonus$DQ$, $JB${"bonus_type": "insight_start", "description_de": "Nächster Dungeon-Run beginnt mit 15 Insight.", "description_en": "Next dungeon run starts with 15 insight.", "value": 15}$JB$::jsonb, $DQ$A fragment of alloy that remembers being part of something larger. Carry it into the next workshop – the fire will recognize it.$DQ$, $DQ$Ein Legierungsfragment, das sich erinnert, Teil von etwas Größerem gewesen zu sein. Tragt es in die nächste Werkstatt – das Feuer wird es erkennen.$DQ$, 15, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_pharmakon_vial$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Pharmakon Vial$DQ$, $DQ$Pharmakon-Phiole$DQ$, $DQ$event_modifier$DQ$, $JB${"benefit": {"stress_heal": 80}, "cost": {"aptitude_penalty": {"duration_hours": 24, "saboteur": -1, "scope": "temporary"}}, "modifier": "dual_effect"}$JB$::jsonb, $DQ$A vial containing a substance that is simultaneously remedy and poison. Heals 80 stress. Temporarily reduces Saboteur aptitude by 1 for 24h.$DQ$, $DQ$Eine Phiole mit einer Substanz, die gleichzeitig Heilmittel und Gift ist. Heilt 80 Stress. Reduziert Saboteur-Aptitude temporär um 1 für 24h.$DQ$, 15, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_innovation_blueprint$DQ$, $DQ$The Prometheus$DQ$, 3, $DQ$Innovation Blueprint$DQ$, $DQ$Innovationsblaupause$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "any", "boost": 1}$JB$::jsonb, $DQ$The workshop's final gift. A blueprint that imprints itself on the bearer – permanent knowledge, paid for in fire. +1 to one aptitude of the bearer's highest.$DQ$, $DQ$Das letzte Geschenk der Werkstatt. Eine Blaupause, die sich dem Träger einprägt – permanentes Wissen, bezahlt in Feuer. +1 auf eine Aptitude des höchsten Werts des Trägers.$DQ$, 50, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_prototype_core$DQ$, $DQ$The Prometheus$DQ$, 3, $DQ$Prototype Core$DQ$, $DQ$Prototyp-Kern$DQ$, $DQ$permanent_dungeon_bonus$DQ$, $JB${"bonus_type": "crafting_mastery", "description_de": "Alle zukünftigen Prometheus-Dungeon-Crafting-Proben +10%.", "description_en": "All future Prometheus dungeon crafting checks +10%."}$JB$::jsonb, $DQ$The core of The Prototype. It pulses with unfinished potential. Whoever carries this understands the workshop better than the workshop understands itself.$DQ$, $DQ$Der Kern des Prototypen. Er pulsiert mit unfertigem Potential. Wer dies trägt, versteht die Werkstatt besser, als die Werkstatt sich selbst versteht.$DQ$, 30, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_stolen_fire$DQ$, $DQ$The Prometheus$DQ$, 3, $DQ$Stolen Fire$DQ$, $DQ$Gestohlenes Feuer$DQ$, $DQ$arc_modifier$DQ$, $JB${"arc_effect": "innovation_catalyst", "description_de": "Der Agent, der dies trägt, erzeugt +0,15 Gebäudebereitschaft pro Zyklus.", "description_en": "The agent who carries this generates +0.15 Building Readiness per cycle."}$JB$::jsonb, $DQ$Fire from the gods. Not a metaphor – a substance. It does not burn the hand that carries it. It burns everything the hand touches.$DQ$, $DQ$Feuer der Götter. Keine Metapher – eine Substanz. Es verbrennt nicht die Hand, die es trägt. Es verbrennt alles, was die Hand berührt.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
