INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$load_bearing_knowledge$DQ$, $DQ$The Tower$DQ$, 1, $DQ$Load-Bearing Knowledge$DQ$, $DQ$Tragendes Wissen$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "guardian", "check_bonus": 5, "scope": "this_dungeon"}$JB$::jsonb, $DQ$Intuition for what holds and what breaks – and how to be on the right side. Guardian checks +5%.$DQ$, $DQ$Intuition für das, was hält, und das, was bricht – und wie man auf der richtigen Seite steht. Wächter-Proben +5%.$DQ$, 15, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$collapse_resonance$DQ$, $DQ$The Tower$DQ$, 1, $DQ$Collapse Resonance$DQ$, $DQ$Einsturzresonanz$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 30, "when": "immediate"}$JB$::jsonb, $DQ$A frequency captured from a controlled demolition. Hearing it resets the nervous system – the body forgets its fear of falling.$DQ$, $DQ$Eine Frequenz, eingefangen bei einem kontrollierten Abriss. Sie zu hören setzt das Nervensystem zurück – der Körper vergisst seine Angst vor dem Fallen.$DQ$, 25, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$demolition_echo$DQ$, $DQ$The Tower$DQ$, 1, $DQ$Demolition Echo$DQ$, $DQ$Abrissecho$DQ$, $DQ$dungeon_buff$DQ$, $JB${"aptitude": "saboteur", "check_bonus": 5, "scope": "this_dungeon"}$JB$::jsonb, $DQ$The resonance of a perfectly placed charge. Saboteur checks +5%.$DQ$, $DQ$Die Resonanz einer perfekt platzierten Ladung. Saboteur-Proben +5%.$DQ$, 20, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$foundation_attunement_shard$DQ$, $DQ$The Tower$DQ$, 2, $DQ$Foundation Attunement Shard$DQ$, $DQ$Fundamenteinstimmungssplitter$DQ$, $DQ$moodlet$DQ$, $JB${"decay_type": "permanent", "description_de": "Eingestimmt auf strukturellen Stress. Spürt Instabilität vor den Instrumenten.", "description_en": "Attuned to structural stress. Senses instability before instruments do.", "emotion": "determination", "moodlet_type": "structurally_attuned", "strength": 8}$JB$::jsonb, $DQ$Permanent: agent gains 'structurally_attuned' moodlet.$DQ$, $DQ$Permanent: Agent erhält 'strukturell_eingestimmt' Moodlet.$DQ$, 30, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$collapse_fragment$DQ$, $DQ$The Tower$DQ$, 2, $DQ$Collapse Fragment$DQ$, $DQ$Einsturzfragment$DQ$, $DQ$memory$DQ$, $JB${"content_de": "Die Mathematik des Strukturversagens bezeugt. Intuition gewonnen für den Moment, ab dem Systeme nicht mehr zu retten sind.", "content_en": "Witnessed the mathematics of structural failure. Gained intuition for when systems are past the point of rescue.", "importance": 7}$JB$::jsonb, $DQ$Creates a high-importance Reflection Memory about structural collapse.$DQ$, $DQ$Erzeugt eine hochbedeutende Reflexionserinnerung über strukturellen Zusammenbruch.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
