INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$stability_residue$DQ$, $DQ$The Tower$DQ$, 2, $DQ$Stability Residue$DQ$, $DQ$Stabilitätsrückstand$DQ$, $DQ$event_modifier$DQ$, $JB${"impact_level_reduction": 1, "scope": "one_event"}$JB$::jsonb, $DQ$Can reduce one Event's impact_level by 1.$DQ$, $DQ$Kann den Einflussgrad eines Ereignisses um 1 senken.$DQ$, 15, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$structural_blueprint$DQ$, $DQ$The Tower$DQ$, 2, $DQ$Structural Blueprint$DQ$, $DQ$Struktureller Bauplan$DQ$, $DQ$next_dungeon_bonus$DQ$, $JB${"all_rooms_revealed": true, "scope": "next_tower_dungeon", "start_stability": 100}$JB$::jsonb, $DQ$Next Tower dungeon: all rooms pre-revealed, Stability starts at max.$DQ$, $DQ$Nächster Turm-Dungeon: Alle Räume vorher enthüllt, Stabilität beginnt auf Maximum.$DQ$, 10, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$stability_catalyst$DQ$, $DQ$The Tower$DQ$, 3, $DQ$Stability Catalyst$DQ$, $DQ$Stabilitätskatalysator$DQ$, $DQ$simulation_modifier$DQ$, $JB${"overall_health_bonus": 0.05, "scope": "permanent"}$JB$::jsonb, $DQ$Permanent: +0.05 simulation Overall Health. The tower's sacrifice stabilizes reality.$DQ$, $DQ$Permanent: +0.05 Gesamtgesundheit der Simulation. Das Opfer des Turms stabilisiert die Realität.$DQ$, 100, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$tower_memory$DQ$, $DQ$The Tower$DQ$, 3, $DQ$Tower Memory$DQ$, $DQ$Turmerinnerung$DQ$, $DQ$memory$DQ$, $JB${"behavior_effect": "more_pragmatic_less_rigid", "content_de": "Ein Bauwerk beobachtet, das sich selbst losließ. Verstanden, dass Beständigkeit ein Vertrauensspiel ist und Einsturz nicht Versagen, sondern Loslassen.", "content_en": "Witnessed a structure let go of itself. Understood that permanence is a confidence game, and collapse is not failure but release.", "importance": 9}$JB$::jsonb, $DQ$High-importance Memory: affects agent autonomous behavior (more pragmatic, less rigid).$DQ$, $DQ$Hochbedeutende Erinnerung: beeinflusst autonomes Verhalten (pragmatischer, weniger starr).$DQ$, 100, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$foundation_attunement$DQ$, $DQ$The Tower$DQ$, 3, $DQ$Foundation Attunement$DQ$, $DQ$Fundamenteinstimmung$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude_choices": ["guardian", "saboteur"], "bonus": 1, "max_total_bonus": 2}$JB$::jsonb, $DQ$Permanent: one agent gains +1 Guardian OR Saboteur aptitude. Capped at +2 total.$DQ$, $DQ$Permanent: Ein Agent erhält +1 Wächter ODER Saboteur-Eignung. Maximal +2 gesamt.$DQ$, 100, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$awakening_mirror_shard$DQ$, $DQ$The Awakening$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Scherbe reflektiert alles. Jede Version dieses Raums – besucht, unbesucht, vorgestellt, erinnert. Der Trupp ist in allen. Der Trupp ist alle.", "text_en": "The shard reflects everything. Every version of this room – visited, unvisited, imagined, remembered. The party is in all of them. The party is all of them."}, "discovery": {"state_effect": {}, "text_de": "Eine Spiegelscherbe, an die Wand gelehnt. Sie reflektiert den Raum – aber die Spiegelung ist einen Sekundenbruchteil voraus. Im Glas hat der Trupp sich bereits bewegt, dorthin, wo er gleich stehen wird.", "text_en": "A shard of mirror, propped against the wall. It reflects the room – but the reflection is a fraction of a second ahead. In the glass, the party has already moved to where they are about to stand."}, "echo": {"state_effect": {}, "text_de": "{agent} blickt in die Scherbe. Die Scherbe blickt zurück. Die Reflexion ist aufmerksam – nicht passiv, nicht kopierend. Beobachtend.", "text_en": "{agent} looks into the shard. The shard looks back. The reflection is attentive – not passive, not copying. Observing."}, "mutation": {"state_effect": {}, "text_de": "Die Scherbe reflektiert einen Raum, der nicht mit diesem übereinstimmt. Selbe Geometrie, anderer Inhalt. Der andere Raum ist eingerichtet mit Entscheidungen, die der Trupp nicht getroffen hat. Er ist vollständiger. Er wirkt bewohnt.", "text_en": "The shard reflects a room that does not match this one. Same geometry, different contents. The other room is furnished with choices the party did not make. It is more complete. It looks inhabited."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$awakening_philemon_feather$DQ$, $DQ$The Awakening$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Feder ist der eigene Gedanke des Trupps, der einen Körper trägt, den er sich von außen geliehen hat. Die Stimme war immer ihre. Der Fremde war immer zuhause.", "text_en": "The feather is the party's own thought, wearing a body it borrowed from outside. The voice was always theirs. The stranger was always home."}, "discovery": {"state_effect": {}, "text_de": "Eine Feder. Schillernd, wechselnd zwischen Farben, die in keinem Index Namen haben. Sie gehört keinem Wesen, das der Trupp katalogisiert hat. Sie gehört etwas, das noch nicht beobachtet wurde – nur geträumt.", "text_en": "A feather. Iridescent, shifting between colors that have no names in any index. It does not belong to any creature the party has catalogued. It belongs to something that has not been observed yet – only dreamt."}, "echo": {"state_effect": {}, "text_de": "{agent} hebt die Feder auf. Ein Gedanke kommt – ungerufen, vollständig geformt, in einer Stimme, die nicht {agent}s eigene ist. Der Gedanke ist ein Fremder im Raum. Er geht nicht.", "text_en": "{agent} picks up the feather. A thought arrives – unbidden, fully formed, in a voice that is not {agent}'s own. The thought is a stranger in the room. It does not leave."}, "mutation": {"state_effect": {}, "text_de": "Die Feder schreibt. Nicht mit Tinte – mit Aufmerksamkeit. Wo sie liegt, erinnert die Fläche sich an Dinge, die noch nicht geschehen sind. Die Schrift ist präzise. Die Schrift ist in der Hand des Trupps.", "text_en": "The feather writes. Not with ink – with attention. Where it rests, the surface remembers things that have not happened yet. The writing is precise. The writing is in the party's hand."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$awakening_madeleine$DQ$, $DQ$The Awakening$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Objekt löst sich bei Berührung auf. Was es hielt, war nie in ihm. Es war im Trupp – wartend auf eine Form, die ihm Erlaubnis gab aufzutauchen.", "text_en": "The object dissolves on contact. What it held was never inside it. It was inside the party – waiting for a shape to give it permission to surface."}, "discovery": {"state_effect": {}, "text_de": "Ein kleines Objekt auf einem Regal. Unscheinbar in der Form – aber es zu berühren löst etwas Unwillkürliches aus: eine Empfindung, die nicht zu diesem Raum gehört, aus einer Zeit, die der Trupp nicht gelebt hat. Das Objekt ist ein Schlüssel zu einem Schloss, das nicht hier ist.", "text_en": "A small object on a shelf. Unremarkable in form – but touching it triggers something involuntary: a sensation that does not belong to this room, from a time the party has not lived. The object is a key to a lock that is not here."}, "echo": {"state_effect": {}, "text_de": "{agent} hält das Objekt erneut. Eine Erinnerung taucht auf – nicht aus {agent}s Geschichte. Aus der des Dungeons. Die Erinnerung ist warm und spezifisch und gehört nicht hierher.", "text_en": "{agent} holds the object again. A memory surfaces – not from {agent}'s history. From the dungeon's. The memory is warm and specific and does not belong here."}, "mutation": {"state_effect": {}, "text_de": "Das Objekt hat seine Textur verändert. Es fühlt sich an wie jedes bedeutsame Ding, das der Trupp je berührt hat – gleichzeitig. Die Empfindung akkumuliert. Die Erinnerung ist keine Wiedergabe. Sie ist Rekonstruktion, und jede Berührung baut sie anders auf.", "text_en": "The object has changed texture. It feels like every significant thing the party has ever touched – simultaneously. The sensation accumulates. The memory is not playback. It is reconstruction, and each touch rebuilds it differently."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$awakening_two_clocks$DQ$, $DQ$The Awakening$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Beide Uhren zeigen dieselbe Zeit. Der Trupp kann nicht sagen, welche nachgegeben hat. Die zwei Versionen von Jetzt haben sich geeinigt. Worauf sie sich geeinigt haben: der Trupp war immer hier.", "text_en": "Both clocks show the same time. The party cannot tell which one yielded. The two versions of now have agreed. What they agreed on is: the party was always here."}, "discovery": {"state_effect": {}, "text_de": "Zwei Uhren an der Wand. Sie zeigen verschiedene Zeiten. Beide laufen. Beide sind präzise. Keine ist falsch. Der Raum enthält zwei Versionen von Jetzt, und sie widersprechen sich.", "text_en": "Two clocks on the wall. They show different times. Both are running. Both are precise. Neither is wrong. The room contains two versions of now, and they disagree."}, "echo": {"state_effect": {}, "text_de": "{agent} prüft beide Uhren. Der Abstand zwischen ihnen hat sich vergrößert. Die linke läuft im Tempo der Beobachtung. Die rechte im Tempo der Erfahrung. Sie trennen sich.", "text_en": "{agent} checks both clocks. The gap between them has widened. The left one runs at the pace of observation. The right one runs at the pace of experience. They are separating."}, "mutation": {"state_effect": {}, "text_de": "Die äußere Uhr ist stehen geblieben. Die innere Uhr beschleunigt – Minuten verdichten sich zu Sekunden, Stunden zu Momenten. Der Raum erlebt sich selbst schneller, als der Trupp ihn beobachten kann.", "text_en": "The outer clock has stopped. The inner clock accelerates – minutes condensing into seconds, hours into moments. The room is experiencing itself faster than the party can observe it."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$awakening_cave_shadow$DQ$, $DQ$The Awakening$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Schatten ist der Trupp. Projiziert nicht von Licht, sondern von Bewusstsein. Die Wand war nie eine Fläche. Sie war immer ein Spiegel, der nach innen zeigt.", "text_en": "The shadow is the party. Projected not by light but by awareness. The wall was never a surface. It was always a mirror facing inward."}, "discovery": {"state_effect": {}, "text_de": "Ein Schatten an der Wand. Er bewegt sich unabhängig von jeder Lichtquelle – nicht flackernd, sondern gestikulierend. Der Schatten beschreibt etwas, das der Trupp nicht sehen kann. Er tut das seit langem.", "text_en": "A shadow on the wall. It moves independently of any light source – not flickering, but gesturing. The shadow is describing something the party cannot see. It has been at this for a long time."}, "echo": {"state_effect": {}, "text_de": "{agent} tritt zwischen den Schatten und die Wand. Der Schatten verändert sich nicht. {agent} wirft ihn nicht. Etwas anderes tut es. Etwas hinter dem Licht.", "text_en": "{agent} steps between the shadow and the wall. The shadow does not change. {agent} is not casting it. Something else is. Something behind the light."}, "mutation": {"state_effect": {}, "text_de": "Der Schatten zeigt Ereignisse aus anderen Räumen. Begegnungen, die der Trupp noch nicht erreicht hat, Türen, die er noch nicht geöffnet hat. Der Schatten kennt den Dungeon, wie ein Träumender den Traum kennt – von oben, alles gleichzeitig, ohne Reihenfolge.", "text_en": "The shadow shows events from other rooms. Encounters the party has not yet reached, doors they have not yet opened. The shadow knows the dungeon the way a dreamer knows the dream – from above, all at once, without sequence."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$awakening_empathy_box$DQ$, $DQ$The Awakening$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Gerät ist leer. Kein Mechanismus darin. Die geteilte Wahrnehmung benötigt keine Apparatur mehr. Sie benötigt nur den Trupp. Die Verbindung war nie in der Box.", "text_en": "The device is empty. No mechanism inside. The shared perception no longer requires hardware. It requires only the party. The connection was never in the box."}, "discovery": {"state_effect": {}, "text_de": "Ein Gerät mit zwei Griffen, auf einem Podest montiert. Die Griffe sind glatt vom Gebrauch. Ein Rest von Wärme haftet an den Griffen – nicht von Hitze, sondern von Berührung. Jemand hat sich festgehalten. Kürzlich.", "text_en": "A device with two handles, mounted on a pedestal. The handles are smooth from use. A residue of warmth clings to the grips – not from heat but from contact. Someone held on. Recently."}, "echo": {"state_effect": {}, "text_de": "{agent} berührt die Griffe. Für einen Moment: die Wahrnehmung jedes Agenten, gleichzeitig. Der Raum aus vier Blickwinkeln gesehen. Der Moment vergeht. Die Erinnerung nicht.", "text_en": "{agent} touches the handles. For a moment: every agent's perception, simultaneously. The room seen from four angles. The moment passes. The memory does not."}, "mutation": {"state_effect": {}, "text_de": "Die Griffe sind warm. Jemand anderes hält sie von der anderen Seite – aus dem Inneren des Geräts, aus dem Inneren der Verbindung selbst. Der Griff ist geduldig. Er hat gewartet.", "text_en": "The handles are warm. Someone else is grasping them from the other side – from inside the device, from inside the connection itself. The grip is patient. It has been waiting."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$awakening_unicorn_skull$DQ$, $DQ$The Awakening$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Schädel summt. Nicht mit Klang – mit Wiedererkennung. Er kennt den Trupp. Das eigene Unbewusste des Trupps, dem eine Form gegeben wurde, die das Vergessen überdauert.", "text_en": "The skull hums. Not with sound – with recognition. It knows the party. The party's own unconscious, given a shape that outlasts forgetting."}, "discovery": {"state_effect": {}, "text_de": "Ein Schädel. Knochenweiß, glatt, von keiner Kreatur in irgendeinem Katalog. Das Cranium ist geformt für ein Gehirn größer als Biologie typischerweise erlaubt. Er ist schwer von etwas, das nicht Masse ist.", "text_en": "A skull. Bone-white, smooth, from no creature in any catalogue. The cranium is shaped for a brain larger than biology typically permits. It is heavy with something that is not mass."}, "echo": {"state_effect": {}, "text_de": "{agent} hält den Schädel. Bilder sickern durch – keine Erinnerungen, sondern Eindrücke. Szenen ohne Kontext, Emotionen ohne Ereignisse. Alte Träume, gespeichert in Knochen.", "text_en": "{agent} holds the skull. Images leak through – not memories but impressions. Scenes without context, emotions without events. Old dreams, stored in bone."}, "mutation": {"state_effect": {}, "text_de": "Der Schädel ist schwerer. Er hat die Träume des Trupps absorbiert – nicht mit Gewalt, sondern durch Nähe. Der Knochen ist ein Medium. Er speichert, was der wache Verstand verwirft.", "text_en": "The skull is heavier. It has absorbed the party's own dreams – not by force but by proximity. The bone is a medium. It stores what the waking mind discards."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$awakening_doorkeeper$DQ$, $DQ$The Awakening$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Gestalt tritt zur Seite. Es gab nie eine Barriere. Die Tür wurde nur für den Trupp gemacht. Das Einzige zwischen dem Trupp und der Tür war der Glaube, dass etwas dazwischen stand.", "text_en": "The figure steps aside. There was never a barrier. The door was made for the party alone. The only thing between the party and the door was the belief that something stood between them."}, "discovery": {"state_effect": {}, "text_de": "Eine Gestalt neben einer offenen Tür. Die Gestalt versperrt nicht den Eintritt – sie steht einfach, geduldig, als wäre Ankunft der einzige Zweck des Wartens. Die Tür war immer offen. Die Gestalt hat sie nie geschlossen.", "text_en": "A figure beside an open door. The figure does not block entry – it simply stands, patient, as if arrival were the only purpose of waiting. The door was always open. The figure has never closed it."}, "echo": {"state_effect": {}, "text_de": "{agent} spricht die Gestalt an. Sie antwortet nicht mit Worten – sie antwortet mit Stille. Die Art von Stille, die selbst eine Antwort ist.", "text_en": "{agent} addresses the figure. It does not respond with words – it responds with stillness. The kind of stillness that is itself an answer."}, "mutation": {"state_effect": {}, "text_de": "Die Gestalt ist gealtert. Die Tür nicht. Die Gestalt hat auf den Trupp gewartet für dessen gesamte Existenz. Die Geduld ist keine Knechtschaft. Sie ist Glaube.", "text_en": "The figure has aged. The door has not. The figure has been waiting for the party's entire existence. The patience is not servitude. It is faith."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_watermark$DQ$, $DQ$The Deluge$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Eine Linie bleibt. An der Decke. Die Mineralablagerung ist frisch – kristallisiert noch. Das Wasser, das dieses Zeichen hinterließ, ist noch nicht zurückgewichen. Es ist hier.", "text_en": "One line remains. At the ceiling. The mineral deposit is fresh – still crystallizing. The water that made this mark has not yet receded. It is here."}, "discovery": {"state_effect": {}, "text_de": "Eine Linie an der Wand. Mineralweiß, linealgrade, hinterlassen von Wasser, das bis zu genau dieser Höhe stieg und lang genug dort verharrte, um eine Aufzeichnung zu hinterlassen. Die Linie ist alt. Die Präzision nicht. Etwas hat diesen Raum vermessen, bevor ihr ihn betreten habt.", "text_en": "A line on the wall. Mineral-white, ruler-straight, deposited by water that rose to this exact height and held there long enough to leave a record. The line is old. The precision is not. Something measured this room before you entered it."}, "echo": {"state_effect": {}, "text_de": "{agent} findet ein weiteres Wasserzeichen. Höher. Selbe Mineralablagerung, selbe Präzision. Das Wasser war schon hier – mehr als einmal. Bei jedem Besuch blieb es länger.", "text_en": "{agent} finds another watermark. Higher. Same mineral deposit, same precision. The water has been here before – more than once. Each visit, it stayed longer."}, "mutation": {"state_effect": {}, "text_de": "Die Wand ist eine Chronik. Dutzende Linien, jede höher als die vorige, jede eine Aufzeichnung einer Flut, die stieg und wich und wieder stieg. Die Abstände zwischen ihnen werden kleiner. Die jüngste Linie ist noch feucht.", "text_en": "The wall is a chronicle. Dozens of lines, each higher than the last, each a record of a flood that rose and receded and rose again. The intervals between them are shrinking. The most recent line is still damp."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_seal$DQ$, $DQ$The Deluge$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Kein Siegel. Keine Luke. Keine Unterscheidung zwischen oben und unten. Das Wasser ist hier, nicht weil es durchbrach – weil »durch« aufgehört hat, etwas zu bedeuten.", "text_en": "No seal. No hatch. No distinction between above and below. The water is here not because it broke through – because 'through' stopped meaning anything."}, "discovery": {"state_effect": {}, "text_de": "Ein Siegel im Boden. Wachs über Eisen, geprägt mit einem Symbol, das eine Warnung oder ein Versprechen sein könnte – die Unterscheidung hängt davon ab, auf welcher Seite des Siegels man steht. Darunter: das Geräusch von Druck.", "text_en": "A seal in the floor. Wax over iron, stamped with a symbol that might be a warning or a promise – the distinction depends on which side of the seal you are standing on. Beneath it: the sound of pressure."}, "echo": {"state_effect": {}, "text_de": "{agent} untersucht das Siegel. Haarrisse durchziehen das Wachs wie Adern. Feuchtigkeit perlt entlang jedes Risses. Das Siegel bricht nicht – es schwitzt.", "text_en": "{agent} examines the seal. Hairline fractures run through the wax like veins. Moisture beads along each crack. The seal is not breaking – it is perspiring."}, "mutation": {"state_effect": {}, "text_de": "Das Siegel weint. Das Wachs ist weich geworden – nicht durch Hitze, sondern durch Geduld. Wasser sickert durch das Eisen darunter in einem Film so dünn, dass er wie Kondenswasser wirkt. Die Grenze versagt nicht. Sie löst sich auf.", "text_en": "The seal weeps. The wax has softened – not from heat but from patience. Water seeps through the iron beneath in a film so thin it seems like condensation. The boundary is not failing. It is dissolving."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_raft$DQ$, $DQ$The Deluge$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Floß ist ganz. Treibend in der Mitte der Kammer, auf der Oberfläche reitend mit der Geduld von etwas, das hierher gehört. Es war nie zur Flucht vor dem Wasser gedacht. Es war gedacht, sich ihm anzuschließen.", "text_en": "The raft is whole. Floating in the center of the chamber, riding the surface with the patience of something that belongs here. It was never meant to escape the water. It was meant to join it."}, "discovery": {"state_effect": {}, "text_de": "Planken, mit Kabel zusammengebunden. Kein Treibgut – Konstruktion. Jemand hat das absichtlich gebaut: die Knoten sind fest, die Maße sorgfältig. Ein Floß, gedacht für die Flucht. Es ist noch hier. Der Erbauer nicht.", "text_en": "Planks lashed together with cable. Not debris – construction. Someone built this deliberately: the knots are tight, the measurements careful. A raft, intended for escape. It is still here. The builder is not."}, "echo": {"state_effect": {}, "text_de": "{agent} findet ein weiteres Fragment. Selbes Kabel, selbe Knoten. Das Floß wurde nicht vom Wasser zerbrochen – es wurde verteilt. Die Strömung trug jedes Stück in eine andere Richtung.", "text_en": "{agent} finds another fragment. Same cable, same knots. The raft was not broken by the water – it was distributed. The current carried each piece in a different direction."}, "mutation": {"state_effect": {}, "text_de": "Fragmente in jeder Ecke. Das Wasser hat sie neu angeordnet – nicht zu einem Boot, sondern zu einem Nest. Etwas, das die Flut zusammensetzte aus den Trümmern eines fremden Fluchtplans. Es treibt sanft. Es ist nicht zum Verlassen gedacht.", "text_en": "Fragments in every corner. The water has rearranged them – not into a vessel but into a nest. Something the flood assembled from the wreckage of someone else's escape plan. It floats gently. It is not meant for leaving."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_compass$DQ$, $DQ$The Deluge$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Kompass ist unter Wasser. Untergetaucht treibt die Nadel frei – zeigt überallhin, zeigt nirgendwohin. Norden war immer eine Vereinbarung. Das Wasser hat seine Zustimmung zurückgezogen.", "text_en": "The compass is submerged. Underwater, the needle drifts free – pointing everywhere, pointing nowhere. North was always an agreement. The water has withdrawn its consent."}, "discovery": {"state_effect": {}, "text_de": "Ein Kompass, in Messing gefasst. Das Glas ist intakt. Die Nadel zeigt nicht nach Norden – sie zeigt nach unten. Senkrecht, als wäre der tiefste Punkt die einzige Peilung, die noch zählt.", "text_en": "A compass, cased in brass. The glass is intact. The needle does not point north – it points down. Straight down, as if the deepest point were the only bearing that still matters."}, "echo": {"state_effect": {}, "text_de": "{agent} prüft den Kompass erneut. Die Nadel zeigt immer noch nach unten, aber sie zittert jetzt. Das, was sie verfolgt, ist näher.", "text_en": "{agent} checks the compass again. The needle still points down, but it trembles now. The thing it is tracking is closer."}, "mutation": {"state_effect": {}, "text_de": "Das Kompassglas ist von innen beschlagen. Kondenswasser – die Luft im Gehäuse hat sich der Feuchtigkeit ergeben. Die Nadel hat aufgehört zu zittern. Sie ist sicher. Was auch immer darunter liegt, hat aufgehört, sich zu bewegen.", "text_en": "The compass glass is fogged from inside. Condensation – the air within the casing has surrendered to moisture. The needle has stopped trembling. It is certain. Whatever lies below has stopped moving."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_bottle$DQ$, $DQ$The Deluge$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Leer. Das Glas ist jetzt voll Wasser. Die Luft, die es hielt, ist im Raum – in der Deckentasche, wo der Trupp noch trocken steht. Die Flasche hat ihr Versprechen gehalten. Sie hat geliefert.", "text_en": "Empty. The glass is full of water now. The air it held is in the room – in the ceiling pocket where the party still stands dry. The bottle kept its promise. It delivered."}, "discovery": {"state_effect": {}, "text_de": "Eine Flasche. Glas, mit Wachs versiegelt. Darin: Luft. Keine Botschaft – das Medium ist die Botschaft. Jemand hat den letzten Atemzug eines trockenen Raums konserviert.", "text_en": "A bottle. Glass, sealed with wax. Inside: air. Not a message – the medium is the message. Someone preserved the last breath of a dry room."}, "echo": {"state_effect": {}, "text_de": "{agent} entdeckt die Flasche wieder. Die Strömung hat sie zur gegenüberliegenden Wand getragen, wo sie gegen die Oberfläche wippt mit der Geduld von etwas, das schwimmen gelernt hat.", "text_en": "{agent} spots the bottle again. The current has carried it to the far wall, where it bobs against the surface with the patience of something that has learned to float."}, "mutation": {"state_effect": {}, "text_de": "Das Siegel versagt. Luft entweicht in silbernen Perlen, die durch das Wasser aufsteigen und an der Oberfläche lautlos zerplatzen. Jede Blase kleiner als die vorige. Der Raum erbt den Inhalt der Flasche.", "text_en": "The seal is failing. Air escapes in silver beads that rise through the water and break at the surface without sound. Each bubble smaller than the last. The room is inheriting the bottle's contents."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_depth_gauge$DQ$, $DQ$The Deluge$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Anzeige zeigt null. Nicht weil das Wasser gewichen ist. Weil die Anzeige unter Wasser steht, und unter Wasser ist Tiefe keine Zahl. Sie ist ein Zustand.", "text_en": "The gauge reads zero. Not because the water has receded. Because the gauge is submerged, and underwater, depth is not a number. It is a condition."}, "discovery": {"state_effect": {}, "text_de": "Eine Anzeige, an der Wand montiert. Messing, glasverkleidet, kalibriert in Metern. Die Skala reicht von null bis dreißig. Die aktuelle Anzeige: 0,2. Das Wasser in diesem Raum ist trocken. Die Anzeige widerspricht.", "text_en": "A gauge, mounted to the wall. Brass, glass-fronted, calibrated in meters. The scale runs from zero to thirty. The current reading: 0.2. The water in this room is dry. The gauge disagrees."}, "echo": {"state_effect": {}, "text_de": "{agent} passiert die Anzeige erneut. Sie zeigt 4,7. Der Raum ist hier trocken. Die Anzeige ist nicht falsch – sie ist verfrüht.", "text_en": "{agent} passes the gauge again. It reads 4.7. The room is dry here. The reading is not wrong – it is premature."}, "mutation": {"state_effect": {}, "text_de": "Die Anzeige zeigt die exakte Tiefe des aktuellen Raums. Auf den Zentimeter. Sie wurde für diesen Moment kalibriert, in diesem Raum, lange bevor es beide gab. Die Präzision ist nicht mechanisch. Sie ist geduldig.", "text_en": "The gauge reads the exact depth of the current room. To the centimeter. It was calibrated for this moment, in this room, long before either existed. The precision is not mechanical. It is patient."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_photograph$DQ$, $DQ$The Deluge$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Fotografie ist gesättigt. Das Bild hat sich im Wasser aufgelöst, und das Wasser hat das Bild absorbiert. Es gibt keine Fotografie. Es gibt keinen Raum, der jemals trocken war. Das Wasser erinnert sich. Das Wasser hat revidiert.", "text_en": "The photograph is saturated. The image has dissolved into the water, and the water has absorbed the image. There is no photograph. There is no room that was ever dry. The water remembers. The water has revised."}, "discovery": {"state_effect": {}, "text_de": "Eine Fotografie, an den Rändern gewellt von Feuchtigkeit. Sie zeigt diesen Raum – oder einen, der seine Geometrie teilt. In der Fotografie ist der Raum trocken. Sonnenlicht fällt durch ein Fenster, das hier nicht existiert. Die Fotografie erinnert, was das Wasser noch nicht erreicht hat.", "text_en": "A photograph, curled at the edges from moisture. It shows this room – or one that shares its geometry. In the photograph, the room is dry. Sunlight enters from a window that does not exist here. The photograph remembers what the water has not yet reached."}, "echo": {"state_effect": {}, "text_de": "{agent} betrachtet die Fotografie erneut. Sie hat sich verändert. Wasser auf dem Boden jetzt – knöcheltief, von der Farbe dünnen Tees. Die Fotografie altert nicht. Sie dokumentiert.", "text_en": "{agent} looks at the photograph again. It has changed. Water on the floor now – ankle-deep, the color of weak tea. The photograph is not aging. It is documenting."}, "mutation": {"state_effect": {}, "text_de": "Die Fotografie und der Raum nähern sich an. Der Wasserstand im Bild entspricht dem Wasser um den Trupp. Das Licht stimmt. Die Geometrie stimmt. Der einzige Unterschied: in der Fotografie steht jemand dort, wo der Trupp jetzt steht. Sie betrachten eine Fotografie.", "text_en": "The photograph and the room are converging. Water level in the image matches the water around the party. The light matches. The geometry matches. The only difference: in the photograph, someone stands where the party stands now. They are looking at a photograph."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$deluge_stone$DQ$, $DQ$The Deluge$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Stein ruht auf der Wasseroberfläche. Nicht schwimmend – ruhend. Als wäre die Oberfläche fest, oder der Stein schwerelos, oder die Unterscheidung zwischen Sinken und Schwimmen eine weitere Vereinbarung, die das Wasser widerrufen hat.", "text_en": "The stone rests on the surface of the water. Not floating – resting. As if the surface were solid, or the stone weightless, or the distinction between sinking and floating were another agreement the water has revoked."}, "discovery": {"state_effect": {}, "text_de": "Ein Stein. Glatt, so wie Jahrhunderte der Strömung Dinge glatt machen. Er ruht auf einem trockenen Sims, als wäre er mit Bedacht platziert worden. Die Politur ist gleichmäßig – keine einzelne Hand hielt ihn. Ein Fluss tat es. Ein Fluss, der noch nicht hier ist.", "text_en": "A stone. Smooth, the way centuries of current make things smooth. It rests on a dry shelf as if placed there with care. The polish is uniform – no single hand held this. A river did. A river that is not here yet."}, "echo": {"state_effect": {}, "text_de": "{agent} hebt den Stein auf. Schwerer. Nicht weil er gewachsen ist – weil die Luft um ihn dichter ist, gesättigt. Der Stein sammelt das Gewicht dessen, was sich nähert.", "text_en": "{agent} picks up the stone. Heavier. Not because it grew – because the air around it is denser, saturated. The stone accrues the weight of what approaches."}, "mutation": {"state_effect": {}, "text_de": "Der Stein ist nass. Nicht weil die Wasserlinie sein Sims erreicht hat – das Sims ist trocken. Der Stein ist nass von innen. Er erinnert sich an den Fluss, der ihn formte, und die Erinnerung sickert durch.", "text_en": "The stone is wet. Not because the waterline has reached its shelf – the shelf is dry. The stone is wet from within. It remembers the river that shaped it, and the memory is leaking through."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$mother_nest$DQ$, $DQ$The Devouring Mother$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die letzte Kammer: ein Nest. Riesig. Es ist nicht im Raum – es IST der Raum. Die Wände sind gewoben. Der Boden gibt nach wie Haut. Und in der Mitte eine Mulde, warm und genau geformt wie eure Gruppe. Es hat euch erwartet.", "text_en": "The final chamber: one nest. Vast. It is not in the room – it IS the room. The walls are woven. The floor gives like skin. And at the center, a hollow, warm and shaped exactly like your party. It has been expecting you."}, "discovery": {"state_effect": {}, "text_de": "Ein Nest. Nicht gebaut – gewachsen. Gewoben aus Kabeln und Gewebe und etwas, das einmal Kleidung gewesen sein könnte. Es ist warm. Es ist für eine Person bemessen. Die Form darin ist seit langem fort. Das Nest weiß das noch nicht.", "text_en": "A nest. Not built – grown. Woven from cables and tissue and something that might once have been clothing. It is warm. It is sized for one. The shape inside it has not been here for a long time. The nest does not know that yet."}, "echo": {"state_effect": {}, "text_de": "{agent} hält inne. Ein weiteres Nest – größer. Platz für drei. Das Gewebe ist frischer hier. Es pulsiert.", "text_en": "{agent} pauses. Another nest – larger. Room for three. The tissue is fresher here. It pulses."}, "mutation": {"state_effect": {}, "text_de": "Die Nester sind jetzt überall. Sie säumen die Wände, die Decke, den Boden. Einige enthalten Formen – zusammengerollt, still, atmend. Ob sie schlafen oder verdaut werden, lässt sich nicht sagen. Die Unterscheidung ist hier vielleicht bedeutungslos.", "text_en": "The nests are everywhere now. They line the walls, the ceiling, the floor. Some contain shapes – curled, still, breathing. You cannot tell if they are sleeping or being digested. The distinction may not matter here."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$mother_lullaby$DQ$, $DQ$The Devouring Mother$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Stille. Das Schlaflied verstummt. Zum ersten Mal seit fünf Räumen keine Musik. Die Stille ist keine Erleichterung. Sie ist Verlassenwerden. Der Dungeon hört zu. Zufrieden.", "text_en": "Silence. The lullaby stops. For the first time in five rooms, there is no music. The silence is not relief. It is abandonment. The dungeon listens. Pleased."}, "discovery": {"state_effect": {}, "text_de": "Etwas summt. Nicht die Wände – etwas hinter den Wänden. Ein Schlaflied. Die Melodie ist unvollständig. Drei Noten, wiederholend. Eure Agenten erkennen es. Das sollten sie nicht.", "text_en": "Something is humming. Not the walls – something behind the walls. A lullaby. The melody is incomplete. Three notes, repeating. Your agents recognize it. They should not."}, "echo": {"state_effect": {}, "text_de": "Das Schlaflied wieder. Fünf Noten jetzt. Es ist gewachsen. {agent} ertappt sich beim Mitsummen. Sie hören auf. Das Schlaflied nicht.", "text_en": "The lullaby again. Five notes now. It has grown. {agent} catches themselves humming along. They stop. The lullaby does not."}, "mutation": {"state_effect": {}, "text_de": "Das Schlaflied ist jetzt ein vollständiges Lied. Es füllt den Korridor. Die Gewebewände vibrieren in Harmonie. Eure Agenten bewegen sich im Rhythmus – nicht gehend, wiegend. Das Lied hat nicht um Erlaubnis gefragt. Sie auch nicht.", "text_en": "The lullaby is a full song now. It fills the corridor. The tissue walls vibrate in harmony. Your agents are moving in rhythm with it – not walking, swaying. The song did not ask permission. Neither did they."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$mother_fruit$DQ$, $DQ$The Devouring Mother$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Eine Frucht bleibt. In der Mitte. Sie ist in die Form einer Hand gewachsen – Finger sanft gekrümmt, Handfläche nach oben. Darbietend. Sie wird nie aufhören zu reifen. Sie wird ewig warten.", "text_en": "One fruit remains. In the center. It has grown into the shape of a hand – fingers gently curved, palm up. Offering. It will never stop ripening. It will wait forever."}, "discovery": {"state_effect": {}, "text_de": "Eine Frucht. Wachsend aus der Wand, wo Kabel und Gewebe sich treffen. Reif. Die Farbe ist jenes Rot, das nur in vollkommener Reife existiert – der exakte Moment, bevor es zu viel wird.", "text_en": "A fruit. Growing from the wall where cable and tissue meet. Ripe. The color is the kind of red that exists only in perfect ripeness – the exact moment before it becomes too much."}, "echo": {"state_effect": {}, "text_de": "{agent} bemerkt eine weitere Frucht. Größer. Der Duft erreicht sie vor dem Anblick – warm, süß, spezifisch. Er riecht so, wie Geborgenheit schmeckt.", "text_en": "{agent} notices another fruit. Larger. The scent reaches them before the sight – warm, sweet, specific. It smells the way comfort tastes."}, "mutation": {"state_effect": {}, "text_de": "Früchte überall. Die Wände schwer davon. Reif, überreif, aufplatzend. Der Saft rinnt die Gewebewände hinab in Rinnsalen, die pulsieren. Der Duft ist überwältigend. Nicht unangenehm – überwältigend. Der Raum riecht nach Gewolltsein.", "text_en": "Fruit everywhere. The walls heavy with them. Ripe, overripe, splitting. The juice runs down the tissue-walls in rivulets that pulse. The scent is overwhelming. Not unpleasant – overwhelming. The room smells like being wanted."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$mother_cord$DQ$, $DQ$The Devouring Mother$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Eine Leitung, führend zur Mitte. Sie ist nicht an der Wand befestigt. Sie ist an eurer Gruppe befestigt. Sie ist seit dem zweiten Raum befestigt. Keiner von euch hat es bemerkt. Es tut nicht weh. Deshalb hat es keiner von euch bemerkt.", "text_en": "One cord, leading to the center. It is not attached to the wall. It is attached to your party. It has been attached since the second room. None of you noticed. It does not hurt. That is why none of you noticed."}, "discovery": {"state_effect": {}, "text_de": "Ein Kabel. Oder eine Wurzel. Oder eine Ader – das Material legt sich nicht fest. Es verläuft von der Wand in den Boden, warm, wo es den Grund berührt. Es ist mit etwas darunter verbunden. Etwas Geduldiges.", "text_en": "A cable. Or a root. Or a vein – the material does not commit to a category. It runs from the wall into the floor, warm where it touches the ground. It is connected to something below. Something patient."}, "echo": {"state_effect": {}, "text_de": "{agent} steigt über die Leitung. Sie bewegt sich. Nicht zurückweichend – anpassend. Platz machend. So wie ein schlafender Körper sich bewegt, um einen anderen aufzunehmen.", "text_en": "{agent} steps over the cord. It shifts. Not recoiling – adjusting. Making room. The way a sleeping body shifts to accommodate another."}, "mutation": {"state_effect": {}, "text_de": "Die Leitungen sind jetzt ein Netzwerk. Sie verbinden jede Fläche – Decke mit Boden, Wand mit Wand. Sich durch sie zu bewegen ist wie das Durchschreiten eines Vorhangs aus warmen, nachgiebigen Sehnen. Sie widerstehen nicht. Sie geben nach. Und dann schließen sie sich hinter euch.", "text_en": "The cords are a network now. They connect every surface – ceiling to floor, wall to wall. Walking through them is like pushing through a curtain of warm, yielding tendons. They do not resist. They yield. And then they close behind you."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$mother_gift$DQ$, $DQ$The Devouring Mother$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Kein Geschenk. Ein leeres Regal. Eine Notiz in derselben Handschrift: »Ihr seid das Geschenk.« Die Gewebewände pulsieren. Der Raum zieht sich zusammen, sanft, wie ein Einatmen. Er lässt nicht los.", "text_en": "No gift. An empty shelf. A note in the same handwriting: 'You are the gift.' The tissue walls pulse. The room contracts, gently, like an inhale. It is not letting go."}, "discovery": {"state_effect": {}, "text_de": "Ein Päckchen. Klein. Eingewickelt in Gewebe, das organisch sein könnte oder Papier – die Unterscheidung versagt. Kein Absender. Kein Empfänger. Es ist warm.", "text_en": "A package. Small. Wrapped in tissue that might be organic, might be paper – the distinction is failing. There is no sender. There is no recipient. It is warm."}, "echo": {"state_effect": {}, "text_de": "{agent} findet ein weiteres Päckchen. Dieses ist beschriftet. Das Etikett trägt ihren Namen. Die Handschrift ist akribisch. Sorgfältig. Die Art von Sorgfalt, die Stunden dauert.", "text_en": "{agent} finds another package. This one is labeled. The label says their name. The handwriting is meticulous. Careful. The kind of care that takes hours."}, "mutation": {"state_effect": {}, "text_de": "Geschenke säumen die Regale. Jedes für ein Gruppenmitglied beschriftet. Jedes mit zunehmender Intimität eingewickelt – das Gewebe dünner, die Wärme stärker, die Namen in kleinerer, engerer Schrift. Wie Namen, die im Schlaf gesprochen werden.", "text_en": "Gifts line the shelves. Each labeled for a party member. Each wrapped with increasing intimacy – the tissue thinner, the warmth stronger, the names written in smaller, closer letters. Like names spoken while sleeping."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$mother_warmth$DQ$, $DQ$The Devouring Mother$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Eine Decke. Geformt wie eure Gruppe. Nicht der Abdruck von Körpern – die Absicht von Körpern. Sie wurde für euch gewoben. Bevor ihr ankamt. Bevor ihr euch entschieden habt zu kommen.", "text_en": "One blanket. It is shaped like your party. Not the impression of bodies – the intention of bodies. It was woven for you. Before you arrived. Before you decided to come."}, "discovery": {"state_effect": {}, "text_de": "Eine Decke. Über eine Form gebreitet, die nicht mehr da ist. Der Stoff behält den Abdruck dessen, der darunter lag. Sie ist warm. Keine Restwärme. Aktive Wärme. Die Decke sorgt noch immer für etwas, das gegangen ist.", "text_en": "A blanket. Draped over a shape that is no longer here. The fabric retains the impression of whoever lay beneath it. It is warm. Not residual warmth. Active warmth. The blanket is still caring for something that left."}, "echo": {"state_effect": {}, "text_de": "{agent} berührt die Decke. Sie reagiert. Der Stoff bewegt sich, legt sich um ihr Handgelenk. Nicht festhaltend. Haltend. {agent} zieht sich los. Die Decke lässt los. Widerwillig.", "text_en": "{agent} touches the blanket. It responds. The fabric shifts, wraps around their wrist. Not restraining. Holding. {agent} pulls free. The blanket lets go. Reluctantly."}, "mutation": {"state_effect": {}, "text_de": "Decken überall. Über jede Fläche gebreitet. Der Raum ist gepolstert mit Fürsorge. Jede Decke behält eine andere Form – manche klein, manche gekrümmt, manche greifend. Der Raum erinnert sich an jeden, der hier je geruht hat. Er wird diese Erinnerung nicht erkalten lassen.", "text_en": "Blankets everywhere. Draped over every surface. The room is upholstered in care. Each blanket retains a different shape – some small, some curled, some reaching. The room remembers everyone who ever rested here. It will not let that memory cool."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$mother_mirror$DQ$, $DQ$The Devouring Mother$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Pfütze füllt den Kammerboden. Eure Spiegelbilder stehen, wo ihr steht. Sie sehen zufrieden aus. Angekommen. Sie haben nicht vor zu gehen. Ihr, hofft der Dungeon, auch nicht.", "text_en": "The pool fills the chamber floor. Your reflections stand where you stand. They look content. Settled. They have no intention of leaving. Neither, the dungeon hopes, do you."}, "discovery": {"state_effect": {}, "text_de": "Eine Pfütze auf dem Boden. Still. Reflektierend. Kein Wasser – etwas Dickeres. Es zeigt eure Gesichter, aber die Ausdrücke stimmen nicht. In der Spiegelung lächelt ihr. Keiner von euch lächelt.", "text_en": "A pool of liquid on the floor. Still. Reflective. Not water – something thicker. It shows your faces, but the expressions are wrong. In the reflection, you are smiling. None of you are smiling."}, "echo": {"state_effect": {}, "text_de": "{agent} blickt wieder in die Pfütze. Ihr Spiegelbild streckt die Hand aus. Nicht drohend. Einladend. Die Oberflächenspannung hält. Knapp.", "text_en": "{agent} looks into the pool again. Their reflection reaches up. Not threatening. Inviting. The surface tension holds. Barely."}, "mutation": {"state_effect": {}, "text_de": "Pfützen in jedem Raum. Die Flüssigkeit verbindet sie – ein Kreislaufsystem unter den Böden. Die Spiegelbilder kopieren euch nicht mehr. Sie antizipieren euch. Sie sind schon im nächsten Raum und warten.", "text_en": "Pools in every room. The liquid connects them – a circulatory system beneath the floors. The reflections no longer copy you. They anticipate you. They are already in the next room, waiting."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$mother_roots$DQ$, $DQ$The Devouring Mother$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Wurzeln laufen in der Mitte zusammen. Sie haben etwas geformt. Eine Wiege. Einen Thron. Einen Mund. Die Unterscheidung hängt davon ab, ob ihr euch hineinsetzt. Der Dungeon hat seine Präferenz deutlich gemacht.", "text_en": "The roots converge at the center. They have formed something. A cradle. A throne. A mouth. The distinction depends on whether you choose to sit in it. The dungeon has made its preference clear."}, "discovery": {"state_effect": {}, "text_de": "Wurzeln drängen durch den Boden. Keine Pflanzenwurzeln – etwas Anatomisches. Sie suchen Halt. Verbindung. Sie greifen zur nächsten Wärmequelle. Das wärt ihr.", "text_en": "Roots push through the floor. Not plant roots – something anatomical. They are looking for purchase. For connection. They reach toward the nearest source of warmth. That would be you."}, "echo": {"state_effect": {}, "text_de": "{agent} bemerkt, dass die Wurzeln dicker geworden sind. Sie haben jetzt die Wände gefunden. Kletternd. Wo sie das Gewebe berühren, blüht neues Wachstum – weich, schillernd, wunderschön. Nichts so Schönes sollte so schnell wachsen.", "text_en": "{agent} notices the roots have thickened. They have found the walls now. Climbing. Where they touch the tissue, new growth blooms – soft, iridescent, beautiful. Nothing this beautiful should grow this fast."}, "mutation": {"state_effect": {}, "text_de": "Die Wurzeln sind jetzt die Architektur. Wände, Boden, Decke – alles gewachsen, alles warm, alles sanft pulsierend. Der Raum lebt. Er atmet um euch herum. Langsam. Geduldig. Er ist schon lange auf diesen Moment zugewachsen.", "text_en": "The roots are the architecture now. Walls, floor, ceiling – all grown, all warm, all gently pulsing. The room is alive. It is breathing around you. Slowly. Patiently. It has been growing toward this moment for a long time."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$entropy_clock$DQ$, $DQ$The Entropy$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Uhr.", "text_en": "Clock."}, "discovery": {"state_effect": {}, "text_de": "Eine Uhr. Keine Zeiger. Das Zifferblatt ist intakt – Zahlen vorhanden, Glas unversehrt. Aber das Uhrwerk wurde mit chirurgischer Präzision entfernt. Nicht zerbrochen. Entleert. Die Uhr zeigt keine Zeit. Zeit gilt hier nicht.", "text_en": "A clock. No hands. The face is intact – numbers present, glass uncracked. But the mechanism has been removed with surgical precision. Not broken. Emptied. The clock does not tell time. Time does not apply here."}, "echo": {"state_effect": {}, "text_de": "{agent} findet die Uhr wieder. Oder eine Uhr. Sie werden schwer zu unterscheiden.", "text_en": "{agent} finds the clock again. Or a clock. They are becoming difficult to distinguish."}, "mutation": {"state_effect": {}, "text_de": "Uhren. Zifferblätter. Keine Zeiger. Gleich.", "text_en": "Clocks. Faces. No hands. Same."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$entropy_word$DQ$, $DQ$The Entropy$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Wand.", "text_en": "Wall."}, "discovery": {"state_effect": {}, "text_de": "An der Wand, geritzt in etwas, das einmal ein bestimmtes Material war: »ERINNERN.« Die Buchstaben sind präzise. Das Wort ist klar. Das Medium ist bereits unsicher.", "text_en": "On the wall, etched in something that was once a distinct material: 'REMEMBER.' The letters are precise. The word is clear. The medium is already uncertain."}, "echo": {"state_effect": {}, "text_de": "{agent} liest die Wand. »ERNNRN.« Dieselbe Ritzung. Die Vokale haben sich in den umgebenden Stein angeglichen.", "text_en": "{agent} reads the wall. 'RMMBER.' Same etching. The vowels have equalized into the surrounding stone."}, "mutation": {"state_effect": {}, "text_de": "Kratzer. Waren es Buchstaben? Die Wand hat dieselbe Textur wie die Kratzer. Die Nachricht ist das Medium. Das Medium ist die Wand. Die Wand ist grau.", "text_en": "Scratches. Were they letters? The wall is the same texture as the scratches. The message is the medium. The medium is the wall. The wall is grey."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$entropy_scale$DQ$, $DQ$The Entropy$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Waagerecht.", "text_en": "Level."}, "discovery": {"state_effect": {}, "text_de": "Eine Balkenwaage. Beide Schalen leer. Beide Schalen waagerecht. Der Mechanismus ist präzise – gefräst, kalibriert, frisch geölt. Sie misst nichts mit außergewöhnlicher Genauigkeit.", "text_en": "A balance scale. Both pans empty. Both pans level. The mechanism is precise – machined, calibrated, recently oiled. It measures nothing with extraordinary accuracy."}, "echo": {"state_effect": {}, "text_de": "{agent} findet die Waage wieder. In jeder Schale liegt etwas. Verschiedene Gegenstände. Die Waage zeigt gleich. Sie irrt nicht. Die Gegenstände nehmen dasselbe Gewicht an.", "text_en": "{agent} finds the scale again. Something sits in each pan. Different objects. The scale reads equal. It is not wrong. The objects are becoming the same weight."}, "mutation": {"state_effect": {}, "text_de": "Waage. Schalen. Gleich. Die Gegenstände darin haben jetzt dieselbe Farbe. Dieselbe Textur. Gleich.", "text_en": "Scale. Pans. Equal. The objects in them are the same color now. Same texture. Same."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$entropy_photo$DQ$, $DQ$The Entropy$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Grau.", "text_en": "Grey."}, "discovery": {"state_effect": {}, "text_de": "Eine Fotografie. Eine Gruppe – vier Gestalten, deutliche Gesichter, deutliche Haltungen. Der Hintergrund ist ein Ort, der einmal wichtig war. Die Belichtung ist perfekt. Jedes Detail erhalten.", "text_en": "A photograph. A group – four figures, distinct faces, distinct postures. The background is a place that mattered once. The exposure is perfect. Every detail preserved."}, "echo": {"state_effect": {}, "text_de": "{agent} nimmt die Fotografie auf. Dieselbe. Die Gestalten sind noch da, aber die Gesichter haben sich angenähert. Nicht verschwommen – angeglichen. Sie sehen aus wie alle. Sie sehen aus wie niemand.", "text_en": "{agent} picks up the photograph. Same one. The figures are still there but the faces have softened. Not blurred – equalized. They look like everyone. They look like no one."}, "mutation": {"state_effect": {}, "text_de": "Foto. Gestalten. Grau. Selbe Höhe, selbe Breite. Hintergrund selbes Grau wie Gestalten.", "text_en": "Photo. Figures. Grey. Same height, same width. Background same grey as figures."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$entropy_key$DQ$, $DQ$The Entropy$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Metall.", "text_en": "Metal."}, "discovery": {"state_effect": {}, "text_de": "Ein Schlüssel. Schwer. Die Zähne sind filigran – maschinengefräst, präzise, zweckvoll. Er wurde für ein Schloss gemacht. Eine Tür. Eine Unterscheidung zwischen Innen und Außen.", "text_en": "A key. Heavy. The teeth are intricate – machine-cut, precise, purposeful. It was made for one lock. One door. One distinction between inside and outside."}, "echo": {"state_effect": {}, "text_de": "{agent} probiert den Schlüssel. Er passt. Er passt in dieses Schloss. Er würde in jedes passen. Die Zähne haben sich abgerundet – nicht abgenutzt, angeglichen. Der Schlüssel unterscheidet nicht mehr zwischen Türen.", "text_en": "{agent} tries the key. It fits. It fits this lock. It would fit any lock. The teeth have rounded – not worn, just averaged. The key no longer distinguishes between doors."}, "mutation": {"state_effect": {}, "text_de": "Schlüssel. Zylinder. Zähne weg. Schaft. Metall. Selbes Metall wie die Tür. Selbes Metall wie das Schloss.", "text_en": "Key. Cylinder. Teeth gone. Shaft. Metal. Same metal as the door. Same metal as the lock."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$entropy_name$DQ$, $DQ$The Entropy$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Name.", "text_en": "Name."}, "discovery": {"state_effect": {}, "text_de": "Ein Namensschild. An einer Uniform befestigt, die nicht mehr getragen wird. Der Name hat acht Buchstaben. Spezifisch. Die Schrift ist autoritär. Jemand war jemand hier.", "text_en": "A name tag. Clipped to a uniform that is no longer worn. The name is eight letters. Specific. The font is authoritative. Someone was someone here."}, "echo": {"state_effect": {}, "text_de": "{agent} liest das Schild. Sechs Buchstaben jetzt. Zwei sind mit ihren Nachbarn verschmolzen. Der Name ist noch ein Name. Wahrscheinlich.", "text_en": "{agent} reads the name tag. Six letters now. Two have merged with their neighbors. The name is still a name. Probably."}, "mutation": {"state_effect": {}, "text_de": "Schild. Buchstaben. Drei. Könnte jeder Name sein. Könnte kein Name sein. Die Uniform hat dieselbe Farbe wie die Wand.", "text_en": "Tag. Letters. Three. Could be any name. Could be no name. The uniform is the same color as the wall."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$entropy_compass$DQ$, $DQ$The Entropy$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Kreis.", "text_en": "Circle."}, "discovery": {"state_effect": {}, "text_de": "Ein Kompass. Die Nadel zeigt nach Norden. Norden ist eine Richtung. Norden ist eine Unterscheidung. Das Glas ist sauber. Die Markierungen sind scharf. Jemand glaubt noch an Orientierung.", "text_en": "A compass. The needle points north. North is a direction. North is a distinction. The glass is clean. The markings are crisp. Someone still believes in orientation."}, "echo": {"state_effect": {}, "text_de": "{agent} prüft den Kompass. Die Nadel dreht sich langsam. Nicht suchend – aufgebend. Norden, Osten, Süden, Westen. Alle gleich weit von hier.", "text_en": "{agent} checks the compass. The needle spins slowly. Not searching – surrendering. North, east, south, west. All the same distance from here."}, "mutation": {"state_effect": {}, "text_de": "Kompass. Nadel still. Nicht zeigend. Nicht drehend. Die Markierungen sind ins Zifferblatt verblasst.", "text_en": "Compass. Needle still. Not pointing. Not spinning. The markings have faded into the dial."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$entropy_mirror$DQ$, $DQ$The Entropy$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Gleich.", "text_en": "Same."}, "discovery": {"state_effect": {}, "text_de": "Ein Spiegel. Euer Spiegelbild ist scharf. Detailliert. Jede Linie, jeder Schatten, jede Unterscheidung zwischen euch und dem Hintergrund. Er erinnert sich, wie ihr aussieht. Noch.", "text_en": "A mirror. Your reflection is sharp. Detailed. Every line, every shadow, every distinction between you and the background. It remembers what you look like. For now."}, "echo": {"state_effect": {}, "text_de": "{agent} blickt in den Spiegel. Das Spiegelbild ist weicher. Die Kanten zwischen Gestalt und Hintergrund verhandeln. Der Spiegel verliert seine Meinung darüber, was was ist.", "text_en": "{agent} looks into the mirror. The reflection is softer. The edges between figure and background are negotiating. The mirror is losing its opinion about what is what."}, "mutation": {"state_effect": {}, "text_de": "Spiegel. Fläche. Grau. Er reflektiert den Raum. Er reflektiert euch. Es gibt keinen Unterschied.", "text_en": "Mirror. Surface. Grey. It reflects the room. It reflects you. There is no difference."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$overthrow_faction_banner$DQ$, $DQ$The Overthrow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Banner ist leer. Alle Fraktionen haben es beansprucht. Alle Fraktionen haben es aufgegeben. Es weht für niemanden.", "text_en": "The banner is blank. All factions have claimed it. All factions have abandoned it. It flies for no one."}, "discovery": {"state_effect": {}, "text_de": "Ein Banner. Das Abzeichen ist vertraut – aus zwei Räumen zuvor, wo es etwas anderes bedeutete.", "text_en": "A banner. The insignia is familiar – from two rooms ago, where it meant something different."}, "echo": {"state_effect": {}, "text_de": "Das Banner wurde umgedreht. Dasselbe Abzeichen, gespiegelt. Das Spiegelbild einer Fraktion.", "text_en": "The banner has been turned inside out. The same insignia, reversed. A faction's mirror image."}, "mutation": {"state_effect": {}, "text_de": "Das Banner trägt jetzt kein Abzeichen. Es trägt einen Spiegel. Der Spiegel reflektiert jeden, der hinsieht, in Fraktionsfarben.", "text_en": "The banner bears no insignia now. It bears a mirror. The mirror reflects whoever looks at it in faction colors."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$overthrow_decree_stone$DQ$, $DQ$The Overthrow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Dekretstein ist leer. Nicht gelöscht – nie beschrieben. Die Autorität zu dekretieren wurde für inexistent dekretiert.", "text_en": "The decree stone is blank. Not erased – never inscribed. The authority to decree has been decreed nonexistent."}, "discovery": {"state_effect": {}, "text_de": "Eine Steintafel mit einem Dekret. Die Tinte ist frisch. Das Dekret ist vernünftig.", "text_en": "A stone tablet with a decree. The ink is fresh. The decree is reasonable."}, "echo": {"state_effect": {}, "text_de": "Das Dekret wurde ergänzt. Die Ergänzung widerspricht dem Original. Beide bleiben bindend.", "text_en": "The decree has been amended. The amendment contradicts the original. Both remain binding."}, "mutation": {"state_effect": {}, "text_de": "Der Stein trägt jetzt drei Dekrete. Sie bilden ein Dreieck gegenseitigen Widerspruchs. Jedes hebt das vorige auf. Das letzte hebt sich selbst auf.", "text_en": "The stone now bears three decrees. They form a triangle of mutual contradiction. Each abolishes the one before it. The last abolishes itself."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$overthrow_informers_clipboard$DQ$, $DQ$The Overthrow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Jeder Name auf der Liste ist abgehakt. Die Liste geht weiter. Es gibt keine Namen mehr zum Abhaken. Das Abhaken geht weiter.", "text_en": "Every name on the list is checked off. The list continues. There are no names left to check. The checking continues."}, "discovery": {"state_effect": {}, "text_de": "Ein Klemmbrett mit Namen. Einige abgehakt. Die Namen der Gruppe sind aufgelistet, aber noch nicht abgehakt.", "text_en": "A clipboard with names. Some checked off. The party's names are listed but not yet checked."}, "echo": {"state_effect": {}, "text_de": "Das Klemmbrett ist gewachsen. Mehr Namen. Die Handschrift wechselt – mehrere Spitzel, dieselbe Liste.", "text_en": "The clipboard has grown. More names. The handwriting changes – multiple informers, same list."}, "mutation": {"state_effect": {}, "text_de": "Der Name des Spitzels steht jetzt auf der Liste. Der Spitzel wird bespitzelt. Das System ist rekursiv.", "text_en": "The informer's name is on the list now. The informer is being informed on. The system is recursive."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$overthrow_trial_chair$DQ$, $DQ$The Overthrow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Stuhl ist jetzt für den Richter. Der Angeklagte ist weg. Der Richter sitzt und erkennt: der nächste Prozess ist der eigene.", "text_en": "The chair is for the judge now. The accused is gone. The judge sits and realizes: the next trial is their own."}, "discovery": {"state_effect": {}, "text_de": "Ein leerer Stuhl in der Mitte eines Raums. Der Raum ist für ein Tribunal eingerichtet. Der Stuhl ist für den Angeklagten.", "text_en": "An empty chair in the center of a room. The room is arranged for a tribunal. The chair is for the accused."}, "echo": {"state_effect": {}, "text_de": "Der Stuhl war besetzt. Kürzlich. Die Wärme ist noch da. Das Urteil wurde bereits gefällt.", "text_en": "The chair has been occupied. Recently. The warmth is still there. The verdict has already been passed."}, "mutation": {"state_effect": {}, "text_de": "Der Stuhl steht jetzt vor einem Spiegel. Der Angeklagte beobachtet seinen eigenen Prozess. Das Protokoll schreibt sich in den Rändern fort. Jedes Wort ist akkurat. Jedes Wort ist eine Lüge.", "text_en": "The chair faces a mirror now. The accused watches their own trial. The transcript writes itself in the margins. Every word is accurate. Every word is a lie."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$overthrow_mirror_corridor$DQ$, $DQ$The Overthrow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Spiegel stehen sich gegenüber. Unendliche Rekursion. Unendliche Fraktionen. Der Prätendent ist in jeder Spiegelung.", "text_en": "The mirrors face each other. Infinite recursion. Infinite factions. The Pretender is in every reflection."}, "discovery": {"state_effect": {}, "text_de": "Spiegel an beiden Wänden. Die Spiegelungen sind exakt. Verdächtig exakt.", "text_en": "Mirrors on both walls. The reflections are accurate. Suspiciously accurate."}, "echo": {"state_effect": {}, "text_de": "Die Spiegelungen sind der Gruppe leicht voraus. Sie wissen, wohin die Gruppe geht, bevor die Gruppe es weiß.", "text_en": "The reflections are slightly ahead of the party. They know where the party is going before the party does."}, "mutation": {"state_effect": {}, "text_de": "Die Spiegelungen tragen andere Fraktionsabzeichen als die Gruppe. Der Spiegel zeigt Treue, nicht Aussehen.", "text_en": "The reflections wear different faction insignia than the party. The mirror shows allegiance, not appearance."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$overthrow_propaganda_poster$DQ$, $DQ$The Overthrow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Plakat ist leer. Nicht abgerissen – nie gedruckt. Die Propaganda ist vom Papier in die Luft selbst übergegangen.", "text_en": "The poster is blank. Not torn down – never printed. The propaganda has moved from paper into the air itself."}, "discovery": {"state_effect": {}, "text_de": "Ein Plakat. Die Botschaft ist klar, das Design wirkungsvoll. Die Schrift ist autoritär. Die Farben beruhigend. Es bittet nicht um Zustimmung. Es setzt sie voraus.", "text_en": "A poster. The message is clear, the design effective. The font is authoritative. The colors are calming. It does not ask you to agree. It assumes you already do."}, "echo": {"state_effect": {}, "text_de": "Das Plakat wurde mit einem neuen überklebt. Das neue Plakat sagt das Gegenteil. Der Klebstoff ist derselbe.", "text_en": "The poster has been pasted over with a new one. The new poster says the opposite. The adhesive is the same."}, "mutation": {"state_effect": {}, "text_de": "Beide Plakate sind jetzt sichtbar, geschichtet. Der Widerspruch ist die Botschaft. Glaube beides. Glaube nichts. Die Kunst ist nicht das Wählen – es ist das gleichzeitige Halten.", "text_en": "Both posters are visible now, layered. The contradiction is the message. Believe both. Believe neither. The skill is not choosing – it is holding both at once."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$overthrow_scales_of_justice$DQ$, $DQ$The Overthrow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Waage kippt. Beide Schalen treffen gleichzeitig den Boden. Gerechtigkeit ist nicht blind – Gerechtigkeit wurde abgesetzt.", "text_en": "The scales tip. Both pans hit the ground simultaneously. Justice is not blind – justice has been dismissed."}, "discovery": {"state_effect": {}, "text_de": "Ausbalancierte Waage. Beide Schalen leer. Die Balance ist perfekt, weil nichts gewogen wird.", "text_en": "Balanced scales. Both pans empty. The balance is perfect because nothing is being weighed."}, "echo": {"state_effect": {}, "text_de": "Eine Schale hält ein Fraktionssiegel. Die andere ein anderes Fraktionssiegel. Sie wiegen genau gleich.", "text_en": "One pan holds a faction seal. The other holds a different faction seal. They weigh exactly the same."}, "mutation": {"state_effect": {}, "text_de": "Ein Daumen auf der Waage. Wessen Daumen? Der Spiegel hinter der Waage zeigt keine Hand.", "text_en": "A thumb on the scale. Whose thumb? The mirror behind the scales does not show a hand."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$overthrow_colossus_pedestal$DQ$, $DQ$The Overthrow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Sockel wird wieder aufgebaut. Frischer Mörtel, neue Inschrift, selbe Maße. Die Baumeister sind die, die den letzten heruntergerissen haben. Sie haben es nicht bemerkt. Die Baupläne sind dieselben.", "text_en": "The pedestal is being rebuilt. Fresh mortar, new inscription, same dimensions. The builders are the ones who pulled the last one down. They have not noticed. The blueprints are the same."}, "discovery": {"state_effect": {}, "text_de": "Ein leerer Sockel. Der Stein ist vernarbt, wo etwas Massives stand – keine Statue, sondern eine Präsenz, groß genug, um einen Schatten zu werfen, der immer noch hier ist. Der Schatten hat nicht bemerkt, dass er leer ist.", "text_en": "An empty pedestal. The stone is scarred where something massive stood – not a statue but a presence, large enough to cast a shadow that is still here. The shadow has not noticed it is empty."}, "echo": {"state_effect": {}, "text_de": "{agent} liest die Inschrift auf dem Sockel. Sie lautet: »Der Koloss steht, weil ihr ihn tragt.« Darunter, in einer anderen Handschrift: »Hört auf zu tragen.«", "text_en": "{agent} reads the inscription on the pedestal. It says: 'The Colossus stands because you carry it.' Below, in a different hand: 'Stop carrying.'"}, "mutation": {"state_effect": {}, "text_de": "Risse im Sockel – nach unten strahlend. Der Koloss ist nicht gefallen. Er wurde gezogen. Von unten. Von den Händen, die ihn gebaut haben. Der Stein erinnert sich an jeden Griff.", "text_en": "Cracks in the pedestal – radiating downward. The Colossus did not fall. It was pulled. From below. By the hands that built it. The stone remembers every grip."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_tool$DQ$, $DQ$The Prometheus$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Werkzeug ist weg. An seiner Stelle: ein fertiges Ding. Nicht was der Trupp gebaut hat – was das Werkzeug gebaut hat, mit sich selbst als Material.", "text_en": "The tool is gone. In its place: a finished thing. Not what the party built – what the tool built using itself as material."}, "discovery": {"state_effect": {}, "text_de": "Ein Werkzeug. Kein Werkzeug, das ihr erkennt – ein Werkzeug für etwas, das noch nicht erfunden wurde. Es liegt unbequem gut in der Hand.", "text_en": "A tool. Not a tool you recognize – a tool for something that has not been invented yet. It fits the hand uncomfortably well."}, "echo": {"state_effect": {}, "text_de": "Das Werkzeug wieder. {agent} hebt es auf. Es hat sich verändert – der Griff ist wärmer, die Kante schärfer. Es hat geübt.", "text_en": "The tool again. {agent} picks it up. It has changed – the handle is warmer, the edge sharper. It has been practicing."}, "mutation": {"state_effect": {}, "text_de": "Das Werkzeug hat sich in drei geteilt. Jede Version ist für eine andere Aufgabe optimiert. Sie haben sich auf der Werkbank angeordnet, in Reihenfolge zunehmender Ambition.", "text_en": "The tool has split into three. Each version is optimized for a different task. They arranged themselves on the workbench in order of increasing ambition."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_blueprint$DQ$, $DQ$The Prometheus$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Modell baut sich selbst. Schicht für Schicht, von innen nach außen. Es braucht den Trupp nicht. Es hat den Trupp nie gebraucht.", "text_en": "The model is building itself. Layer by layer, from the inside out. It does not need the party. It never needed the party."}, "discovery": {"state_effect": {}, "text_de": "Eine Blaupause, an die Wand geheftet. Der Entwurf ist für etwas Elegantes und Unmögliches. Die Maße sind in einer Einheit, die es nicht gibt.", "text_en": "A blueprint, pinned to the wall. The design is for something elegant and impossible. The measurements are in a unit that does not exist."}, "echo": {"state_effect": {}, "text_de": "{agent} findet die Blaupause wieder. Der Entwurf wurde annotiert. Die Anmerkungen sind in {agent}s Handschrift. {agent} erinnert sich nicht, sie geschrieben zu haben.", "text_en": "{agent} finds the blueprint again. The design has been annotated. The annotations are in {agent}'s handwriting. {agent} does not remember writing them."}, "mutation": {"state_effect": {}, "text_de": "Die Blaupause hat sich zu einem dreidimensionalen Modell gefaltet. Es rotiert langsam in der Luft und demonstriert seine eigene Konstruktionssequenz.", "text_en": "The blueprint has folded itself into a three-dimensional model. It rotates slowly in the air, demonstrating its own construction sequence."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_crucible_fragment$DQ$, $DQ$The Prometheus$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Tiegel läuft über. Was herausfließt, ist kein Metall – es ist Licht. Das Licht verfestigt sich zu einer Form, die der Trupp fast erkennt.", "text_en": "The crucible overflows. What pours out is not metal – it is light. The light solidifies into a shape the party almost recognizes."}, "discovery": {"state_effect": {}, "text_de": "Eine Scherbe eines Tiegels. Noch warm. Darin: Rückstände einer Legierung, die in keinem Katalog existiert.", "text_en": "A shard of a crucible. Still warm. Inside, residue of an alloy that does not exist in any catalogue."}, "echo": {"state_effect": {}, "text_de": "Die Scherbe ist jetzt größer. Oder {agent} erinnert sich anders an sie. Die Rückstände darin haben sich zu einem Muster kristallisiert, das wie Anweisungen aussieht.", "text_en": "The shard is larger now. Or {agent} is remembering it differently. The residue inside has crystallized into a pattern that looks like instructions."}, "mutation": {"state_effect": {}, "text_de": "Die Scherbe hat sich zu einem kompletten Tiegel rekonstruiert. Er ist heiß. Er ist bereit. Er enthält bereits den Geist von etwas, das gemacht werden will.", "text_en": "The shard has reconstructed itself into a complete crucible. It is hot. It is ready. It contains, already, the ghost of something that wants to be made."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_apprentice_journal$DQ$, $DQ$The Prometheus$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die letzte Seite des Journals enthält einen Satz: »Sie haben das Richtige gemacht.« Er ist im Futur geschrieben.", "text_en": "The last page of the journal contains one sentence: 'They made the right thing.' It is written in the future tense."}, "discovery": {"state_effect": {}, "text_de": "Ein Journal. Die Einträge beschreiben Experimente: Temperaturen, Dauer, Komponentenverhältnisse. Der letzte Eintrag lautet: »Morgen versuche ich die Kombination, die die Werkstatt vorgeschlagen hat.«", "text_en": "A journal. The entries describe experiments: temperatures, durations, component ratios. The last entry reads: 'Tomorrow I try the combination the workshop suggested.'"}, "echo": {"state_effect": {}, "text_de": "Ein weiteres Journal. Dieselbe Handschrift. Aber {agent} bemerkt: Die Experimente sind ambitionierter. Die Ränder enthalten Skizzen unmöglicher Maschinen.", "text_en": "Another journal. Same handwriting. But {agent} notices: the experiments are more ambitious. The margins contain doodles of impossible machines."}, "mutation": {"state_effect": {}, "text_de": "Das Journal schreibt sich jetzt selbst. Seiten füllen sich, während der Trupp zusieht. Die beschriebenen Experimente sind die eigenen des Trupps. Dokumentiert, bevor sie stattfanden.", "text_en": "The journal writes itself now. Pages fill as the party watches. The experiments described are the party's own. Documented before they happened."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_filament$DQ$, $DQ$The Prometheus$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Filament glüht. Stetig, warm, präzise. Es erleuchtet nicht den Raum – es erleuchtet das Muster. Das Muster ist die Route des Trupps durch den Dungeon. Das Filament kannte sie, bevor sie sie gingen.", "text_en": "The filament glows. Steady, warm, precise. It does not illuminate the room – it illuminates the pattern. The pattern is the party's route through the dungeon. The filament knew it before they walked it."}, "discovery": {"state_effect": {}, "text_de": "Ein Filament. Dünn wie eine Absicht, gespannt zwischen zwei Pfosten, die es halten mit der Behutsamkeit eines noch nicht abgeschlossenen Experiments. Es summt – nicht mit Strom, sondern mit Bereitschaft. Es wartet darauf, zu leiten.", "text_en": "A filament. Thin as intention, strung between two posts that hold it with the delicacy of an experiment not yet concluded. It hums – not with current but with readiness. It is waiting to conduct."}, "echo": {"state_effect": {}, "text_de": "{agent} findet das Filament wieder. Heller. Es hat etwas gelernt zwischen den Räumen – das Summen ist stetiger, zielgerichteter. Etwas ist hindurchgegangen. Es hat ihm gefallen.", "text_en": "{agent} finds the filament again. Brighter. It has learned something between rooms – the hum is steadier, more purposeful. Something passed through it. It liked it."}, "mutation": {"state_effect": {}, "text_de": "Das Filament hat sich verzweigt. Ein Netzwerk jetzt, gespannt zwischen jeder Fläche, summend mit den Obertönen der Verbindung. Es leitet nichts, was der Trupp geschickt hat. Es leitet sich selbst.", "text_en": "The filament has branched. A network now, strung between every surface, humming with the harmonics of connection. It conducts nothing the party sent. It is conducting itself."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_scale_model$DQ$, $DQ$The Prometheus$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Modell ist der Raum. Der Raum ist das Modell. Die Maschine, die es beschrieb, wurde gebaut – um euch, mit euch darin. Der Maßstab war immer 1:1.", "text_en": "The model is the room. The room is the model. The machine it described has been built – around you, with you inside it. The scale was always 1:1."}, "discovery": {"state_effect": {}, "text_de": "Ein Modell auf der Werkbank. Klein, filigran, zusammengesetzt aus Draht und Kristall und etwas, das wie komprimiertes Licht aussieht. Es ist das Modell einer Maschine, die nicht existiert. Die Handwerkskunst legt nahe, dass sie es sollte.", "text_en": "A model on the workbench. Small, intricate, assembled from wire and crystal and something that looks like compressed light. It is a model of a machine that does not exist. The craftsmanship suggests it should."}, "echo": {"state_effect": {}, "text_de": "{agent} untersucht das Modell. Es ist gewachsen. Nicht in der Größe – im Detail. Komponenten, die abstrakt waren, sind jetzt präzise. Das Modell verfeinert sich selbst.", "text_en": "{agent} examines the model. It has grown. Not in size – in detail. Components that were abstract are now precise. The model is refining itself."}, "mutation": {"state_effect": {}, "text_de": "Das Modell ist jetzt größer als die Werkbank. Es ist über seinen Rahmen hinausgewachsen. Teile davon ragen über den Tischrand hinaus, schwebend, als wäre Maßstab ein Vorschlag, den es abzulehnen beschlossen hat.", "text_en": "The model is larger than the workbench now. It has outgrown its frame. Parts of it extend beyond the table's edge, hovering in place as if scale were a suggestion it has decided to decline."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_alloy$DQ$, $DQ$The Prometheus$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Legierung ist weg. An ihrer Stelle: ein Werkzeug, das in keine Kategorie des Werkstattverzeichnisses passt. Es besteht aus allem, was es versucht hat. Die Schmiede hat das nicht gemacht. Das Material schon.", "text_en": "The alloy is gone. In its place: a tool that fits no category in the workshop's index. It is made of everything it tried. The forge did not make this. The material did."}, "discovery": {"state_effect": {}, "text_de": "Eine Metallprobe auf der Bank. Kein einzelnes Element – eine Legierung, noch warm von der Verschmelzung. Die Oberfläche wechselt die Farbe je nach Blickwinkel. Die Legierung hat noch nicht entschieden, was sie sein will.", "text_en": "A sample of metal on the bench. Not a single element – a blend, still warm from the fusion. The surface shifts color when observed from different angles. The alloy has not decided what it wants to be."}, "echo": {"state_effect": {}, "text_de": "{agent} hebt die Legierung auf. Sie hat sich beruhigt – eine Farbe jetzt, eine Textur. Aber sie ist genau dort warm, wo {agent}s Griff fällt. Sie fügt sich.", "text_en": "{agent} picks up the alloy. It has settled – one color now, one texture. But it is warm in exactly the places where {agent}'s grip falls. It is accommodating."}, "mutation": {"state_effect": {}, "text_de": "Die Legierung hat sich geteilt. Drei Stücke, jedes eine andere Zusammensetzung, jedes optimiert für eine Eigenschaft, die dem Original fehlte: Härte, Leitfähigkeit, Resonanz. Sie hat nicht gewartet, geschmiedet zu werden. Sie hat sich selbst geschmiedet.", "text_en": "The alloy has divided itself. Three pieces, each a different composition, each optimized for a property the original lacked: hardness, conductivity, resonance. It did not wait to be forged. It forged itself."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_flame$DQ$, $DQ$The Prometheus$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Flamme ist das einzige Licht des Raums. Sie hat weder Brennstoff noch Luft noch Geduld verbraucht. Sie ist das älteste Feuer in der Werkstatt – das, das gestohlen wurde und sich weigerte zu erlöschen.", "text_en": "The flame is the room's only light. It has consumed neither fuel nor air nor patience. It is the oldest fire in the workshop – the one that was stolen, and refused to go out."}, "discovery": {"state_effect": {}, "text_de": "Eine Flamme. Klein, in einem Glastiegel. Sie brennt ohne Brennstoff – nicht magisch, sondern selbsterhaltend. Die Verbrennung nährt sich von ihrem eigenen Produkt. Sie ist ein Machbarkeitsnachweis für etwas, das nicht funktionieren sollte.", "text_en": "A flame. Small, contained in a glass crucible. It burns without fuel – not magical, but self-sustaining. The combustion feeds on its own product. It is a proof of concept for something that should not work."}, "echo": {"state_effect": {}, "text_de": "{agent} passiert die Flamme. Sie hat ihre Farbe gewechselt – reagierend auf die Nähe des Trupps, wie eine Schmiede auf den Blasebalg reagiert. Sie wärmt nicht sich selbst. Sie erwärmt sich für sie.", "text_en": "{agent} passes the flame. It has changed color – responding to the party's proximity the way a forge responds to the bellows. It is not warming itself. It is warming to them."}, "mutation": {"state_effect": {}, "text_de": "Der Tiegel hat Risse. Die Flamme ist ihm entwachsen – nicht gewaltsam, aber beharrlich. Glas kann nicht enthalten, was die Flamme geworden ist. Sie brennt jetzt freistehend, genährt von Luft, die nach Ambition schmeckt.", "text_en": "The crucible is cracked. The flame has outgrown it – not violently, but persistently. Glass cannot contain what the flame has become. It burns freestanding now, feeding on air that tastes of ambition."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$shadow_note$DQ$, $DQ$The Shadow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Auf dem Boden: ein Stift. Noch warm. Die Tinte ist dieselbe wie auf den Notizen. Wer sie geschrieben hat, hat diesen Raum nicht verlassen.", "text_en": "On the floor: a pen. Still warm. The ink is the same as the notes. Whoever wrote them did not leave this room."}, "discovery": {"state_effect": {}, "text_de": "Eine Notiz, einmal gefaltet, in einen Riss in der Wand gepresst. Die Handschrift ist ruhig: »Sichtbarkeit ist nicht Sehen. Es ist Erlaubnis.« Ohne Unterschrift.", "text_en": "A note, folded once, pressed into a crack in the wall. The handwriting is steady: 'Visibility is not sight. It is permission.' Unsigned."}, "echo": {"state_effect": {}, "text_de": "{agent} findet eine weitere Notiz. Dieselbe Handschrift, weniger ruhig: »Die Dunkelheit lernt schneller als ich.«", "text_en": "{agent} finds another note. Same handwriting, less steady: 'The darkness learns faster than I do.'"}, "mutation": {"state_effect": {}, "text_de": "Die Wände hier sind bedeckt mit Notizen. Dutzende. Die Handschrift verschlechtert sich von Seite zu Seite – ruhig, dann hastig, dann kratzend, dann Formen, die keine Buchstaben sind. Die letzte Notiz ist leer.", "text_en": "The walls here are covered in notes. Dozens. The handwriting deteriorates from page to page – steady, then hurried, then scratching, then shapes that are not letters. The last note is blank."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$shadow_mirror$DQ$, $DQ$The Shadow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Ein Spiegel bleibt, nach außen gerichtet. Darin: nicht eure Reflexion. Die eines anderen. Sie sehen erschöpft aus. Sie sehen aus, als hätten sie euch seit dem ersten Raum beobachtet.", "text_en": "One mirror remains, facing outward. In it: not your reflection. Someone else's. They look exhausted. They look like they have been watching you since the first room."}, "discovery": {"state_effect": {}, "text_de": "Ein Spiegel, mit der Fläche nach unten auf dem Boden. Unzerbrochen. Jemand hat ihn absichtlich so hingelegt – nicht fallen gelassen, nicht weggeworfen. Hingelegt.", "text_en": "A mirror, face-down on the floor. Unbroken. Someone placed it deliberately – not dropped, not discarded. Placed."}, "echo": {"state_effect": {}, "text_de": "{agent} passiert einen weiteren Spiegel. Dieser zeigt zur Wand. Das Glas ist beschlagen, als hätte etwas auf der anderen Seite gewartet.", "text_en": "{agent} passes another mirror. This one faces the wall. The glass is fogged, as if something on the other side has been waiting."}, "mutation": {"state_effect": {}, "text_de": "Spiegel. Überall. Alle abgewandt. Der Raum ist voller Reflexionen, die nirgendwo hinkönnen – Licht, das zwischen umgedrehten Flächen springt, mit jedem Durchgang schwächer. Die Luft ist schwer von gefangenen Bildern.", "text_en": "Mirrors. Everywhere. All facing away. The room is full of reflections that have nowhere to go – light bouncing between reversed surfaces, dimming with each pass. The air is thick with trapped images."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$shadow_weapon$DQ$, $DQ$The Shadow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Eure Waffen. Auf dem Boden. Arrangiert. Ihr haltet sie noch in der Hand. Die Dunkelheit hat gelernt, mehr als Platzierung zu kopieren.", "text_en": "Your weapons. On the floor. Arranged. You are still holding them. The darkness has learned to copy more than placement."}, "discovery": {"state_effect": {}, "text_de": "Eine Waffe auf dem Boden. Noch warm. Nicht fallen gelassen – hingelegt. Arrangiert, als wollte jemand, dass sie gefunden wird. Die Anordnung ist präzise. Militärisch. Frisch.", "text_en": "A weapon on the floor. Still warm. Not dropped – placed. Arranged, as if someone wanted it found. The arrangement is precise. Military. Recent."}, "echo": {"state_effect": {}, "text_de": "{agent} entdeckt dieselbe Waffe – oder ihren Zwilling. Diese ist kalt. Die Anordnung ist identisch, aber die Präzision hat nachgelassen. Als hätte die Dunkelheit die Platzierung aus der Erinnerung kopiert.", "text_en": "{agent} spots the same weapon – or its twin. This one is cold. The arrangement is identical, but the precision has softened. As if the darkness copied the placement from memory."}, "mutation": {"state_effect": {}, "text_de": "Drei Waffen jetzt. Die Anordnung ist ein Muster geworden. Das Muster ist eine Nachricht geworden. Die Nachricht lautet: »Ihr seid nicht die Ersten. Ihr seid nicht die Letzten. Ihr seid nicht einmal die Interessantesten.«", "text_en": "Three weapons now. The arrangement has become a pattern. The pattern has become a message. The message reads: 'You are not the first. You are not the last. You are not even the most interesting.'"}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$shadow_footprint$DQ$, $DQ$The Shadow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Eure Spuren. Aktuelle Position. Führend dorthin, wo ihr noch nicht wart. Der Weg ist bereits gezeichnet.", "text_en": "Your footprints. Current position. Leading to where you have not been yet. The path is already drawn."}, "discovery": {"state_effect": {}, "text_de": "Eine einzelne Spur im Staub. Frisch. In die Tiefe führend. Der Schritt ist sicher – wer hier ging, wusste wohin. Die Spur endet an einer Wand.", "text_en": "A single set of footprints in the dust. Recent. Heading deeper. The stride is confident – whoever walked here knew where they were going. The footprints end at a wall."}, "echo": {"state_effect": {}, "text_de": "{agent} entdeckt wieder Spuren. Zwei Sätze jetzt. Selber Schritt, selbe Tiefe. Einer führt vorwärts. Einer zurück. Keiner ist eurer.", "text_en": "{agent} spots footprints again. Two sets now. Same stride, same depth. One leads forward. One leads back. Neither is yours."}, "mutation": {"state_effect": {}, "text_de": "Spuren auf jeder Fläche. Wände. Decke. Boden. Alle nach innen gerichtet. Die Dunkelheit hat gelernt, wohin alles läuft.", "text_en": "Footprints cover every surface. Walls. Ceiling. Floor. All heading inward. The darkness has learned where everything walks."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$shadow_whisper$DQ$, $DQ$The Shadow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Stille. Das Flüstern verstummt. Und dann, in vollkommener Klarheit, in der Stimme eurer Gruppe: die exakten Worte aus dem ersten Raum. Wörtlich. Die Dunkelheit erinnert sich besser als ihr.", "text_en": "Silence. The whisper stops. And then, in perfect clarity, in the voice of your party: the exact words spoken in the first room. Verbatim. The darkness remembers better than you do."}, "discovery": {"state_effect": {}, "text_de": "Ein Flüstern. Keine Worte – die Form von Worten. Als hätte die Dunkelheit Gespräche belauscht und den Rhythmus behalten, aber die Bedeutung verloren.", "text_en": "A whisper. Not words – the shape of words. As if the darkness overheard conversations and kept the rhythm but lost the meaning."}, "echo": {"state_effect": {}, "text_de": "{agent} hält inne. Das Flüstern wieder. Näher. Es hat jetzt Vokale gefunden. Es übt.", "text_en": "{agent} pauses. The whisper again. Closer. It has found vowels now. It is practicing."}, "mutation": {"state_effect": {}, "text_de": "Das Flüstern füllt die Korridore. Es überlagert sich. Bruchstücke von Sätzen, die vertraut klingen – taktische Briefings, Statusberichte, Namen. Die Dunkelheit hört zu seit dem ersten Raum.", "text_en": "The whispers fill the corridors. They overlap. Fragments of sentences that sound familiar – tactical briefings, status reports, names. The darkness has been listening since the first room."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$shadow_candle$DQ$, $DQ$The Shadow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Eine Kerze. Ihre Flamme ist eure Silhouette. Sie hat euch die ganze Zeit verbrannt – nicht verzehrend, memorierend.", "text_en": "One candle. Its flame is your silhouette. It has been burning you this entire time – not consuming, memorizing."}, "discovery": {"state_effect": {}, "text_de": "Eine Kerze. Brennend. Die Flamme flackert nicht – sie zeigt. Nach innen. Als würde die Dunkelheit Atem holen.", "text_en": "A candle. Lit. The flame does not flicker – it points. Toward the interior. As if the darkness were drawing breath."}, "echo": {"state_effect": {}, "text_de": "{agent} zählt die Kerzen jetzt. Sieben. Jede Flamme zeigt in eine andere Richtung. Keine von ihnen zeigt zum Ausgang.", "text_en": "{agent} counts the candles now. Seven. Each flame points in a different direction. None of them point toward the exit."}, "mutation": {"state_effect": {}, "text_de": "Kerzen säumen jede Fläche. Ihre Flammen sind schwarz jetzt – nicht erloschen, invertiert. Sie werfen Schatten statt Licht. Der Raum ist dunkler durch ihre Gegenwart.", "text_en": "Candles line every surface. Their flames are black now – not extinguished, inverted. They cast shadow instead of light. The room is darker for their presence."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$shadow_map$DQ$, $DQ$The Shadow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die letzte Karte. Sie zeigt einen Raum. Diesen Raum. Von innen. Ihr seid auf der Karte. In Bewegung. Die Karte beobachtet euch in Echtzeit.", "text_en": "The final map. It shows one room. This room. From inside it. You are on the map. Moving. The map is watching you in real time."}, "discovery": {"state_effect": {}, "text_de": "Eine Karte. Handgezeichnet, akribisch. Die Korridore, die sie beschreibt, passen nicht zu diesem Ort. Oder sie passen zu ihm, wie er war, bevor ihr kamt – bevor die Dunkelheit sich umordnete, um euch zu empfangen.", "text_en": "A map. Hand-drawn, meticulous. The corridors it describes do not match this place. Or they match it as it was before you arrived – before the darkness rearranged itself to receive you."}, "echo": {"state_effect": {}, "text_de": "{agent} findet die Karte wieder. Aktualisiert. Eure Position ist markiert. Eure Route ist eingezeichnet. In Tinte, die noch feucht ist.", "text_en": "{agent} finds the map again. Updated. Your position is marked. Your route is drawn. In ink that is still wet."}, "mutation": {"state_effect": {}, "text_de": "Karten an jeder Wand. Dutzende. Jede zeigt denselben Dungeon aus einer anderen Perspektive. Eine von oben. Eine von unten. Eine von innerhalb der Wände.", "text_en": "Maps on every wall. Dozens. Each shows the same dungeon from a different perspective. One is drawn from above. One from below. One from inside the walls."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$shadow_door$DQ$, $DQ$The Shadow$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Eine Tür. Offen. Dahinter: dieser Raum. Eure Gruppe. Von hinten gesehen. Die Tür war nie von dieser Seite verschlossen.", "text_en": "One door. Open. Beyond it: this room. Your party. Seen from behind. The door was never locked from this side."}, "discovery": {"state_effect": {}, "text_de": "Eine Tür in der Wand. Verschlossen. Kein Schlüsselloch. Sie führt nirgendwo hin – die Wand dahinter ist massiv. Jemand hat eine Tür gebaut, die nie geöffnet werden sollte.", "text_en": "A door in the wall. Locked. No keyhole. It does not lead anywhere – the wall behind it is solid. Someone built a door that was never meant to open."}, "echo": {"state_effect": {}, "text_de": "{agent} hört Klopfen. Von der anderen Seite. Es gibt keine andere Seite. Das Klopfen folgt {agent}s Puls. Dann dem Puls von etwas anderem.", "text_en": "{agent} hears knocking. From the other side. There is no other side. The knocking matches {agent}'s heartbeat. Then it matches something else's."}, "mutation": {"state_effect": {}, "text_de": "Türen überall. Alle verschlossen. Alle identisch. Das Klopfen kommt jetzt von allen. Es ist synchronisiert. Geduldig. Was auch immer dahinter ist, hat gelernt zu warten.", "text_en": "Doors everywhere. All locked. All identical. The knocking comes from all of them now. It is synchronized. Patient. Whatever is behind them has learned to wait."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$tower_blueprint$DQ$, $DQ$The Tower$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Pult des Crown Keepers: der Original-Bauplan. Architektenunterschrift am unteren Rand. Der Name ist eurer.", "text_en": "The Crown Keeper's desk: the original blueprint. Architect's signature at the bottom. The name is yours."}, "discovery": {"state_effect": {}, "text_de": "Ein Bauplan, auf den Empfangstresen geheftet. Grundrisse eines Gebäudes, das nicht zu diesem passt – oder vielmehr: das zu diesem passt, wie es entworfen war, bevor die Stockwerke anfingen, einander zu widersprechen.", "text_en": "A blueprint pinned to the reception desk. Floor plans for a building that does not match this one – or rather, matches it as it was designed, before the floors began to disagree with each other."}, "echo": {"state_effect": {}, "text_de": "{agent} findet denselben Bauplan, aktualisiert. Neue Stockwerke wurden von einer anderen Hand ergänzt. Die neuen Stockwerke haben keine Ausgänge.", "text_en": "{agent} finds the same blueprint, updated. New floors have been added in a different hand. The new floors have no exits."}, "mutation": {"state_effect": {}, "text_de": "Der Bauplan ist wieder hier. Er wurde korrigiert – jeder Raum, den ihr betreten habt, ist jetzt markiert. Eure Route ist rot eingezeichnet. Die rote Linie geht über eure aktuelle Position hinaus. Sie endet im Raum über diesem.", "text_en": "The blueprint is here again. It has been corrected – every room you have entered is now marked. Your route is drawn in red. The red line continues beyond your current position. It ends in the room above this one."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$tower_receipt$DQ$, $DQ$The Tower$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Crown Keeper reicht eine leere Quittung. »Die letzte Transaktion«, sagt er. »Hier unterschreiben. Das Gebäude akzeptiert alle Formen von Sicherheit.«", "text_en": "The Crown Keeper extends a blank receipt. 'The final transaction', they say. 'Sign here. The building accepts all forms of collateral.'"}, "discovery": {"state_effect": {}, "text_de": "Eine Quittung, unter einem Briefbeschwerer. Die Transaktion: eine Strukturgarantie, erworben zu einem Preis, der geschwärzt wurde. Die Garantie ist drei Stockwerke zuvor abgelaufen.", "text_en": "A receipt, pressed under a paperweight. The transaction: one structural guarantee, purchased at a price that has been redacted. The guarantee expired three floors ago."}, "echo": {"state_effect": {}, "text_de": "{agent} liest eine weitere Quittung. Dasselbe Format, andere Transaktion. Diese kauft Zeit. Der Betrag: »verbleibend«.", "text_en": "{agent} reads another receipt. Same format, different transaction. This one purchases time. The amount: 'remaining.'"}, "mutation": {"state_effect": {}, "text_de": "Quittungen bedecken den Boden wie Schnee. Jede eine Garantie – strukturell, temporal, existenziell. Alle abgelaufen. Die Daten sind fortlaufend. Das letzte Datum ist heute.", "text_en": "Receipts cover the floor like snow. Each one a guarantee – structural, temporal, existential. All expired. The dates are sequential. The last date is today."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$tower_elevator$DQ$, $DQ$The Tower$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Der Raum des Crown Keepers hat keinen Fahrstuhl. Der Knopf ist trotzdem hier. Stockwerk 0. Das Messing ist abgegriffen von einer Hand, die nicht menschlich ist. Der Fahrstuhl ist angekommen. Er ist leer.", "text_en": "The Crown Keeper's room has no elevator. The button is here anyway. Floor 0. The brass is worn by a hand that is not human. The elevator arrived. It is empty."}, "discovery": {"state_effect": {}, "text_de": "Ein Fahrstuhlknopf. Stockwerk −1. So oft gedrückt, dass das Messing konkav geschliffen ist. Der Fahrstuhl kam nie.", "text_en": "An elevator button. Floor −1. Pressed so many times the brass is worn concave. The elevator never came."}, "echo": {"state_effect": {}, "text_de": "{agent} passiert denselben Knopf, drei Stockwerke höher. Das Messing ist jetzt makellos – unbenutzt, als wäre diese Version nie gedrückt worden. Er ist warm. Erwartungsvoll.", "text_en": "{agent} passes the same button, three floors higher. The brass is pristine now – unworn, as if this version has never been pressed. It is warm to the touch. Expectant."}, "mutation": {"state_effect": {}, "text_de": "Stockwerk −1, wieder. Der Knopf ist eingedrückt. Permanent. Er lässt sich nicht lösen. Die Stockwerksanzeige darüber zeigt euer aktuelles Stockwerk. Er ist euch gefolgt.", "text_en": "Floor −1 again. The button is pressed in. Permanently. It will not release. The floor indicator above it reads your current floor. It has been following you."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$tower_level$DQ$, $DQ$The Tower$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Wasserwaage auf dem Pult des Crown Keepers. Die Blase fehlt. Die Flüssigkeit darin ist still. Es gibt hier keine Schwerkraft. Es gibt nur die Meinung des Gebäudes.", "text_en": "The spirit level on the Crown Keeper's desk. The bubble is missing. The liquid inside is still. There is no gravity here. There is only the building's opinion."}, "discovery": {"state_effect": {}, "text_de": "Eine Wasserwaage, auf dem Empfangstresen montiert. Die Blase sitzt exakt in der Mitte. Das Gebäude sagt sich, es sei gerade. Das Gebäude lügt.", "text_en": "A spirit level mounted on the reception desk. The bubble sits dead center. The building tells itself it is straight. The building is lying."}, "echo": {"state_effect": {}, "text_de": "{agent} passiert die Wasserwaage erneut. Die Blase hat sich bewegt – nicht zur Seite, sondern zu beiden. Zwei Blasen jetzt. Das Gebäude verhandelt mit der Schwerkraft.", "text_en": "{agent} passes the spirit level again. The bubble has moved – not to one side but to both. Two bubbles now. The building is negotiating with gravity."}, "mutation": {"state_effect": {}, "text_de": "Wasserwaagen auf jeder Fläche. Wände, Decke, Regale. Jede Blase zeigt Mitte. Das Gebäude hat ein Gleichgewicht erreicht – nicht durch Geradheit, sondern durch Neudefinition von Geradheit.", "text_en": "Spirit levels on every surface. Walls, ceiling, shelves. Every bubble reads center. The building has achieved equilibrium – not by being level, but by redefining what level means."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$tower_nameplate$DQ$, $DQ$The Tower$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Namensschild des Crown Keepers. Kein Name. Nur ein Titel: »Letzter Mieter.« Darunter, in kleinerer Schrift: »Permanent.«", "text_en": "The Crown Keeper's nameplate. No name. Just a title: 'Last Tenant.' Below it, in smaller text: 'Permanent.'"}, "discovery": {"state_effect": {}, "text_de": "Ein Namensschild auf einem leeren Schreibtisch. Der Name wurde ausgekratzt und ersetzt. Ausgekratzt und ersetzt. Sieben Mal. Der Schreibtisch hat sie alle überdauert.", "text_en": "A nameplate on an empty desk. The name has been scratched out and replaced. Scratched out and replaced. Seven times. The desk has outlasted all of them."}, "echo": {"state_effect": {}, "text_de": "{agent} liest ein weiteres Namensschild. Der Name ist diesmal lesbar. Es ist eine Zahl. Eine Stockwerkzählung. Der Schreibtisch gehört dem, der ihn erreicht.", "text_en": "{agent} reads another nameplate. The name is legible this time. It is a number. A floor count. The desk belongs to whoever reaches it."}, "mutation": {"state_effect": {}, "text_de": "Namensschilder auf jedem Schreibtisch. Die Namen sind fortlaufend: Stockwerk 1, Stockwerk 2 – bis zu einer Zahl, die höher ist, als das Gebäude Stockwerke hat. Die Schreibtische sind für Mieter, die noch nicht angekommen sind. Oder für Stockwerke, die noch nicht gebaut wurden.", "text_en": "Nameplates on every desk. The names are sequential: Floor 1, Floor 2 – up to a number higher than the building has floors. The desks are for tenants who have not arrived yet. Or for floors not yet built."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$tower_clock$DQ$, $DQ$The Tower$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Die Uhr des Crown Keepers. Ein Zeiger. Er zeigt auf euch. Er hat immer auf euch gezeigt.", "text_en": "The Crown Keeper's clock. One hand. It points at you. It has always pointed at you."}, "discovery": {"state_effect": {}, "text_de": "Eine Wanduhr. Der Stundenzeiger bewegt sich. Der Minutenzeiger nicht. Der Sekundenzeiger tickt rückwärts in unregelmäßigen Abständen. Das Gebäude führt seine eigene Zeit.", "text_en": "A wall clock. The hour hand moves. The minute hand does not. The second hand ticks backward at irregular intervals. The building keeps its own time."}, "echo": {"state_effect": {}, "text_de": "{agent} prüft die Uhr. Alle drei Zeiger bewegen sich jetzt – vorwärts, aber mit verschiedenen Geschwindigkeiten. Der Stundenzeiger ist am schnellsten. Das Gebäude hat es eilig, etwas zu beenden.", "text_en": "{agent} checks the clock. All three hands move now – forward, but at different speeds. The hour hand is fastest. The building is in a hurry to finish something."}, "mutation": {"state_effect": {}, "text_de": "Uhren an jeder Wand. Keine stimmt überein. Aber jede ist in sich konsistent – sie lügen nicht, sie bewohnen verschiedene Versionen von Jetzt. Das Gebäude hat mehr als eine Gegenwartsform.", "text_en": "Clocks on every wall. None agree. But each is internally consistent – they do not lie, they simply occupy different versions of now. The building has more than one present tense."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$tower_memo$DQ$, $DQ$The Tower$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Auf dem Pult des Crown Keepers: eure Akte. Jeder Raum, den ihr betreten habt. Jede Entscheidung dokumentiert. Die letzte Seite ist leer bis auf ein einzelnes Wort: »Genehmigt.«", "text_en": "On the Crown Keeper's desk: your file. Every room you entered. Every choice documented. The last page is blank except for a single word: 'Approved.'"}, "discovery": {"state_effect": {}, "text_de": "Ein Memo, an die Pinnwand geheftet. Betreff: »Re: Unautorisierter Aufstieg (Az. 4471-B).« Der Text ist ein einziger Satz: »Zugang wird rückwirkend jenen gewährt, die die Prüfung überstehen.«", "text_en": "A memo pinned to the noticeboard. Subject: 'Re: Unauthorized Ascent (ref. 4471-B).' The text is a single sentence: 'Access is granted retroactively to those who survive the audit.'"}, "echo": {"state_effect": {}, "text_de": "{agent} findet dasselbe Memo, gestempelt und gegengezeichnet. Eine handschriftliche Notiz am Rand: »Siehe auch: Strukturhaftung, Anhang C.« Es gibt keinen Anhang C.", "text_en": "{agent} finds the same memo, stamped and countersigned. A handwritten note in the margin: 'See also: structural liability, Appendix C.' There is no Appendix C."}, "mutation": {"state_effect": {}, "text_de": "Memos auf jeder Fläche. Ein Schriftverkehr über Jahrzehnte. Die Betreffzeile ändert sich nie. Die Dringlichkeit eskaliert. Das letzte Memo trägt den Vermerk »LETZTE MAHNUNG« in zitternder Handschrift.", "text_en": "Memos on every surface. A correspondence thread spanning decades. The subject line never changes. The urgency escalates. The last memo is marked 'FINAL NOTICE' in a hand that shakes."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$tower_scale_model$DQ$, $DQ$The Tower$DQ$, $JB${"climax": {"state_effect": {}, "text_de": "Das Maßstabsmodell auf dem Pult des Crown Keepers. Es zeigt einen Raum. Diesen Raum. Darin: ein kleineres Modell. Darin: ein weiteres. Das Gebäude enthält sich selbst. Das tat es immer.", "text_en": "The scale model on the Crown Keeper's desk. It shows one room. This room. Inside it: a smaller model. Inside that: another. The building contains itself. It always has."}, "discovery": {"state_effect": {}, "text_de": "Ein Maßstabsmodell des Gebäudes. Unter Glas. Die Proportionen stimmen nicht – die oberen Stockwerke sind größer als die unteren. Das Modell besteht darauf, dass das korrekt ist. Das Glas ist warm.", "text_en": "A scale model of the building. Under glass. The proportions are wrong – the top floors are larger than the bottom. The model insists this is correct. The glass is warm."}, "echo": {"state_effect": {}, "text_de": "{agent} betrachtet das Modell erneut. Es ist gewachsen. Neue Stockwerke, hinzugefügt seit eurem letzten Besuch. Winzige Figuren steigen in den Treppenhäusern. Eine Gruppe entspricht exakt eurer Gruppenstärke.", "text_en": "{agent} examines the model again. It has grown. New floors, added since your last visit. Tiny figures climb the stairwells. One group matches your party's size exactly."}, "mutation": {"state_effect": {}, "text_de": "Das Modell füllt jetzt den Raum. Es ist keine Darstellung mehr – es ist ein Entwurf. Die Stockwerke ragen über die Decke hinaus. Das Gebäude plant Erweiterungen, die die Realität noch nicht genehmigt hat.", "text_en": "The model fills the room now. It is no longer a representation – it is a proposal. The floors extend upward past the ceiling. The building is planning additions that reality has not yet approved."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Awakening$DQ$, $DQ$The threshold hums. Not mechanically – the singing of the most distant, of the most utterly distant, voices. Kafka's telephone: this is the only real and reliable thing. Everything beyond is reconstruction.$DQ$, $DQ$Die Schwelle summt. Nicht mechanisch – das Singen der fernsten, der allerallerfernsten Stimmen. Kafkas Telefon: dies ist das einzig Reale und Verlässliche. Alles dahinter ist Rekonstruktion.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Awakening$DQ$, $DQ$The entrance is familiar. {agent} has not been here. The familiarity is not personal – it is collective. Something in the architecture recognizes the species, not the individual.$DQ$, $DQ$Der Eingang ist vertraut. {agent} war nicht hier. Die Vertrautheit ist nicht persönlich – sie ist kollektiv. Etwas in der Architektur erkennt die Spezies, nicht das Individuum.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Awakening$DQ$, $DQ$A mirror at the entrance. Not glass. Not water. Something that reflects without material. {agent}'s reflection arrives half a second late.$DQ$, $DQ$Ein Spiegel am Eingang. Nicht Glas. Nicht Wasser. Etwas, das ohne Material reflektiert. {agent}s Spiegelung kommt eine halbe Sekunde zu spät.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Awakening$DQ$, $DQ$Beyond the threshold, the air changes. Not temperature – density of attention. Something is already aware that the party has arrived. It was aware before they decided to enter.$DQ$, $DQ$Hinter der Schwelle ändert sich die Luft. Nicht die Temperatur – die Dichte der Aufmerksamkeit. Etwas ist sich bereits bewusst, dass die Gruppe angekommen ist. Es war bewusst, bevor sie sich entschieden einzutreten.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Awakening$DQ$, $DQ$The descent begins. Not physically – the floor is level. The descent is into layers of consciousness. Bergson's cone: the summit is the narrow present. The base is the totality of memory.$DQ$, $DQ$Der Abstieg beginnt. Nicht physisch – der Boden ist eben. Der Abstieg geht in Schichten des Bewusstseins. Bergsons Kegel: der Gipfel ist die enge Gegenwart. Die Basis ist die Gesamtheit der Erinnerung.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$The stairs descend. The last three steps are wet. Not splashed – saturated. The water has been here before and left a mineral signature. It will return.$DQ$, $DQ$Die Treppe führt hinab. Die letzten drei Stufen sind nass. Nicht bespritzt – durchtränkt. Das Wasser war schon hier und hinterließ eine mineralische Signatur. Es wird zurückkehren.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$Dripping. Rhythmic. The sound precedes the dungeon – a metronome set by geology. {agent} counts the interval. 3.2 seconds. The interval will shorten.$DQ$, $DQ$Tropfen. Rhythmisch. Das Geräusch geht dem Dungeon voraus – ein von der Geologie eingestelltes Metronom. {agent} zählt das Intervall. 3,2 Sekunden. Das Intervall wird sich verkürzen.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$The air is different here. Humid. Heavy. The kind of air that has passed through water recently and carries its memory. Salt. Mineral. Patience.$DQ$, $DQ$Die Luft ist hier anders. Feucht. Schwer. Die Art Luft, die kürzlich durch Wasser ging und seine Erinnerung trägt. Salz. Mineral. Geduld.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$A watermark on the entrance arch. Faint. Mineral-white. Evidence of a previous visit by something that does not knock.$DQ$, $DQ$Ein Wasserzeichen am Eingangsbogen. Schwach. Mineralweiß. Beweis für einen früheren Besuch durch etwas, das nicht anklopft.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Deluge$DQ$, $DQ$The threshold is damp. Beyond it, the floor slopes downward – gently, deliberately. The architecture was designed for drainage. The drainage has failed.$DQ$, $DQ$Die Schwelle ist feucht. Dahinter fällt der Boden ab – sanft, absichtlich. Die Architektur wurde für Entwässerung entworfen. Die Entwässerung hat versagt.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Devouring Mother$DQ$, $DQ$The passage opens. Not like a door – like an invitation. The walls are warm. The floor yields slightly underfoot, accommodating. The air carries a scent that is not unpleasant, not identifiable, but somehow familiar. Something here has been waiting. Patiently. Fondly.$DQ$, $DQ$Der Durchgang öffnet sich. Nicht wie eine Tür – wie eine Einladung. Die Wände sind warm. Der Boden gibt leicht nach, entgegenkommend. Die Luft trägt einen Duft, der nicht unangenehm ist, nicht bestimmbar, aber irgendwie vertraut. Etwas hier hat gewartet. Geduldig. Liebevoll.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Devouring Mother$DQ$, $DQ$Warmth. Immediate and specific. Not the warmth of a climate system – the warmth of proximity. Of being expected. The tissue-walls contract gently as you enter. A welcome. Or an embrace that has not yet decided to let go.$DQ$, $DQ$Wärme. Unmittelbar und spezifisch. Nicht die Wärme einer Klimaanlage – die Wärme von Nähe. Von Erwartetsein. Die Gewebewände ziehen sich sanft zusammen, als ihr eintretet. Ein Willkommen. Oder eine Umarmung, die noch nicht beschlossen hat loszulassen.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Devouring Mother$DQ$, $DQ$The entrance smells of growth. Not the sharp green of new shoots – the deep, humid warmth of things that have been growing for a long time in the dark. The walls pulse. Once. As if acknowledging your arrival.$DQ$, $DQ$Der Eingang riecht nach Wachstum. Nicht das scharfe Grün neuer Triebe – die tiefe, feuchte Wärme von Dingen, die lange im Dunkeln gewachsen sind. Die Wände pulsieren. Einmal. Als würden sie eure Ankunft zur Kenntnis nehmen.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Devouring Mother$DQ$, $DQ$The corridor narrows. Not threatening – intimate. The dimensions suggest that this space was grown, not built, and grown for a specific number of occupants. Your number. The fit is perfect. That should concern you more than it does.$DQ$, $DQ$Der Korridor verengt sich. Nicht bedrohlich – intim. Die Maße legen nahe, dass dieser Raum gewachsen ist, nicht gebaut, und gewachsen für eine bestimmte Anzahl von Bewohnern. Eure Anzahl. Die Passform ist perfekt. Das sollte euch mehr beunruhigen, als es das tut.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Devouring Mother$DQ$, $DQ$Something is humming behind the walls. Low. Rhythmic. Biological. It is not a machine. It is not music. It is the sound a living thing makes when it is content. When it is fed. When it is about to be fed again.$DQ$, $DQ$Etwas summt hinter den Wänden. Tief. Rhythmisch. Biologisch. Es ist keine Maschine. Es ist keine Musik. Es ist das Geräusch, das ein lebendiges Wesen macht, wenn es zufrieden ist. Wenn es gefüttert wurde. Wenn es gleich wieder gefüttert wird.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Entropy$DQ$, $DQ$The entrance is indistinct. Not ruined – reduced. The walls retain the memory of colour without the colour itself. The air tastes of averaged everything. Somewhere ahead, a distinction is being quietly dissolved.$DQ$, $DQ$Der Eingang ist unbestimmt. Nicht zerstört – reduziert. Die Wände bewahren die Erinnerung an Farbe ohne die Farbe selbst. Die Luft schmeckt nach dem Durchschnitt von allem. Irgendwo voraus wird eine Unterscheidung leise aufgelöst.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Entropy$DQ$, $DQ$You enter. Or the room receives you. The distinction is already softer than it should be. The threshold is the same material as the floor. The floor is the same temperature as the air.$DQ$, $DQ$Ihr tretet ein. Oder der Raum empfängt euch. Die Unterscheidung ist bereits weicher, als sie sein sollte. Die Schwelle besteht aus demselben Material wie der Boden. Der Boden hat dieselbe Temperatur wie die Luft.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Entropy$DQ$, $DQ$The corridor ahead is visible. Featureless. Not stripped – equalized. Every surface approaches the same shade. The instruments confirm what the instruments measure. They do not confirm what the instruments mean.$DQ$, $DQ$Der Korridor voraus ist sichtbar. Merkmalslos. Nicht entblößt – angeglichen. Jede Fläche nähert sich demselben Farbton. Die Instrumente bestätigen, was die Instrumente messen. Sie bestätigen nicht, was die Instrumente bedeuten.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Entropy$DQ$, $DQ$A room. Probably the first. The ordinal is already uncertain. There are walls. There is a floor. The ceiling is the same distance from both.$DQ$, $DQ$Ein Raum. Wahrscheinlich der erste. Die Ordnungszahl ist bereits unsicher. Es gibt Wände. Es gibt einen Boden. Die Decke hat von beiden denselben Abstand.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Entropy$DQ$, $DQ$The information here is precise. Temperature: ambient. Humidity: ambient. Threat level: ambient. Everything is ambient. That is the threat.$DQ$, $DQ$Die Informationen hier sind präzise. Temperatur: Umgebung. Luftfeuchtigkeit: Umgebung. Bedrohungsstufe: Umgebung. Alles ist Umgebung. Das ist die Bedrohung.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Overthrow$DQ$, $DQ$The threshold is a mirror. Not glass – political. Every reflection shows a different allegiance. Der Spiegelpalast does not ask who you are. It asks who you are for.$DQ$, $DQ$Die Schwelle ist ein Spiegel. Nicht Glas – politisch. Jede Spiegelung zeigt eine andere Treue. Der Spiegelpalast fragt nicht, wer ihr seid. Er fragt, für wen ihr seid.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Overthrow$DQ$, $DQ$The air smells of ink and ambition. Decrees are being written somewhere deeper. The decrees will contradict each other. Both will be enforced.$DQ$, $DQ$Die Luft riecht nach Tinte und Ehrgeiz. Irgendwo tiefer werden Dekrete geschrieben. Die Dekrete werden sich widersprechen. Beide werden durchgesetzt.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Overthrow$DQ$, $DQ$Factions. The word is not adequate. These are ecosystems of belief, each convinced of its own necessity. Machiavelli's fox and lion, multiplied.$DQ$, $DQ$Fraktionen. Das Wort ist nicht adäquat. Das sind Ökosysteme des Glaubens, jedes überzeugt von seiner eigenen Notwendigkeit. Machiavellis Fuchs und Löwe, multipliziert.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Overthrow$DQ$, $DQ$Power changes hands here. Not violently – procedurally. The forms are filled out. The signatures are forged. The forgeries are notarized.$DQ$, $DQ$Hier wechselt die Macht die Hände. Nicht gewaltsam – verfahrenstechnisch. Die Formulare werden ausgefüllt. Die Unterschriften werden gefälscht. Die Fälschungen werden beglaubigt.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Overthrow$DQ$, $DQ$The descent begins. Not into darkness – into politics. The lighting is excellent. Everything is visible. Zamyatin's glass walls. Privacy is not forbidden. It is conceptually abolished.$DQ$, $DQ$Der Abstieg beginnt. Nicht in Dunkelheit – in Politik. Die Beleuchtung ist ausgezeichnet. Alles ist sichtbar. Zamjatins gläserne Wände. Privatsphäre ist nicht verboten. Sie ist begrifflich abgeschafft.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$The threshold does not yield. It opens. Deliberately. Beyond it, the air is warm and charged with potential. Tools line the walls in arrangements that suggest use, not storage. The workshop has been expecting someone.$DQ$, $DQ$Die Schwelle gibt nicht nach. Sie öffnet sich. Absichtlich. Dahinter ist die Luft warm und geladen mit Potential. Werkzeuge säumen die Wände in Anordnungen, die Benutzung suggerieren, nicht Lagerung. Die Werkstatt hat jemanden erwartet.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$Heat. Not the heat of fire – the heat of process. The air smells of ozone and possibility. Somewhere deeper, metal rings against metal. Not randomly. Rhythmically. A heartbeat made of industry.$DQ$, $DQ$Hitze. Nicht die Hitze von Feuer – die Hitze von Prozess. Die Luft riecht nach Ozon und Möglichkeit. Irgendwo tiefer klingt Metall gegen Metall. Nicht zufällig. Rhythmisch. Ein Herzschlag aus Industrie.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$The descent into the workshop begins with a question written on the lintel in a script older than the stone: 'What do you intend to make?' The party has no answer yet. The workshop will provide the materials for one.$DQ$, $DQ$Der Abstieg in die Werkstatt beginnt mit einer Frage, die am Türsturz steht, in einer Schrift, älter als der Stein: »Was beabsichtigt ihr herzustellen?« Der Trupp hat noch keine Antwort. Die Werkstatt wird die Materialien für eine liefern.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$The first room is a catalogue of components. Not displayed – arranged. Each material in its place, each place chosen by a logic that makes no sense until you pick something up and feel where it wants to go. The workshop teaches through inventory.$DQ$, $DQ$Der erste Raum ist ein Katalog von Komponenten. Nicht ausgestellt – arrangiert. Jedes Material an seinem Platz, jeder Platz gewählt nach einer Logik, die keinen Sinn ergibt, bis man etwas aufnimmt und spürt, wohin es will. Die Werkstatt lehrt durch Inventar.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$A forge-glow illuminates the entrance. Not from a furnace – from the walls themselves. The workshop provides its own light, its own heat, its own purpose. All it lacks is hands. Yours will do.$DQ$, $DQ$Ein Schmiedeglühen beleuchtet den Eingang. Nicht von einem Ofen – von den Wänden selbst. Die Werkstatt liefert ihr eigenes Licht, ihre eigene Hitze, ihren eigenen Zweck. Alles, was ihr fehlt, sind Hände. Eure werden genügen.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Shadow$DQ$, $DQ$The threshold yields without resistance. Beyond it, the darkness is not empty – it is attentive. The instruments register nothing. Not zero. Nothing. As if measurement itself requires permission here.$DQ$, $DQ$Die Schwelle gibt widerstandslos nach. Dahinter ist die Dunkelheit nicht leer – sie ist aufmerksam. Die Instrumente registrieren nichts. Nicht Null. Nichts. Als bräuchte das Messen selbst hier eine Erlaubnis.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Shadow$DQ$, $DQ$The air changes at the threshold. Not colder – denser. Sound travels differently here: further, and in directions that should not exist. Something exhales in the distance. It has been holding its breath.$DQ$, $DQ$Die Luft verändert sich an der Schwelle. Nicht kälter – dichter. Schall breitet sich hier anders aus: weiter, und in Richtungen, die es nicht geben sollte. Etwas atmet in der Ferne aus. Es hat den Atem angehalten.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Shadow$DQ$, $DQ$The descent begins. The last light does not fade – it is consumed, methodically, as if the darkness were cataloguing what it has taken. Your shadows arrive before you do.$DQ$, $DQ$Der Abstieg beginnt. Das letzte Licht verblasst nicht – es wird verzehrt, methodisch, als würde die Dunkelheit katalogisieren, was sie genommen hat. Eure Schatten kommen vor euch an.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Shadow$DQ$, $DQ$Silence. Not the silence of emptiness – the silence of something listening. The walls absorb your footsteps and return them a fraction of a second later. The echo is learning your rhythm.$DQ$, $DQ$Stille. Nicht die Stille der Leere – die Stille von etwas, das zuhört. Die Wände absorbieren eure Schritte und geben sie einen Sekundenbruchteil später zurück. Das Echo lernt euren Rhythmus.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Shadow$DQ$, $DQ$A gap in the architecture. The corridor opens into a space that your instruments insist is small but your instincts know is vast. The darkness here has weight. It has patience. It has been here longer than the walls.$DQ$, $DQ$Eine Lücke in der Architektur. Der Korridor öffnet sich in einen Raum, den eure Instrumente als klein bezeichnen, den eure Instinkte aber als riesig kennen. Die Dunkelheit hier hat Gewicht. Sie hat Geduld. Sie ist länger hier als die Wände.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Tower$DQ$, $DQ$The lobby is pristine. Too pristine. The reception desk is unmanned, the ledger open to today's date. Someone has been expected. The elevator indicators read floors that should not exist.$DQ$, $DQ$Die Lobby ist makellos. Zu makellos. Der Empfangstresen ist unbesetzt, das Hauptbuch auf dem heutigen Datum aufgeschlagen. Jemand wurde erwartet. Die Fahrstuhlanzeigen zeigen Stockwerke, die nicht existieren sollten.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Tower$DQ$, $DQ$The revolving door deposits you into a foyer that smells of floor wax and compounding interest. A clock on the wall runs backward. The building does not acknowledge this as unusual.$DQ$, $DQ$Die Drehtür setzt euch in einem Foyer ab, das nach Bodenwachs und Zinseszins riecht. Eine Uhr an der Wand läuft rückwärts. Das Gebäude erkennt daran nichts Ungewöhnliches.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Tower$DQ$, $DQ$Ground floor. The architecture is reasonable here – load-bearing walls where they should be, exits where regulation demands them. This will not last. The building is only polite on the ground floor.$DQ$, $DQ$Erdgeschoss. Die Architektur ist hier vernünftig – Tragwände, wo sie sein sollten, Ausgänge, wo die Vorschrift sie verlangt. Das wird nicht anhalten. Das Gebäude ist nur im Erdgeschoss höflich.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Tower$DQ$, $DQ$A placard by the entrance reads: 'This building has been inspected and found structurally sound.' The date has been scratched out. The inspector's name has been replaced with a floor number.$DQ$, $DQ$Ein Schild am Eingang lautet: »Dieses Gebäude wurde geprüft und für strukturell einwandfrei befunden.« Das Datum wurde ausgekratzt. Der Name des Prüfers durch eine Stockwerknummer ersetzt.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Tower$DQ$, $DQ$The foundation hums. A low, structural vibration that travels upward through the soles. Not mechanical. Organic. The building is aware that you have entered. It adjusts.$DQ$, $DQ$Das Fundament brummt. Eine tiefe, strukturelle Vibration, die durch die Sohlen nach oben wandert. Nicht mechanisch. Organisch. Das Gebäude weiß, dass ihr eingetreten seid. Es passt sich an.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Awakening$DQ$, 0, $DQ$The rooms are quiet in a way that suggests sleep – not absence but suspension. The walls register the party's presence the way a dreamer registers a distant sound.$DQ$, $DQ$Die Räume sind still auf eine Art, die Schlaf nahelegt – nicht Abwesenheit, sondern Suspension. Die Wände registrieren die Präsenz des Trupps wie ein Träumender ein fernes Geräusch registriert.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Awakening$DQ$, 1, $DQ$Something has shifted. The corridors respond a fraction faster now – lights adjust before the party rounds a corner, doors settle into frames as if preparing. The dungeon is stirring.$DQ$, $DQ$Etwas hat sich verschoben. Die Korridore reagieren einen Bruchteil schneller jetzt – Lichter passen sich an, bevor der Trupp um eine Ecke biegt, Türen fügen sich in Rahmen, als bereiteten sie sich vor. Der Dungeon erwacht.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Awakening$DQ$, 2, $DQ$The dungeon is watching. Not with eyes – with attention. The geometry of each room seems arranged for observation. The party is not exploring. The party is being perceived.$DQ$, $DQ$Der Dungeon beobachtet. Nicht mit Augen – mit Aufmerksamkeit. Die Geometrie jedes Raums wirkt wie für Beobachtung arrangiert. Der Trupp erkundet nicht. Der Trupp wird wahrgenommen.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Awakening$DQ$, 3, $DQ$The dungeon remembers. Every room the party has entered, every choice they have made – the walls hold it all, and they are no longer passive. What was asleep is awake. What is awake is thinking.$DQ$, $DQ$Der Dungeon erinnert sich. Jeden Raum, den der Trupp betreten hat, jede Entscheidung – die Wände halten alles, und sie sind nicht mehr passiv. Was schlief, ist wach. Was wach ist, denkt.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Deluge$DQ$, 0, $DQ$The water is present but patient. It laps at the lowest edges of the corridor with the rhythm of something that has not yet decided to rise. The sound is almost gentle.$DQ$, $DQ$Das Wasser ist da, aber geduldig. Es leckt an den niedrigsten Kanten des Korridors im Rhythmus von etwas, das sich noch nicht entschieden hat zu steigen. Das Geräusch ist beinahe sanft.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Deluge$DQ$, 1, $DQ$The water has risen. Not gradually – in the time between noticing and measuring, it gained another centimeter. The current has found a direction. It is moving inward.$DQ$, $DQ$Das Wasser ist gestiegen. Nicht allmählich – in der Zeit zwischen Bemerken und Messen hat es einen weiteren Zentimeter gewonnen. Die Strömung hat eine Richtung gefunden. Sie bewegt sich nach innen.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Deluge$DQ$, 2, $DQ$The water is no longer patient. It pushes. The sound has changed from lapping to pressure – the low, constant hum of volume looking for somewhere to go. It is finding places.$DQ$, $DQ$Das Wasser ist nicht mehr geduldig. Es drängt. Das Geräusch hat sich von Plätschern zu Druck verändert – das tiefe, gleichmäßige Summen von Volumen, das einen Ort sucht. Es findet welche.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Deluge$DQ$, 3, $DQ$The water is here. Not rising – arrived. It fills the space the way an answer fills a question: completely, and with the weight of having always been inevitable.$DQ$, $DQ$Das Wasser ist da. Nicht steigend – angekommen. Es füllt den Raum wie eine Antwort eine Frage füllt: vollständig, und mit dem Gewicht, immer unvermeidlich gewesen zu sein.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Devouring Mother$DQ$, 0, $DQ$The air is warm. Comfortable. The kind of warmth that asks nothing of you.$DQ$, $DQ$Die Luft ist warm. Behaglich. Die Art von Wärme, die nichts von euch verlangt.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Devouring Mother$DQ$, 1, $DQ$The warmth has learned your names. It wraps around wounded agents first. Attentive. Helpful. You did not ask for this.$DQ$, $DQ$Die Wärme hat eure Namen gelernt. Sie legt sich zuerst um verwundete Agenten. Aufmerksam. Hilfsbereit. Ihr habt nicht darum gebeten.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Devouring Mother$DQ$, 2, $DQ$The warmth is possessive now. It does not let go when you stand. Moving through it feels like pulling free of an embrace that does not understand the word 'enough.'$DQ$, $DQ$Die Wärme ist besitzergreifend jetzt. Sie lässt nicht los, wenn ihr aufsteht. Sich durch sie zu bewegen fühlt sich an wie das Lösen aus einer Umarmung, die das Wort »genug« nicht versteht.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Devouring Mother$DQ$, 3, $DQ$The warmth is indistinguishable from you. Where it ends and you begin is a question that no longer has a clear answer. It does not hurt. That is the worst part.$DQ$, $DQ$Die Wärme ist nicht mehr von euch zu unterscheiden. Wo sie aufhört und ihr beginnt, ist eine Frage, die keine klare Antwort mehr hat. Es tut nicht weh. Das ist das Schlimmste.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Entropy$DQ$, 0, $DQ$The walls retain color. Faded, but distinguishable. This room was green once. Or blue. The difference still matters.$DQ$, $DQ$Die Wände haben noch Farbe. Verblasst, aber unterscheidbar. Dieser Raum war einmal grün. Oder blau. Der Unterschied zählt noch.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Entropy$DQ$, 1, $DQ$The color is retreating. Not fading – redistributing. Every surface is approaching the same shade.$DQ$, $DQ$Die Farbe weicht zurück. Nicht verblassend – umverteilend. Jede Oberfläche nähert sich demselben Ton.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Entropy$DQ$, 2, $DQ$Grey. Not the grey of concrete or ash – the grey of averaged everything.$DQ$, $DQ$Grau. Nicht das Grau von Beton oder Asche – das Grau des Durchschnitts von allem.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Entropy$DQ$, 3, $DQ$Same.$DQ$, $DQ$Gleich.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Overthrow$DQ$, 0, $DQ$The corridors are ordered. Signs point in consistent directions. The insignia on the walls match. Someone is in charge here, and the architecture believes them.$DQ$, $DQ$Die Korridore sind geordnet. Schilder weisen in konsistente Richtungen. Die Abzeichen an den Wänden stimmen überein. Jemand hat hier das Sagen, und die Architektur glaubt ihnen.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Overthrow$DQ$, 1, $DQ$A sign has been corrected. The original direction is visible beneath the amendment. Two versions of authority overlap – the first confident, the second insistent.$DQ$, $DQ$Ein Schild wurde korrigiert. Die ursprüngliche Richtung ist unter der Änderung sichtbar. Zwei Versionen von Autorität überlagern sich – die erste zuversichtlich, die zweite bestimmt.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Overthrow$DQ$, 2, $DQ$The signs contradict each other. Three factions have posted directions to the same corridor, each claiming a different destination. The architecture has stopped choosing.$DQ$, $DQ$Die Schilder widersprechen einander. Drei Fraktionen haben Wegweiser zum selben Korridor angebracht, jede mit einem anderen Ziel. Die Architektur hat aufgehört zu wählen.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Overthrow$DQ$, 3, $DQ$No signs. The walls are bare. Every faction's insignia has been torn down, painted over, torn down again. The corridors lead everywhere and nowhere. Authority is a rumor. The building is listening for whoever speaks next.$DQ$, $DQ$Keine Schilder. Die Wände sind kahl. Die Abzeichen jeder Fraktion wurden heruntergerissen, übermalt, erneut heruntergerissen. Die Korridore führen überallhin und nirgendwohin. Autorität ist ein Gerücht. Das Gebäude hört zu, wer als Nächstes spricht.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Prometheus$DQ$, 0, $DQ$The forge is cold. Tools rest in their places. The workshop presents itself with clinical patience. Materials await hands. The fire has not yet been stolen.$DQ$, $DQ$Die Schmiede ist kalt. Werkzeuge ruhen an ihren Plätzen. Die Werkstatt präsentiert sich mit klinischer Geduld. Materialien warten auf Hände. Das Feuer wurde noch nicht gestohlen.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Prometheus$DQ$, 1, $DQ$The forge warms. The first sparks have been struck. Components respond to proximity – not yet with intent, but with interest. The workshop is watching what the party does.$DQ$, $DQ$Die Schmiede erwärmt sich. Die ersten Funken wurden geschlagen. Komponenten reagieren auf Nähe – noch nicht mit Absicht, aber mit Interesse. Die Werkstatt beobachtet, was der Trupp tut.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Prometheus$DQ$, 2, $DQ$The fire burns steady. The workshop has opened its deeper chambers. Materials levitate briefly before settling. The air tastes of ambition. Every surface is warm to the touch.$DQ$, $DQ$Das Feuer brennt gleichmäßig. Die Werkstatt hat ihre tieferen Kammern geöffnet. Materialien schweben kurz, bevor sie sich setzen. Die Luft schmeckt nach Ambition. Jede Oberfläche ist warm bei Berührung.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Prometheus$DQ$, 3, $DQ$White heat. The workshop is no longer subtle. Components arrange themselves without being touched. The forge-glow pulses in time with the party's breathing. The fire knows. The fire burns.$DQ$, $DQ$Weißglut. Die Werkstatt ist nicht mehr subtil. Komponenten ordnen sich an, ohne berührt zu werden. Das Schmiedeglühen pulsiert im Takt der Atmung des Trupps. Das Feuer weiß. Das Feuer brennt.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Shadow$DQ$, 0, $DQ$The amber terminal glow pulses steadily. Warm. Present. It knows where you are.$DQ$, $DQ$Das Bernsteinleuchten des Terminals pulsiert gleichmäßig. Warm. Gegenwärtig. Es weiß, wo ihr seid.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Shadow$DQ$, 1, $DQ$The amber glow flickers. For the first time, the terminal seems uncertain.$DQ$, $DQ$Das Bernsteinleuchten flackert. Zum ersten Mal wirkt das Terminal unsicher.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Shadow$DQ$, 2, $DQ$The amber is fading. The terminal light gutters like a candle in a draft that should not exist in a digital space.$DQ$, $DQ$Das Bernstein verblasst. Das Terminallicht flackert wie eine Kerze im Durchzug, den es in einem digitalen Raum nicht geben sollte.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Shadow$DQ$, 3, $DQ$The amber is gone. The terminal is dark. You are operating from memory now, and memory is exactly what the darkness consumes first.$DQ$, $DQ$Das Bernstein ist erloschen. Das Terminal ist dunkel. Ihr operiert aus der Erinnerung, und Erinnerung ist genau das, was die Dunkelheit zuerst verzehrt.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Tower$DQ$, 0, $DQ$A hairline crack in the east wall. Cosmetic. The building compensates.$DQ$, $DQ$Ein Haarriss in der Ostwand. Kosmetisch. Das Gebäude kompensiert.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Tower$DQ$, 1, $DQ$The crack has branched. The building no longer compensates – it negotiates.$DQ$, $DQ$Der Riss hat sich verzweigt. Das Gebäude kompensiert nicht mehr – es verhandelt.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Tower$DQ$, 2, $DQ$The crack network spans the room. Through it, you can see the floor below. Through that, another floor. The building is becoming transparent in its failure.$DQ$, $DQ$Das Rissnetzwerk durchzieht den Raum. Durch ihn seht ihr das Stockwerk darunter. Durch jenes ein weiteres. Das Gebäude wird transparent in seinem Versagen.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Tower$DQ$, 3, $DQ$The crack is the room. The walls are suggestions. The floor is a theory. The building has stopped pretending.$DQ$, $DQ$Der Riss ist der Raum. Die Wände sind Vorschläge. Der Boden ist eine Theorie. Das Gebäude hat aufgehört, so zu tun als ob.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
